export const timeTableStrings = {
    levels : "levels",
    terms : "terms",
    selectedLevel : "selectedLevel",
    selectedTerm : "selectedTerm",
    timeTableEditMode : "timeTableEditMode",
    timeTableDurationFormat : "timeTableDurationFormat",
    subjects : 'subjects',
    tabValue : "tabValue",
    tabComponent : "tabComponent",
}

export const timeTableConstant = {
    SET_TIMETABLE : "SET_TIMETABLE",
    CLEAN_UP : "CLEAN_UP",
}

export const timeTableReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case timeTableConstant.SET_TIMETABLE :
            return {...state, ...payload};
        case timeTableConstant.CLEAN_UP :
            return {};
        default : return state;
    }
}

