import { fetchGet, post } from "../utils"

export const insureAboutUsServices = {
    unsubscribe : (id, email, callback) => {
        fetchGet("app", "unsubscribe", {id, email}, ({unsubscribe, result, message})=>{
            callback(unsubscribe, result, message);
        })
    },
    addMessage : (data, callback) => {
        post(data, "app", "addMessage", ({addMessage, result, message})=>{
            callback(addMessage, result, message);
        })
    },
    getSiteInfo : callback => {
        fetchGet("app", "getSiteInfo", {name : "aboutUs"}, ({getSiteInfo, result, message})=>{
            callback(getSiteInfo, result, message);
        })
    }
}