export const receivableStrings = {

}
export const receivableConstants = {
    SET_RECEIVABLE : "SET_RECEIVABLE",
    CLEAN_UP_RECEIVABLE :"CLEAN_UP_RECEIVABLE",
}
const receivableInitialState = {

}
export const receivableReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case receivableConstants.SET_RECEIVABLE : 
            return {...state, ...payload};
        case receivableConstants.CLEAN_UP_RECEIVABLE : 
            return {...state, ...receivableInitialState}
        default : return {...state};
    }
}
export * from './actions';
export * from './services';
