export const classStrings = {
    selectedLevel : "selectedLevel",
    classes : "levelClasses",
    listEditMode : "listEditMode",
    subjectsAndAssessments : "subjectsAndAssessments",
    selectedTerm : "selectedTerm",
    terms : "terms",
    classStudents : "classStudents",
    selectedClass : "selectedClass",
    classTimetable : "classTimetable",
    timeTableDurationFormat : "timeTableDurationFormat",
    timeTableEditMode : "timeTableEditMode",
}
export const classConstants = {
    SET_CLASS : "SET_CLASS",
    SET_CLASS_CLEAN_UP : "SET_CLASS_CLEAN_UP"
}
const initialState = {
    
}
export const classReducer = (state=initialState, action) => {
    const {type, payload} = action;
    switch(type){
        case classConstants.SET_CLASS : 
            return {...state, ...payload};
        case classConstants.SET_CLASS_CLEAN_UP : 
            return {};
        default : return {...state};
    }
}
