export const insureUtilStrings = {
    theme : "theme",
    tokenAlias : "tokenAlias",
    isLoggedIn : "isLoggedIn",
    userAlias : "userAlias",
    backendUrl : "backendUrl",
    backendBaseUrl : "backendBaseUrl",
    myProfile : "myProfile",
    settings : "settings",
    forms : "forms",
    subheadImage : "subheadImage",
}

export const insureUtilConstants = {
    SET_UTIL : "SET_UTIL",
}

export const insureUtilReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case insureUtilConstants.SET_UTIL : 
            return {...state, ...payload};
        default : return {...state};
    }
}

