import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, mainStageHeaderAction, mainStageHeaderStrings, breadCrumbActions, MyTable } from "../../includes";
import { routeNamesInventory } from '../routeNames';
import { history } from '../../../helpers';
import { supplierActions } from './actions';
import { supplierStrings } from './config';


const style = theme => ({
    root: {
        marginTop : 20
    }
})
class _Suppliers extends Component {
    constructor(props) {
        super(props);
        this.state = {
            lastId : null,
            rows : null
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "SUPPLIERS",
            [headerStrings.backButtonAction] : null,
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesInventory.dashboard},
            {name : "Suppliers", path : routeNamesInventory.suppliers},
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.buttons] : [
                {value : "New Supplier", onClick : ()=>history.push(routeNamesInventory.newSupplier)}
            ]
        })(dispatch);
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {lastId, rows} =this.state;
        const {dispatch} = this.props;
        supplierActions.getSuppliersBrief(lastId, rows)(dispatch);
    }
    rowAction = row => () =>{
        history.push(routeNamesInventory.supplier_ + row._id, row);
    }
    render() {
        const {
            classes,
            [supplierStrings.suppliersBrief] : suppliersBrief
        } = this.props;
        return (
            <div className={classes.root}>
                <MyTable
                    header={["ID", "Name", "Active Products", "All Productes"]}
                    dataMap={["_id", "name", "activeProductCount", "allProductCount"]}
                    data={suppliersBrief || []}
                    rowAction={this.rowAction.bind(this)}
                    />
            </div>
        );
    }
}


_Suppliers.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({supplierReducer}) => ({
    [supplierStrings.suppliersBrief] : supplierReducer[supplierStrings.suppliersBrief],
})


export const Suppliers = connect(mapStateToProps)(withStyles(style)(_Suppliers));
export {Suppliers as default}