import { insureAdminConstants, insureAdminSiteStrings } from "./config";
import { insureAdminSiteServices } from "./services";
import { successNotice, errorNotice } from "../utils";

export const insureAdminSiteActions = {
    postNewArticle : (form, callback) => dispatch => {
        insureAdminSiteServices.postNewArticle(form, (done, result, message)=>{
            if(done) {
                successNotice(message, dispatch);
                insureAdminSiteActions.getSiteInfo()(dispatch);
            }
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    deleteArticle : (name, subname, callback) => dispatch => {
        insureAdminSiteServices.deleteArticle(name, subname, (done, result, message)=>{
            if(done) {
                successNotice(message, dispatch);
                insureAdminSiteActions.getSiteInfo()(dispatch);
            }
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    updateArticle : (property, name, subname, value, callback) => dispatch => {
        insureAdminSiteServices.updateArticle(property, name, subname, value, (done, result, message)=>{
            if(done) {
                successNotice(message, dispatch);
                insureAdminSiteActions.getSiteInfo()(dispatch);
            }
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    postFile : (form, callback) => dispatch =>{
        insureAdminSiteServices.postFile(form, (done, result, message)=>{
            if(done) {
                successNotice(message, dispatch);
                // insureAdminSiteActions.payload({
                //     [insureAdminSiteStrings.siteInfo] : result
                // })(dispatch);
            }
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    postSiteInfo : (name, subname, propName, value, callback) => dispatch => {
        insureAdminSiteServices.postSiteInfo(name, subname, propName, value, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getSiteInfo : callback => dispatch => {
        insureAdminSiteServices.getSiteInfo((done, result, message)=>{
            if(done) insureAdminSiteActions.payload({
                [insureAdminSiteStrings.siteInfo] : result,
            })(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch => dispatch({
        type : insureAdminConstants.SET_SITE_INFO,
        payload
    })
}