import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { Grid, Card, CardContent, CardHeader, CardActionArea } from '@material-ui/core';
import { TermInfoCard } from './TermInfoCard';
import { colors } from '../../../utils';
import { NewTermCard } from './NewTermCard';
import { InfoText } from '../../includes';
const style = theme => ({
    root: {
        padding : 10,
        backgroundColor : colors.grayTrans,
        [theme.breakpoints.down("md")] : {
            marginTop : 20, 
        }
    }
})
class _TermBoard extends Component {
    render() {
        let {classes, terms, newTermDialogOpen} = this.props;
        if(!terms || terms.length === 0)
            terms = [{new : true, onClick : ()=>{}}];
        else if(!terms[terms.length - 1].new)
            terms = [...terms, {new : true}];
        return (
            <Card className={classes.root}>
                <CardHeader titleTypographyProps={{style : {color: colors.white, fontWeight : "bold"}}} title="Terms"/>
                <CardContent>
                    <Grid container spacing={2}>
                    {terms && terms.map((term, index)=> {
                        return  term.new ? 
                        <Grid key={index} item xs={12} sm={12} md={6} lg={6} xl={4}>
                            <NewTermCard newTermDialogOpen={newTermDialogOpen}/>
                        </Grid> :
                        <Grid key={index} item xs={6} sm={12} md={6} lg={6} xl={4}>
                            <TermInfoCard term={term}/>
                        </Grid>
                    })}
                    </Grid>
                </CardContent>
                <CardActionArea><InfoText>
                    Check for existing classes in creating a term, if present, 
                    add check to included existing classes in session, 
                    else do ask for new classes immediately after term creations.
                </InfoText>
                <InfoText>This can be done letter in the class area</InfoText>
                </CardActionArea>
            </Card>
        );
    }
}
_TermBoard.propTypes = {
    classes : PropTypes.object.isRequired,
    terms : PropTypes.array,
    newTermDialogOpen : PropTypes.func,
};
export const TermBoard = withStyles(style)(_TermBoard);