import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { MenuItem, Button, Menu } from '@material-ui/core';
const style = theme => ({
    root: {
        position : "relative",
        margin : 10,
        display : "flex",
        justifyContent : "center",
        alignItems : 'center',
    },
    button : {

    },
    menu : {
        
    },
    menuItem : {},
})
class _MyPopupMenu extends Component {
    constructor(props) {
        super(props);
        this.state = {
            anchorEl : null
        }
    }
    handleOptionClick = option => () =>{
        this.props.optionClickCallback(option);
        this.setState({anchorEl: null});
    }
    render() {
        const {
            classes, buttonName, buttonValue, 
            options, optionValueProp, optionNameProp, full
        } = this.props;
        const {anchorEl} = this.state;
        return (
            <div ref="root" className={classes.root}>
                <Button 
                    onClick={e=>this.setState({anchorEl : full ? this.refs.root : e.target})}
                    className={classes.button}
                    aria-controls={buttonName+"-menu"}
                    aria-haspopup="true">{buttonValue}</Button>
                {options && <Menu
                    style={{
                        width : "100%",
                    }}
                    classes={{
                        paper : classes.menu
                    }}
                    className={classes.menu}
                    id="level-menu"
                    anchorEl={anchorEl}
                    open={Boolean(anchorEl)}
                    {...this.props.menuProps}
                    onClose={e=>this.setState({anchorEl : null})}>
                        {options && options.map((option, index)=>
                            <MenuItem 
                                className={classes.menuItem}
                                value={option[optionValueProp]} 
                                onClick={this.handleOptionClick(option)} key={index}>
                                {option[optionNameProp]}
                            </MenuItem>)}
                </Menu>}
                </div>
        );
    }
}
_MyPopupMenu.propTypes = {
    classes : PropTypes.object.isRequired,
    buttonName : PropTypes.string.isRequired,
    buttonValue : PropTypes.string.isRequired,
    options : PropTypes.array,
    optionValueProp : PropTypes.string,
    optionNameProp : PropTypes.string,
    optionClickCallback : PropTypes.func,
    full : PropTypes.bool,
    menuProps : PropTypes.object,
};
export const MyPopupMenu = withStyles(style)(_MyPopupMenu);