import React, { Component } from 'react'
import PropTypes from 'prop-types'
import { Grid, FormControl, TextField, Checkbox, FormHelperText, FormControlLabel, Switch, MenuItem, OutlinedInput, Select, InputLabel } from '@material-ui/core';
import classNames from 'classnames';

const style = theme => {{
    
}}
export default class GridFields extends Component {
    static propTypes = {
        element : PropTypes.object.isRequired,
    }
    
    
    render() {
        let {className, description, name, type, gridItemSize, ...props} = this.props.element;
        switch(type){
            case "select" : return <Grid item {...this.props.itemContainerProps} {...gridItemSize}>
                    <FormControl>
                        <InputLabel htmlFor={this.props.element.label}>{this.props.element.label}</InputLabel>
                        <Select                                            
                            variant="standard"
                            value={this.props.data[name] || ""}
                            input={<OutlinedInput id={this.props.data[name]}name={this.props.element.label} labelWidth={100}/>}
                            onChange={this.props.onTextChange(name)}
                            {...this.props.fieldProps}>
                                {this.props.element.options && this.props.element.options.map((item, i)=>{
                                    return <MenuItem key={"select"+i+"-"+this.props.index} value={item.value}>{item.name}</MenuItem>
                                })}
                        </Select>
                        {!this.props.mergeDescriptions && 
                            <FormHelperText {...this.props.fieldDescriptionProps}>
                                {description}
                            </FormHelperText>}
                    </FormControl>
                </Grid>;
            case "check" : return <Grid item  {...this.props.itemContainerProps} {...gridItemSize}>
                <FormControl>
                    <FormControlLabel
                        label={this.props.element.label}
                        control={<Checkbox
                            checked={this.props.data[name]}
                            onChange={this.props.handleChecked(name)}
                            {...this.props.fieldProps}/>}/>                                    
                    {!this.props.mergeDescriptions && 
                        <FormHelperText {...this.props.fieldDescriptionProps}>
                            {description}
                        </FormHelperText>}
                </FormControl>
            </Grid>;
            case "radio" : 
            case "switch" : return <Grid item  {...this.props.itemContainerProps} {...gridItemSize}>
                    <FormControl>
                        <FormControlLabel
                            label={this.props.element.label}
                            control={<Switch 
                                checked={this.props.data[name] || false}
                                onChange={this.props.handleChecked(name)}
                                {...this.props.fieldProps}/>}
                            />
                        {!this.props.mergeDescriptions && 
                        <FormHelperText {...this.props.fieldDescriptionProps}>
                            {description}
                        </FormHelperText>}
                    </FormControl>
                </Grid>
            default : 
                let mainProps = {...this.props.textFieldProps, ...props};
                return <Grid item  {...this.props.itemContainerProps} {...gridItemSize}>
                    <TextField
                        value={this.props.data[name] ||""}
                        type={type}
                        onChange={this.props.onTextChange(name)}
                        className={classNames(this.props.classes.texfField, className)}
                        {...this.props.fieldProps}
                        {...mainProps}/>
                    {!this.props.mergeDescriptions && 
                    <FormHelperText {...this.props.fieldDescriptionProps}>
                        {description}
                    </FormHelperText>}
                </Grid> ;
        }
    }
}
