import React, { useState } from "react";
import { HIRButton } from "../HIRButton/HIRButton";
import { CircularProgress } from "@material-ui/core";
import { makeStyles } from "@material-ui/styles";

export const HIRButtonTable = ({onClickCallback, title, type})=>{
    const style = makeStyles({
        btn : {
            fontSize : 9
        },
    });
    const classes = style();
    const [loading, setLoading] = useState(false)
    const onClick=(e)=>{
        e.stopPropagation();
        e.preventDefault();
        setLoading(true);
        if(onClickCallback) onClickCallback(setLoading);
    }
    return <HIRButton 
        disabled={loading}
        onClick={onClick} classes={classes} type={type}>
        {loading && <CircularProgress 
            color="secondary" 
            style={{width : 11, height : 11}}/>}
            {title}
    </HIRButton>
}