import React, { Component, Fragment } from 'react';
import {connect} from 'react-redux';
import { Typography, FormControlLabel,Menu, Checkbox, Button, MenuItem, FormControl } from '@material-ui/core';
import { colors } from '../../../../utils';
import { sessionStrings } from '../config';
import { sessionActions } from '../actions';


class _NewLevelMainStageHeader extends Component{
    constructor(props) {
        super(props);
        this.state = {
            menuAnchorEl : null,
            usePreviousLevel : false,
            selectedSession : null
        }
    }
    
    handleCheckChange = e => {
        const { dispatch } = this.props;
        const usePreviousLevel = e.target.checked;
        sessionActions.setUsePreviousLevel(usePreviousLevel)(dispatch);
        if(!usePreviousLevel) {
            sessionActions.setSessionPreviousLevels(null)(dispatch);
            this.setState({selectedSession : null});
        }
    }
    handleMenuButtonClick = e => {
        this.setState({menuAnchorEl: e.target})
    }
    handlePreviousMenuClick = selectedSession => () => {
        this.setState({selectedSession, menuAnchorEl : null});
        sessionActions.getSessionLevels(selectedSession._id)(this.props.dispatch);
    }
    render(){
        const {
            [sessionStrings.usePreviousLevel] : usePreviousLevel,
            [sessionStrings.sessions] : sessions = []
        } = this.props;
        const {menuAnchorEl, selectedSession} = this.state;
        return(
            <Fragment>
                <FormControlLabel
                    style={{marginLeft : 5}}
                    control={<Checkbox
                        style={{color : colors.white}}
                        checked={Boolean(usePreviousLevel)}
                        onChange={this.handleCheckChange.bind(this)}
                        />}
                    label={<Typography style={{color : colors.white}}>Use previous level</Typography>}
                    />
                {usePreviousLevel && <FormControl style={{padding : 10}}>
                    <Button 
                        style={{
                            color : colors.white, 
                            backgroundColor : colors.secondary
                        }} 
                        aria-controls="simple-menu" 
                        aria-haspopup="true" 
                        onClick={this.handleMenuButtonClick.bind(this)}>
                        {(selectedSession && selectedSession.name) || "Select Session"}
                    </Button>
                    <Menu
                        id="simple-menu"
                        anchorEl={menuAnchorEl}
                        keepMounted
                        open={Boolean(menuAnchorEl)}
                        onClose={()=>this.setState({menuAnchorEl: null})}
                    >
                        {sessions && sessions.map((sess, index)=> 
                            <MenuItem key={index} onClick={this.handlePreviousMenuClick(sess)}>{sess.name}</MenuItem>)}
                    </Menu>
                </FormControl>}
            </Fragment>
        )
    }
}
export const NewLevelMainStageHeader = connect(({sessionReducer})=>({
    ...sessionReducer
}))(_NewLevelMainStageHeader);
