import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { Card, CardHeader, CardContent, List, ListItem, ListItemText, Divider } from '@material-ui/core';
import { colors } from '../../../utils';
const style = theme => ({
    root: {
        
    },
    header : {
        color : colors.gray
    },
    listItemText : {
        overflowWrap : "break-word"
    }
})
class _SimpleListBoard extends Component {
    render() {
        const {classes, title, data, nameMapper, valueMapper, show, skip} = this.props;
        if(!nameMapper) throw("Name mapper missing")
        if(show && skip) throw("Can not use show and skip at same time --");
        else if(!show && !skip) throw("You must put either SHOW or SKIP")
        return (
            <Card className={classes.root} {...this.props.cardProps}>
                {title && <Fragment>
                    <CardHeader {...this.props.cardHeaderProps} title={title}/>
                    <Divider/>
                </Fragment>}
                {/* <CardContent> */}
                    <List>
                        {data && Object.entries(data).map((itemArray, index)=>{
                            if(!itemArray[0]) return null;
                            if(show) return show.indexOf(itemArray[0]) !== -1 ?
                                <ListItem key={index}>
                                    <ListItemText className={classes.listItemText}>
                                        <strong className={classes.header}>
                                            {nameMapper(itemArray[0])}: 
                                        </strong> {valueMapper ? valueMapper(itemArray[0], itemArray[1]) : itemArray[1]}
                                    </ListItemText>
                                </ListItem> : null
                            else return skip.indexOf(itemArray[0]) === -1 ? 
                                <ListItem key={index}>
                                    <ListItemText className={classes.listItemText}>
                                        <strong className={classes.header}>
                                            {nameMapper(itemArray[0])}: 
                                        </strong> {valueMapper ? valueMapper(itemArray[0], itemArray[1]) : itemArray[1]}
                                    </ListItemText>
                                </ListItem> : null
                        })}
                    </List>
            </Card>
        );
    }
}
_SimpleListBoard.propTypes = {
    classes : PropTypes.object.isRequired,
    title: PropTypes.string,
    data : PropTypes.object,
    nameMapper : PropTypes.func.isRequired,
    valueMapper : PropTypes.func,
    skip : PropTypes.array,
    show : PropTypes.array,

    cardProps : PropTypes.object,
    cardHeaderProps : PropTypes.shape(CardHeader.propTypes),
};
export const SimpleListBoard = withStyles(style)(_SimpleListBoard);