import React, {Fragment} from 'react';
import { Screen, Header, screenStrings } from '../includes';
import {connect} from 'react-redux';
import {Redirect, Route} from 'react-router-dom';
import {insureUtil, insureActions, insureUtilStrings} from  './utils';
import { insureRouteNames } from './routeNames';
import { Footer } from '../includes/SiteComponent';


export const InsureSiteRoute = connect(
    ({screenReducer, insureUtilReducer})=>({
        [screenStrings.appTheme] : screenReducer[screenStrings.appTheme],
        [insureUtilStrings.settings] : insureUtilReducer[insureUtilStrings.settings]
    })
)(({component : Component, ...props}) => {
    const {
        [screenStrings.appTheme] : appTheme,
        [insureUtilStrings.settings] : settings
    } = props;
    let contactValue;
    if(settings) {
        const {item : contactItems} = settings.getFirstObjectByPropValue("name", "contactInfo") || {};
        if(contactItems) contactValue = contactItems.value;
    }
    const {facebook, instagram, twitter} = contactValue || {};
    return (
        <Fragment>
            <Header
                rootProps={{                    
                    style: {backgroundColor : appTheme ? appTheme.primary : null}
                }}
                titleProps={{
                    style : {
                        color : appTheme ? appTheme.backgroundTypo : null,
                        borderBottom : "none",
                    }
                }}
                drawerProps={{
                    color : appTheme ? appTheme.backgroundTypo : null,
                    bgColor : appTheme ? appTheme.drawerBg : null,
                }}
                iconProps={{
                    style : {color : appTheme ? appTheme.backgroundTypo : null}
                }} />
            <Route {...props} component={prop=><Component {...prop}/>}/>
            <Footer
                footerProps={{
                    style : {
                        backgroundColor : appTheme ? appTheme.primary : null,
                    }
                }}
                socialMediaProps={{facebook, instagram, twitter}}
                //     facebook: "moboinsure.health",
                //     instagram: "moboinsure.health",
                //     twitter: "moboinsure.health",
                // }}
                />
        </Fragment>
    )
});
export const InsurePrivateRoute = connect(
    ({screenReducer, insureUtilReducer})=>({
        [screenStrings.appTheme] : screenReducer[screenStrings.appTheme],
        [insureUtilStrings.settings] : insureUtilReducer[insureUtilStrings.settings]
    })
)(({component : Component, ...props}) => {
    const {
        [screenStrings.appTheme] : appTheme,
        [insureUtilStrings.settings] : settings
    } = props;
    let contactValue;
    if(settings) {
        const {item : contactItems} = settings.getFirstObjectByPropValue("name", "contactInfo") || {};
        if(contactItems) contactValue = contactItems.value;
    }
    const {facebook, instagram, twitter} = contactValue || {};
    return (
        <Route {...props} render={props => { 
            return (
                insureUtil.isLogedIn()
                ? <Fragment>
                    <Header
                        rootProps={{                    
                            style: {backgroundColor : appTheme ? appTheme.primary : null}
                        }}
                        titleProps={{
                            style : {
                                color : appTheme ? appTheme.backgroundTypo : null,
                                borderBottom : "none",
                            }
                        }}
                        drawerProps={{
                            color : appTheme ? appTheme.backgroundTypo : null,
                            bgColor : appTheme ? appTheme.drawerBg : null,
                        }}
                        iconProps={{
                            style : {color : appTheme ? appTheme.backgroundTypo : null}
                        }} />
                    <Route {...props} component={prop=><Component {...prop}/>}/>
                    <Footer
                        footerProps={{
                            style : {
                                backgroundColor : appTheme ? appTheme.primary : null,
                            }
                        }}
                        socialMediaProps={{facebook, instagram, twitter}}/>
                </Fragment>
                : (props.match.path === insureRouteNames.login ?
                    <Component {...props}/> : 
                <Redirect to={{ pathname: insureRouteNames.login, state: { from: props.location } }} />)
            )}
        } />
    )
});
export const InsureLogoutRoute = rest =>(
    <Route {...rest} render={props=>{
        insureActions.logout();
        return <Redirect to={{ pathname: insureRouteNames.home, state: { from: props.location } }}/> 
    }}/>
)