import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import classNames from 'classnames';
import {withStyles} from '@material-ui/core/styles';
import { invProductStrings } from '../../config';
import { invProductActions } from '../../actions';
import { StageHeaderPlane, MyDialog} from '../../../utils';
import { INVButton } from '../../../Includes';
import { INVDescriptionBox } from './INVDescriptionBox';
import { INVNewDescription } from './INVNewDescription';

const style = theme => ({
    root: {
    },
    headerStage : {
        marginButtom : 20,
    }
})

class _INVItemDescriptions extends Component {
    constructor(props) {
        super(props);
        this.state = {
            description : null,
            editMode : false,
            newDescriptionDialog : false,
        }
        this.optionNameContexts = {};
        this.optionValueContexts = {}
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {dispatch} = this.props;
        invProductActions.getProductDescriptions()(dispatch);
    }    
    newDescriptionBtn(){
        const {classes} = this.props;
        return <INVButton
            onClick={()=>this.setState({newDescriptionDialog : true})}>
                New Description
            </INVButton>
    }
    createDescription(data, context){
        const {dispatch} = this.props;
        invProductActions.createProductDescription(data, done=>{
            context.setState({loading : false});
            if(done) this.setState({newDescriptionDialog : false});
        })(dispatch);
    }
    render() {
        const {classes, [invProductStrings.productDescriptions] : descriptions} = this.props;
        
        return (
            <div className={classNames(classes.root, "animated", "zoomIn")}>
                <div>
                    <StageHeaderPlane
                        classes={{root : classes.headerStage}}
                        visible={true}
                        components={[
                            this.newDescriptionBtn.bind(this)
                        ]}
                        />
                </div>
                <div style={{marginTop : 20}}>
                    {descriptions && descriptions.map((item, index)=>{ 
                        return <INVDescriptionBox
                            description={item}
                            key={index}/>
                    })}
                </div>
                <MyDialog open={this.state.newDescriptionDialog}
                    close={()=>this.setState({newDescriptionDialog : false})}>
                        <INVNewDescription
                            createDescription={this.createDescription.bind(this)}/>
                    </MyDialog>
            </div>
        );
    }
}


_INVItemDescriptions.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({invProductReducer}) => {
    console.log(invProductReducer);
    return ({
        [invProductStrings.productDescriptions] : invProductReducer[invProductStrings.productDescriptions],
    })
}


export const INVItemDescriptions = connect(mapStateToProps)(withStyles(style)(_INVItemDescriptions));
export {INVItemDescriptions as default}