import { mainStageStrings, mainStageConstants } from "./constants";

const initialState = {
    
}
export const mainStageReducer = (state=initialState, action) =>{
    const {type, payload} = action;
    switch(type){
        case mainStageConstants.SET_MAIN_STAGE : 
            return {...state, ...payload};
        default : return {...state};
    }
}