import { teacherConstants, teacherStrings } from "./config";
import { sessionServices } from "../Sessions";
import { store } from "../../../helpers";
import { teacherServices } from "./services";

export const teacherActions = {
    getLevelTeachers : (levelId, callback) => dispatch => {
        teacherServices.getLevelTeachers(levelId, (done, result, message)=>{
            if(done) dispatch({
                type : teacherConstants.SET_TEACHER,
                payload : {
                    [teacherStrings.levelTeachers] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getStudentRemarks : (levelId, classId, termId, callback)=>dispatch=>{
        teacherServices.getStudentRemarks(
            levelId, classId, termId, (done, result, message)=>{
                if(done) dispatch({
                    type : teacherConstants.SET_TEACHER,
                    payload : {
                        [teacherStrings.classStudentRemarks] : result
                    }
                })
                if(callback) callback(done,result, message);
            }
        )
    },
    getTeacherRemarks : (/* teacherId,  */callback) => dispatch=>{
        teacherServices.getTeacherRemarks(/* teacherId, */ (done, result, message)=>{
            if(done)dispatch({
                type : teacherConstants.SET_TEACHER,
                payload : {
                    [teacherStrings.teacherRemarks] : result
                }
            })
            if(callback) callback(done,result, message);
        })
    },
    //term is specific to sessions, not nested
    getTerms : callback=>dispatch=>{
        sessionServices.getSessionTerms(null, (done, result, message)=>{
            if(done) dispatch({
                type : teacherConstants.SET_TEACHER,
                payload : {
                    [teacherStrings.terms] : result
                }
            })
            if(callback) callback(done, result, message);
        })
    },
    getClasses : (levelId, callback)=>dispatch=>{
        sessionServices.getClasses(levelId, (done, result, message)=>{
            if(done) {
                const {teacherReducer} = store.getState();
                const levelClasses = {...teacherReducer[teacherStrings.classes]};
                if(!levelClasses){
                    levelClasses = {[levelId] : result};
                }else levelClasses[levelId] = result;
                dispatch({
                    type : teacherConstants.SET_TEACHER,
                    payload : {
                        [teacherStrings.classes] : levelClasses
                    }
                })
            }
            if(callback) callback(done,result,message);
        })
    },
    //for teacher the level is already set 
    getLevels : callback => dispatch => {
        sessionServices.getSessionLevels(/*no sessionId*/null,(done, result, message)=>{
            if(done) dispatch({
                type : teacherConstants.SET_TEACHER,
                payload : {
                    [teacherStrings.levels] : result
                }
            })
            if(callback) callback(done, result, message);
        })
    },
    setSelectedLevel : level => dispatch => dispatch({
        type : teacherConstants.SET_TEACHER,
        payload : {
            [teacherStrings.selectedLevel] : level
        }
    }),
    setSelectedClass : selectedClass => dispatch => dispatch({
        type : teacherConstants.SET_TEACHER,
        payload : {
            [teacherStrings.selectedClass] : selectedClass
        }
    }),
    setSelectedTerm : term => dispatch => dispatch({
        type : teacherConstants.SET_TEACHER,
        payload : {
            [teacherStrings.selectedTerm] : term
        }
    })
}