import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import classNames from 'classnames';
import { invProductStrings } from '../../config';
import { invProductActions } from '../../actions';
import { MyTable, EditableCellMapFormat,  HighlightedInfo, inventoryUtil, appActions, alertAction } from "../../../utils";
import { Button } from '@material-ui/core';
import { INVButton } from '../../../Includes';
import { Sync } from '@material-ui/icons';

const style = theme => ({
    root: {
    }
})
class _INVDrugGenericNames extends Component {
    constructor(props) {
        super(props);
        this.state = {
            drugNames : null,
        }
    }
    componentDidMount() {
        this.getDrugNames();
    }
    getDrugNames(){
        const {dispatch} = this.props;
        invProductActions.getDrugNames((done, result)=>{
            if(done) this.setState({drugNames : result});
        })(dispatch);
    }
    newFormContext = {};
    cellMapFormat=superProps=>props=><EditableCellMapFormat {...props} {...superProps}/>
    deleteBtnHandler = row => () => {
        const {dispatch} = this.props;
        appActions.showSnackDialog("Are you sure you want to delete this tag?",
        [<Button key="deleteForm" onClick={()=>{
            appActions.closeSnackDialog()(dispatch);
            invProductActions.deleteDrugName(row._id, (done)=>{
                if(done) this.getDrugNames();
            })(dispatch);
        }}>Delete</Button>])(dispatch);
    }
    editBtnHandler = row => () => {
        const {drugNames} = this.state;
        const index = drugNames.findIndex(item=>item._id === row._id);
        if(index || index === 0){
            drugNames[index].editing = true;
        }
        this.setState({drugNames});
    }
    addButtonHandler = row => () => {
        const {dispatch} = this.props;
        const nameComponent = this.newFormContext.name;
        const descriptionComponent = this.newFormContext.description;
        const name = nameComponent.state.data.value;
        const description = descriptionComponent.state.data.value;
        if(!name || !String(name).trim()){
            appActions.showSnackbar(
                alertAction.error("Form name can not be an empty string")
            )(dispatch);
            return;
        }
        const data = {name, description};
        invProductActions.createDrugName(data, (done, result)=>{
            if(done) {
                nameComponent.setState({value : ""});
                descriptionComponent.setState({vallue : ""});
                this.getDrugNames();
            }
        })(dispatch);
    }
    editFinishBtnHandler = row => () => {
        const {dispatch} = this.props;        
        const {context} = row;
        const {name : nComponent, description : dComponent} = context;
        const name = nComponent.state.data.value;
        const description = dComponent.state.data.value;
        if(!name || !String(name).trim()){
            appActions.showSnackbar(
                alertAction.error("Form name can not be an empty string")
            )(dispatch);
            return;
        }
        const data = {name, description};
        invProductActions.updateDrugName(row._id, data, (done)=>{
            if(done) {
                this.getDrugNames();
            }
        })(dispatch);
    }
    cancelEditBtnHandler = row => () => {
        const {drugNames} = this.state;
        const index = drugNames.findIndex(item=>item._id === row._id);
        if(index || index === 0){
            delete drugNames[index].editing;
        }
        this.setState({drugNames});
    }
    render() {
        const {
            classes
        } = this.props;
        let {drugNames} = this.state;
        let header = ["ID", "Forms", "Description"];
        let dataMap = ["_id", "name", "description"];
        if(inventoryUtil.isAdmin()){
            header = [...header, "Actions"];
            dataMap = [...dataMap, "action"];
            drugNames = drugNames ? 
                [...drugNames.map(
                    item=>({...item, editable : true, delible : true})
                ), {new : true}] : 
                [{new : true}]
        }
        return (
            <div className={classNames(classes.root, "animated", "zoomIn")}>
                <HighlightedInfo>
                    Deleting a name already in use will default the name to 'UNKNOWN'
                </HighlightedInfo>
                <INVButton
                    loading={this.state.syncing}
                    type="secondary"
                    onClick={()=>{}}>
                        <Sync fontSize="small" style={{color : "white"}}/>
                         Sync
                    </INVButton>
                <MyTable
                    header={header}
                    dataMap={dataMap}
                    data={drugNames}
                    CellMap={this.cellMapFormat({
                        skipEdit : ["_id"],
                        getContext : (context, cellMap) => this.newFormContext[cellMap] = context,
                        deleteBtnHandler : this.deleteBtnHandler.bind(this),
                        editBtnHandler : this.editBtnHandler.bind(this),
                        addButtonHandler : this.addButtonHandler.bind(this),
                        editFinishBtnHandler : this.editFinishBtnHandler.bind(this),
                        cancelEditBtnHandler : this.cancelEditBtnHandler.bind(this),
                    })}
                    />
            </div>
        );
    }
}


_INVDrugGenericNames.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({invProductReducer}) => ({
    [invProductStrings.drugNames] : invProductReducer[invProductStrings.drugNames],
})


export const INVDrugGenericNames = connect(mapStateToProps)(withStyles(style)(_INVDrugGenericNames));
export {INVDrugGenericNames as default}