import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { 
    headerActions, headerStrings, mainStageHeaderAction, 
    mainStageHeaderStrings, breadCrumbActions, MyTable,
    history,
    StageHeaderPlane
} from "../utils";
import { routeNamesInventory } from '../routeNames';
import { invSupplierActions } from './actions';
import { invSupplierStrings } from './config';
import { INVButton } from '../Includes';
import { INVSupplierList } from './INVSupplierList';


const style = theme => ({
    root: {
        marginTop : 20
    }
})
class _INVSuppliers extends Component {
    constructor(props) {
        super(props);
        this.state = {
            lastId : null,
            rows : null
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "SUPPLIERS",
            [headerStrings.backButtonAction] : null,
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesInventory.dashboard},
            {name : "Suppliers", path : routeNamesInventory.suppliers},
        ])(dispatch);
    }
    componentDidMount() {
        const {lastId, rows} =this.state;
        const {dispatch} = this.props;
        invSupplierActions.getSuppliersBrief(lastId, rows)(dispatch);
    }
    rowAction = row => () =>{
        history.push(routeNamesInventory.supplier_ + row._id, row);
    }
    newButton(){
        return <INVButton
            onClick={()=>this.props.history.push(routeNamesInventory.newSupplier)}
            >New</INVButton>
    }
    render() {
        const {
            classes,
            [invSupplierStrings.suppliersBrief] : suppliersBrief
        } = this.props;
        return (
            <div className={classes.root}>
                <div>
                    <StageHeaderPlane
                        visible={true}
                        components={[
                            this.newButton.bind(this)
                        ]}
                        />
                </div>
                <INVSupplierList
                    suppliers={suppliersBrief || []}
                    />
            </div>
        );
    }
}


_INVSuppliers.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({invSupplierReducer}) => ({
    [invSupplierStrings.suppliersBrief] : invSupplierReducer[invSupplierStrings.suppliersBrief],
})


export const INVSuppliers = connect(mapStateToProps)(withStyles(style)(_INVSuppliers));
export {INVSuppliers as default}