import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { colors, customSuperSetState } from '../../../../utils';
import { RemarkSetting } from './RemarkSetting';
import { StudentRemarks } from './StudentRemarks';
import { teacherStrings } from '../config';


const style = theme => ({
    root: {
    },
    stageBtnComp : {
        backgroundColor : colors.white,
        color : colors.primary,
        margin : 10,
        "&:hover" : {
            backgroundColor : colors.white,
        }
    }
})
class _Remarks extends Component {
    constructor(props) {
        super(props);
        this.state = {
            page : "home"
        }        
    }
    mySetState = customSuperSetState(this);
    render() {
        const {classes} = this.props;
        const {page} = this.state;
        return (
            <div className={classes.root}>
                {page === "home" && <StudentRemarks
                    superSetState={this.mySetState}/>}
                {page === "setting" && <RemarkSetting 
                    back={()=>this.setState({page : "home"})}/>}
            </div>
        );
    }
}


_Remarks.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({teacherReducer}) => ({
    [teacherStrings.classStudentRemarks] : teacherReducer[teacherStrings.classStudentRemarks],
    [teacherStrings.teacherRemarks] : teacherReducer[teacherStrings.teacherRemarks]
})


export const Remarks = connect(mapStateToProps)(withStyles(style)(_Remarks));
export {Remarks as default};