import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { FormControl, Button } from '@material-ui/core';
import { colors } from '../../../utils';
import { payrollActions, payrollStrings } from '../config';


const style = theme => ({
    root: {
    },
    control : {
        margin : 10
    },
    grow : {
        display : "flex",
        flexGrow : 1
    }
})

class _EmployeeHeaderComponent extends Component {
    editBtnHandler = ()=>{
        const {
            dispatch, 
            [payrollStrings.employeeEditMode] : employeeEditMode
        } = this.props;
        payrollActions.setEmployeeEditMode(!Boolean(employeeEditMode))(dispatch);
    }
    cancelEditHandler = () => {
        payrollActions.setEmployeeEditMode(false)(this.props.dispatch);
    }
    render() {
        const {
            classes, 
            [payrollStrings.employeeEditMode] : employeeEditMode
        } = this.props;
        return (
            <div className={classes.root}>
                <div className={classes.grow}/>
                <FormControl className={classes.control}>
                    <Button
                        style={{
                            backgroundColor : colors.secondary,
                            color : colors.white
                        }}
                        onClick={this.editBtnHandler.bind(this)}>
                            {employeeEditMode ? "Save" : "Edit"}
                        </Button>
                </FormControl>
                {employeeEditMode && <FormControl className={classes.control}>
                    <Button color="secondary" onClick={this.cancelEditHandler.bind(this)}>
                        Cancel
                    </Button>
                </FormControl>}
            </div>
        );
    }
}


_EmployeeHeaderComponent.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({payrollReducer}) => ({
    [payrollStrings.employeeEditMode] : payrollReducer[payrollStrings.employeeEditMode],
})


export const EmployeeHeaderComponent = connect(mapStateToProps)(withStyles(style)(_EmployeeHeaderComponent));
export {EmployeeHeaderComponent as default}