import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { Typography, TextField, Button, FormControl } from '@material-ui/core';
import { insureUtil } from '../../../utils';
const style = theme => ({
    root: {
        padding : 20,        
    },
    header : {
        fontWeight : "bold",
        color : insureUtil.getTheme().white,
    },
    btn : {
        padding : 10,
        backgroundColor : insureUtil.getTheme().primary,
        color : insureUtil.getTheme().white,
        "&:hover" : {
            backgroundColor : insureUtil.getTheme().primary
        }
    },
    inputContainer : {
        display : "flex",
        flexDirection : "column",
    }
})
class _NewsLetter extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data : {
                email : "",
                name : "",
            },
            laoding : false
        }
    }
    subClick(){
        const {name, email} = this.state.data;
        const {subscribeBtnClick, notify} = this.props;
        if(!String(name).trim() || !String(email).trim()){
            if(notify) notify("Empty field error", "error");
        }
        if(subscribeBtnClick) 
            subscribeBtnClick(name, email, done => {
                if(done) this.setState({data : {email : "", name : ""}, loading : false})
            });
    }
    onChange = name => e => {
        const value = e.target.value;
        const data = {...this.state.data};
        data[name] = value;
        this.setState({data});
    }
    render() {
        const {classes} = this.props;
        const {name, email} = this.state.data;
        return (
            <div className={classes.root}>
                <Typography variant="h5" 
                    className={classes.header} paragraph>
                    Never miss an update
                </Typography>
                <div className={classes.inputContainer}>
                    <FormControl>
                        <TextField
                            value={name}
                            onChange={this.onChange("name")}
                            margin="normal"
                            label="Name"
                            variant="outlined"
                            placeholder="Name"/>
                    </FormControl>
                    <FormControl>
                        <TextField
                            value={email}
                            onChange={this.onChange("email")}
                            margin="normal"
                            label="Email"
                            variant="outlined"
                            placeholder="Email"/>
                    </FormControl>
                    <div>
                        <Button variant="contained" 
                            className={classes.btn}
                            disabled={this.state.loading}
                            onClick={this.subClick.bind(this)}>
                            Subscribe Newsletter
                        </Button>
                    </div>
                </div>
            </div>
        );
    }
}
_NewsLetter.propTypes = {
    classes : PropTypes.object.isRequired,
    subscribeBtnClick : PropTypes.func,
    notify : PropTypes.func,
};
export const NewsLetter = withStyles(style)(_NewsLetter);