import React from 'react';
import { store, history } from "../../../helpers";
import { chatFooterStrings, chatFooterConstants } from "../../includes";
import { trackerUtil } from "../utils";
import { ChatSettingComponent } from './ChatSettingComponent';
import { AllChatListItemComponent } from './AllChatListItemComponent';
import { contactStrings, contactActions } from '../Contacts';
import { routeNamesTracker } from '../routeNames';

export function chatConfiguration(){
    const theme = trackerUtil.getTheme();
    const containerStyle = {
        style : {
            backgroundColor : "#9e9eb5", //theme.secondary,
            color : theme.white
        }
    };
    store.dispatch({
        type : chatFooterConstants.SET_CHATFOOTER,
        payload : {
            [chatFooterStrings.allChatContainerProps] : containerStyle,
            [chatFooterStrings.chatBoxContentContainerProps] : containerStyle,
            [chatFooterStrings.allChatSettingPopupContent] : ChatSettingComponent,
            [chatFooterStrings.userId] : parseInt(trackerUtil.getUserId()),
            [chatFooterStrings.smallScreenFabClick] : ()=>history.push(routeNamesTracker.contacts),
            [chatFooterStrings.allChatListItemComponent] : AllChatListItemComponent,
            [chatFooterStrings.getMessagesAction] : contactActions.getMessages,
            [chatFooterStrings.sendMessageAction] : contactActions.sendMessage,
        }
    });
    //this is return via feedback
    contactActions.getMyOnlineContacts();
}