import { studentConstant, studentStrings } from "./config";
import { studentServices } from "./services";

function needCallbackThrowable(name){
    throw(name+" must have callback function");
}
export const studentActions = {
    getSubjectsAndAssessments_NO_DISPATCH : (levelId, termId, callback)=>{
        if(!callback) needCallbackThrowable("getSubjectsAndAssessments_NO_DISPATCH");
        studentServices.getSubjectsAndAssessments(levelId, termId, callback);
    },
    getStudentAcademicInfo_NO_DISPATCH : (studentId, levelId, callback)=>{
        if(!callback) needCallbackThrowable("getStudentAcademicInfo_NO_DISPATCH");
        studentServices.getStudentAcademicInfo(studentId, levelId, callback)
    },
    getStudentInfo : (studentId, callback)=> dispatch => {
        studentServices.getStudentInfo(studentId, (done, result, message)=>{
            if(done){
                dispatch({
                    type : studentConstant.SET_STUDENT,
                    payload : {
                        [studentStrings.studentProfile] : result
                    }
                })
            }
            if(callback) callback(done, result, message);
        });
    },
    getStudents : (lastId, rows, callback) => dispatch=>{
        studentServices.getStudents(lastId, rows, (done, result, message)=>{
            if(done) dispatch({
                type : studentConstant.SET_STUDENT,
                payload : {
                    [studentStrings.students] : result
                }
            })
            if(callback) callback(done, result, message);
        })
    },
    getStudentGroupForm : callback =>dispatch => {
        studentServices.getStudentGroupForm((done, result, message)=>{
            if(done) dispatch({
                type : studentConstant.SET_STUDENT,
                payload : {
                    [studentStrings.studentGroupForm] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getParentForm : callback => dispatch => {
        studentServices.getParentForm((done, result, message)=>{
            if(done) dispatch({
                type : studentConstant.SET_STUDENT,
                payload : {
                    [studentStrings.parentForm] : result
                }
            })
            if(callback) callback(done, result, message);
        });
    },
    getStudentForm : callback => dispatch=>{
        console.log("I was triggered")
        studentServices.getStudentForm((done, result, message)=>{
            if(done) dispatch({
                type : studentConstant.SET_STUDENT,
                payload : {
                    [studentStrings.studentForm] : result
                }
            })
            if(callback) callback(done, result, message);
        })
    },
    setShowAllStudents : set => dispatch => dispatch({
        type : studentConstant.SET_STUDENT,
        payload : {
            [studentStrings.showAllStudents] : set
        }
    }),
    setSelectedLevel : selectedLevel => dispatch => dispatch({
        type : studentConstant.SET_STUDENT,
        payload : {
            [studentStrings.selectedLevel] : selectedLevel
        }
    }),
    setSelectedClass : selectedClass => dispatch => dispatch({
        type : studentConstant.SET_STUDENT,
        payload : {
            [studentStrings.selectedClass] : selectedClass
        }
    }),
}