export const staffStrings = {
    categories : "categories",
    formAdmin : "adimForm",
    formTeacher : "teacherForm",
    formOthers : "otherForm",
    staffListAdmin : "adminStaffList",
    staffListTeacher : "teacherStaffList",
    staffListOthers : "otherStaffList",
}
export const staffConstants = {
    SET_STAFF : "SET_STAFF"
}

const initialState = {
    [staffStrings.categories] : null
}
export const staffReducer = (state=initialState, action) => {
    const {type, payload} = action;
    switch(type){
        case staffConstants.SET_STAFF : 
            return {...state, ...payload};
        default : return {...state};
    }
}
export * from './actions';