export const saleStrings = {

}
export const saleConstants = {
    SET_SALE : "SET_SALE",
    CLEAN_UP_SALE :"CLEAN_UP_SALE",
}
const saleInitialState = {

}
export const saleReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case saleConstants.SET_SALE : 
            return {...state, ...payload};
        case saleConstants.CLEAN_UP_SALE : 
            return {...state, ...saleInitialState}
        default : return {...state};
    }
}
export * from './actions';
export * from './services';
