import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { ContactUs } from './ContactUs';
import { inovateOSUtil } from '../utils';
import FollowUs from './FollowUs/FollowUs';
import { Grid, Typography } from '@material-ui/core';
import { NewsLetter } from '../../../includes';
import { inovateOSPageActions } from '../Pages';


const style = theme => ({
    root: {
        backgroundColor : inovateOSUtil.getTheme().primaryDark,
        paddingTop : 20,
    },
    container : {
        justifyContent : "center",
    },
    copyRight : {
        color : "gray",
        textAlign : "center",
    },
    newsletterHeader : {
        fontWeight : "bold",
        color : inovateOSUtil.getTheme().secondary,
    },
    newsletterBtn : {
        padding : 10,
        backgroundColor : inovateOSUtil.getTheme().secondary,
        color : inovateOSUtil.getTheme().wheat,
        "&:hover" : {
            backgroundColor : inovateOSUtil.getTheme().secondary
        }
    },
})
class _InovateOSFooter extends Component {
    subscribeNewsletter(name, email, callback){
        const {dispatch} = this.props;
        inovateOSPageActions.subscribeNewsLetter(name, email, (done)=>{
            if(callback) callback(done)
        })(dispatch);
    }
    render() {
        const {classes} = this.props;
        return (
            <div className={classes.root}>
                <Grid className={classes.container} container spacing={0}>
                    <Grid item xs={12} sm={6} md={4} lg={4} xl={4}>
                        <div className={classes.contact}>
                            <ContactUs/>
                        </div>
                    </Grid>
                    <Grid item xs={12} sm={6} md={4} lg={4} xl={4}>
                        <div className={classes.follow}>
                            <NewsLetter
                                textFieldProps={{
                                    inputProps : {
                                        style : {
                                            backgroundColor : inovateOSUtil.getTheme().wheat,
                                            borderRadius : 10,
                                        }
                                    }
                                }}
                                subscribeBtnClick={this.subscribeNewsletter.bind(this)}
                                classes={{
                                    header : classes.newsletterHeader,
                                    btn : classes.newsletterBtn
                                }}/>
                        </div>                            
                    </Grid>
                    <Grid item xs={12} sm={6} md={4} lg={4} xl={4}>
                        <div className={classes.follow}>
                            <FollowUs/>
                        </div>                            
                    </Grid>
                </Grid>
                <div className={classes.copyRightContainer}>
                    <Typography className={classes.copyRight}>
                        © Copyright {new Date().getFullYear()}. All Rights Reserved.
                    </Typography>
                </div>
            </div>
        );
    }
}


_InovateOSFooter.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = state => ({
    state
})


export const InovateOSFooter = connect(mapStateToProps)(withStyles(style)(_InovateOSFooter));
export {InovateOSFooter as default}