export const insureAdminCooperativeStrings = {
    subscribers : "coopSubscribers",
    payments : "coopPayments",
};
export const insureAdminCooperativeConstants = {
    SET_INSURE_ADMIN_COOPERATIVE : "SET_INSURE_ADMIN_COOPERATIVE",
}
export const insureAdminCooperativeReducer = (state={}, action)=>{
    const {type, payload}  = action;
    switch(type){
        case insureAdminCooperativeConstants.SET_INSURE_ADMIN_COOPERATIVE : 
            return {...state, ...payload};
        default : return state;
    }
}
export * from './actions';
export * from './services';