import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, StageHeaderPlane, HighlightedInfo, MyDialog, FormDisplay, formStrings } from '../utils';
import { hirRouteNames } from '../routeNames';
import { HIRButton } from '../Includes';
import { HIRFindPatient } from '../HIRPatients';
import { hirAccountActions } from './actions';
import { hirAccountStrings } from './config';
import { HIRNewPayment } from './HIRNewPayment';
import { Grid, Menu, MenuItem } from '@material-ui/core';
import { HIRRevenueList } from './HIRRevenueList';
import { HIRAccountUserList } from './HIRAccountUserList';
import HIRAllPaymentList from './HIRAllPaymentList/HIRAllPaymentList';
import { HIRReceipt } from './HIRReceipt/HIRReceipt';
import { hirUserStrings, hirUserActions } from '../HIRUsers/config';
import { HIRMultiplePayment } from './HIRNewPayment/HIRMultiplePayment';
import { HIRReceiptMultiple } from './HIRReceipt/HIRReceiptMultiple';
import { hirAppActions as appActions, hirAlertActions as alertAction } from '../utils';

const style = theme => ({
    root: {
    },
    info : {
        backgroundColor : theme.colors.secondary,
        color : theme.colors.white,
    },
    flexGrow : {
        display : "flex",
        flexGrow : 1
    },
    formHeader : {
        display : "none"
    },
    paper : {
        display : 'flex',
        justifyContent : "center",
        alignItems : "center",
    }
})
class _HIRAccounts extends Component {
    constructor(props) {
        super(props);
        this.state={
            newPaymentPatientDialog : false,
            newPaymentDialog : false,
            patient : null,
            lastId : null,
            rows : 100,
            newPayment : null,
            receiptDialog : false,
            paymentType : "single",
        }
        const {dispatch } = props;
        headerActions({
            [headerStrings.headerTitle] : "ACCOUNTS",
            [headerStrings.backButtonAction] : null
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", pathname : hirRouteNames.dashboard},
            {name : "Account", pathname : hirRouteNames.account}
        ])(dispatch);
        this.viewFormConfig = [
            {name : "view", label : "View", type : "select", options : [
                {_id : "all", name : "All"},
                {_id : "revenue", name : "Revenue Category"},
                {_id : "users", name : "Users"}
            ]}
        ]
        this.formName = "paymentViw";
    }
    componentDidMount() {
        const {dispatch, [hirUserStrings.users] : users} = this.props;
        if(!users) hirUserActions.getUsers()(dispatch);
    }
    
    searchAction(text, context){
        const {dispatch} = this.props;
        if(!String(text).trim()){
            appActions.showSnackbar(
                alertAction.error("You can't make a search with an empty string")
            )(dispatch);
            return ;
        }
        hirAccountActions.searchPaymentsByPatient(text)(dispatch);
    }
    showNewPaymentMenu(e){
        const target = e.target;
        this.setState(state=>({menuAnchor : !state.menuAnchor ? target : null}))
    }
    newButton = () => {
        const {menuAnchor} = this.state;
        return <div>
            <HIRButton
                type="primary" 
                onClick={this.showNewPaymentMenu.bind(this)}>
                    New
                </HIRButton>
            <Menu 
                anchorEl={menuAnchor}
                open={Boolean(menuAnchor)}
                onClose={()=>this.setState({menuAnchor : null})}
                >
                <MenuItem 
                    onClick={()=>this.setState({
                        newPaymentPatientDialog : true, 
                        paymentType : "single",
                        menuAnchor : null
                    })}>Single Payment</MenuItem>
                <MenuItem 
                    onClick={()=>this.setState({
                        newPaymentPatientDialog : true, 
                        menuAnchor : null,
                        paymentType : "multiple"
                    })}>Multiple Payment</MenuItem>
                <MenuItem 
                    onClick={()=>this.setState({
                        newPaymentPatientDialog : true, 
                        menuAnchor : null,
                        paymentType : "nonPatient"
                    })}>Non-patient Payment</MenuItem>
            </Menu>
        </div>
    }
    closePatientSearchDialog(){
        const {dispatch} = this.props;
        this.setState({newPaymentPatientDialog: false});
        hirAccountActions.payload({
            [hirAccountStrings.searchPatients] : []
        })(dispatch);
    }
    searchPatientRowAction = row => () => {
        this.setState({
            newPaymentPatientDialog : false, 
            newPaymentDialog : true,
            patient : row
        })
    }
    postPayment(data, context){
        const {dispatch} = this.props;
        const {lastId, rows, patient} = this.state;
        hirAccountActions.postPayment(lastId, rows, patient ? patient._id : null, data, (done, result)=>{
            if(context) context.setState({loading : false});
            if(done){
                const {monthOnlyView} = this.allPaymentContext.state;
                const date = new Date();
                hirAccountActions.searchPaymentsByDate(
                    date.getFullYear(),
                    date.getMonth() + 1,
                    monthOnlyView ? null : date.getDate()
                )(dispatch);
                this.setState({
                    newPaymentDialog : false, 
                    receiptDialog : true, 
                    newPayment : result,
                    patient : null,
                    multiple : result.groupId ? true : false
                });
            }
        })(dispatch);
    }
    render() {
        const {
            classes,
            
            [formStrings.forms] : forms
        } = this.props;
        let formData;
        if(forms && forms[this.formName]) {
            formData = forms[this.formName];
        }else {
            formData = {view : "all"};
        }
        const {
            newPaymentPatientDialog,
            newPaymentDialog, 
            patient, newPayment, receiptDialog, paymentType, multiple
        } = this.state;
        return (
            <div className={classes.root}>

                <Grid container spacing={2} style={{flexDirection : "row-reverse"}}>
                    <Grid item xs={12} sm={6} md={4} lg={4} xl={3}>
                        <FormDisplay
                            classes={{header : classes.formHeader}}
                            formConfig={this.viewFormConfig}
                            formData={formData}
                            formName={this.formName}/>
                    </Grid>
                </Grid>
                
                {formData.view === "all" && <div>
                    <div style={{marginBottom : 20}}>
                        <StageHeaderPlane
                            isRequired={false}
                            visible={true}
                            searchActions={this.searchAction.bind(this)}
                            components={[
                                this.newButton
                            ]}
                            />
                    </div>
                    <HIRAllPaymentList
                        getContext={context=>this.allPaymentContext = context}/>
                    
                </div>}
                {formData.view === "revenue" && <HIRRevenueList/>}
                {formData.view === "users" && <HIRAccountUserList/>}

                <HighlightedInfo classes={{general : classes.info}} closable>
                    This account is customized to handle only recievables,
                    request for main accounting package (chokey2nv@yahoo.com)
                </HighlightedInfo>
                <MyDialog 
                    open={newPaymentPatientDialog}
                    close={this.closePatientSearchDialog.bind(this)}>
                        {paymentType === "nonPatient" ?
                        <HIRNewPayment
                            postPayment={this.postPayment.bind(this)}/>
                        :<HIRFindPatient
                            patientListProps={{
                                tableProps : {
                                    rowAction : this.searchPatientRowAction.bind(this)
                                }
                            }}
                            />}
                    </MyDialog>
                <MyDialog 
                    open={newPaymentDialog}
                    close={()=>this.setState({newPaymentDialog : false})}>
                        {paymentType === "single" ? 
                            <HIRNewPayment
                                patient={patient}
                                postPayment={this.postPayment.bind(this)}
                                /> :
                            <HIRMultiplePayment
                                patient={patient}
                                postPayment={this.postPayment.bind(this)}
                                />}
                    </MyDialog>
                <MyDialog 
                    classes={{
                        dialogPaper : classes.paper
                    }}
                    open={receiptDialog}
                    close={()=>this.setState({receiptDialog : false})}>
                        {multiple ? 
                            <HIRReceiptMultiple
                                payment={newPayment}/> :
                            <HIRReceipt
                                payment={newPayment}/>}
                </MyDialog>
            </div>
        );
    }
}


_HIRAccounts.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({formReducer, hirAccountReducer, hirUserReducer}) => ({
    [formStrings.forms] : formReducer[formStrings.forms],
    [hirUserStrings.users] : hirUserReducer[hirUserStrings.users]
})


export const HIRAccounts = connect(mapStateToProps)(withStyles(style)(_HIRAccounts));
export {HIRAccounts as default}