import { store } from "../../../../helpers";
import { hirUtilStrings } from "./config";
import { _retrieveData, monthSelections } from "../../../../utils";
import { appActions, alertAction } from "../../../../actions";
import { errorNotice, successNotice, monthLabels, onEnterPress, _storeData } from "../../../../utils";

export * from '../../../../helpers';
export * from '../../../includes';
export const hirOnEnterPress = onEnterPress;
export const hirAppActions = appActions;
export const hirAlertActions = alertAction;
export const hirErrorNotice = errorNotice;
export const hirSuccessNotice = successNotice;
export const hirMonthLabel = monthLabels;
export const hirMonthSelections = monthSelections;
export const _hirStoreData = _storeData;
export const hirUtil = {
    getTheme : ()=>(store.getState().hirUtilReducer[hirUtilStrings.theme]),
    getToken : ()=>localStorage.getItem(store.getState().hirUtilReducer[hirUtilStrings.tokenAlias]),
    getUserId : () => localStorage.getItem(store.getState().hirUtilReducer[hirUtilStrings.userAlias]),
    isLogedIn : () => {
        const userId = hirUtil.getUserId();
        const token = hirUtil.getToken();
        return userId && token;
    },
    fetchGet : async (owner, action, stringQuery, callback)=>{
        const state = store.getState().hirUtilReducer;
        const USERID = _retrieveData(state[hirUtilStrings.userAlias]);
        const TOKEN = _retrieveData(state[hirUtilStrings.tokenAlias]);
        const TYPE = _retrieveData(state[hirUtilStrings.userType]);
        stringQuery = {...stringQuery, userId : USERID, token : TOKEN, type : TYPE};
        let count = 0;
        let build = "";
        for (const i in stringQuery) {
            if (stringQuery.hasOwnProperty(i)) {
                const elem = stringQuery[i];
                if(count === 0){
                    build += "?"+i+"="+elem;
                }else build += "&"+i+"="+elem;
                count++;
            }
        }
        fetch(state[hirUtilStrings.backendUrl]+owner+"/"+action+build).then(
            response=> response.json()
        ).then(response=>{
            if(callback) callback(response)
        });
    },
    fetchPost : async (owner, action, options, callback, query = {})=>{
        const state = store.getState().hirUtilReducer;
        const USERID = _retrieveData(state[hirUtilStrings.userAlias]);
        const TOKEN = _retrieveData(state[hirUtilStrings.tokenAlias]);
        const TYPE = _retrieveData(state[hirUtilStrings.userType]);
        const stringQuery = {userId : USERID, token : TOKEN, type : TYPE, ...query};
        let count = 0;
        let build = "";
        for (const i in stringQuery) {
            if (stringQuery.hasOwnProperty(i)) {
                const elem = stringQuery[i];
                if(count === 0){
                    build += "?"+i+"="+elem;
                }else build += "&"+i+"="+elem;
                count++;
            }
        }
        fetch(state[hirUtilStrings.backendUrl]+owner+"/"+action+build, options).then(
            response=> response.json()
        ).then(response=>callback(response))
        .catch(e => {
            console.error(e);
        });
    },
    post : async (data, owner, action, callback, query)=>{
        hirUtil.fetchPost(owner, action, {
            method : "post",
            headers : {
                "Content-Type" : "Application/json"
            },
            body : JSON.stringify(data)
        }, callback, query);
    }
}


