import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { inovateOSPageStrings } from '../../config';
import { inovateOSPageActions } from '../../actions';
import { Typography } from '@material-ui/core';
import { inovateOSUtil } from '../../../utils';


const style = theme => ({
    root : {
        display : "flex",
        flexDirection :"column",
        background : inovateOSUtil.getTheme().background,
        alignItems : "center",
        textAlign : "center",
        padding : 100,
        [theme.breakpoints.down("xs")] : {
            padding : 20,
            paddingTop : 50,
        },
    },
    header : {
        width : "fit-content",
        color : inovateOSUtil.getTheme().secondary,
        borderBottom : "solid 5px " + inovateOSUtil.getTheme().primary,
        marginBottom : 50,
        fontWeight : "bold",
        fontFamily : "sans-serif",
    },
    text : {
        fontSize : 21,
        fontStyle : "italic",
        [theme.breakpoints.down("xs")] : {
            fontSize : 18
        }
    }
})
class _WhoWeAre extends Component {
    componentDidMount() {
        const {dispatch} = this.props;
        inovateOSPageActions.getHomeInfo()(dispatch);
    }
    
    render() {
        const {classes, [inovateOSPageStrings.homeInfo] : homeInfo} = this.props;
        let introItem;
        if(homeInfo && homeInfo.values){
            introItem= homeInfo.values.find(item=>item.name === "intro");
        }
        return (
            <div className={classes.root}>
                <Typography variant="h4" className={classes.header} paragraph>
                    {introItem && String(introItem.header).toUpperCase()}
                </Typography>
                {introItem && introItem.value && introItem.value.map(
                    (item, index)=><Typography key={index} className={classes.text}>
                        {item}
                    </Typography>
                )}
            </div>
        )
    }
}


_WhoWeAre.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({inovateOSPageReducer}) => ({
    [inovateOSPageStrings.homeInfo] : inovateOSPageReducer[inovateOSPageStrings.homeInfo],
})


export const WhoWeAre = connect(mapStateToProps)(withStyles(style)(_WhoWeAre));
export {WhoWeAre as default}