import { payrollConstants, payrollStrings } from "./config";
import { payrollServices } from "./services";

export const payrollActions = {
    getPayrollHistoryDetail_NO_DISPACT : (historyId, callback) => {
        payrollServices.getPayrollHistoryDetails(historyId, callback);
    },
    getPayrollHistory : callback => dispatch => {
        payrollServices.getPayrollHistory((done, result, message)=>{
            if(done) dispatch({
                type : payrollConstants.SET_PAYROLL,
                payload : {
                    [payrollStrings.payrollHistory] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    }, 
    setEmployeeEditMode : mode => dispatch => dispatch({
        type: payrollConstants.SET_PAYROLL,
        payload : {
            [payrollStrings.employeeEditMode] : mode
        }
    }),
    updatePayrollEmployeeTabComponent : component =>dispatch=>dispatch({
        type : payrollConstants.SET_PAYROLL,
        payload : {
            [payrollStrings.payrollEmployeeTabComponent] : component
        }
    }),
    updateEmployeeTabValue : tabValue => dispatch=>dispatch({
        type : payrollConstants.SET_PAYROLL,
        payload : {
            [payrollStrings.payrollEmployeeTabValue] : tabValue
        }
    }),
    getPayrollEmployeeStatus : callback => dispatch => {
        payrollServices.getPayrollEmployeeStatus((done, result, message)=>{
            if(done) dispatch({
                type : payrollConstants.SET_PAYROLL,
                payload : {
                    [payrollStrings.payrollEmployeeStatus] : result,
                }
            }); 
            if(callback) callback(done, result, message);
        })
    },
    getPayrollEmployeeCount : callback => dispatch => {
        payrollServices.getPayrollEmployeeCount((done, result, message)=>{
            if(done)dispatch({
                type : payrollConstants.SET_PAYROLL,
                payload : {
                    [payrollStrings.payrollEmployeeCount] : result.count
                }
            })
            if(callback)callback(done, result, message);
        })
    },
    getPayrollEmployeeInfo : (empId, callback) => dispatch=>{
        payrollServices.getPayrollEmployeeInfo(empId, (done, result, message)=>{
            if(done) dispatch({
                type : payrollConstants.SET_PAYROLL,
                payload : {
                    [payrollStrings.payrollEmployeeInfo] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    }, 
    getPayrollEmployeeBrief : (lastId, rows, callback)=>dispatch=>{
        payrollServices.getPayrollEmployeeBrief(lastId, rows, (done, result, message)=>{
            if(done)dispatch({
                type : payrollConstants.SET_PAYROLL,
                payload : {
                    [payrollStrings.payrollEmployeeBrief] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getPayrollDeductions : callback=>dispatch=>{
        payrollServices.getPayrollDeductions((done, result, message)=>{
            if(done)dispatch({
                type : payrollConstants.SET_PAYROLL,
                payload : {
                    [payrollStrings.payrollDeductions] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getPayrollBenefits : callback=>dispatch=>{
        payrollServices.getPayrollBenefits((done, result, message)=>{
            if(done)dispatch({
                type : payrollConstants.SET_PAYROLL,
                payload : {
                    [payrollStrings.payrollBenefits] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    setDeductionEditMode : mode => dispatch => dispatch({
        type : payrollConstants.SET_PAYROLL,
        payload : {
            [payrollStrings.deductionEditMode] : mode
        }
    }),
    setBenefitEditMode : mode => dispatch => dispatch({
        type : payrollConstants.SET_PAYROLL,
        payload : {
            [payrollStrings.benefitEditMode] : mode
        }
    }),
}