import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions } from '../../includes';
import { GoogleMap,LoadScript, Marker, InfoWindow} from '@react-google-maps/api';
import { mapStyle } from '../utils';
import $ from 'jquery';
import { CircularProgress, Typography } from '@material-ui/core';


console.log(window.google);
const style = theme => ({
    root: {
        position : "absolute", 
        top : 0, left : 0,
        width : "100%",
        height : "100%",
        display : "flex",
        justifyContent : 'center',
        alignItems : "center",
    },
    connecting : {
        display : 'flex',
        flexDirection : "column",
        justifyContent : 'center',
        alignItems : "center",
    }
})
class _Map extends Component {
    constructor(props) {
        super(props);
        this.state = {
            selectedItem : null,
            googleError : null,
            internet : null
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "MAPS",
        })(dispatch);
        breadCrumbActions.setBreadCrumb(null)(dispatch);
    }
    componentWillMount() {
        const url = "https://maps.googleapis.com/maps/api/js?key="+process.env.REACT_APP_GOOGLE_API_KEY+"&v=weekly&callback=initMap";
        $.ajax(url)
        .then(res=>{
            this.setState({internet : true});
        }).catch((request, status, error)=>{
            setInterval(() => {
                $.ajax({
                    type : "GET",
                    url,
                    success : res => {
                        console.log(res);
                        this.setState({internet : true})
                    },
                    error : (request, status, error) => {
                        const {internet} = this.state;
                        if(status === "error" && internet !== false){
                            this.setState({internet : false});
                        }
                    }
                })
            }, 1000);
        })
    }
    
    selectMarkerHandler = selectedItem => () => {
        this.setState({selectedItem})
    }
    render() {
        const {classes} = this.props;
        const {selectedItem, loaded, googleError, internet} = this.state;
        const w = window;
        const google = w.google;
        console.log(loaded);
        return (
            <div className={classes.root}>
                {/** do a setState after loading to get the google script */}
                {!internet ? 
                    (internet === null ? 
                        <div className={classes.connecting}>
                            <CircularProgress size={50} color="primary"/>
                            <Typography paragraph variant="h4">Connecting...</Typography>
                        </div> : 
                        <div className={classes.connecting}>
                            <Typography paragraph variant="h5">No Internet connection found.</Typography>
                        </div>) : 
                    <LoadScript
                        onLoad={()=>this.setState({loaded})}
                        onError={err=>this.setState({googleError : err})}
                        id="script-loader"
                        googleMapsApiKey={process.env.REACT_APP_GOOGLE_API_KEY}
                        >
                            <GoogleMap
                                
                                id="example-map"
                                zoom={7}
                                center={{lat : 9.076479, lng : 7.398574}}                            
                                mapContainerStyle={{
                                    height: "100vh",
                                    width: "100vw"
                                }}
                                defaultOptions={{
                                    styles : mapStyle
                                }}
                                
                                >
                                    {[
                                        {lat : 9.076479, lng : 7.398574},
                                        {lat : 9.006479, lng : 7.498574},
                                    ].map((item, index)=>{
                                        return <Marker 
                                        key={index} 
                                        position={{
                                            lat : item.lat,
                                            lng : item.lng
                                        }}
                                        icon={{
                                            url : "/images/laughing_boy.jpg",
                                            scaledSize : google && new google.maps.Size(25, 25)
                                        }}
                                        onClick={this.selectMarkerHandler(item)}/>
                                    })}
                                    {selectedItem && <InfoWindow
                                        position={{
                                            lat : selectedItem.lat,
                                            lng : selectedItem.lng
                                        }}
                                        onCloseClick={()=>this.setState({selectedItem : null})}>
                                            <div>{selectedItem.lat + ", " + selectedItem.lng+" was selected"}</div>
                                        </InfoWindow>}
                                </GoogleMap>
                        </LoadScript> 
                        // <div style={{
                        //     width : "100vw",
                        //     height : "100vh",
                        //     display : "flex",
                        //     justifyContent : "center",
                        //     alignItems : "center",
                        //     color : "white"
                        // }}>
                        //     can't locate google map, ensure you are connected to internet
                        // </div>
                }
                </div>
        );
    }
}


_Map.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = state => ({
    state
})


export const Map = connect(mapStateToProps)(withStyles(style)(_Map));
export {Map as default}