export const stockConstants = {
    SET_STOCK : "SET_STOCK",
    CLEAN_UP_STOCK :"CLEAN_UP_STOCK",
}
const stockInitialState = {

}
export const stockReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case stockConstants.SET_STOCK : 
            return {...state, ...payload};
        case stockConstants.CLEAN_UP_STOCK : 
            return {...state, ...stockInitialState}
        default : return {...state};
    }
}
