import React, { Component } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import {withStyles} from '@material-ui/core/styles';
import { TextField, Button, IconButton, FormLabel, FormControl } from '@material-ui/core';
import { ProfilePicture } from '../../ProfilePicture';
import { Cancel, Add } from '@material-ui/icons';
const style = theme => ({
    root: {
        display : "flex",
        flexDirection : "column",
    },
    inputItemContainer : {
        display : "flex",
    },
    textField : {
        margin : 5,
        flex : 1
    },
    text : {

    },
    addParaBtnContainer : {
        display : "flex",
        justifyContent : "flex-end"
    },
    cancelBtn : {},
    createBtn : {
        marginLeft : 20
    },
})
class _NewArticle extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data : {
                image : null,
                header : "",
                body : [""],
            }
        }
    }
    
    onChange = (name, index) => e => {
        let data = {...this.state.data};
        const value = e.target.value; 
        if(name === "body"){
            data[name][index] = value;
        }else data[name] = value;
        this.setState({data});
    }
    createBtnClick(){
        const {data} = this.state;
        const {notify} = this.props;
        if(!data.header || !String(data.header)){
            if(notify) notify("Article header is empty", "error");
            return;
        }
        if(!data.body || !String(data.body)){
            if(notify) notify("Article body is empty", "error");
            return;
        }
        const form = new FormData();
        form.append("header", data.header);
        form.append("body", data.body.join("@#$"));
        if(data.src) form.append("src", data.src);
        const {onCreateClick} = this.props;
        if(onCreateClick) onCreateClick(form);
    }
    setImage(image){
        let data = {...this.state.data};
        data.src = image;
        this.setState({data});
    }
    addNewInput(){
        let data = {...this.state.data};
        data.body = [...data.body, ""];
        this.setState({data});
    }
    delete = index => () => {
        let data = {...this.state.data};
        data.body.splice(index, 1);
        this.setState({data});
    }
    render() {
        const {classes} = this.props;
        const {header, body} = this.state.data;
        return (
            <div className={classes.root}>
                <ProfilePicture
                    {...this.props.profilePictureProps}
                    editable
                    title="new image"
                    uploadImage={this.setImage.bind(this)}
                    />
                <TextField
                    className={classes.text}
                    margin="normal"
                    variant="outlined"
                    label="Header"
                    placeholder="Header"
                    value={header}
                    onChange={this.onChange("header")}/>
                <div className={classes.cardContent}>
                    <FormLabel>Body</FormLabel>
                    {body && body.map((item, index)=>{
                        return <div 
                            key={index}
                            className={classes.inputItemContainer}>
                            <FormControl>
                                <IconButton onClick={this.delete(index)}>
                                    <Cancel color="secondary"/>
                                </IconButton>
                            </FormControl>
                            <TextField
                                variant="outlined"
                                className={classes.textField}
                                placeholder={"Paragraph " + (index + 1)}
                                margin="normal"
                                value={item}
                                onChange={this.onChange("body", index)}
                                multiline
                                rows={4}
                                rowsMax={4}/>
                        </div>
                    })}
                </div>
                <div className={classes.addParaBtnContainer}>
                    <IconButton
                        className={classNames(classes.btn, classes.addBtn)}
                        onClick={()=>this.addNewInput()}>
                            <Add/>
                        </IconButton>
                </div>
                <div className={classes.btnContainer}>
                    <Button 
                        className={classes.cancelBtn}
                        color="secondary"
                        variant="contained"
                        onClick={this.props.cancelBtnClick}
                    >Cancel</Button>
                    <Button 
                        className={classes.createBtn}
                        color="primary"
                        variant="contained"
                        onClick={this.createBtnClick.bind(this)}
                    >Create</Button>
                </div>
            </div>
        );
    }
}
_NewArticle.propTypes = {
    classes : PropTypes.object.isRequired,
    cancelBtnClick : PropTypes.func,
    onCreateClick : PropTypes.func,
    profilePictureProps : PropTypes.shape(
        ProfilePicture.propTypes
    ),
    notify : PropTypes.func,
};
export const NewArticle = withStyles(style)(_NewArticle);