export const assessmentStrings = {
    usePreviousAssessments : "usePreviousAssessments",
    editMode : "editMode",
}
export const assessmentConstants = {
    SET_ASSESSMENT : "SET_ASSESSMENT",
    CLEAN_UP_ASSESSMENT :  "CLEAN_UP_ASSESSMENT",
}
export const assessmentReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case assessmentConstants.SET_ASSESSMENT :
            return {...state, ...payload};
        case assessmentConstants.CLEAN_UP_ASSESSMENT : 
            return {};
        default : return {...state};
    }
}
export * from './actions';
export * from './services';