export const nameMapper = (name)=>{
    switch(name){
        case "currentSessionLevel" : return "Current Level";
        case "currentSessionClass" : return "Current Class";
        case "lastLevelPosition" : return "Last Level Position";
        case "lastClassPosition" : return "Last Class Position";
        case "lastName" : return "Last Name";
        case "firstName" : return "First Name";
        case "middleName" : return "Middle Name";
        case "dob" : return "Date of Birth";
        case "address" : return "Address";
        case "city" : return "City";
        case "state" : return "State";
        case "country" : return "Country";
        case "gender" : return "Gender";
        case "email" : return "Email";
        case "phone" : return "Phone";
        default : return name;
    }
}