import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Carousel } from '../../../../includes';
import { inovateOSPageStrings } from '../config';
import { inovateOSPageActions } from '../actions';
import { inovateOSUtilStrings, inovateOSUtil } from '../../utils';
import { InovateOSWhatWeDo } from './InovateOSWhatWeDo';
import { WhoWeAre } from './WhoWeAre';
import { ServiceArea } from './ServiceArea';


const style = theme => ({
    root: {
    }
})
class _InovateOSHome extends Component {
    componentDidMount() {
        const {
            dispatch,
            [inovateOSPageStrings.carousel] : carousel,
        } = this.props;
        if(!carousel) inovateOSPageActions.getCarousel()(dispatch);
    }
    
    render() {
        const {
            classes,
            [inovateOSPageStrings.carousel] : carousel,
            [inovateOSUtilStrings.backendBaseUrl] : baseUrl,
            subContainer
        } = this.props;
        return (
            <div className={classes.root}>
                <Carousel
                    items={carousel && carousel.values}
                    baseUrl={baseUrl}/>
                <InovateOSWhatWeDo/>
                <WhoWeAre/>
                <div style={{
                    background : "linear-gradient(0deg, black, " + inovateOSUtil.getTheme().background+")",
                    height : 100,
                }}/>
                <ServiceArea/>
            </div>
        );
    }
}


_InovateOSHome.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({inovateOSPageReducer, inovateOSUtilReducer}) => ({
    [inovateOSPageStrings.carousel]: inovateOSPageReducer[inovateOSPageStrings.carousel],
    [inovateOSUtilStrings.backendBaseUrl] : inovateOSUtilReducer[inovateOSUtilStrings.backendBaseUrl],
})


export const InovateOSHome = connect(mapStateToProps)(withStyles(style)(_InovateOSHome));
export {InovateOSHome as default}