import { insureAdminMessageServices } from "./services"
import { insureAdminMessageConstants, insureAdminMessageStrings } from "./config"
import { errorNotice, successNotice } from "../utils";

export const insureAdminMessageActions = {
    sendEmail : (emailData, callback)=>dispatch =>{
        insureAdminMessageServices.sendEmail(emailData, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    deleteMessages : (messageIds, callback)=>dispatch => {
        insureAdminMessageServices.deleteMessages({messageIds}, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getMessages : (lastId, rows, callback)=>dispatch => {
        insureAdminMessageServices.getMessages(lastId, rows, (done, result, message)=>{
            if(done) insureAdminMessageActions.payload({
                [insureAdminMessageStrings.messages] : result
            })(dispatch); else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch => dispatch({
        type : insureAdminMessageConstants.SET_INSURE_ADMIN_MESSAGES,
        payload
    })
}