import React from 'react';
import { agroAdminRouteNames } from "./routeNames";

const Site = React.lazy(()=>import("./Site/Home/Home"));
const AboutUs = React.lazy(()=>import("./Site/AboutUs/AboutUs"));
const Blogs = React.lazy(()=>import("./Site/Blogs/Blogs"));
const BlogView = React.lazy(()=>import("./Site/Blogs/BlogView/BlogView"));
const BlogEdit = React.lazy(()=>import("./Site/Blogs/BlogEdit/BlogEdit"));

export const agroAdminRoutes = [
    {path : agroAdminRouteNames.home, exact : true, component : Site},
    {path : agroAdminRouteNames.aboutUs, exact : true, component : AboutUs},
    {path : agroAdminRouteNames.blog, exact : true, component : Blogs},
    {path : agroAdminRouteNames.blogView, exact : true, component : BlogView},
    {path : agroAdminRouteNames.blogEdit, exact : true, component : BlogEdit},
]