import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { Card, CardHeader, FormLabel, ExpansionPanel, ExpansionPanelSummary, ExpansionPanelDetails } from '@material-ui/core';
import { INVButton } from '../../../../Includes';
import { INVDescriptionValueBox } from './INVDescriptionValueBox';
import { INVDescriptionCategorised } from './INVDescriptionCategorised/INVDescriptionCategorised';
import { inventoryUtil } from '../../../../utils';
const style = theme => ({
    root: {
        
    },
    headerContainer : {
        display : "flex",
    },
    grow:{
        display : 'flex',
        flexGrow : 1,
    },
    editBtn : {
        marginRight : 20,
    }
})
class _INVDescriptionBox extends Component {
    state = {
        editMode : false,
    }
    render() {
        const {classes, description} = this.props;
        return (
            <div className={classes.root}>
                <ExpansionPanel>
                    <ExpansionPanelSummary>
                        {/* <div className={classes.headerContainer}> */}
                            <FormLabel>{description.name}</FormLabel>
                            <div className={classes.grow}/>
                            <INVButton
                                type="secondary"
                                classes={{btn : classes.editBtn}}
                                onClick={()=>this.setState({editMode : true})}
                                style={{
                                    padding : 5,
                                    backgroundColor : "transparent",
                                    border : "solid 1px",
                                    color : inventoryUtil.getTheme().secondary
                                }}>
                                    Edit
                                </INVButton>
                        {/* </div> */}
                    </ExpansionPanelSummary>
                    <ExpansionPanelDetails>
                        {description.categorised ? 
                            <INVDescriptionCategorised 
                                values={description.values || []}/> : 
                            <INVDescriptionValueBox
                                values={description.values || []}/>
                        }
                    </ExpansionPanelDetails>
                </ExpansionPanel>
                
                <div>

                </div>
            </div>
        );
    }
}
_INVDescriptionBox.propTypes = {
    classes : PropTypes.object.isRequired,
    description : PropTypes.object,
};
export const INVDescriptionBox = withStyles(style)(_INVDescriptionBox);