import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { FormLabel, IconButton, Grid } from '@material-ui/core';
import { invProductStrings } from '../../../config';
import { invProductActions } from '../../../actions';
import { MyPopupMenu, inventoryUtil, appActions, alertAction } from '../../../../utils';
import { Delete, Add, ArrowDownward } from '@material-ui/icons';
import { INVButton } from '../../../../Includes';


const style = theme => ({
    root: {
    },
    packageContainer : {
        display : "flex",
        flexDirection : "column",
        alignItems : "center",
        justifyContent : "center",
    },
    product : {
        padding : 10,
        borderRadius : 10,
        backgroundColor : inventoryUtil.getTheme().secondary,
        color : inventoryUtil.getTheme().white,
    }
})
class _INVNewProductPackaging extends Component {
    constructor(props) {
        super(props);
        const {editMode, packaging} = props;
        this.state = {
            packagings : editMode ? packaging.packageIds : [1],
            loading : false,
        }
    }
    
    componentDidMount() {
        const {dispatch, [invProductStrings.productPackages]: packages} = this.props;
        if(!packages) invProductActions.getProductPackages()(dispatch);
    }
    getMenuOption = (item, index) => option => {
        const {packagings} = this.state;
        packagings[index] = option._id;
        this.setState({packagings});
    }
    addRow = index => () => {
        const {packagings} = this.state;
        packagings.splice(++index, 0, 1);
        this.setState({packagings})
    }
    deleteRow = index => () => {
        const {packagings} = this.state;
        packagings.splice(index, 1);
        this.setState({packagings})
    }
    createPackaging(){
        this.setState({loading : true})
        const {packagings} = this.state;
        const {createPackaging, dispatch, editMode, editPackaging, packaging} = this.props;
        for (let i = 0; i < packagings.length; i++) {
            const value = packagings[i];
            if(value === 1) {
                appActions.showSnackbar(
                    alertAction.error("Package number "+(i+1)+" can not be empty")
                )(dispatch);
                return this.setState({loading : false});
            }
        }
        if(editMode && editPackaging) editPackaging(packaging._id, packagings, this);
        else if(createPackaging) createPackaging(packagings, this);
        else this.setState({loading : false});
    }
    render() {
        const {classes, 
            [invProductStrings.productPackages] : productPackages,
            editMode
        } = this.props;
        const {packagings, loading} = this.state;
        return (
            <div className={classes.root}>
                <FormLabel>Build New Product Packaging</FormLabel>
                <Grid container spacing={2}>
                    {packagings && packagings.map((item, index)=>{
                        let buttonValue = "Select Package";
                        if(item !== 1){
                            let pack = productPackages.find(_item=>_item._id == item);
                            if(pack) buttonValue = pack.name;
                        }
                        return <Fragment key={index}>
                            <Grid item xs={8} sm={8} md={8} lg={8} xl={8}>
                                <div className={classes.packageContainer}>
                                    <MyPopupMenu
                                        options={productPackages}
                                        optionNameProp="name"
                                        optionValueProp="_id"
                                        buttonName={index+"packageBtn"}
                                        buttonValue={buttonValue}
                                        optionClickCallback={this.getMenuOption(item, index)}
                                        />
                                    <ArrowDownward color="secondary"/>
                                </div>
                            </Grid>
                            <Grid item>
                                {index !== 0 && <IconButton onClick={this.deleteRow(index)}>
                                    <Delete color="secondary" fontSize="small"/>
                                </IconButton>}
                                <IconButton onClick={this.addRow(index)}>
                                    <Add fontSize="small"/>
                                </IconButton>
                            </Grid>
                        </Fragment>
                    })}
                    <Grid item xs={8} sm={8} md={8} lg={8} xl={8}>
                        <div className={classes.packageContainer}>
                            <span className={classes.product}>PRODUCT</span>
                        </div>
                    </Grid>
                </Grid>
                <div style={{marginTop : 20}}>
                    <INVButton 
                        type={editMode ? "secondary" : "primary"}
                        loading={loading}
                        onClick={this.createPackaging.bind(this)}>
                            {editMode ? "Edit" : "Create"} Product Packaging
                        </INVButton>
                </div>
            </div>
        );
    }
}


_INVNewProductPackaging.propTypes = {
    classes : PropTypes.object.isRequired,
    createPackaging : PropTypes.func,
    editPackaging : PropTypes.func,
    editMode : PropTypes.bool,
    packaging : PropTypes.object,
};
const mapStateToProps = ({invProductReducer}) => ({
    [invProductStrings.productPackages] : invProductReducer[invProductStrings.productPackages],
})


export const INVNewProductPackaging = connect(mapStateToProps)(withStyles(style)(_INVNewProductPackaging));
export {INVNewProductPackaging as default}