export const siteStrings = {
    site : "site",
}
export const siteConstants = {
    SET_SITE :"SET_SITE",
}
export const siteReducer = (state={}, action) => {
    const {type, payload} = action;
    switch(type){
        case siteConstants.SET_SITE : 
            return {...state, ...payload};
        default : return {...state};
    }
}
export * from './actions';
export * from './services';