import { store } from "../../../../helpers";
import { inovateOSUtilStrings } from "./config";
import { _retrieveData, _storeData } from "../../../../utils";

export const inovateOSUtil = {
    getTheme : ()=>(store.getState().inovateOSUtilReducer[inovateOSUtilStrings.theme]),
    getToken : ()=>{
        const reducer = store.getState().inovateOSUtilReducer;
        return localStorage.getItem(reducer[inovateOSUtilStrings.tokenAlias])
    },
    getUserId : () => {
        const reducer = store.getState().inovateOSUtilReducer;
        return localStorage.getItem(reducer[inovateOSUtilStrings.userAlias])
    },
    isLogedIn : (userIdAlias, tokenAlias) => {
        let token; let userId;
        if(userIdAlias){
            userId = localStorage.getItem(userIdAlias);
            token = localStorage.getItem(tokenAlias);
        }else{
            userId = inovateOSUtil.getUserId();
            token = inovateOSUtil.getToken();
        }
        return userId && token;
    },
    fetchGet : async function(owner, action, stringQuery, callback){
        const state = store.getState().inovateOSUtilReducer;
        const USERID = _retrieveData(state[inovateOSUtilStrings.userAlias]);
        const TOKEN = _retrieveData(state[inovateOSUtilStrings.tokenAlias]);
        stringQuery = {...stringQuery, userId : USERID, token : TOKEN};
        let count = 0;
        let build = "";
        for (const i in stringQuery) {
            if (stringQuery.hasOwnProperty(i)) {
                const elem = stringQuery[i];
                if(count === 0){
                    build += "?"+i+"="+elem;
                }else build += "&"+i+"="+elem;
                count++;
            }
        }
        fetch(state[inovateOSUtilStrings.backendUrl]+owner+"/"+action+build).then(
            response=> response.json()
        ).then(response=>{
            if(callback) callback(response)
        });
    },
    fetchPost : async function(owner, action, options, callback, query = {}){
        const state = store.getState().inovateOSUtilReducer;
        const USERID = _retrieveData(state[inovateOSUtilStrings.userAlias]);
        const TOKEN = _retrieveData(state[inovateOSUtilStrings.tokenAlias]);
        const stringQuery = {userId : USERID, token : TOKEN, ...query}; //this.getStoredUserInfo();
        let count = 0;
        let build = "";
        for (const i in stringQuery) {
            if (stringQuery.hasOwnProperty(i)) {
                const elem = stringQuery[i];
                if(count === 0){
                    build += "?"+i+"="+elem;
                }else build += "&"+i+"="+elem;
                count++;
            }
        }
        fetch(state[inovateOSUtilStrings.backendUrl]+owner+"/"+action+build, options).then(
            response=> response.json()
        ).then(response=>callback(response))
        .catch(e => {
            console.error(e);
        });
    },
    post : function(data, owner, action, callback, query){
        inovateOSUtil.fetchPost(owner, action, {
            method : "post",
            headers : {
                "Content-Type" : "Application/json"
            },
            body : JSON.stringify(data)
        }, callback, query);
    }
}