import React from 'react';
import { inovateOSAdminRouteNames } from "./routeNames";
import {connect} from 'react-redux';
import { Router, Switch, Route} from 'react-router-dom';
import { 
    headerActions, headerStrings, screenActions,  mainStageAction, 
    MySnackbar, SnackDialog, mainStageHeaderAction,  mainStageStrings
} from '../../includes';
import { PrivateRoutePlane, LogoutRoute } from './RouteTemplates';
import { history } from '../../../helpers';
import { inovateOSAdminMenuItem } from './menuItems';
import { inovateOSAdminUtilActions, theme1, inovateOSAdminUtil, inovateOSAdminUtilStrings, inovateOSAdminActions } from './utils';
import { withStyles } from '@material-ui/core';
import { inovateOSAdminRoutes } from './routes';
import Login from './Login/Login';
import $ from 'jquery';


const styles = theme => ({
    mainStage : {
        margin : 0,
        padding : 0,
    }
})
class _InovateOSAdminApp extends React.PureComponent{
    constructor(props) {
        super(props);

        const {pathname} = history.location;
        if(String(pathname).startsWith("/super")){
            const {
                dispatch,
                [inovateOSAdminUtilStrings.myProfile] : myProfile,
            } = props;
            inovateOSAdminUtilActions({
                [inovateOSAdminUtilStrings.theme] : theme1,
                [inovateOSAdminUtilStrings.tokenAlias] : "inovateOSAdminToken",
                [inovateOSAdminUtilStrings.userAlias] : "inovateOSAdminUserId",
                [inovateOSAdminUtilStrings.backendUrl] : "http://157.245.71.43/api/v1/",
                [inovateOSAdminUtilStrings.backendBaseUrl] : "http://157.245.71.43",
                [inovateOSAdminUtilStrings.defaultImage] : "/image/default.png",
            })(dispatch);
            headerActions({
                [headerStrings.headerTitle] : "INOVATE-OS",
                [headerStrings.headerTitleProps] : {
                    style : {
                        borderBottom : "none",
                        color : inovateOSAdminUtil.getTheme().white,
                    }
                },
                [headerStrings.drawer] : true,
                [headerStrings.visible] : true,
                [headerStrings.menuItems] : inovateOSAdminMenuItem,
            })(dispatch);
            screenActions.setTheme(theme1)(dispatch);
            mainStageAction({
                [mainStageStrings.containerProps] : {
                    style : {
                        margin : 0,
                        padding : 0,
                        height : "calc(100vh - 115px)",
                        marginTop : 66,
                    }
                }
            })(dispatch);
            mainStageHeaderAction({
                [mainStageHeaderAction.visible] : false,
            })(dispatch);            
            if(inovateOSAdminUtil.isLogedIn()){
                if(!myProfile)
                    inovateOSAdminActions.getUser()(dispatch);
                // chatConfiguration();
            }

        }
        
    }
    componentDidMount(){
        // $("body").css("backgroundColor", inovateOSAdminUtil.getTheme().background);
        if(history.location.pathname.startsWith("/super"))
            $("title").text("InovateOS-Admin");
    }
    render(){
        return(
            <Router history={history}>
                <div>
                    <React.Suspense
                        fallback={<div>Loading...</div>}>
                        <Switch>
                            {inovateOSAdminRoutes && inovateOSAdminRoutes.map((route, index)=>{
                                
                                return <PrivateRoutePlane {...route} key={index}/>
                            })}
                            <Route path={inovateOSAdminRouteNames.login} exact component={props=><Login {...props}/>}/>
                            <LogoutRoute path="/super/logout"/>
                        </Switch>
                    </React.Suspense>
                    <MySnackbar/>
                    <SnackDialog/>
                </div>
            </Router>
        )
    }
}
const mapStateToProps = ({inovateOSAdminUtilReducer}) => ({
    [inovateOSAdminUtilStrings.myProfile] : inovateOSAdminUtilReducer[inovateOSAdminUtilStrings.myProfile],
})
export const InovateOSAdminApp =  connect(mapStateToProps)(withStyles(styles)(_InovateOSAdminApp));