import { fetchGet, post, fetchPost } from "../utils";
const owner = "admin";
export const inovateOSAdminSiteServices = {
    postNewArticle : (form, callback)=>{
        fetchPost(owner, "postNewArticle", {
            method : "post",
            body : form
        }, ({postNewArticle, result, message})=>{
            callback(postNewArticle, result, message);
        })
    },
    deleteArticle : (name, subname, callback) => {
        post({name, subname}, owner, "deleteArticle", ({deleteArticle, result, message})=>{
            callback(deleteArticle, result, message);
        })
    },
    updateArticle : (property, name, subname, value, callback) => {
        if(property === "src"){
            fetchPost(owner, "updateArticle", {
                method : "post",
                body : value
            }, ({updateArticle, result, message})=>{
                callback(updateArticle, result, message);
            })
        }else{
            post({property, name, subname, value}, owner, "updateArticle", ({updateArticle, result, message})=>{
                callback(updateArticle, result, message);
            })
        }
    },
    postFile : (form, callback)=>{
        fetchPost(owner, "postFile", {
            method : "post",
            body : form,
        }, ({postFile, result, message})=>{
            callback(postFile, result, message);
        })
    },
    postSiteInfo : (name, subname, propName, value, callback) => {
        let queryObj = {name};
        if(propName) queryObj.propName = propName;
        if(subname) queryObj.subname = subname;
        post({value}, owner, "postSiteInfo", ({postSiteInfo, result, message})=>{
            callback(postSiteInfo, result, message);
        }, queryObj)
    },
    getSiteInfo : callback => {
        fetchGet(owner, "getAllSiteInfo", {}, ({getAllSiteInfo, result, message})=>{
            callback(getAllSiteInfo, result, message);
        });
    }
}