import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, MyTable } from '../../includes';
import { routeName } from '../../../utils';
import { payrollStrings, payrollActions } from '../config';
import { TableCell } from '@material-ui/core';
import { history } from '../../../helpers';


const style = theme => ({
    root: {
        marginTop : 20
    },
    cell : {
        padding : 5,
        paddingLeft : 10
    }
})
class _PayrollHistory extends Component {
    constructor(props) {
        super(props);
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "PAYROLL HISTORY",
            [headerStrings.backButtonAction] : null
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeName.dashboard},
            {name : "Payroll history", path : routeName.payrollHistory},
        ])(dispatch);

        this.initialiseComponent();
    }
    initialiseComponent(){
        const {dispatch} = this.props;
        payrollActions.getPayrollHistory()(dispatch);
    }
    cellMapFormat = ({row, cellMap}) =>{
        const {classes} = this.props;
        switch(cellMap){
            case "employeeIds" : 
                return <TableCell className={classes.cell}>
                    {row[cellMap] && row[cellMap].length}
                </TableCell>
            
            case "total" : return <TableCell className={classes.cell}>
                {row[cellMap] && Number(row[cellMap]).toLocaleString()}
            </TableCell>
            default : return <TableCell className={classes.cell}>
                {row[cellMap]}
            </TableCell>
        }
    }
    rowAction = row => () => {
        history.push(routeName.payrollHistoryDetail_ + row._id, row);
    }
    render() {
        const {
            classes, 
            [payrollStrings.payrollHistory] : payrollHistory
        } = this.props;
        return (
            <div className={classes.root}>
                <MyTable
                    header={["Date", "Description", "Number of Emp.", "Total Amount (N)"]}
                    dataMap={["date", "description", "employeeIds", "total"]}
                    data={payrollHistory}
                    rowAction={this.rowAction.bind(this)}
                    CellMap={this.cellMapFormat.bind(this)}
                    />
            </div>
        );
    }
}


_PayrollHistory.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({payrollReducer}) => ({
    [payrollStrings.payrollHistory] : payrollReducer[payrollStrings.payrollHistory],
})


export const PayrollHistory = connect(mapStateToProps)(withStyles(style)(_PayrollHistory));
export {PayrollHistory as default}