import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { hirDashboardActions } from './actions';
import { MyChart, headerActions, headerStrings, breadCrumbActions } from '../../includes';
import { hirDashboardStrings } from './config';
import { monthLabels } from '../../../utils';
import { hirUtil } from '../utils';
import { Grid, FormLabel } from '@material-ui/core';
import { CountBox } from './CountBox';
import localIp from 'local-ip-url';
import ReactToPrint from 'react-to-print';
import { hirRouteNames } from '../routeNames';


const style = theme => ({
    root: {
    },
    label : {
        fontWeight : "bold",
        color : theme.colors.primary1,
    },
    gridContainer : {
        marginTop : 20,
        marginBottom : 10,
    },
    grow : {
        display : "flex",
        flexGrow : 1
    },
    ipContainer : {
        display : 'flex',
    },
    ip : {
        padding : 10,
        borderRadius : 20,
        backgroundColor : theme.colors.secondary,
        color : theme.colors.white,
        marginRight : 10,
    }
})
class _Dashboard extends Component {
    constructor(props) {
        super(props);
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "Dashboard",
            [headerStrings.backButtonAction] : null
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", pathname : hirRouteNames.dashboard}
        ])(dispatch);
    }
    
    componentDidMount() {
        const {dispatch} = this.props;
        hirDashboardActions.getLocalIP()(dispatch);
        this.getPaymentMonthDayData();
        this.getPaymentYearMonthData();

        this.getAppointmentMonthDayData();
        this.getAppointmentYearMonthData();
        this.getActualAppointmentMonthDayData();
        this.getActualAppointmentYearMonthData();

        this.getPatientMonthDayData();
        this.getPatientYearMonthData();

        this.getPaymentTotalAmounts();
        this.getAppointmentTotalCounts();
        this.getPatientTotalCounts();
    }
    getPatientTotalCounts(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getPatientDayTotalCount(
            date.getFullYear(),
            date.getMonth() + 1,
            date.getDate()
        )(dispatch);
        hirDashboardActions.getPatientMonthTotalCount(
            date.getFullYear(),
            date.getMonth() + 1
        )(dispatch);
        hirDashboardActions.getPatientYearTotalCount(
            date.getFullYear()
        )(dispatch);
    }
    getAppointmentTotalCounts(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getAppointmentDayTotalCount(
            date.getFullYear(),
            date.getMonth() + 1,
            date.getDate()
        )(dispatch);
        hirDashboardActions.getAppointmentMonthTotalCount(
            date.getFullYear(),
            date.getMonth() + 1
        )(dispatch);
        hirDashboardActions.getAppointmentYearTotalCount(
            date.getFullYear()
        )(dispatch);
    }
    getPaymentTotalAmounts(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getPaymentDayTotalAmount(
            date.getFullYear(),
            date.getMonth() + 1,
            date.getDate()
        )(dispatch);
        hirDashboardActions.getPaymentMonthTotalAmount(
            date.getFullYear(),
            date.getMonth() + 1
        )(dispatch);
        hirDashboardActions.getPaymentYearTotalAmount(
            date.getFullYear()
        )(dispatch);
    }
    getPatientMonthDayData(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getPatientMonthDayData(
            date.getFullYear(), 
            date.getMonth() + 1
        )(dispatch);
    }
    getPatientYearMonthData(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getPatientYearMonthData(
            date.getFullYear()
        )(dispatch);
    }
    getActualAppointmentMonthDayData(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getActualAppointmentMonthDayData(
            date.getFullYear(),
            date.getMonth() + 1
        )(dispatch);
    }
    getActualAppointmentYearMonthData(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getActualAppointmentYearMonthData(
            date.getFullYear()
        )(dispatch);
    }
    getAppointmentMonthDayData(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getAppointmentMonthDayData(
            date.getFullYear(),
            date.getMonth() + 1
        )(dispatch);
    }
    getAppointmentYearMonthData(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getAppointmentYearMonthData(
            date.getFullYear()
        )(dispatch);
    }
    getPaymentYearMonthData(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getPaymentYearMonthData(
            date.getFullYear()
        )(dispatch);
    }
    getPaymentMonthDayData(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getPaymentMonthDayData(
            date.getFullYear(), date.getMonth() + 1
        )(dispatch);
    }
    deriveDailyData(data){
        const returnData = [];
        if(data) for (let i = 1; i < 31; i++) {
            const value = data.find(item=>item._id.day ===i);
            if(value)returnData.push(value.amount);
            else returnData.push(0);
        }
        return returnData;
    }
    deriveMonthlyData(data, valueName){
        const returnData = [];
        if(data) for (let i = 0; i < monthLabels.length; i++) {
            const value = data.find(item=>item._id.month==i+1);
            if(value){
                returnData.push(value[valueName]);
            }else returnData.push(0);
        }
        return returnData;
    }
    generateSequence(end){
        const returnData =[];
        for (let i = 0; i < end; i++) {
            returnData.push(i+1)
        }
        return returnData;
    }
    deriveDay(data, valueName){
        const returnData = [];
        if(data) for (let i = 0; i < 31; i++) {
            const value = data.find(item=>item._id.day === i+1)
            if(value) returnData.push(value[valueName]);
            else returnData.push(0);
        }
        return returnData;
    }
    render() {
        const {
            classes,
            [hirDashboardStrings.paymentMonthDayData] : paymentMonthDay,
            [hirDashboardStrings.paymentYearMonthData] : paymentYearMonth,
            [hirDashboardStrings.appointmentMonthDayData] : appointmentMonthDay,
            [hirDashboardStrings.appointmentYearMonthData] : appointmentYearMonth,
            [hirDashboardStrings.actualAppointmentMonthDayData] : actualAppointmentMonthDay,
            [hirDashboardStrings.actualAppointmentYearMonthData] : actualAppointmentYearMonth,
            [hirDashboardStrings.patientMonthDayData] : patientMonthDay,
            [hirDashboardStrings.patientYearMonthData] : patientYearMonth,

            [hirDashboardStrings.paymentDayTotalAmount] : paymentDayTotalAmount,
            [hirDashboardStrings.paymentMonthTotalAmount] : paymentMonthTotalAmount,
            [hirDashboardStrings.paymentYearTotalAmount] : paymentYearTotalAmount,

            [hirDashboardStrings.appointmentDayTotalCount] : appointmentDayTotalCount,
            [hirDashboardStrings.appointmentMonthTotalCount] : appointmentMonthTotalCount,
            [hirDashboardStrings.appointmentYearTotalCount] : appointmentYearTotalCount,

            [hirDashboardStrings.patientDayTotalCount] : patientDayTotalCount,
            [hirDashboardStrings.patientMonthTotalCount] : patientMonthTotalCount,
            [hirDashboardStrings.patientYearTotalCount] : patientYearTotalCount,

            [hirDashboardStrings.ip] : ip,
        } = this.props;
        const date = new Date();
        return (
            <div className={classes.root}>
                <div className={classes.ipContainer}>
                    <div className={classes.grow}/>
                    <div className={classes.ip}>IP (Public/ WIFI): http://{ip}</div>
                    <div className={classes.ip}>IP (LAN): http://192.168.0.10{ip && String(ip).substr(String(ip).lastIndexOf(":"))}</div>
                </div>
                <div>
                    <div className={classes.gridContainer} ref={e=>this.printComponentRevenue=e}>
                        <FormLabel className={classes.label}>Revenue</FormLabel>
                        <Grid container spacing={4}>
                            <Grid item xs={6} sm={4} md={4} lg={4} xl={4}>
                                <CountBox
                                    color="#9e9e9e"
                                    header={"This Year - ("+new Date().getFullYear()+")"}
                                    text={
                                        paymentYearTotalAmount && 
                                        paymentYearTotalAmount[0] ?
                                        "N"+Number(paymentYearTotalAmount[0].amount).toLocaleString() :
                                        "0.00"
                                    }/>
                            </Grid>
                            <Grid item xs={6} sm={4} md={4} lg={4} xl={4}>
                                <CountBox
                                    header={monthLabels[new Date().getMonth()]+", "+new Date().getFullYear()}
                                    text={
                                        paymentMonthTotalAmount && 
                                        paymentMonthTotalAmount[0] ?
                                        "N"+Number(paymentMonthTotalAmount[0].amount).toLocaleString() :
                                        "0.00"
                                    }/>
                            </Grid>
                            <Grid item xs={6} sm={4} md={4} lg={4} xl={4}>
                                <CountBox
                                    color="#607d8b"
                                    header="Today"
                                    text={
                                        paymentDayTotalAmount && 
                                        paymentDayTotalAmount[0] ? 
                                        "N"+Number(paymentDayTotalAmount[0].amount).toLocaleString()  :
                                        "0.00"
                                    }/>
                            </Grid>
                        </Grid>
                        <Grid container spacing={2}>
                            <Grid item xs={12} sm={12} md={12} lg={12} xl={12}>
                                <MyChart
                                    canvasId="paymentMonthDay"
                                    title={"Revenue for " + monthLabels[date.getMonth()] + " ("+date.getFullYear()+")"}
                                    labels={this.generateSequence(31)}
                                    datasets={[{
                                        label: 'Total amount :',
                                        data : this.deriveDay(paymentMonthDay, "amount"),
                                        backgroundColor : hirUtil.getTheme().primaryTrans,
                                        borderColor : hirUtil.getTheme().primary,
                                    }]}
                                />
                            </Grid>
                            <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                                <MyChart
                                    canvasId="paymentYearMonth"
                                    title={"Monthly Revenue " + new Date().getFullYear()+" (line)"}
                                    labels={monthLabels}
                                    datasets={[{
                                        label: 'Total amount :',
                                        data : this.deriveMonthlyData(paymentYearMonth, "amount"),                                
                                        backgroundColor : hirUtil.getTheme().primaryTrans,
                                        borderColor : hirUtil.getTheme().primary,
                                    }]}
                                />
                            </Grid>
                            <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                                <MyChart
                                    canvasId="paymentYearMonth2"
                                    type="pie"
                                    title={"Monthly Revenue " + new Date().getFullYear()+" (pie)"}
                                    labels={monthLabels}
                                    datasets={[{
                                        label: 'Total amount :',
                                        data : this.deriveMonthlyData(paymentYearMonth, "amount"),
                                        backgroundColor : [
                                            "red", "#673AB7", "blue", "orange", "lightblue", "orange",
                                            "gold", "black", "brown", "pink", "red", "coral"
                                        ],
                                        borderColor : [
                                            "red", "#673AB7", "blue", "orange", "lightblue", "orange",
                                            "gold", "black", "brown", "pink", "red", "coral"
                                        ]
                                    }]}
                                />
                            </Grid>
                        </Grid>
                    </div>
                    <ReactToPrint 
                        trigger={()=><button>Print</button>}
                        content={()=>this.printComponentRevenue}
                    />
                </div>
                <div>
                    <div className={classes.gridContainer} ref={e=>this.printComponentAppointment=e}>
                        <FormLabel className={classes.label}>Appointments</FormLabel>
                        <Grid container spacing={4}>
                            <Grid item xs={6} sm={4} md={4} lg={4} xl={4}>
                                <CountBox
                                    color="#9e9e9e"
                                    header={"This Year - ("+new Date().getFullYear()+")"}
                                    text={
                                        appointmentYearTotalCount && 
                                        appointmentYearTotalCount[0] ?
                                        appointmentYearTotalCount[0].count :
                                        "0"
                                    }/>
                            </Grid>
                            <Grid item xs={6} sm={4} md={4} lg={4} xl={4}>
                                <CountBox
                                    header={monthLabels[new Date().getMonth()]+", "+new Date().getFullYear()}
                                    text={
                                        appointmentMonthTotalCount && 
                                        appointmentMonthTotalCount[0] ?
                                        appointmentMonthTotalCount[0].count :
                                        "0"
                                    }/>
                            </Grid>
                            <Grid item xs={6} sm={4} md={4} lg={4} xl={4}>
                                <CountBox
                                    color="#607d8b"
                                    header="Today"
                                    text={
                                        appointmentDayTotalCount && 
                                        appointmentDayTotalCount[0] ?
                                        appointmentDayTotalCount[0].count :
                                        "0"
                                    }/>
                            </Grid>
                        </Grid>
                        <Grid container spacing={2}>
                            <Grid item xs={12} sm={12} md={12} lg={12} xl={12}>
                                <MyChart
                                    canvasId="appointmentMonthDay"
                                    title={"Appointments for " + monthLabels[date.getMonth()] + " ("+date.getFullYear()+")"}
                                    labels={this.generateSequence(31)}
                                    datasets={[
                                        {
                                            label: 'Total Expected Appointments :',
                                            data : this.deriveDay(appointmentMonthDay, "count"),
                                            backgroundColor : hirUtil.getTheme().primaryTrans,
                                            borderColor : hirUtil.getTheme().primary,
                                        },
                                        {
                                            label: 'Total Actual Appointments :',
                                            data : this.deriveDay(actualAppointmentMonthDay, "count"),
                                            backgroundColor : hirUtil.getTheme().secondary,
                                            borderColor : hirUtil.getTheme().secondary,
                                        }
                                    ]}
                                />
                            </Grid>
                            <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                                <MyChart
                                    canvasId="appointmentYearMonth"
                                    title={"Monthly Appointments " + new Date().getFullYear()+" (line)"}
                                    labels={monthLabels}
                                    datasets={[
                                        {
                                            label: 'Total Expected Appointments :',
                                            data : this.deriveMonthlyData(appointmentYearMonth, "count"),                                
                                            backgroundColor : hirUtil.getTheme().primaryTrans,
                                            borderColor : hirUtil.getTheme().primary,
                                        },{
                                            label: 'Total Actula Appointments :',
                                            data : this.deriveMonthlyData(actualAppointmentYearMonth, "count"),                                
                                            backgroundColor : hirUtil.getTheme().secondary,
                                            borderColor : hirUtil.getTheme().secondary,
                                        },
                                    ]}
                                />
                            </Grid>
                            <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                                <MyChart
                                    canvasId="appointmentYearMonth2"
                                    type="doughnut"
                                    title={"Monthly Appointments " + new Date().getFullYear()+" (doughnut)"}
                                    labels={monthLabels}
                                    datasets={[
                                        {
                                            label: 'Total Actual Appointments :',
                                            data : this.deriveMonthlyData(actualAppointmentYearMonth, "count"),
                                            backgroundColor : [
                                                "red", "#673AB7", "blue", "orange", "lightblue", "orange",
                                                "gold", "black", "brown", "pink", "red", "coral"
                                            ],
                                            borderColor : [
                                                "red", "#673AB7", "blue", "orange", "lightblue", "orange",
                                                "gold", "black", "brown", "pink", "red", "coral"
                                            ]
                                        }
                                    ]}
                                />
                            </Grid>
                        </Grid>
                    </div>
                    <ReactToPrint 
                        trigger={()=><button>Print</button>}
                        content={()=>this.printComponentAppointment}
                    />
                </div>
                <div>
                    <div className={classes.gridContainer} ref={e=>this.printComponentPatients=e}>
                        <FormLabel className={classes.label}>Patients</FormLabel>
                        <Grid container spacing={4}>
                            <Grid item xs={6} sm={4} md={4} lg={4} xl={4}>
                                <CountBox
                                    color="#9e9e9e"
                                    header={"This Year - ("+new Date().getFullYear()+")"}
                                    text={
                                        patientYearTotalCount && 
                                        patientYearTotalCount[0] ?
                                        patientYearTotalCount[0].count :
                                        "0"
                                    }/>
                            </Grid>
                            <Grid item xs={6} sm={4} md={4} lg={4} xl={4}>
                                <CountBox
                                    header={monthLabels[new Date().getMonth()]+" "+new Date().getFullYear()}
                                    text={
                                        patientMonthTotalCount && 
                                        patientMonthTotalCount[0] ?
                                        patientMonthTotalCount[0].count :
                                        "0"
                                    }/>
                            </Grid>
                            <Grid item xs={6} sm={4} md={4} lg={4} xl={4}>
                                <CountBox
                                    color="#607d8b"
                                    header="Today"
                                    text={
                                        patientDayTotalCount && 
                                        patientDayTotalCount[0] ?
                                        patientDayTotalCount[0].count :
                                        "0"
                                    }/>
                            </Grid>
                        </Grid>
                        <Grid container spacing={2}>
                            <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                                <MyChart
                                    canvasId="patientMonthDay"
                                    title={"New Patients for " + monthLabels[date.getMonth()] + " ("+date.getFullYear()+")"}
                                    labels={this.generateSequence(31)}
                                    datasets={[
                                        {
                                            label: 'Total Count of Patients:',
                                            data : this.deriveDay(patientMonthDay, "count"),
                                            backgroundColor : hirUtil.getTheme().primaryTrans,
                                            borderColor : hirUtil.getTheme().primary,
                                        },
                                    ]}
                                />
                            </Grid>
                            <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                                <MyChart
                                    canvasId="patientYearMonth"
                                    title={"New Patients " + new Date().getFullYear()+" (line)"}
                                    labels={monthLabels}
                                    datasets={[
                                        {
                                            label: 'Total Patient Count :',
                                            data : this.deriveMonthlyData(patientYearMonth, "count"),                                
                                            backgroundColor : hirUtil.getTheme().primaryTrans,
                                            borderColor : hirUtil.getTheme().primary,
                                        }
                                    ]}
                                />
                            </Grid>
                        </Grid>
                    </div>
                    <ReactToPrint 
                        trigger={()=><button>Print</button>}
                        content={()=>this.printComponentPatients}
                    />
                </div>
            </div>
        );
    }
}


_Dashboard.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({hirDashboardReducer}) => ({
    ...hirDashboardReducer
})


export const Dashboard = connect(mapStateToProps)(withStyles(style)(_Dashboard));
export {Dashboard as default}