import React, { PureComponent } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import {Link} from 'react-router-dom';
import {withStyles} from '@material-ui/core/styles';
import { Paper, Grid, Typography } from '@material-ui/core';
const style = theme => ({
    root: {
        padding : 5,
        marginTop : 20,
        background : "transparent",
    },
    rightAlign : {
        direction : "rtl"
    },
    img : {
        width : "100%",
        maxHeight : "100%",
    },
    header : {
        textDecoration : "none",
        cursor : "pointer",
    }
})
class _ServiceItemBox extends PureComponent {
    render() {
        const {classes, src, header, body, alt, baseUrl, footer : Footer, headerLink} = this.props;
        return (
            <div className={classNames(classes.root, alt ? classes.rightAlign : null)} {...this.props.containerProps}>
                <Paper elevation={0} {...this.props.paperProps}>
                    <Grid container spacing={2}>
                        <Grid item xs={12} sm={6} md={4} lg={4} xl={4}>
                            <img className={classes.img} src={baseUrl ? baseUrl+src : src} title={header}/>
                        </Grid>
                        <Grid item xs={12} sm={6} md={8} lg={8} xl={8}>
                            <div className={classes.bodyContainer}>
                                <Typography variant="h5" className={header} paragraph>
                                    {headerLink ? 
                                        <Link 
                                            className={classes.header}
                                            to={headerLink}>{header}</Link> : 
                                        header}
                                </Typography>
                                {body && body.map((item, index)=>
                                    <Typography paragraph key={index}>{item}</Typography>
                                )}
                                {Footer && <Footer/>}
                            </div>
                        </Grid>
                    </Grid>
                </Paper>
            </div>
        );
    }
}
_ServiceItemBox.propTypes = {
    classes : PropTypes.object.isRequired,
    src : PropTypes.string,
    header : PropTypes.string,
    body : PropTypes.array,
    alt : PropTypes.bool,
    baseUrl : PropTypes.string,
    headerLink : PropTypes.oneOfType([
        PropTypes.string, PropTypes.object,
    ])
};
export const ServiceItemBox = withStyles(style)(_ServiceItemBox);