import React from 'react';
import { agroRouteNames } from "./routeNames";

const Home = React.lazy(()=>import("./Site/Home/Home"));
const Services = React.lazy(()=>import("./Site/Services/Services"));
const AboutUs = React.lazy(()=>import("./Site/AboutUs/AboutUs"));
const Blog = React.lazy(()=>import("./Site/Blog/Blog"));
const ContactUs = React.lazy(()=>import("./Site/ContactUs/ContactUs"));

export const agroRoutes = [
    {path : agroRouteNames.site, exact : true, component : Home},
    {path : agroRouteNames.services, exact : true, component : Services},
    {path : agroRouteNames.aboutUs, exact : true, component : AboutUs},
    {path : agroRouteNames.blog, exact : true, component : Blog},
    {path : agroRouteNames.contactUs, exact : true, component : ContactUs},
]