import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { inovateOSUtilStrings } from '../utils';
import { headerStrings, headerActions } from '../../../includes';
import { InovateOSHeaderCompenentMenu } from './InovateOSHeaderCompenentMenu';
import { inovateOSPageStrings, inovateOSPageActions } from '../Pages';
import { inovateOSRouteNames } from '../routeNames';


const style = theme => ({
    root: {
    }
})
class _InovateOSSiteHeaderLeftCompnent extends Component {
    componentDidMount() {
        const {
            dispatch,
            [inovateOSPageStrings.services] : services,
        } = this.props;
        if(!services) inovateOSPageActions.getServices()(dispatch);
    }    
    render() {
        let {
            classes,
            [headerStrings.menuItems] : menuItems,
            [inovateOSPageStrings.services] : services
        } = this.props;
        if(menuItems){
            menuItems = menuItems.map(item => {
                if(item.name === "Services" && services){
                    item.tree = services.map(
                        item=>({
                            name : item.header, 
                            pathname : inovateOSRouteNames.serviceItem_+item.name
                        })
                    )
                }
                return item
            })
        }
        return (
            <div className={classes.root}>
                <InovateOSHeaderCompenentMenu
                    list={menuItems}/>
            </div>
        );
    }
}


_InovateOSSiteHeaderLeftCompnent.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({headerReducer, inovateOSPageReducer}) => ({
    [headerStrings.menuItems] : headerReducer[headerStrings.menuItems],
    [inovateOSPageStrings.services] : inovateOSPageReducer[inovateOSPageStrings.services],
})


export const InovateOSSiteHeaderLeftCompnent = connect(mapStateToProps)(withStyles(style)(_InovateOSSiteHeaderLeftCompnent));
export {InovateOSSiteHeaderLeftCompnent as default}