import { insureUtilConstants, insureUtilStrings } from "./config";
import { insureUtilServices } from "./services";
import { errorNotice, insureUtil, _storeData } from "./insureUtil";
import { store } from "../../../helpers";

export const insureUtilActions = payload => dispatch => dispatch({
    type : insureUtilConstants.SET_UTIL,
    payload 
});

export const insureActions = {
    getForms : callback => dispatch => {
        insureUtilServices.getForms((done, result, message)=>{
            if(done) insureUtilActions({
                [insureUtilStrings.forms] : result
            })(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getSettings : callback => dispatch => {
        insureUtilServices.getSettings((done, result, message)=>{
            if(done) {
                const {item : subheadItem} = result.getFirstObjectByPropValue("name", "subheadImage");
                if(subheadItem){
                    insureUtilActions({
                        [insureUtilStrings.subheadImage] : 
                        store.getState().insureUtilReducer[insureUtilStrings.backendBaseUrl]+subheadItem.value
                    })(dispatch)
                }
                insureUtilActions({
                    [insureUtilStrings.settings] : result
                })(dispatch);
            }
            if(callback) callback(done, result, message);
        })
    },
    getUser : callback => dispatch => {
        insureUtilServices.getUser((done, result, message)=>{
            if(done){
                insureUtilActions({
                    [insureUtilStrings.myProfile] : result ? result.myProfile : null
                })(dispatch);
            }
            if(callback) callback(done, result, message);
        })
    },
    signup : (data, callback) => dispatch => {
        insureUtilServices.signup(data, (done, result, message)=>{
            const reducer = store.getState().insureUtilReducer;
            if(done){
                _storeData(reducer[insureUtilStrings.tokenAlias], result.myProfile.token);
                _storeData(reducer[insureUtilStrings.userAlias], result._id);
                insureUtilActions({
                    [insureUtilStrings.myProfile] : result.myProfile,
                    [insureUtilStrings.isLoggedIn] : insureUtil.isLogedIn(),
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    login : (email, password, callback) => dispatch => {
        insureUtilServices.login(email, password, (done, result, message)=>{
            const reducer = store.getState().insureUtilReducer;
            if(done){
                _storeData(reducer[insureUtilStrings.tokenAlias], result.myProfile.token);
                _storeData(reducer[insureUtilStrings.userAlias], result._id);
                insureUtilActions({
                    [insureUtilStrings.myProfile] : result.myProfile,
                    [insureUtilStrings.isLoggedIn] : insureUtil.isLogedIn(),
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    logout : () => {
        const reducer = store.getState().insureUtilReducer;
        localStorage.removeItem(reducer[insureUtilStrings.tokenAlias]);
        localStorage.removeItem(reducer[insureUtilStrings.userAlias]);
        insureUtilActions({
            [insureUtilStrings.isLoggedIn] : false
        })(store.dispatch);
    },
}
