export const parentStrings = {
    parents : "parents",
}
export const parentConstants = {
    SET_PARENTS : "SET_PARENTS",
    CLEAN_UP_PARENTS : "CLEAN_UP_PARENTS",
}
export const parentReducer = (state = {}, action) => {
    const {type, payload } = action;
    switch(type){
        case parentConstants.SET_PARENTS :
            return {...state, ...payload};
        case parentConstants.CLEAN_UP_PARENTS : 
            return {};
        default : return {...state};
    }
}
export * from './actions';
export * from './services';