import React, { Component } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import {withStyles} from '@material-ui/core/styles';
import {connect} from 'react-redux';
import { MyTable, EditableCellMapFormat, MyListCard, inventoryUtil, inventoryAppActions, inventoryAlertActions } from '../../../../../utils';
import { ListItem, ListItemSecondaryAction, ListItemText, CardActions, List, TextField } from '@material-ui/core';
import { Delete, Add } from '@material-ui/icons';
import {INVUnCatOptionListFooter} from './INVUnCatOptionListFooter';
const style = theme => ({
    root: {
        
    },
    listItem : {
        fontSize : 12,
    },
    listRoot : {
        backgroundColor : inventoryUtil.getTheme().background,
    }
})
class _INVUnCategorisedOptions extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data : props.data || [],
        }
        const {getContext} = props;
        if(getContext) getContext(this)
    }
    cellMapFormat = superProps => props => <EditableCellMapFormat {...props} {...superProps}/>
    tableCellContentView(editing, {row, cellMap}){
        if(editing){
            return row[cellMap]
        }else{
            switch(cellMap){
                case "name" : return row
            }
        }
    }
    deleteBtnHandler = row => () => {
        const {data} = this.state;
        const index = data.findIndex(item=>item===row);
        if(index || index === 0) data.splice(index, 1);
        this.setState({data});
    }
    descriptionComponent = ({item}) => {
        const {classes} = this.props;
        return <ListItem>
            <ListItemText className={classes.listItem}>{item}</ListItemText>
            <ListItemSecondaryAction>
                <Delete fontSize="small" color="secondary"
                    onClick={this.deleteBtnHandler(item)}/>
            </ListItemSecondaryAction>
        </ListItem>
    }
    addNewValue(newValue){
        const {data} = this.state;
        data.push(newValue);
        this.setState({data});
    }

    render() {
        const {classes} = this.props;
        return (
            <div className={classNames("animated", "slideInRight", classes.root)}>
                <MyListCard
                    classes={{root : classes.listRoot}}
                    cardHeaderProps={{
                        titleTypographyProps : {
                            style : {
                                fontSize : 14,
                                fontWeight : "bold"
                            }
                        }
                    }}
                    title={this.props.title || "Description Values"}
                    list={this.state.data}
                    component={this.descriptionComponent.bind(this)}
                    footer={()=><INVUnCatOptionListFooter dispatch={this.props.dispatch} getValue={this.addNewValue.bind(this)}/>}
                    />
            </div>
        );
    }
}
_INVUnCategorisedOptions.propTypes = {
    classes : PropTypes.object.isRequired,
    getContext : PropTypes.func,
};
export const INVUnCategorisedOptions = connect()(withStyles(style)(_INVUnCategorisedOptions));