import React, { Component, useState } from 'react';
import { ListItem, ListItemSecondaryAction, CardActions, List, TextField, IconButton } from '@material-ui/core';
import { Add } from '@material-ui/icons';
import { inventoryAppActions, inventoryAlertActions } from '../../../../../utils';
import { makeStyles } from '@material-ui/styles';

export const INVUnCatOptionListFooter = function({getValue, dispatch, iconButtonProps={}}){
    const classes = makeStyles({
        icon : {
            borderRadius : 100,
            backgroundColor : "green",
            color : "white"
        }
    })();
    const [value, setValue] = useState("");
    function onChange(e){
        const newValue = e.target.value;
        setValue(newValue);
    }
    function addNewValue(){
        if(String(value).trim()){
            getValue(value)
            setValue("")
        }else{
            inventoryAppActions.showSnackbar(
                inventoryAlertActions.error("New Value is an empty string, add a value")
            )(dispatch);
        }
    }
    return <CardActions>
        <List style={{width : "100%"}}>
            <ListItem>
                <div>
                    <TextField
                        style={{
                            width : "90%"
                        }}
                        inputProps={{
                            width : "90%"
                        }}
                        margin="normal" 
                        variant="outlined" 
                        label="New Value"
                        placeholder="New value"
                        value={value}
                        onChange={onChange}
                        />
                </div>
                <ListItemSecondaryAction>
                    <IconButton onClick={addNewValue} {...iconButtonProps}>
                        <Add className={classes.icon}/>
                    </IconButton>
                </ListItemSecondaryAction>
            </ListItem>
        </List>
    </CardActions>
}