import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {Link} from 'react-router-dom';
import classNames from 'classnames';
import {withStyles} from '@material-ui/core/styles';
import { Paper, IconButton } from '@material-ui/core';
import { ArrowDownwardOutlined, Edit } from "@material-ui/icons";
import { routeNamesInventory } from '../../../../routeNames';
import { inventoryUtil } from '../../../../../../Inventory/utils';

const style = theme => ({
    root: {
        position : "relative",
        display : "flex",
        flexDirection : "column",
        justifyContent : "center",
        alignItems : "center",
        padding : 10,
    },
    selectable : {
        "&:hover" : {
            backgroundColor : inventoryUtil.getTheme().background
        }
    },
    selected : {
        backgroundColor : inventoryUtil.getTheme().primary
    },
    package : {
        margin : 5,
        border : "solid 2px " + inventoryUtil.getTheme().background,
        borderRadius : 10,
        padding : 10,
        fontSize : 12,
    },
    productStyle : {
        backgroundColor : inventoryUtil.getTheme().secondary,
        color : inventoryUtil.getTheme().white,
        fontSize : 12,
    },
    editBtn : {
        position : "absolute",
        right : 5,
        top : 5,
    },
})
class _PackagingDisplay extends Component {
    onClick(){
        const {onEdit, packaging} = this.props;
        if(onEdit) onEdit(packaging)
    }
    onSelectPackaging(e){
        const {packaging, onSelectCallback} = this.props;
        if(onSelectCallback) onSelectCallback(packaging);
    }
    render() {
        const {classes, editable, packages, packaging, canSeeList, selectable, selected} = this.props;
        return (
            <Paper className={classNames(
                classes.root, 
                selectable && !selected && classes.selectable,
                selected && classes.selected
            )}
            onClick={this.onSelectPackaging.bind(this)}>
                {editable && <IconButton className={classes.editBtn} onClick={this.onClick.bind(this)}>
                    <Edit fontSize="small"/>
                </IconButton>}
                {packaging && packaging.packageIds && packaging.packageIds.map(
                    (packageId, index) => {
                        let pack;
                        if(packages){
                            pack = packages.find(item=>item._id === packageId);
                        }
                        return pack ?
                            <Fragment key={index}>
                                <div className={classes.package}>{pack.name}</div>
                                <ArrowDownwardOutlined color="secondary"/>
                            </Fragment>:
                            null;
                    }
                )}
                <div className={classNames(classes.package, classes.productStyle)}>
                        product</div>
                {canSeeList && packaging && packaging.packageIds && packaging.packageIds.length !== 0 &&
                    <div><Link 
                        to={{pathname : routeNamesInventory.packagingItems_ + packaging._id}}
                        style={{fontSize : 11}}>See items</Link> </div>}
            </Paper>
        );
    }
}


_PackagingDisplay.propTypes = {
    classes : PropTypes.object.isRequired,
    packages : PropTypes.array,
    packaging : PropTypes.object,
    editable : PropTypes.bool,
    onEdit : PropTypes.func,
    canSeeList : PropTypes.bool,
    selectable : PropTypes.bool,
    selected : PropTypes.bool,
    onSelectCallback : PropTypes.func,
};


export const INVPackagingDisplay = connect()(withStyles(style)(_PackagingDisplay));
export {INVPackagingDisplay as default}