import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, mainStageHeaderAction, 
    mainStageHeaderStrings, MyTable, history
} from "../../utils";
import { routeNamesInventory } from '../../routeNames';
import { invProductActions } from '../actions';
import { invProductStrings } from '../config';
import { TableCell } from '@material-ui/core';


const style = theme => ({
    root: {
        marginTop : 20,
    },
    cell : {
        padding : 5
    }
})
class _Items extends Component {
    constructor(props) {
        super(props);
        this.state = {
            rows : null,
            lastId : null
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "PRODUCTS",
            [headerStrings.backButtonAction] : null
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesInventory.dashboard},
            {name : "Products", path : routeNamesInventory.items},
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.buttons] : [
                {value : "New Item", onClick : ()=>history.push(routeNamesInventory.newItem)}
            ]
        })(dispatch);
    }
    componentDidMount(){
        const {
            dispatch,
            [invProductStrings.itemForms] : itemForms,
        } = this.props;
        const {rows, lastId} = this.state;
        invProductActions.getproductItemsBrief_NO_DISPATCH(
            lastId, rows, (done, result, message)=>{
                if(done) this.setState({productItems : result});
            }
        );
        if(!itemForms) invProductActions.getItemForms()(dispatch);
    }
    cellMapFormat = ({row, cellMap})=>{
        const {
            classes,
            [invProductStrings.itemForms] :itemForms
        } = this.props;
        switch(cellMap){
            case "stockInfo" : return <TableCell className={classes.name}>
                {row[cellMap] ? Number(row[cellMap].totalStock).toLocaleString() : null}
            </TableCell>
            case "supplier" : 
                return <TableCell className={classes.cell}>
                    {row[cellMap] && row[cellMap].name}
                </TableCell>
            case "formId" : 
                const {item} = itemForms.getFirstObjectByPropValue("_id", row[cellMap]) || {};
                return <TableCell className={classes.cell}>{item ? item.name : null}</TableCell>
            default : return <TableCell className={classes.cell}>
                {row[cellMap]}
            </TableCell>
        }
    }
    render() {
        const {
            classes,
        } = this.props;
        const {productItems} = this.state;
        console.log(productItems)
        return (
            <div className={classes.root}>
                <MyTable
                    header={["ID", "Name", "Form", "Brand", "Category", "Supplier", "Stock"]}
                    dataMap={["_id", "name", "formId", "brand", "category", "supplier", "stockInfo"]}
                    data={productItems}
                    CellMap={this.cellMapFormat.bind(this)}
                    rowAction={row=>()=>history.push(routeNamesInventory.item_+row._id, row)}/>
            </div>
        );
    }
}


_Items.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({invProductReducer}) => ({
    [invProductStrings.itemForms] : invProductReducer[invProductStrings.itemForms],
    [invProductStrings.stockCategories] : invProductReducer[invProductStrings.stockCategories],
})


export const Items = connect(mapStateToProps)(withStyles(style)(_Items));
export {Items as default}