import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { TextParagraphEditableCard, TextFieldEditableCard } from '../../../includes';
import { agroAdminUtil } from '../../utils';
const style = theme => ({
    root: {
        
    },
    title : {
        fontWeigth : "bold",
        color : agroAdminUtil.getTheme().secondary
    }
})
class _ContentControl extends Component {
    onChange(e){

    }
    render() {
        const {classes, value, name} = this.props;
        return (
            <div className={classes.root}>
                {value && 
                    (typeof value === "string" ?
                    <TextFieldEditableCard {...this.props}/>:
                    <TextParagraphEditableCard
                    {...this.props}/>)}
            </div>
        );
    }
}
_ContentControl.propTypes = {
    classes : PropTypes.object.isRequired,
    _id : PropTypes.number,
    name : PropTypes.string,
    value : PropTypes.oneOfType([PropTypes.string,PropTypes.array]),
};
export const ContentControl = withStyles(style)(_ContentControl);