import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { FormDisplay } from '../../../includes';
import { HIRPrimaryButton, HIRButton } from '../../Includes/Buttons';
import { getFormDisplayData } from '../../../includes/Forms/FormDisplay/functions';
import { appActions, alertAction } from '../../../../actions';
import { CircularProgress } from '@material-ui/core';
import {patientNameMapper} from '../patientNameMapper';

const style = theme => ({
    root: {
    }
})
class _HIRNewPatient extends Component {
    constructor(props) {
        super(props);
        this.state = {
            loading : false
        }
        const required = true;
        this.formConfig = [
            {name : "lastName", label : "Last Name", placeholder : "Last name", required : true},
            {name : "firstName", label : "First Name", placeholder : "First name", required : true},
            {name : "middleName", label : "Middle Name", placeholder : "Middle name", },
            {name : "gender", label : "Gender", type : 'radio', options : [
                {_id : "m", name : "Male"},
                {_id : "f", name : "Female"},
            ], required : true },
            {name : "oldId", label : "Old Card Number", placeholder : "Old Card Number"},
            {name : "occupation", label : "Occupation", placeholder : "Occupation"},
            {name : "dob", label : "Date of Birth", placeholder : "Date of birth", type : "date", required : true},
            {name : "address", label : "Address", placeholder : "Address", type : "textarea", required : true},
            {name : "email", label : "Email", placeholder : "Email"},
            {name : "phone", label : "Phone", placeholder : "Phone"},
            {name : "nextOfKin", label : "Next of kin", placeholder : "Next of kin"},
            {name : "nextOfKinAddress", label : "Address (Next of kin)", placeholder : "Address"},
            {name : "nextOfKinPhone", label : "Phone (Next of kin)", placeholder : "Phone"}
        ]
    }
    formCreatOnClick(){
        this.setState({loading : true});
        const {dispatch, createRecord, editRecord, edit} = this.props;
        const data = getFormDisplayData(this.formDisplayContex, (name, value, context)=>{
            if(["lastName", "firstName", "middleName", "dob", "phone", "gender"].indexOf(name) !== -1 &&
            !String(value).trim()){
                appActions.showSnackbar(
                    alertAction.error(patientNameMapper(name) + " can not be emepty")
                )(dispatch);
                return false;
            }
            if(name === "dob"){
                if(new Date().getFullYear() < new Date(value).getFullYear()){
                    appActions.showSnackbar(
                        alertAction.error(patientNameMapper(name) + " can not be in future")
                    )(dispatch);
                    return false;
                }
            }
            return true;
        })()
        if(data){
            if(edit && editRecord) editRecord(data, this);
            else if(createRecord) createRecord(data, this);
        }
        else this.setState({loading : false});
    }
    
    render() {
        const {classes, edit, data} = this.props;
        const {loading} = this.state;
        return (
            <div className={classes.root}>
                <FormDisplay
                    formName="newPatientForm"
                    getContext={context=>this.formDisplayContex = context}
                    header="New Patient"
                    formConfig={this.formConfig}
                    formData={data}
                    footer={()=>{

                        return <HIRButton
                            disabled={loading}
                            type="primary"
                            onClick={this.formCreatOnClick.bind(this)}>
                                {loading && <CircularProgress style={{color : "white"}} size={25}/>} 
                                {edit ? "Edit" : "Create"} Record
                            </HIRButton>
                    }}
                    />
            </div>
        );
    }
}


_HIRNewPatient.propTypes = {
    classes : PropTypes.object.isRequired,
    createRecord : PropTypes.func,
    editRecord : PropTypes.func,
    edit : PropTypes.bool,
    data : PropTypes.object,

};
const mapStateToProps = state => ({
    state
})


export const HIRNewPatient = connect(mapStateToProps)(withStyles(style)(_HIRNewPatient));
export {HIRNewPatient as default}