import React from 'react';
import { hirRouteNames } from './routeNames';

const HIRDashboard = React.lazy(()=>import("./HIRDashboard/HIRDashboard"));
const HIRAccounts = React.lazy(()=>import("./HIRAccounts/HIRAccounts"));
const HIRAccountViewPaymentDetail = React.lazy(()=>import("./HIRAccounts/HIRViewPaymentDetail/HIRViewPaymentDetail"));
const HIRPatients = React.lazy(()=>import("./HIRPatients/HIRPatients"));
const HIRFamilies = React.lazy(()=>import("./HIRFamilies/HIRFamilies"));
const HIRFamilyView = React.lazy(()=>import("./HIRFamilies/HIRFamilyView/HIRFamilyView"));
const HIRPatientView = React.lazy(()=>import("./HIRPatients/HIRPatientView/HIRPatientView"));
const HIRAppointments = React.lazy(()=>import("./HIRAppointments/HIRAppointments"));
const HIRSettings= React.lazy(()=>import("./HIRSettings/HIRSettings"));
const HIRUsers= React.lazy(()=>import("./HIRUsers/HIRUsers"));


export const hirRoutes = [
    {path : hirRouteNames.dashboard, exact : true, component : HIRDashboard},
    {path : hirRouteNames.account, exact : true, component : HIRAccounts},
    {path : hirRouteNames.accountViewPaymentDetail, exact : true, component : HIRAccountViewPaymentDetail},
    {path : hirRouteNames.families, exact : true, component : HIRFamilies},
    {path : hirRouteNames.familiesView, exact : true, component : HIRFamilyView},
    {path : hirRouteNames.patients, exact : true, component : HIRPatients},
    {path : hirRouteNames.patientView, exact : true, component : HIRPatientView},
    {path : hirRouteNames.appointments, exact : true, component : HIRAppointments},
    {path : hirRouteNames.settings, exact : true, component : HIRSettings},
    {path : hirRouteNames.users, exact : true, component : HIRUsers},
]