import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyCustomTabs, headerActions, headerStrings, breadCrumbActions } from "../../utils";
import { INVTags } from "./INVTags";
import { INVItemForms } from "./INVItemForms";
import { INVItemPackages } from './INVItemPackages';
import { routeNamesInventory } from '../../routeNames';
import { INVItemDescriptions } from './INVItemDescriptions';
import INVItemPackaging from './INVItemPackaging/INVItemPackaging';
import { INVProductCategories } from './INVProductCategories';
import INVDrugGenericNames from './INVDrugGenericNames/INVDrugGenericNames';


const style = theme => ({
    root: {
    }
})
class _INVItemConfiguration extends Component {
    constructor(props) {
        super(props);
        this.state = {
            tabValue : null
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "PRODUCT CONFIGURATION",
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesInventory.dashboard},
            {name : "Product Configuration", path : routeNamesInventory.productConfig},
        ])(dispatch);

    }
    render() {
        const {classes} = this.props;
        const {tabValue} = this.state;
        return (
            <div className={classes.root}>
                <MyCustomTabs
                    position="sticky"
                    tabs={{
                        drugs : "Drug Active Ingredients",
                        description : "Descriptions",
                        categories : "Categories",
                        forms : "Forms",
                        packages : "Packages",
                        itemPackaging : "Item Packaging",
                        tags : "Tags",
                    }}
                    getInitialTabValue={tabValue => this.setState({tabValue})}
                    />
                <div style={{marginTop : 20}}>
                    {tabValue === "categories" && <INVProductCategories/>}
                    {tabValue === "drugs" && <INVDrugGenericNames/>}
                    {tabValue === "tags" && <INVTags/>}
                    {tabValue === "forms" && <INVItemForms/>}
                    {tabValue === "packages" && <INVItemPackages/>}
                    {tabValue === "itemPackaging" && <INVItemPackaging/>}
                    {tabValue === "description" && <INVItemDescriptions/>}
                </div>
            </div>
        );
    }
}


_INVItemConfiguration.propTypes = {
    classes : PropTypes.object.isRequired
};
export const INVItemConfiguration = connect()(withStyles(style)(_INVItemConfiguration));
export {INVItemConfiguration as default}