import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {Link} from "react-router-dom";
import {withStyles} from '@material-ui/core/styles';
import { Card, CardHeader, Typography, CardMedia, CardContent, Button, CardActions } from '@material-ui/core';
import { insureUtil } from '../../utils';
const style = theme => ({
    root: {
        display : "flex",
        flexDirection : "column",
        textAlign : "center", 
        marginTop : 50,
        padding : 10,
    },
    headerText : {
        fontWeight : "bold",
        marginBottom : 50,
        fontSize : 13,
    },
    headerContent : {
        height : "1cm"
    },
    card : {
        margin : 5,
    },
    cardHeaderText : {
        backgroundColor : insureUtil.getTheme().primary,
    },
    view : {
        backgroundColor : insureUtil.getTheme().secondary,
        color : insureUtil.getTheme().white,
        textDecoration : "none",
        padding : 10,
        borderRadius : 5,
        fontSize : 11,
    },
    content : {
        height : "1.5cm",
        fontSize : 11,
    }
})
class _ServiceCard extends Component {
    render() {
        const {classes, header, src, body, status, baseUrl, summary, toUrl} = this.props;
        return (
            <Card className={classes.card}>
                <CardHeader
                    classes={{
                        content : classes.headerContent  
                    }}
                    titleTypographyProps={{
                        className : classes.headerText
                    }} title={header}/>
                <CardMedia 
                    style={{height : 200}}
                    image={baseUrl ? baseUrl+src : src}/>
                <CardContent className={classes.content}>
                    {summary ? summary : body && body[0]}
                </CardContent>
                <CardActions>
                    <Link className={classes.view} to={toUrl}>View</Link>
                </CardActions>
            </Card>
        );
    }
}
_ServiceCard.propTypes = {
    classes : PropTypes.object.isRequired,    
    header : PropTypes.string,
    src : PropTypes.string,
    body : PropTypes.array,
    status : PropTypes.string,
    baseUrl : PropTypes.string,
    toUrl : PropTypes.oneOfType([PropTypes.object, PropTypes.string])
};
export const ServiceCard = withStyles(style)(_ServiceCard);