import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { StageHeaderPlane, MyTable } from '../../../../utils';
import { invProductStrings } from '../../../config';
import { invProductActions } from '../../../actions';


const style = theme => ({
    root: {
    }
})
class _INVDrugNameSelection extends Component {
    constructor(props) {
        super(props);
        this.state={
            selectedDrugs : []
        }
        const {getContext} = props;
        if(getContext) getContext(this);
    }
    componentDidMount() {
        const {
            dispatch,
            [invProductStrings.drugNames] : drugNames
        } = this.props;
        if(!drugNames) invProductActions.getDrugNames()(dispatch);
    }
    searchActions(keyword){
        
    }
    rowAction = drugName => () => {
        const {onSelection, drugNames} = this.props;
        const {selectedDrugs} = this.state;
        if(!drugNames.find(item=>item._id === drugName._id)){
            selectedDrugs.push(drugName);
        }
        if(onSelection) onSelection(drugName);
    }
    render() {
        const {classes, [invProductStrings.drugNames] : drugNames} = this.props;
        const {selectedDrugs, keyword} = this.state;
        let drugSearchResult;
        if(drugNames && String(keyword).trim()){
            drugSearchResult = drugNames.map(item=>String(item.name).includes(keyword) && item);
        }
        return (
            <div className={classes.root}>
                
                <div className={classes.selectedNamesContainer}>
                    
                </div>
                <div className={classes.searchContainer}>
                    <StageHeaderPlane
                        visible={true}
                        searchActions={this.searchActions.bind(this)}
                        />
                </div>
                <div>
                    <MyTable
                        header={["ID", "Drug Name", "Description"]}
                        dataMap={["_id", "name", "description"]}
                        data={drugSearchResult}
                        rowAction={this.rowAction.bind(this)}
                        />
                </div>
            </div>
        );
    }
}


_INVDrugNameSelection.propTypes = {
    classes : PropTypes.object.isRequired,
    onSelection : PropTypes.func,
    getContext : PropTypes.func,
};
const mapStateToProps = ({invProductReducer}) => ({
    [invProductStrings.drugNames] : invProductReducer[invProductStrings.drugNames],
})


export const INVDrugNameSelection = connect(mapStateToProps)(withStyles(style)(_INVDrugNameSelection));
export {INVDrugNameSelection as default};