export const priceListStrings = {
    pricelists : "pricelists",
    pricelistItems : "pricelistItems",
    stockCategories : "pricelist_stockCategories",
    itemPackages : "pricelist_itemPackage",
    selectedPriceListItems : "selectedPriceListItems",
}

export const priceListConstants = {
    SET_PRICE_LIST : "SET_PRICE_LIST",
}
export const priceListReducer = (state={}, action) => {
    const {type, payload} = action;
    switch(type){
        case priceListConstants.SET_PRICE_LIST : 
            return {...state, ...payload};
        default : return {...state};
    }
}
export * from './actions';
export * from './services';