import React, {Fragment} from 'react';
import {Redirect, Route} from 'react-router-dom';
import {inventoryUtil, inventoryActions, Screen} from  './utils';
import { routeNamesInventory } from './routeNames';


export const PrivateRoutePlane = ({component : Component, ...props}) => (
    <Route {...props} render={props => { 
        return (
            //inventoryUtil.isLogedIn()
            true ? 
            <Fragment>
                <Screen {...props} component={Component}/>
            </Fragment>
            : <Redirect to={{ pathname: routeNamesInventory.login, state: { from: props.location } }} />
        )}
    } />
);
export const LogoutRoute = rest =>(
    <Route {...rest} render={props=>{
        inventoryActions.logout();
        return <Redirect to={{ pathname: routeNamesInventory.login, state: { from: props.location } }}/> 
    }}/>
)