export const agroUtilStrings = {
    theme : "theme",
    tokenAlias : "tokenAlias",
    userAlias : "userAlias",
    backendUrl : "backendUrl",
    myProfile : "myProfile",
    trackingMe : "trackingMe",
    disableAllTracking : "disableAllTracking",
}

export const agroUtilConstants = {
    SET_UTIL : "SET_UTIL",
}

export const agroUtilReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case agroUtilConstants.SET_UTIL : 
            return {...state, ...payload};
        default : return {...state};
    }
}

