import { hirUtil } from "../utils";
const {post, fetchGet, fetchPost} = hirUtil;

const owner = "1";

export const hirPatientServices = {
    migratePatientData : (patients, callback) => {
        post({patients}, owner, "migratePatientData", ({migratePatientData, result, message})=>{
            callback(migratePatientData, result, message);
        })
    },
    getPatientsByIds : (patientIds, callback) => {
        post({patientIds}, owner, "getPatientsByIds", ({getPatientsByIds, result, message})=>{
            callback(getPatientsByIds, result, message);
        })
    },
    getPatientsByOldIds : (patientIds, callback) => {
        post({patientIds}, owner, "getPatientsByOldIds", ({getPatientsByOldIds, result, message})=>{
            callback(getPatientsByOldIds, result, message);
        })
    },
    getSearchMinMaxPatientId : (keyword, callback) => {
        fetchGet(owner, "getSearchMinMaxPatientId", {keyword}, ({getSearchMinMaxPatientId, result, message})=>{
            callback(getSearchMinMaxPatientId, result, message);
        })
    },
    searchPatient : (keyword, rows, skip, callback) =>{
        fetchGet(owner, "searchPatient", {keyword, rows, skip}, ({searchPatient, result, message})=>{
            callback(searchPatient, result, message);
        })
    },
    getPatientPayments : (patientId, callback) => {
        fetchGet(owner, "getPatientPayments", {patientId}, ({getPatientPayments, result, message})=>{
            callback(getPatientPayments, result, message);
        });
    },
    getPatientAppointments : (patientId, callback) => {
        fetchGet(owner, "getPatientAppointments", {patientId}, ({getPatientAppointments, result, message})=>{
            callback(getPatientAppointments, result, message);
        })
    },
    getAPatient : (patientId, callback) => {
        fetchGet(owner, "getAPatient", {patientId}, ({getAPatient, result, message})=>{
            callback(getAPatient, result, message);
        })
    },
    editRecord : (patientId, data, callback) => {
        post({patientId, data}, owner, "editRecord", ({editRecord, result, message})=>{
            callback(editRecord, result, message);
        })
    },
    createRecord : (data, callback) => {
        post(data, owner, "createRecord", ({createRecord, result, message})=>{
            callback(createRecord, result, message);
        })
    },
    getPatients : (rows, skip, callback)=> {
        fetchGet(owner, "getPatients", {rows, skip}, ({getPatients, result, message})=>{
            callback(getPatients, result, message);
        })
    },
    getRecentVisitedPatientByDate : (year, month, day, limit, callback) => {
        post({year, month, day, limit}, owner, "getRecentVisitedPatientByDate", ({getRecentVisitedPatientByDate, result, message})=>{
            callback(getRecentVisitedPatientByDate, result, message);
        })
    },
    getMaxMinPatientIds : callback => {
        fetchGet(owner, "getMaxMinPatientIds", {}, ({getMaxMinPatientIds, minId, maxId, message})=>{
            callback(getMaxMinPatientIds, minId, maxId, message);
        })
    }
}