import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Avatar, Typography } from '@material-ui/core';
import { trackerUtil } from '../../../utils';
import { contactStrings } from '../../config';


const style = theme => ({
    root: {
        backgroundColor : trackerUtil.getTheme().primary,
        display : "flex",
        flexDirection : "column",
        justifyContent : "center",
        alignItems : "center",
        height : 210,
        padding : 20,
    },
    avatar : {
        height : 150,
        width : 150,
    },
    name : {
        marginTop : 20,
        color : trackerUtil.getTheme().backgroundTypo
    }
})
class _InfoBox extends Component {
    render() {
        const {classes, 
            [contactStrings.contacts] : contacts,
            [contactStrings.contactId] : contactId
        } = this.props;
        console.log(this.props);
        const contact = contacts ? contacts.find(item => item._id === contactId) : null;
        return (
            <div className={classes.root}>
                <Avatar src="/images/laughing_boy.jpg" className={classes.avatar}/>
                <Typography paragraph className={classes.name}>{contact && contact.name}</Typography>
            </div>
        );
    }
}


_InfoBox.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({contactReducer}) => ({
    [contactStrings.contactId] : contactReducer[contactStrings.contactId],
    [contactStrings.contacts] : contactReducer[contactStrings.contacts],
})


export const InfoBox = connect(mapStateToProps)(withStyles(style)(_InfoBox));
export {InfoBox as default}