import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { StageHeaderPlane, HighlightedInfo, mainStageHeaderStrings, SimplePagination } from '../../../includes';
import HIRPatientList from '../HIRPatientList/HIRPatientList';
import { hirPatientActions } from '../actions';
import { appActions, alertAction } from '../../../../actions';


const style = theme => ({
    root: {
    },
    pageBtn : {
        textTransform : "lowercase",
        fontSize : 11,
        padding : 10,
        borderRadius : 20,
    },
    pagePrevBtn : {
        backgroundColor : theme.colors.secondary
    },
    pageNextBtn : {
        backgroundColor : theme.colors.primary,
    },
})
class _HIRFindPatient extends Component {
    state = {
        minId : null, 
        maxId : null, 
        skip : 0,
        rows : 100,
        keyword : "",
    }
    searchAction=(keyword, searchContext)=>{
        const{dispatch}=this.props;
        if(!String(keyword).trim()) {
            appActions.showSnackbar(
                alertAction.error("Can't search with empty string")
            )(dispatch);
            return;
        }
        hirPatientActions.getSearchMinMaxPatientId(keyword, (done, {maxId, minId}, message)=>{
            if(done) this.setState({minId, maxId});
        })
        this.setState({keyword});
        this.searchPatients(keyword, true);
    }
    searchPatients(keyword, start, nav){
        const {dispatch} = this.props;
        const {rows, skip} = this.state;
        let newSkip;
        if(start){
            newSkip = 0;
        }else{
            const prevSkip = skip - rows;
            const nextSkip = skip + rows;
            newSkip = nav === "backward" ? prevSkip : nextSkip
        }
        hirPatientActions.searchPatient(
            keyword, rows, newSkip, 
            (done, result, message)=>{
                if(done){
                    this.setState({skip : newSkip, searchPatients : result})
                    this.configurePagination(result);
                }
        })(dispatch);
    }
    configurePagination(result){
        if(result.length !== 0){
            const newLastId = result[result.length - 1]._id;
            const newFirstId = result[0]._id;
            this.setState({lastId : newLastId, firstId : newFirstId})
        }
    }
    pageNextBtnClick(){
        const {keyword} = this.state;
        this.searchPatients(keyword, false);
    }
    pagePrevBtnClick(){
        const {keyword} = this.state;
        this.searchPatients(keyword, false, "backward");
    }
    render() {
        const {classes} = this.props;
        const { minId, skip, rows, lastId, searchPatients} = this.state;
        return (
            <div className={classes.root}>
                <HighlightedInfo>
                    Search for patient by name or hospital number
                </HighlightedInfo>
                <div style={{marginBottom : 20}}>
                    <StageHeaderPlane
                        visible={true}
                        {...{[mainStageHeaderStrings.searchActions] : this.searchAction.bind(this)}}
                        />
                    <HIRPatientList
                        patients={searchPatients}
                        {...this.props.patientListProps}
                        />
                        <SimplePagination
                            classes={{
                                btn : classes.pageBtn,
                                prevBtn : classes.pagePrevBtn,
                                nextBtn : classes.pageNextBtn,
                                root : classes.pageRoot
                            }}
                            prevBtnProps={{
                                disabled : skip === 0
                            }}
                            nextBtnProps={{
                                disabled : !searchPatients || searchPatients.length < rows || minId === lastId
                            }}
                            prevBtnClick={this.pagePrevBtnClick.bind(this)}
                            nextBtnClick={this.pageNextBtnClick.bind(this)}/>
                </div>
            </div>
        );
    }
}


_HIRFindPatient.propTypes = {
    classes : PropTypes.object.isRequired,
    // patients : PropTypes.array,
    searchAction : PropTypes.func,
    patientListProps : PropTypes.shape(HIRPatientList.propTypes),
};
const mapStateToProps = ({}) => ({
})


export const HIRFindPatient = connect(mapStateToProps)(withStyles(style)(_HIRFindPatient));
export {HIRFindPatient as default}