import { classConstants, classStrings } from "./config";
import { classServices } from "./services";
import { sessionServices } from "../Sessions";
import { studentServices } from "../Students/services";
import { store } from "../../../helpers";
import { timeTableServices } from "../TimeTable/config";

export const classActions = {
    setTimeTableEditeMode : mode => dispatch => dispatch({
        type : classConstants.SET_CLASS,
        payload : {
            [classStrings.timeTableEditMode] : mode
        }
    }),
    getTimeTableDurationFormat : (levelId, termId, callback) => dispatch =>{
        timeTableServices.getTimeTableDurationFormat(levelId, termId, (done, result, message)=>{
            if(done) dispatch({
                type : classConstants.SET_CLASS,
                payload : {
                    [classStrings.timeTableDurationFormat] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getClassTimeTable: (levelId, classId, termId, callback) => dispatch => {
        classServices.getClassTimeTable(levelId, classId, termId, (done, result, message)=>{
            if(done)dispatch({
                type : classConstants.SET_CLASS,
                payload : {
                    [classStrings.classTimetable] : result
                }
            });
            if(callback)callback(done, result, message);
        });
    },
    getClassStudentsAndAssessments : (levelId, classId, termId, callback)=>dispatch=>{
        classServices.getClassStudentsAndAssessments(
            classId, levelId, termId, 
            (done, result, message)=>{
                if(done) dispatch({
                    type : classConstants.SET_CLASS,
                    payload : {
                        [classStrings.classStudents] : result,
                    }
                })
            }
        )
    },
    setSelectedClass : selectedClass => dispatch => dispatch({
        type : classConstants.SET_CLASS,
        payload : {
            [classStrings.selectedClass] : selectedClass
        }
    }),
    getTerms : (levelId, callback)=>dispatch=>{
        sessionServices.getSessionTerms(null, (done, result, message)=>{
            if(done) dispatch({
                type : classConstants.SET_CLASS,
                payload : {
                    [classStrings.terms] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    setSelectedTerm : (term) => dispatch => dispatch({
        type : classConstants.SET_CLASS,
        payload : {
            [classStrings.selectedTerm] : term
        }
    }),
    getSubjectsAndAssessments : (levelId, termId, callback)=>dispatch => {
        studentServices.getSubjectsAndAssessments(levelId, termId, (done, result, message)=>{
            if(done) {
                let subjAss = store.getState().classReducer[classStrings.subjectsAndAssessments];
                if(subjAss) subjAss = {...subjAss, [termId] : result};
                else subjAss = {[termId] : result};
                dispatch({
                    type : classConstants.SET_CLASS,
                    payload : {
                        [classStrings.subjectsAndAssessments] : subjAss
                    }
                });
            }
            if(callback) callback(done, result, message);
        })
    },
    setListEditMode : mode => dispatch => dispatch({
        type : classConstants.SET_CLASS,
        payload : {
            [classStrings.listEditMode] : mode
        }
    }),
    getLevelClasses : (levelId, callback) => dispatch => {
        sessionServices.getClasses(levelId, (done, result, message)=>{
            if(done)dispatch({
                type : classConstants.SET_CLASS,
                payload : {
                    [classStrings.classes] : result
                }
            })
            if(callback) callback(done, result, message);
        })
    },
    setSelectedLevel : selectedLevel => dispatch => dispatch({
        type : classConstants.SET_CLASS,
        payload : {
            [classStrings.selectedLevel] : selectedLevel
        }
    }),
    cleanup : () => dispatch => dispatch({
        type : classConstants.SET_CLASS_CLEAN_UP
    })
}