import { hirPatientServices } from "./services"
import { hirPatientStrings, hirPatientConstants } from "./config";
import { hirAppointmentServices } from "../HIRAppointments/config"
import { hirAccountServices } from "../HIRAccounts"
import { hirFamilyServices } from "../HIRFamilies/config";
import { hirErrorNotice as errorNotice, hirSuccessNotice as successNotice } from "../utils";

export const hirPatientActions = {
    getFamily : (familyId, callback) => dispatch => {
        hirFamilyServices.getAFamily(familyId, (done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getPatientYearlyAppointments : (patientId, year, callback) =>dispatch => {
        return new Promise((resolve, reject)=>{
            hirAppointmentServices.getPatientYearlyAppointments(patientId, year, (done, result, message)=>{
                if(!done){
                    errorNotice(message, dispatch);
                    reject(message);
                }else{
                    resolve(result);
                }
                if(callback) callback(done, result, message);
            })
        });
    },
    getPatientYearlyPayments : (patientId, year, callback) => dispatch => {
        return new Promise((resolve, reject)=>{
            hirAccountServices.getPatientYearlyPayments(patientId, year, (done, result, message)=>{
                if(!done) {
                    errorNotice(message, dispatch);
                    reject(message);
                }else {
                    resolve(result);
                }
                if(callback) callback(done, result, message);
            })
        })
        
    },
    updatePayment : (patientId, paymentId, data, callback) => dispatch => {
        hirAccountServices.updatePayment(paymentId, data, (done, result, message)=>{
            if(done){
                successNotice(message, dispatch);
                hirPatientActions.getPatientPayments(patientId)(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    deletePayment : (patientId, paymentId, groupId, callback) => dispatch => {
        hirAccountServices.deletePayment(paymentId, groupId, (done, result, message)=>{
            if(done){
                successNotice(message, dispatch);
                hirPatientActions.getPatientPayments(patientId)(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result,message);
        })
    },
    deleteAppointment : (patientId, appointmentId, callback)=>dispatch=>{
        hirAppointmentServices.deleteAppointment(appointmentId, (done, result, message)=>{
            if(done) {
                successNotice(message, dispatch);
                hirPatientActions.getPatientAppointments(patientId)(dispatch);
            }
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    migratePatientData : (patients, callback)=>dispatch => {
        hirPatientServices.migratePatientData(patients, (done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getPatientsByIdsForVerification : (patientIds, callback) => dispatch => {
        hirPatientServices.getPatientsByOldIds(patientIds, (done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        });
    },
    getSearchMinMaxPatientId : (keyword, callback) => {
        hirPatientServices.getSearchMinMaxPatientId(keyword, callback);
    },
    searchPatient : (keyword, rows, skip,  callback) => dispatch => {
        hirPatientServices.searchPatient(keyword, rows, skip, (done, result, message)=>{
            if(done){
                // hirPatientActions.payload({
                //     [hirPatientStrings.patients] : result
                // })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getPatientPayments : (patientId, callback) => dispatch => {
        hirPatientServices.getPatientPayments(patientId, (done, result, message)=>{
            if(done){
                hirPatientActions.payload({
                    [hirPatientStrings.patientPayments] : {[patientId] : result}
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    postPayment : (patientId, data, callback) => dispatch => {
        hirAccountServices.postPayment({patientId, data}, (done, result, message)=>{
            if(done){
                successNotice(message, dispatch);
                hirPatientActions.getPatientPayments(patientId)(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getPatientAppointments : (patientId, callback) => dispatch => {
        hirPatientServices.getPatientAppointments(patientId, (done, result, message)=>{
            if(done){
                hirPatientActions.payload({
                    [hirPatientStrings.patientAppointments] : {[patientId] : result}
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    bookPatientAppointment : (data, callback) => dispatch => {
        hirAppointmentServices.bookAppointment(data, (done, result, message)=>{
            if(done){
                hirPatientActions.getPatientAppointments(data.patientId)(dispatch);
                successNotice(message, dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    editRecord : (patientId, data, callback) => dispatch => {
        hirPatientServices.editRecord(patientId, data, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    createRecord : (data, callback) => dispatch => {
        hirPatientServices.createRecord(data, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, message);
            if(callback) callback(done, result, message);
        })
    },
    getAPatient : (patientId, callback)=>dispatch=>{
        hirPatientServices.getAPatient(patientId, (done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getRecentVisitedPatientByDate : (year, month, day, limit, callback) => dispatch => {
        hirPatientServices.getRecentVisitedPatientByDate(year, month, day, limit, (done, result, message)=>{
            if(done) hirPatientActions.payload({
                [hirPatientStrings.recentVisitPatients] : result
            })(dispatch) ;
            if(callback) callback(done, result, message);
        })
    },
    getPatients : (rows, skip, callback) => dispatch => {
        hirPatientServices.getPatients(rows, skip, (done, result, message, minId, maxId)=>{
            if(done) hirPatientActions.payload({
                [hirPatientStrings.patients] : result,
            })(dispatch);
            if(callback) callback(done, result, message, minId, maxId);
        })
    },
    getMaxMinPatientIds : callback => {
        hirPatientServices.getMaxMinPatientIds(callback);
    },
    payload : payload => dispatch => dispatch({
        type : hirPatientConstants.SET_HIR_PATIENTS,
        payload
    })
}