import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {Link} from "react-router-dom";
import {withStyles} from '@material-ui/core/styles';
import { Typography, IconButton, Popover, List, ListItem, ListItemText } from '@material-ui/core';
import { insureRouteNames } from '../../routeNames';
import { insureUtil, insureUtilStrings, insureUtilActions, insureActions } from '../../utils';
import { AccountBox, AccountCircle } from '@material-ui/icons';
import { history } from '../../../../helpers';


const style = theme => ({
    root: {
    },
    name : {
        fontFamily : "fantasy",
        fontWeight : 800,
    }
})
class _RightHeaderComponent extends Component {
    constructor(props) {
        super(props);
        this.state = {
            anchorEl : null
        }
    }
    componentDidMount() {
        const {
            dispatch,
            [insureUtilStrings.myProfile] : myProfile
        } = this.props;
        if(!myProfile){
            insureActions.getUser()(dispatch);
        }
    }
    
    render() {
        const {
            classes,
            [insureUtilStrings.myProfile] : myProfile,
            [insureUtilStrings.isLoggedIn] : isLoggedIn,
        } = this.props;
        const {anchorEl} = this.state;
        return (
            <div className={classes.root}>
                { isLoggedIn ? 
                    <div>
                        <IconButton onClick={(e)=>this.setState({anchorEl : e.currentTarget})}>
                            <AccountCircle/>
                        </IconButton>
                        <Popover 
                            open={Boolean(anchorEl)}
                            anchorEl={anchorEl}
                            onClose={()=>this.setState({anchorEl : null})}
                            anchorOrigin={{
                                vertical : "bottom",
                                horizontal : "right",
                            }}>
                                <div>
                                    <div style={{
                                        padding : 50,
                                        backgroundColor : insureUtil.getTheme().secondary,
                                        color : insureUtil.getTheme().primary
                                    }}>
                                        <Typography component="strong" className={classes.name}>{myProfile && myProfile.name}</Typography>
                                    </div>
                                    <List>
                                        <ListItem button onClick={()=>history.push(insureRouteNames.userAccount)}>
                                            <ListItemText>My Account</ListItemText>
                                        </ListItem>
                                        <ListItem>
                                            <Link to={{pathname : insureRouteNames.logout}}>Logout</Link>
                                        </ListItem>
                                    </List>
                                </div>
                            </Popover>
                    </div> :
                    <Link to={{pathname : insureRouteNames.login, state : {}}}>login</Link>}
            </div>
        );
    }
}


_RightHeaderComponent.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({insureUtilReducer}) => ({
    [insureUtilStrings.myProfile] : insureUtilReducer[insureUtilStrings.myProfile],
    [insureUtilStrings.isLoggedIn] : insureUtilReducer[insureUtilStrings.isLoggedIn],
})


export const RightHeaderComponent = connect(mapStateToProps)(withStyles(style)(_RightHeaderComponent));
export {RightHeaderComponent as default}