import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import { Link } from 'react-router-dom';
import {withStyles} from '@material-ui/core/styles';
import { List, ListItem, ListItemIcon, Avatar, ListItemText, ListItemSecondaryAction, FormControl, Switch, IconButton, Button, FormLabel } from '@material-ui/core';
import { Done, Settings, Add } from '@material-ui/icons';
import { trackerUtil, onEnterPress, trackerUtilStrings, trackerUtilActions } from '../../utils';
import { contactStrings } from '../config';
import { contactActions } from '../actions';
import { MyDialog } from '../../../includes';
import PhoneInput from 'react-phone-number-input';
import 'react-phone-number-input/style.css'
import { appActions, alertAction } from '../../../../actions';
import { routeNamesTracker } from '../../routeNames';

const style = theme => ({
    root: {
        borderRight : "solid .1px " + trackerUtil.getTheme().secondary,
        height : "100%",
        overflow : "scroll"
    },
    icon : {
        fontSize : "bold",
        color :  trackerUtil.getTheme().secondary
    },
    text : {
        color : trackerUtil.getTheme().backgroundTypo
    },
    contactListContainer : {
        overflow : "scroll",
        flexGrow : 1
    },
    phone : {
        background : trackerUtil.getTheme().white,
        borderRadius : 5,
        border : "none"
    },
    newPhoneContact : {
        [theme.breakpoints.up("md")] : {
            // width : "40%"
        }
    }
})
class _ContactList extends Component {
    constructor(props) {
        super(props);
        this.state = {
            newContactDialog : false,
            phone : "",
            loading : false,
            disableAllTracking : null,
        }
        this.userId = parseInt(trackerUtil.getUserId());
    }
    static getDerivedStateFromProps(props, state) {
        const {
            [trackerUtilStrings.disableAllTracking] : disableAllTracking,
        } = props;
        if(!state.disableAllTracking || disableAllTracking !== state.disableAllTracking){
            ContactList.allTrackingActions(disableAllTracking, props);
            state.disableAllTracking = disableAllTracking;
        }
        return state;
    }
    componentDidMount(){
        this.getContacts();
    }
    getContacts(){
        const {dispatch} = this.props;
        contactActions.getContacts()(dispatch);
    }
    handleClick=item=>()=>{
        const {dispatch} = this.props;
        contactActions.payload({
            [contactStrings.pageDisplay] : 2,
            [contactStrings.contactId] : item._id,
        })(dispatch);
    }
    addNewContact(){
        const {
            dispatch,
            [trackerUtilStrings.myProfile] : profile
        } = this.props;
        // this.setState({loading: true});
        const {phone} = this.state;
        if(profile && profile.phone === phone){
            appActions.showSnackbar(
                alertAction.error("You can't add your number as contact")
            )(dispatch);
            return;
        }
        if(!phone.trim()){
            appActions.showSnackbar(
                alertAction.error("Empty field!")
            )(dispatch);
            return;
        }
        contactActions.addNewContact(phone, (done, result, message)=>{
            if(done){
                this.setState({loading : false, newContactDialog : false, phone : ""})
                this.getContacts();
            }
            else this.setState({loading : false, phone : ""})
        })(dispatch);
    }
    handleAllowTracking = contact => e =>{
        const checked = e.target.checked;
        const {dispatch} = this.props;
        if(checked){
            appActions.showSnackDialog(
                "This will allow "+contact.name+" to track your location.\n Do you want to continue",
                <Button 
                    onClick={this.allowTracking(contact._id)}
                    style={{color : trackerUtil.getTheme().white}} 
                    key="allow">Allow</Button>
            )(dispatch);
        }else{
            appActions.showSnackDialog(
                "This will stop "+contact.name+" from tracking your location.\n Do you want to continue",
                <Button 
                    onClick={this.stopTracking(contact._id)}
                    style={{color : trackerUtil.getTheme().white}} 
                    key="allow">Stop Tracking</Button>
            )(dispatch);
        }
    }
    stopTracking = contactId => () => {
        const {dispatch} = this.props;
        appActions.closeSnackDialog()(dispatch);
        contactActions.disableTracking(contactId)(dispatch);
    }
    allowTracking = contactId => () => {
        const {dispatch} = this.props;
        appActions.closeSnackDialog()(dispatch);
        contactActions.allowTracking(contactId)(dispatch);
    }
    handleAllTrackingSwitch(e){
        const option = e.target.checked;
        const {dispatch} = this.props;
        appActions.showSnackDialog(
            option ? 
                "This will disable all (permitted) from tracking you.\nDo you want to continue?" :
                "This will allow all those permitted to track you.\nDo you want to continue?",
            <Button 
                onClick={()=>this.disableAllTrackingActions(option)}
                style={{color : trackerUtil.getTheme().white}} 
                key="allow">Continue</Button>
        )(dispatch);
    }
    static disableAllTracking(props){
        const {
            dispatch,
            [trackerUtilStrings.trackingMe] : trackingMe
        } = props;
        this.trackingMe = trackingMe;
        trackerUtilActions({
            [trackerUtilStrings.trackingMe] : []
        })(dispatch);
    }
    static enableAllTracking(props){
        const {dispatch} = props;
        if(this.trackingMe) trackerUtilActions({
            [trackerUtilStrings.trackingMe] : this.trackingMe
        })(dispatch);
    }
    static allTrackingActions = (option, props) => option ? this.disableAllTracking(props) : this.enableAllTracking(props);
    disableAllTrackingActions(option){
        const {dispatch} = this.props;
        appActions.closeSnackDialog()(dispatch);
        ContactList.allTrackingActions(option, this.props);
        contactActions.disableAllTracking(option)(dispatch);
    }
    render() {
        const {
            classes,
            [contactStrings.contacts] : contacts,
            [trackerUtilStrings.trackingMe] : trackingMe,
            [trackerUtilStrings.disableAllTracking] : disableAllTracking,
        } = this.props;
        const { newContactDialog, phone, loading} = this.state;
        return (
            <div className={classes.root}>
                <List>
                    <ListItem divider>
                        <ListItemIcon>
                            <Link to={{pathname : routeNamesTracker.myProfile}}>
                                <Avatar src="/images/laughing_boy.jpg"/>
                            </Link>
                        </ListItemIcon>
                        <ListItemSecondaryAction>
                            <IconButton onClick={()=>this.setState({newContactDialog :true})}>
                                <Add className={classes.text}/>
                            </IconButton>
                        </ListItemSecondaryAction>
                    </ListItem>
                </List>
                <List>
                    <ListItem divider>
                        <ListItemIcon>
                            <Settings className={classes.text}/>
                        </ListItemIcon>
                        <ListItemText className={classes.text} style={{fontWeight : "bold"}}>
                            Disable all
                        </ListItemText>
                        <ListItemSecondaryAction>
                            <Switch size="small"
                                checked={Boolean(disableAllTracking)}
                                onChange={this.handleAllTrackingSwitch.bind(this)}/>
                        </ListItemSecondaryAction>
                    </ListItem>
                </List>
                <List className={classes.contactListContainer}>
                {contacts && contacts.map((item, index)=>{
                    return (item.contactIds && 
                        item.contactIds.indexOf(this.userId) !== -1 ? 
                        <ListItem key={index} button divider onClick={this.handleClick(item)}>
                            <ListItemIcon>
                                <Avatar src={item.avatar}/>
                            </ListItemIcon>
                            <ListItemText className={classes.text}>{item.name}</ListItemText>
                            <ListItemSecondaryAction>
                                <FormControl>
                                    <div>
                                        {item.trackingMe && 
                                        item.trackingMe.indexOf(this.userId) !== -1 && 
                                        <Done fontSize="small" className={classes.icon}/>}
                                        <Switch size="small"
                                            disabled={disableAllTracking}
                                            checked={Boolean(trackingMe && trackingMe.indexOf(item._id) !== -1)}
                                            onChange={this.handleAllowTracking(item)}/>
                                    </div>
                                </FormControl>
                            </ListItemSecondaryAction>
                        </ListItem> : 
                        <ListItem key={index} button divider onClick={this.handleClick(item)}>
                            <ListItemIcon>
                                <Avatar src={item.avatar}/>
                            </ListItemIcon>
                            <ListItemText style={{color : "lightblue"}}>{item.name}</ListItemText>
                            <ListItemSecondaryAction>
                                <FormControl>
                                    <div>
                                        {item.trackingMe && 
                                        item.trackingMe.indexOf(this.userId) !== -1 && 
                                        <Done fontSize="small" className={classes.icon}/>}
                                        <Switch size="small"
                                            disabled={disableAllTracking}
                                            checked={Boolean(trackingMe && trackingMe.indexOf(item._id) !== -1)}
                                            onChange={this.handleAllowTracking(item)}/>
                                    </div>
                                </FormControl>
                            </ListItemSecondaryAction>
                        </ListItem>)
                })} 
                </List>
                <MyDialog 
                    open={newContactDialog}
                    close={()=>this.setState({newContactDialog : false})}
                    >
                        <FormControl className={classes.newPhoneContact}>
                            <FormLabel style={{textAlign : "center", marginTop : 20}}>New Contact</FormLabel>
                            <PhoneInput
                                className={classes.phone}
                                style={{
                                    marginTop : 20,
                                    marginBottom : 10,
                                    padding : 10,
                                    borderRadius : 5
                                }}
                                placeholder="Enter phone number"
                                value={phone || ""}
                                onChange={phone=>this.setState({phone})} 
                                onKeyDown={onEnterPress(this.addNewContact.bind(this))}/>

                            <div style={{display : "flex", justifyContent : "center", padding : 20}}>
                                <Button 
                                    disabled={loading}
                                    onClick={()=>this.addNewContact()} color="primary" variant="contained">
                                    Add New Contact
                                </Button>
                            </div>
                        </FormControl>   
                </MyDialog>              
            </div>
        );
    }
}


_ContactList.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({contactReducer, trackerUtilReducer}) => ({
    [contactStrings.pageDisplay] : contactReducer[contactStrings.pageDisplay],
    [contactStrings.contacts] : contactReducer[contactStrings.contacts],
    [trackerUtilStrings.trackingMe] : trackerUtilReducer[trackerUtilStrings.trackingMe],
    [trackerUtilStrings.myProfile] : trackerUtilReducer[trackerUtilStrings.myProfile],
    [trackerUtilStrings.disableAllTracking] : trackerUtilReducer[trackerUtilStrings.disableAllTracking],
})


export const ContactList = connect(mapStateToProps)(withStyles(style)(_ContactList));
export {ContactList as default}