import { inovateOSAdminMessageServices } from "./services"
import { inovateOSAdminMessageConstants, inovateOSAdminMessageStrings } from "./config"
import { errorNotice, successNotice } from "../utils";

export const inovateOSAdminMessageActions = {
    sendEmail : (emailData, callback)=>dispatch =>{
        inovateOSAdminMessageServices.sendEmail(emailData, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    deleteMessages : (messageIds, callback)=>dispatch => {
        inovateOSAdminMessageServices.deleteMessages({messageIds}, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getMessages : (lastId, rows, callback)=>dispatch => {
        inovateOSAdminMessageServices.getMessages(lastId, rows, (done, result, message)=>{
            if(done) inovateOSAdminMessageActions.payload({
                [inovateOSAdminMessageStrings.messages] : result
            })(dispatch); else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch => dispatch({
        type : inovateOSAdminMessageConstants.SET_INSURE_ADMIN_MESSAGES,
        payload
    })
}