import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { List, ListItem, ListItemText } from "@material-ui/core";
import { connect } from 'react-redux';
import { chatFooterActions, chatFooterStrings } from '../../includes';
const style = theme => ({
    root: {
    }
})
class _ChatSettingComponent extends Component {
    itemClickHandler = option => e => {
        e.stopPropagation()
        const {close, dispatch} =this.props;
        if(close) close();
        chatFooterActions({
            [chatFooterStrings.visible] : false
        })(dispatch);
    }
    render() {
        const {classes, context, close} = this.props;
        return (
            <div className={classes.root}>
                <List>
                    <ListItem button onClick={this.itemClickHandler("hide")}>
                        <ListItemText>Hide Footer</ListItemText>
                    </ListItem>
                </List>
            </div>
        );
    }
}
_ChatSettingComponent.propTypes = {
    classes : PropTypes.object.isRequired,
    context : PropTypes.any, 
    close : PropTypes.func.isRequired,
};
export const ChatSettingComponent = connect()(withStyles(style)(_ChatSettingComponent));