import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { ContactList } from './ContactLIst';
import { Grid, withWidth, Hidden, IconButton } from '@material-ui/core';
import LocationActivity from './LocationActivity/LocationActivity';
import { headerActions, headerStrings, breadCrumbActions } from '../../includes';
import Chats from './Chats/Chats';
import HeaderControl from './HeaderControl';
import { contactStrings } from './config';
import { contactActions } from './actions';


const style = theme => ({
    root: {
        height : "100%",
    },
    container : {
        height : "100%",
    },
    item : {
        height : "100%"
    }
})
class _Contacts extends Component {
    constructor(props) {
        super(props);
        this.state = {
            display : 1
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "CONTACTS",
            [headerStrings.headerRight] : <HeaderControl/>
        })(dispatch);
    }
    contactSelectionHandler = () => {
        const {width, dispatch} = this.props;
        switch(width){
            case "sm" : 
                return contactActions.setPageDisplay(2)(dispatch);
        }
    }
    render() {
        const {classes, width, 
            [contactStrings.pageDisplay] : pageDisplay
        } = this.props;
        switch(width){
            case "xs" : return <div className={classes.root}>
                    <Grid className={classes.container} container spacing={0}>
                        <Grid className={classes.item} item xs={12} sm={5} md={4} lg={4} xl={4}>
                            {pageDisplay === 1 ? <ContactList onClick={this.contactSelectionHandler.bind(this)}/>:
                            (pageDisplay === 3 ?
                                <LocationActivity/> : 
                                <Chats/>
                            )}
                        </Grid>
                    </Grid>
                </div>;
            case "sm" : return <div className={classes.root}>
                    <Grid className={classes.container} container spacing={0}>
                        <Grid className={classes.item} item xs={12} sm={5} md={4} lg={4} xl={4}>
                            <ContactList onClick={this.contactSelectionHandler.bind(this)}/>
                        </Grid>
                        <Grid className={classes.item} item xs={false} sm={7} md={5} lg={5} xl={5}>
                            {pageDisplay === 3 ?
                                <LocationActivity/> : 
                                <Chats/>
                            }
                        </Grid>
                    </Grid>
                </div>;
            default : return (
                <div className={classes.root}>
                    <Grid className={classes.container} container spacing={0}>
                        <Grid className={classes.item} item xs={12} sm={5} md={4} lg={4} xl={4}>
                            <ContactList/>
                        </Grid>
                        <Grid className={classes.item} item xs={false} sm={7} md={5} lg={5} xl={5}>
                            <Hidden xsDown>
                                <Chats/>
                            </Hidden>
                        </Grid>
                        <Grid className={classes.item} item xs={false} sm={false} md={3} lg={3} xl={3}>
                            <Hidden smDown>
                                <LocationActivity/>
                            </Hidden>
                        </Grid>
                    </Grid>
                </div>
            );
        }
    }
}


_Contacts.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({contactReducer}) => ({
    ...contactReducer
})


export const Contacts = connect(mapStateToProps)(withStyles(style)(withWidth()(_Contacts)));
export {Contacts as default}