export const hirPatientStrings = {
    patients : "hir_patients",
    recentVisitPatients : "recentVisitPatients",
    patientAppointments : "patientAppointments",
    patientPayments : "patientPayments",
    patientPaymentStatData : "patientPaymentStatData",
}
export const hirPatientConstants = {
    SET_HIR_PATIENTS : "SET_HIR_PATIENTS",
}
export const hirPatientReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type) {
        case hirPatientConstants.SET_HIR_PATIENTS : 
            return {...state, ...payload};
        default : return state
    }
}
export * from './actions';
export * from './services';