import { insureBlogStrings, insureBlogConstants } from "./config";
import { insureBlogServices } from "./services";

export const insureBlogActions = {
    getBlogs : (lastId, rows, callback) => dispatch => {
        insureBlogServices.getBlogs(lastId, rows, (done, result, message)=>{
            if(done) insureBlogActions.payload({
                [insureBlogStrings.blogs] : result.values,
            })(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch => dispatch({
        type : insureBlogConstants.SET_BLOG,
        payload
    })
}