import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { payrollStrings } from '../../config';
import { MyTable, headerActions, headerStrings, breadCrumbActions } from '../../../includes';
import { payrollActions } from '../../actions';
import { colors, routeName } from '../../../../utils';


const style = theme => ({
    root: {
    }
})
class _EmployeeStatus extends Component {
    constructor(props) {
        super(props);
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "EMPLOYEE STATUS",
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeName.dashboard},
            {name : "Employee status", path : routeName.payrollEmployees},
        ])(dispatch)
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {dispatch} = this.props;
        payrollActions.getPayrollEmployeeStatus()(dispatch);
    }
    render() {
        const {
            classes, 
            [payrollStrings.payrollEmployeeStatus] : payrollEmployeeStatus,
        } = this.props;
        let header = ["ID", "Name", "Description"];
        let dataMap = ["_id", "name", "description"];
        if(true){
            header = [...header, "Actions"];
            dataMap = [...dataMap, "actions"];
        }
        return (
            <div className={classes.root}>
                <MyTable
                    // title="Employee Payroll Status"
                    titleProps={{
                        style:{color : colors.secondary}
                    }}
                    header={header}
                    dataMap={dataMap}
                    data={payrollEmployeeStatus}
                    />
            </div>
        );
    }
}


_EmployeeStatus.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({payrollReducer}) => ({
    [payrollStrings.payrollEmployeeStatus] : payrollReducer[payrollStrings.payrollEmployeeStatus],
})


export const EmployeeStatus = connect(mapStateToProps)(withStyles(style)(_EmployeeStatus));
export {EmployeeStatus as default}