import { parentServices } from "./services"
import { parentConstants, parentStrings } from "./config"

export const parentActions = {
    getParents : (lastId, row, callback) => dispatch => {
        parentServices.getParents(lastId, row, (done, result, message)=>{
            if(done)dispatch({
                type : parentConstants.SET_PARENTS,
                payload : {
                    [parentStrings.parents] : result
                }
            })
            if(callback) callback(done, result, message);
        })
    }
}