import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { hirSettingActions, hirSettingStrings } from '../../HIRSettings/config';
import { FormDisplay } from '../../../includes';
import { HIRButton } from '../../Includes/Buttons';
import { CircularProgress } from '@material-ui/core';
import { getFormDisplayData } from '../../../includes/Forms/FormDisplay/functions';
import { appActions, alertAction } from '../../../../actions';


const style = theme => ({
    root: {
    }
})
class _HIRNewPayment extends Component {
    constructor(props) {
        super(props);
        this.formConfig = [
            {name : "amount", label : "Amount", type : "number", placeholder : "Amount"},
            {name : "revenueType", label : "revenueType", type : "select", options : [
        
            ]},
        ]
        if(props.showDescription)
            this.formConfig.push({name : "description", label : "Description", placeholder : "Description"})
        this.state = {
            loading : false
        }
    }
    componentDidMount() {
        const {
            dispatch,
            [hirSettingStrings.settings] : settings
        } = this.props;
        if(!settings) hirSettingActions.getSettings()(dispatch);
    }
    onClick(){
        this.setState({loading : true});
        const {dispatch, postPayment, editMode, editPayment} = this.props;
        const data = getFormDisplayData(
            this.newPaymentFormContext
        )((message, type)=>{
            appActions.showSnackbar(
                alertAction[type](message)
            )(dispatch);
        });
        if(data){
            if(editMode && editPayment)
                editPayment(data, this);
            else if(postPayment)
                postPayment(data, this);
        }else this.setState({loading : false});
    }
    createAptButton = ({loading}) => () => {
        const {editMode} = this.props;
        return <HIRButton 
            disabled={loading}
            type={editMode ? "secondary" : "primary"} onClick={this.onClick.bind(this)}>
            {loading && <CircularProgress style={{
                width : 30, height : 30
            }} color="secondary"/>}
            {editMode ? "Edit" : "Post"} Payment
        </HIRButton>
    }
    render() {
        const {
            classes, 
            [hirSettingStrings.settings] : settings,
            patient, paymentData, editMode
        } = this.props;
        const {loading } = this.state;
        let lastName, firstName; 
        if(patient){
            const {myProfile} = patient;
            lastName = myProfile.lastName;
            firstName = myProfile.firstName;
        }
        if(settings){
            const revenueTypes = settings.find(item=>item.name === "revenue");
            if(revenueTypes){
                this.formConfig = [...this.formConfig.map(item=>{
                    if(item.name === "revenueType"){
                        item.options = revenueTypes.values.map(item=>({_id : item.name, name : item.value}))                        
                    }
                    return item;
                })]
            }
        }
        return (
            <div className={classes.root}>
                <FormDisplay
                    getContext={context=>this.newPaymentFormContext = context}
                    header={lastName && "Payment for "+lastName+", "+firstName}
                    formName="newAppointment"
                    formConfig={this.formConfig}
                    formData={paymentData ? {...paymentData, amount : String(paymentData.amount)} : null}
                    footer={this.createAptButton({loading})}
                />
            </div>
        );
    }
}


_HIRNewPayment.propTypes = {
    classes : PropTypes.object.isRequired,
    patient : PropTypes.object,
    postPayment : PropTypes.func,
    editMode : PropTypes.bool,
    paymentData : PropTypes.object,
    editPayment : PropTypes.func,
    showDescription : PropTypes.bool,
};
const mapStateToProps = ({hirSettingReducer}) => ({
    [hirSettingStrings.settings] : hirSettingReducer[hirSettingStrings.settings],
})


export const HIRNewPayment = connect(mapStateToProps)(withStyles(style)(_HIRNewPayment));
export {HIRNewPayment as default}