import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { MyTable } from '../../../../../utils';
import { TableCell } from '@material-ui/core';
import { INVDescriptionValueBox } from '../INVDescriptionValueBox';
const style = theme => ({
    root: {
        
    },
    cell : {
        padding : 5,
        fontSize : 11,
    }
})
class _INVDescriptionCategorised extends Component {
    cellMapFormat = ({row, cellMap}) => {
        const {classes} = this.props;
        switch(cellMap){
            case "values" : return <TableCell className={classes.cell}>
                <INVDescriptionValueBox values={row[cellMap]}/>
            </TableCell>
            default : return <TableCell className={classes.cell}>
                {row[cellMap]}
            </TableCell>
        }
    }
    render() {
        const {classes, values} = this.props;
        return (
            <MyTable    
                elevation={0}
                header={["Property Names", "Property Values"]}
                dataMap={["name", "values"]}
                CellMap={this.cellMapFormat.bind(this)}
                data={values}/>
        );
    }
}
_INVDescriptionCategorised.propTypes = {
    classes : PropTypes.object.isRequired,
    values : PropTypes.array,
};
export const INVDescriptionCategorised = withStyles(style)(_INVDescriptionCategorised);