import React, {Fragment} from 'react';
import { Screen, Header } from '../includes';
import {Redirect, Route} from 'react-router-dom';
import {agroAdminUtil, agroAdminActions} from  './utils';
import { agroAdminRouteNames } from './routeNames';


export const SiteRoute = ({component : Component, ...props}) => {
    return (
        <Fragment>
            <Header/>
            <Route {...props} component={prop=><Component {...prop}/>}/>
        </Fragment>
    )
}
export const PrivateRoutePlane = ({component : Component, ...props}) => (
    <Route {...props} render={props => { 
        return (
            agroAdminUtil.isLogedIn()
            ? <Fragment>
                <Screen {...props} component={Component}/>
            </Fragment>
            : (props.match.path === agroAdminRouteNames.login ||
                props.match.path === agroAdminRouteNames.signup ?
                <Component {...props}/> : 
            <Redirect to={{ pathname: agroAdminRouteNames.login, state: { from: props.location } }} />)
        )}
    } />
);
export const LogoutRoute = rest =>(
    <Route {...rest} render={props=>{
        agroAdminActions.logout();
        return <Redirect to={{ pathname: '/login', state: { from: props.location } }}/> 
    }}/>
)