import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {Link} from 'react-router-dom';
import {withStyles} from '@material-ui/core/styles';
import { TextField, FormGroup, FormControl, FormLabel, Typography, Button } from '@material-ui/core';
import { appActions, alertAction } from '../../../actions';
import { insureAdminUtil, insureAdminActions, onEnterPress } from '../utils';
import { insureAdminRouteNames } from '../routeNames';


const style = theme => ({
    root: {
        background : insureAdminUtil.getTheme().secondary,
        backgroundSize : "cover",
        height : "100vh",
        width : "100vw",
    },
    overLay : {
        height : "100%",
        width : "100%",
        backgroundColor : insureAdminUtil.getTheme().primaryTrans,
        display : "flex",
        flexDirection : "column",
        alignItems : "center",
        justifyContent : "center"
    },
    pageTitle : {
        fontWeight : 800,
        color : insureAdminUtil.getTheme().white,
        fontFamily : "fantasy",
        marginBottom : 50,
    },
    formContainer : {
        backgroundColor : insureAdminUtil.getTheme().primary, 
        padding : 20,
        borderRadius : 10,
        width : "50%",
        [theme.breakpoints.down("xs")] : {
            width : "80%"
        },
        [theme.breakpoints.up("md")] : {
            width : "30%",
        }
    },
    textField : {
        background : insureAdminUtil.getTheme().white,
        borderRadius : 5,
        border : "none"
    },
    noBorder : {
        border : "none"
    },
    headerContainer : {
        marginBottom : 50,
    },
    header : {
        color : insureAdminUtil.getTheme().white,
        fontWeight : "bold"
    },
    loginButton : {
        marginTop : 20,
        backgroundColor : insureAdminUtil.getTheme().primary,
        color : insureAdminUtil.getTheme().white
    }
})
class _Login extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data  : {
                email : "",
                password : "",
                loading : false
            },
            loading : false
        }
    }
    handleChange=name=>event=>{
        let value = event.target.value;
        let data = {...this.state.data};
        data[name] = value;
        this.setState({data});
    }
    login(){
        this.setState({loading : true});
        const {email, password} = this.state.data;
        const {dispatch} = this.props;
        if(email.trim() === "" && password.trim() === ""){
            appActions.showSnackbar(
                alertAction.error("Empty field error!")
            )(this.props.dispatch);
            this.setState({loading : false});
            return;
        }
        insureAdminActions.loging(email, password, done => {
            if(done)
                this.props.history.replace(insureAdminRouteNames.home);
            else this.setState({loading : false});
        })(dispatch);
    }
    render() {
        const {classes} = this.props;
        const {username, password, loading} = this.state;
        return (
            <div id="home" className={classes.root}>
                <div className={classes.overLay}>
                    <Typography className={classes.pageTitle} variant="h4">MOBOINSURE ADMIN</Typography>
                    <div className={classes.formContainer}>
                        <FormGroup>
                            <FormLabel className={classes.headerContainer}>
                                <Typography className={classes.header} component="h4" variant="h4">Login</Typography>
                            </FormLabel>
                            <FormControl>
                                <TextField
                                    label="Email"
                                    placeholder="email"
                                    margin="normal"
                                    onChange={this.handleChange("email")}
                                    value={username}
                                    className={classes.textField}
                                    variant="outlined"
                                    onKeyDown={onEnterPress(this.login.bind(this))}/>
                            </FormControl>
                            <FormControl>
                                <TextField
                                    label="Password"
                                    placeholder="password"
                                    margin="normal"
                                    onChange={this.handleChange("password")}
                                    value={password}
                                    type="password"
                                    className={classes.textField}
                                    variant="outlined"
                                    onKeyDown={onEnterPress(this.login.bind(this))}/>
                            </FormControl>
                            <FormControl>
                                <Button
                                    disabled={loading}
                                    className={classes.loginButton}
                                    onClick={()=>this.login()}>
                                        Login
                                    </Button>
                            </FormControl>
                            <div style={{marginTop : 20, direction : "rtl"}}>
                                <a style={{
                                    color : insureAdminUtil.getTheme().secondary
                                }} target="_blank" href="/">Go to Site</a>
                            </div>
                        </FormGroup>
                    </div>
                </div>
            
            </div>
        );
    }
}


_Login.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapDispatchToProps = dispatch => {
    return {
        dispatch
    }
}
const mapStateToProps = state => ({
    state
})


export const Login = connect(mapStateToProps,mapDispatchToProps)(withStyles(style)(_Login));
export {Login as default};