import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Typography, withWidth, IconButton } from '@material-ui/core';
import { Settings, Chat } from '@material-ui/icons';
import AllChats from './components/AllChats/AllChats';
import { ChatBox } from './components/ChatBox';
import OverflowChatBox from './components/OverflowChatBox/OverflowChatBox';
import { FabIconControl } from './components/FabIconControl';
import { chatFooterStrings } from './config';
import { chatFooterActions } from './actions';


const style = theme => ({
    root: {
        height : 50,
        position : "fixed",
        bottom : 0,
        width : "100%",
        display : "flex",
        justifyContent : "flex-end",
        zIndex : 2000
    },
})
class _ChatFooter extends Component {
    static width = 250
    closeChatBox(_id, context){
        const {
            dispatch, 
            [chatFooterStrings.chattingContacts] : contacts,
        } = this.props;
        if(contacts){
            const {item, index} = contacts.getFirstObjectByPropValue("_id", _id);
            contacts.splice(index, 1);
            chatFooterActions({
                [chatFooterStrings.chattingContacts] : [...contacts]
            })(dispatch);
        }
    }
    render() {
        const {
            classes, width,
            [chatFooterStrings.visible] : visible,
            [chatFooterStrings.chattingContacts] : contacts,
            [chatFooterStrings.chatBoxMessages] : messages

        } = this.props;
        if(!visible) return null;

        switch(width){
            case "xs" : 
            // case "sm" : 
                return <FabIconControl/>
            default : 
                let maxChatBox = 3;
                if(width === "sm") maxChatBox = 1;
                else if (width === "md") maxChatBox = 2;
                return (
                    <Fragment>
                        <AllChats/>
                        {contacts && contacts.map((item, index)=>{
                            if(index === maxChatBox) return null;
                            return <ChatBox
                                open={index === 0}
                                close={this.closeChatBox.bind(this)}
                                key={index}
                                messages={messages && messages[item._id]}
                                {...item}
                                right={((ChatFooter.width + 2) * (index +1)) + 2}/>
                        })}
                        <OverflowChatBox 
                            contacts={contacts && contacts.slice(maxChatBox)} 
                            maxChatBox={maxChatBox}
                            right={
                                (
                                    (ChatFooter.width + 2) * 
                                    (contacts ? (contacts.length > maxChatBox ? maxChatBox + 1 : contacts.length + 1) : 1)
                                ) + 2
                            }/>
                    </Fragment>
                );
        }
    }
}


_ChatFooter.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({chatFooterReducer}) => {
    
    return ({
        ...chatFooterReducer
    })
}


export const ChatFooter = connect(mapStateToProps)(withWidth()(withStyles(style)(_ChatFooter)));
export {ChatFooter as default}