import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { sessionActions } from '../actions';
import { mainStageHeaderAction, mainStageHeaderStrings, MyTable, EditableCellMapFormat } from '../../../includes';
import { FormControlLabel, Switch, ExpansionPanel, ExpansionPanelSummary, ExpansionPanelDetails, Button } from '@material-ui/core';
import { colors } from '../../../../utils';
import { sessionStrings } from '../config';
import { appActions } from '../../../../actions';


const style = theme => ({
    root: {
        marginTop : 20
    }
})
class _LevelClasses extends Component {
    constructor(props) {
        super(props);
        this.state = {
            previousClasses : [],
            levels : [],
            usingPreviousClasses : false
        }
        const {dispatch} = props;
        // this.levels = this.props.getParam("levels");
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [()=><FormControlLabel
                style={{margin : 5, color: colors.white}}
                control={<Switch 
                    // checked={true} 
                    onChange={this.setUsePreviousClasses.bind(this)}/>}
                label="Use exisiting classes"
                />],
            [mainStageHeaderStrings.buttons] : [
                {name:"Finish", value:"Finish", 
                style :{backgroundColor : colors.secondary}, 
                variant : "contained", onClick:()=>{
                    appActions.toogleScreenProgress(true)(dispatch)
                    this.props.finish(this.state.levels);
                }}
            ]
        })(dispatch)

    }
    setUsePreviousClasses = e => {
        const checked = e.target.checked;
        sessionActions.setUsePreviousClasses(checked)(this.props.dispatch);
    }
    componentDidMount(){
        const self = this;
        //REMOVE 
        //this is meant to be the new level
        sessionActions.getSessionLevels(1, (done, result)=>{
            if(done) this.setState({levels:result})
        })(this.props.dispatch);
        //input is from the levels of the previous page
        sessionActions.getClassesByLevelIds_NO_DISPATCH([1,2,3], (done, result, message)=>{
            this.setState({
                previousClasses : result
            });
        });
    }
    static getDerivedStateFromProps(props, state) {
        if(props[sessionStrings.usePreviousClasses]){
            if(!state.usingPreviousClasses){
                LevelClasses.addPreviousClasses(state);
                state.usingPreviousClasses = true;
            }
        }else {
            if(state.usingPreviousClasses){
                LevelClasses.removePrevioiusClasses(state);
                state.usingPreviousClasses = false;
            }
        }
        return state;
    }
    static addPreviousClasses(state){
        const {previousClasses, levels = []} = state;
        for (let i = 0; i < levels.length; i++) {
            const level = levels[i];
            if(level._id && 
            previousClasses.lenght !== 0 &&
            previousClasses[level._id]){
                if(level.classes){
                    // previousClasses[level._id].map(item=>({...item, levelIndex : i}));
                    levels[i].classes.unshift(...previousClasses[level._id]);
                }else levels[i].classes = [...previousClasses[level._id]];
            }
        }
        return levels;
    }
    static removePrevioiusClasses(state){
        const {levels=[]} = state;
        for (let i = 0; i < levels.length; i++) {
            if(levels[i].classes){
                levels[i].classes.removeObjectWithProp("_id");
            }            
        }
        return levels;
    }
    cellMapContext = {};
    getCellMapContext = levelId => (context, name) => {
        if(!this.cellMapContext[levelId]){
            this.cellMapContext[levelId] = {[name] : context};
        }else {
            this.cellMapContext[levelId][name] = context;
        }
    }
    addButtonHandler = (levelId, idType) => listLength => () => {
        let data = {};
        for (const mapItem in this.cellMapContext[levelId]) {
            if (this.cellMapContext[levelId].hasOwnProperty(mapItem)) {
                const context = this.cellMapContext[levelId][mapItem];
                if(mapItem !== "action"){
                    const {name, value} = context.state.data;
                    data[name] = value;
                }
            }
        }
        data.editable = true;
        //new row is already number zero
        data.id = listLength;
        let levels = [...this.state.levels];
        const level = levels.getFirstObjectByPropValue(idType, levelId);
        if(level){
            const {classes} = level.item;
            if(classes)
                level.item.classes.push(data);
            else level.item.classes = [data];
            levels.splice(level.index, 1, {...level.item});
        }
        this.setState({levels});
    }
    editBtnHandler = (levelId, idType) => row => () => {
        const levels = [...this.state.levels];
        const {item : level, index : levelIndex}  = levels.getFirstObjectByPropValue(idType, levelId);
        
        const {classes : levelClass} = level;
        //this is for the editable only
        //for now only the added is editable
        const {item : classItem, index : classIndex} = levelClass.getFirstObjectByPropValue("id", row.id);

        levelClass.splice(classIndex, 1, {...classItem, editing : true});
        level.classes = [...levelClass];
        levels.splice(levelIndex, 1, {...level});
        this.setState({level});
    }
    cancelEditBtnHandler = (levelId, idType) => row => () => {
        const levels = [...this.state.levels];
        const {item : level, index : levelIndex}  = levels.getFirstObjectByPropValue(idType, levelId);
        
        const {classes : levelClass} = level;
        //this is for the editable only
        //for now only the added is editable
        const {item : classItem, index : classIndex} = levelClass.getFirstObjectByPropValue("id", row.id);
        delete classItem.editing;
        levelClass.splice(classIndex, 1, {...classItem});
        level.classes = [...levelClass];
        levels.splice(levelIndex, 1, {...level});
        this.setState({level});
    }
    editFinishBtnHandler = (levelId, idType) => row => () => {
        let data = {};
        for (const i in row.context) {
            if (row.context.hasOwnProperty(i)) {
                const context = row.context[i];
                if(i !== "action"){
                    const {name, value} = context.state.data;
                    data[name] = value;
                }
            }
        }
        const levels = [...this.state.levels];
        const {item : level, index : levelIndex}  = levels.getFirstObjectByPropValue(idType, levelId);
        
        const {classes : levelClass} = level;
        //this is for the editable only
        //for now only the added is editable
        const {item : classItem, index : classIndex} = levelClass.getFirstObjectByPropValue("id", row.id);
        delete classItem.editing;
        levelClass.splice(classIndex, 1, {...classItem, ...data});
        level.classes = [...levelClass];
        levels.splice(levelIndex, 1, {...level});
        this.setState({level});
    }
    deleteBtnHandler = (levelId, idType) => row => () => {
        const {dispatch} = this.props;
        appActions.showSnackDialog(
            "Are you sure you want to delete this class",
            <Button key="delete" variant="outlined" style={{color : colors.white}} onClick={()=>{
                let levels = [...this.state.levels];
                const {item : level, index : levelIndex}  = levels.getFirstObjectByPropValue(idType, levelId);
                const {classes : levelClass} = level;
                let classIndexMain;
                if(row.id){
                    const {index : classIndex} = levelClass.getFirstObjectByPropValue("id", row.id);
                    classIndexMain = classIndex;
                }
                else{
                    const {index : classIndex} = levelClass.getFirstObjectByPropValue("_id", row.id);
                    classIndexMain = classIndex;
                }
                levelClass.splice(classIndexMain, 1);
                level.classes = [...levelClass];
                levels.splice(levelIndex, 1, {...level});
                this.setState({level});
                appActions.closeSnackDialog()(dispatch);
            }}>Delete</Button>
        )(dispatch);
    }
    render() {
        const {
            classes
        } = this.props;
        const {levels} = this.state;
        return (
            <div className={classes.root}>
                {levels && levels.map((level, index)=>{
                    const idType = level._id ? "_id" : "id"; 
                    const id = level._id ? level._id : level.id;
                    const tableConfig = {
                        title : level.name + " classes",
                        header : ["Name", "Short Name", ""],
                        dataMap : ["name", "short", "action"],
                        data : level.classes ? 
                            [...level.classes, {new: true}] : 
                            [{new : true}],
                        CellMap : EditableCellMapFormat,
                        getCellMapContext : this.getCellMapContext(id, idType),
                        addButtonHandler : this.addButtonHandler(id, idType),
                        editBtnHandler : this.editBtnHandler(id, idType),
                        cancelEditBtnHandler : this.cancelEditBtnHandler(id, idType),
                        editFinishBtnHandler : this.editFinishBtnHandler(id, idType),
                        deleteBtnHandler : this.deleteBtnHandler(id, idType),
                    }
                    return <ExpansionPanel style={{backgroundColor : colors.grayTrans}} key={index} expanded={true}>
                        <ExpansionPanelSummary style={{
                            color : colors.primary, 
                            fontWeight : "bold"
                        }}>{level.name}</ExpansionPanelSummary>
                        <ExpansionPanelDetails>
                            <MyTable
                            {...tableConfig}/>
                        </ExpansionPanelDetails>
                    </ExpansionPanel>
                })}
            </div>
        );
    }
}

const mapStateToProps = ({sessionReducer}) => ({
    // [sessionStrings.sessionPreviousClasses] : sessionReducer[sessionStrings.sessionPreviousClasses],
    [sessionStrings.usePreviousClasses] : sessionReducer[sessionStrings.usePreviousClasses],
})
_LevelClasses.propTypes = {
    classes : PropTypes.object.isRequired,
    finish : PropTypes.func,
};
export const LevelClasses = connect(mapStateToProps)(withStyles(style)(_LevelClasses));