import React, { Component } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import {withStyles} from '@material-ui/core/styles';
import {connect} from 'react-redux';
import { MyTable, EditableCellMapFormat, TextFieldComponent, appActions, alertAction, inventoryUtil } from '../../../../../utils';
import { Chip, FormLabel } from '@material-ui/core';
import { INVCategorisedOptionValueInput } from './INVCategorisedOptionValueInput';
const style = theme => ({
    root: {
        backgroundColor : inventoryUtil.getTheme().background,
    }, 
    chip : {
        margin : 3,
    },
    addValueBtn : {
        fontSize : 12,
    }
})
class _INVCategorisedOptions extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data : props.data || [], //sample {id : "colors",name : "Colors",values : ["red", "brown", "red"]}
            newPropertyValues : [],
            editingOption : {},
        }
        const {getContext} = props;
        if(getContext) getContext(this);
    }
    cellMapFormat = superProps => props => <EditableCellMapFormat {...props} {...superProps}/>

    deleteBtnHandler = row => () => {
        const {data} = this.state;
        const index = data.findIndex(item=>item.id===row.id);
        if(index || index === 0){
            data.splice(index, 1);
        }
        this.setState({data});
    }
    editBtnHandler = row => () => {
        const {data, editingOption} = this.state;
        if(editingOption && editingOption.id){
            let index = data.findIndex(item=>item.id === editingOption.id);
            if(index || index === 0)
                delete data[index].editing;
        }
        let index = data.findIndex(item=>item.id === row.id);
        if(index || index === 0){
            this.setState({editingOption : {
                ...data[index], 
                values : data[index].values ? 
                [...data[index].values] : []}
            });
            data[index] = {...row, editing : true};
        }
        this.setState({data});
    }
    addButtonHandler = () => () => {
        const {dispatch} = this.props;
        const optionName = this.newOptionNameContext.state.value;
        if(!String(optionName).trim()){
            appActions.showSnackbar(
                alertAction.error("New option name can not be empty! Insert a value")
            )(dispatch);
            return;
        }
        const {newPropertyValues, data} = this.state;
        if(newPropertyValues && newPropertyValues.length === 0){
            appActions.showSnackbar(
                alertAction.error("No values added for the new option!")
            )(dispatch);
            return;
        }
        const id = String(optionName).split(" ").join("").toLowerCase();
        data.push({
            id, name : optionName, values : newPropertyValues
        })
        this.setState({data, newPropertyValues : []});
        
    }
    editFinishBtnHandler = () => () => {
        const {dispatch} = this.props;
        const {data, editingOption} = this.state;
        let optionName
        const textComponent = this.optionNameContext[editingOption.id];
        if(textComponent){
            optionName = textComponent.state.value;
            if(!String(optionName).trim()){
                appActions.showSnackbar(
                    alertAction.error("Option name came not empty!")
                )(dispatch);
                return;
            }
        }else{
            appActions.showSnackbar(
                alertAction.error("Dev Error... send report to website!")
            )(dispatch);
            return;
        }
        const index = data.findIndex(item=>item.id===editingOption.id);
        if(index || index === 0){
            editingOption.name = optionName;
            data[index] = editingOption;
        }
        this.setState({data});
    }
    cancelEditBtnHandler = row => () => {
        const {data} = this.state;
        const index = data.findIndex(item=>item.id === row.id);
        if(index || index === 0){
            delete data[index].editing;
        }
        this.setState({data});
    }
    onDeleteOptionValue = (row, value) => e => {
        const {newPropertyValues, editingOption} = this.state;
        if(row.new){
            const index = newPropertyValues.findIndex(item=>item===value);
            if(index || index === 0) newPropertyValues.splice(index, 1);
            this.setState({newPropertyValues});
        }else{
            const values = editingOption.values;
            const index = values.findIndex(item=>item===value);
            if(index || index === 0) values.splice(index, 1);
            editingOption.values = values;
            this.setState({editingOption});
        }
    }
    getOptionValue = row => value => {
        const {dispatch} = this.props;
        if(!String(value).trim()){
            appActions.showSnackbar(
                alertAction.error("Empty field!")
            )(dispatch);
            return;
        }
        const {newPropertyValues, editingOption} = this.state;
        if(row.new){
            newPropertyValues.push(value);
            this.setState({newPropertyValues})
        }else{
            editingOption.values ? 
                editingOption.values.push(value) :
                editingOption.values = [value];
            this.setState({editingOption});
        }
    }
    optionNameContext = {};
    newOptionNameContext;
    tableCellContentView = (editing, {row, cellMap}) => {
        const {classes, dispatch} = this.props;
        if(editing){
            switch(cellMap){
                case "name" : 
                    return <TextFieldComponent
                        value={row.name}
                        fieldProps={{
                            label : "Property Name",
                            placeholder : "Property name"
                        }} 
                        getContext={context=> 
                            row.new ? this.newOptionNameContext = context : 
                            this.optionNameContext[row.id] = context}
                        />;
                case "values" : 
                    let values;
                    if(row.new){
                        values = this.state.newPropertyValues;
                    }else{
                        values = this.state.editingOption.values || [];
                    }
                    return <div>
                        {values && values.map((item, index)=>{
                            return <Chip 
                            className={classes.chip}
                            onDelete={this.onDeleteOptionValue(row, item)}
                            key={index}
                            label={item}/>
                        })}
                        <INVCategorisedOptionValueInput 
                            dispatch={dispatch}
                            iconButtonProps={{
                                title : "Add value to list of option values",
                                classes : {btn : classes.addValueBtn}
                            }}
                            getValue={this.getOptionValue(row)}/>
                    </div>
            }
        }else{
            switch(cellMap){
                case "name" : 
                    return row[cellMap];
                case "values" : 
                    return <div>
                        {row[cellMap].map((item, index)=>{
                            return <Chip 
                            className={classes.chip}
                            key={index}
                            label={item}/>
                        })}
                    </div>
            }
        }
    }
    render() {
        const {classes} = this.props;
        const {data} = this.state;
        let tableData 
        if(data){
            tableData = data.map(item=>({...item, editable : true, delible : true}));
            tableData.push({new : true});
        }else tableData = [{new : true}]

        return (
            <div className={classNames("animated", "slideInRight")}>
                <FormLabel style={{marginBottom : 10}}>Property Names and Values</FormLabel>
                <MyTable
                    classes={{
                        root : classes.root
                    }}
                    header={["Property Name", "Property Values", "Action"]}
                    dataMap={["name", "values", "action"]}
                    data={tableData}
                    CellMap={this.cellMapFormat({
                        deleteBtnHandler : this.deleteBtnHandler.bind(this),
                        editBtnHandler : this.editBtnHandler.bind(this),
                        addButtonHandler : this.addButtonHandler.bind(this),
                        editFinishBtnHandler : this.editFinishBtnHandler.bind(this),
                        cancelEditBtnHandler : this.cancelEditBtnHandler.bind(this),
                        tableCellContentView : this.tableCellContentView.bind(this),
                    })}
                    />
            </div>
        );
    }
}
_INVCategorisedOptions.propTypes = {
    classes : PropTypes.object.isRequired,
    getContext : PropTypes.func,
};
export const INVCategorisedOptions = connect()(withStyles(style)(_INVCategorisedOptions));