import { hirFamilyServices } from "./services"
import { hirFamilyStrings, hirFamilyConstants } from "./config";
import { hirPatientServices } from "../HIRPatients";
import { hirAccountServices } from "../HIRAccounts";
import { hirAppointmentServices } from "../HIRAppointments/config";
import { hirSuccessNotice as successNotice, hirErrorNotice as errorNotice} from "../utils";

export const hirFamilyActions = {
    getAFamily : (familyId, callback) => dispatch => {
        hirFamilyServices.getAFamily(familyId, (done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getFamilyYearlyAppointments : (memberIds, year, callback) => dispatch => {
        hirAppointmentServices.getMultiplePatientYearlyAppointments(memberIds, year, (done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getFamilyYearlyPayments : (members, year, callback) => dispatch=>{
        hirAccountServices.getMultiplePatientYearlyPayments(members, year, (done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    createPatient : (data, callback)=>dispatch => {
        hirPatientServices.createRecord(data, (done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            else successNotice("Patient created!", dispatch);
            if(callback) callback(done, result, message);
        })
    },
    deleteFamilyMember : (familyId, patientId, callback) => dispatch => {
        hirFamilyServices.deleteFamilyMember(familyId, patientId, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    setNewFamilyMembers : (familyId, value) => dispatch => {
        hirFamilyActions.payload({
            [hirFamilyStrings.newFamilyMembers] : {[familyId] : value}
        })(dispatch);
    },
    addFamilyMembers : (familyId, members, newMemberIds, newMembers, callback) => dispatch => {
        familyId = parseInt(familyId);
        hirFamilyServices.addFamilyMembers(familyId, members, newMemberIds, (done, result, message, newMemberId)=>{
            if(done) {
                hirFamilyActions.setNewFamilyMembers(familyId, null)(dispatch);
                successNotice(message, dispatch);
            }else {
                if(newMemberId && newMembers){
                    const member = newMembers.find(item => item._id === newMemberId);
                    if(member) message += " (" + member.myProfile.lastName + ")";
                }
                errorNotice(message, dispatch);
            }
            if(callback) callback(done, result, message);
        })
    },
    deleteFamily : (familyId, callback) => dispatch => {
        hirFamilyServices.deleteFamily(familyId, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result,message);
        })
    },
    editFamilyRecord : (familyId, data, callback) => dispatch => {
        hirFamilyServices.editFamilyRecord(familyId, data, (done, result, message)=>{
            if(done) successNotice(message,dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    createFamilyRecord : (data, callback) => dispatch => {
        hirFamilyServices.createFamilyRecord(data, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getFamilies : (rows, skip, callback) => dispatch => {
        hirFamilyServices.getFamilies(rows, skip, (done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            else{
                hirFamilyActions.payload({
                    [hirFamilyStrings.families] : result
                })(dispatch);
            }
            if(callback) callback(done, result, message);
        })
    },
    getFamilyMinMaxIds_NO_DISPATCH : callback => {
        hirFamilyServices.getFamilyMinMaxIds(callback);
    },
    payload : payload => dispatch => dispatch({
        type : hirFamilyConstants.SET_HIR_FAMILY,
        payload
    })
}