export const chatFooterStrings = {
    visible : "visible",
    chattingContacts : "chatingContacts",
    activeContactId : "activeContactId",
    allChatSettingPopupContent : "allChatSettingPopupContent",
    allChatContainerProps : "allChatContainerProps",
    allChatListItemComponent : "allChatListItemComponent",
    allChatListData : "allChatListData",
    allChatListItemValueProp : "allChatListItemValueProp",
    allChatListItemOnClickHandler : "allChatListItemOnClickHandler",
    chatBoxOnClose : "chatBoxOnClose",
    chatBoxMessages : "chatBoxMessages",
    chatBoxContentContainerProps : "chatBoxContentContainerProps",
    userId :"userId",
    smallScreenFabClick : "smallScreenFabClick",
    getMessagesAction : "getMessagesAction",
    sendMessageAction : "sendMessageAction",
}
export const chatFooterConstants = {
    SET_CHATFOOTER : "SET_CHATFOOTER",
}
export const chatFooterReducer = (state = {
    [chatFooterStrings.visible] : true
}, action)=>{
    const {type, payload} = action;
    switch(type){
        case chatFooterConstants.SET_CHATFOOTER : 
            return {...state, ...payload}
        default : return {...state};
    }
}
