export const USERID = _retrieveData(Manager.userIdAlias);
export const TOKEN = _retrieveData(Manager.tokenAlias);
export async function fetchGet(owner, action, stringQuery, callback){
    const USERID = _retrieveData(Manager.userIdAlias);
    const TOKEN = _retrieveData(Manager.tokenAlias);
    console.log(USERID, TOKEN);
    stringQuery = {...stringQuery, userId : USERID, token : TOKEN};
    let count = 0;
    let build = "";
    for (const i in stringQuery) {
        if (stringQuery.hasOwnProperty(i)) {
            const elem = stringQuery[i];
            if(count === 0){
                build += "?"+i+"="+elem;
            }else build += "&"+i+"="+elem;
            count++;
        }
    }
    fetch(strings.backendUrl+owner+"/"+action+build).then(
        response=> response.json()
    ).then(response=>{
        if(callback) callback(response)
    });
}
//remove
export async function fetchPost(owner, action, options, callback, query = {}){
    const USERID = _retrieveData(Manager.userIdAlias);
    const TOKEN = _retrieveData(Manager.tokenAlias);
    const stringQuery = {userId : USERID, token : TOKEN, ...query}; //this.getStoredUserInfo();
    let count = 0;
    let build = "";
    for (const i in stringQuery) {
        if (stringQuery.hasOwnProperty(i)) {
            const elem = stringQuery[i];
            if(count === 0){
                build += "?"+i+"="+elem;
            }else build += "&"+i+"="+elem;
            count++;
        }
    }
    fetch(strings.backendUrl+owner+"/"+action+build, options).then(
        response=> response.json()
    ).then(response=>callback(response))
    .catch(e => {
        console.log(e);
    });
}
