export function post(data, owner, action, callback, query){
    fetchPost(owner, action, {
        method : "post",
        headers : {
            "Content-Type" : "Application/json"
        },
        body : JSON.stringify(data)
    }, callback, query);
}


export const onEnterPress = action => event => {
    if (event.key === 'Enter') {
        event.preventDefault();
        event.stopPropagation();
        if(action)
            action();
    }
}
export function _storeData(type, payload){
    if(!payload || !type) return;
    localStorage.setItem(String(type), String(payload));
}
export function _retrieveData(name){
    return localStorage.getItem(name);
}
export const customSuperSetState = context=>{
    return function(first, callback){
        if(first instanceof Function){
            if(!context.state)
                throw("The component has no state");
            else{
                var newStateObject = first(context.state);
                context.setState(newStateObject)
            }
        }else {
            context.setState(first);
            if(callback) callback();
        }
    }
}
export const cipher = salt => {
    let textToChars = text => text.split("").map(c => c.charCodeAt(0));
    let byteHex = n => ("0" + Number(n).toString(16)).substr(-2);
    let applySaltToChar = code => textToChars(salt).reduce((a, b)=> a ^ b, code);
    return text => text.split("")
        .map(textToChars)
        .map(applySaltToChar)
        .map(byteHex)
        .join("");
}
export const decipher = salt => {
    let textToChars = text => text.split("").map( c => c.charCodeAt(0));
    // let saltChars = textToChars(salt);
    let applySaltToChar = code => textToChars(salt).reduce((a, b) => a ^ b, code);
    return encoded => encoded.match(/.{1,2}/g)
        .map(hex => parseInt(hex, 16))
        .map(applySaltToChar)
        .map(charCode => String.fromCharCode(charCode))
        .join("");
}
