export const inovateOSUtilStrings = {
    theme : "theme",
    tokenAlias : "tokenAlias",
    isLoggedIn : "isLoggedIn",
    userAlias : "userAlias",
    backendUrl : "backendUrl",
    backendBaseUrl : "backendBaseUrl",
    myProfile : "myProfile",
    settings : "settings",
    forms : "forms",
    subheadImage : "subheadImage",
    carousel : "carousel",
}

export const inovateOSUtilConstants = {
    SET_UTIL : "SET_UTIL",
}

export const inovateOSUtilReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case inovateOSUtilConstants.SET_UTIL : 
            return {...state, ...payload};
        default : return {...state};
    }
}

