import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { Grid, colors as mColors} from "@material-ui/core";
import { colors } from '../../../utils';
const style = theme => ({
    root: {
        marginBottom : 20,
    },
    info : {
        backgroundColor : "#CDDC39",
        padding : 10,
        borderRadius : 10
    },
    outlined : {
        padding : 10,
        borderRadius : 10,
        border : "solid 1px #CDDC39",
        backgroundColor : colors.gainsboro
    }
})
class _SelectedInfo extends Component {
    render() {
        const {classes, selectedInfo, skip, outlined, nameMapping, valueMapping} = this.props;
        if(!skip) throw("_SelectedInfo must have a SKIP prop - use empty array if none");
        if(!nameMapping) throw("Missing name mapper");
        return (
            <div className={classes.root}>
                {selectedInfo && <div className={outlined ? classes.outlined : classes.info}>
                    <Grid container spacing={2}>
                        {selectedInfo && Object.entries(selectedInfo).map((info, index)=>{
                            return skip && skip.indexOf(info[0]) === -1 ? <Grid key={index} item xs={12} sm={6} md={4} lg={3} xl={3}>
                                <strong style={{color : colors.gray}}>{nameMapping(info[0])}: </strong> 
                                    {valueMapping ? valueMapping(info[0], info[1]) : info[1]}
                            </Grid> : null
                        })}
                    </Grid>
                </div>}
            </div>
        );
    }
}
_SelectedInfo.propTypes = {
    classes : PropTypes.object.isRequired,
    selectedInfo : PropTypes.object,
    nameMapping : PropTypes.func.isRequired,
    valueMapping : PropTypes.func,
    skip : PropTypes.array,
    outlined : PropTypes.bool,
};
export const SelectedInfo = withStyles(style)(_SelectedInfo);