import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {Link} from 'react-router-dom';
import {withStyles} from '@material-ui/core/styles';
import { ServiceBox } from './ServiceBox';
import { inovateOSUtil, inovateOSUtilStrings } from '../../../utils';
import $ from 'jquery';
import { inovateOSPageStrings } from '../../config';
import { inovateOSPageActions } from '../../actions';
import { Typography } from '@material-ui/core';
import { inovateOSRouteNames } from '../../../routeNames';


const style = theme => ({
    root: {
        position : "relative",
        width : "100%",
        minHeight : 600,
    },
    overlay : {
        paddingTop : 100,
        paddingBottom : 100,
        position : "absolute",
        width : "100%",
        backgroundColor : "#5355e4a6",
        minHeight : 400,
    },
    headerContainer : {
        display : "flex",
        justifyContent : "center",
    },
    header : {
        width : "fit-content",
        color : inovateOSUtil.getTheme().secondary,
        borderBottom : "solid 5px " + inovateOSUtil.getTheme().primary,
        marginBottom : 50,
        fontWeight : "bold",
        fontFamily : "sans-serif",
        textTransform : "uppercase",
    },
    container : {
        padding : 20,
    },
    allServicesLink : {
        textDecoration : "none",
        padding : 10,
        borderRadius : 10,
        backgroundColor : inovateOSUtil.getTheme().secondary,
        color : inovateOSUtil.getTheme().wheat,
    }
})
class _ServiceArea extends Component {
    state = {
        height : 400,
    }
    componentDidMount() {
        setTimeout(()=>{
            $("#serviceOverlayRoot").css("height", (parseInt($("#serviceOverlayContainer").css("height").replace("px", ""))+200) + "px");
        }, 2000);
        window.onresize = e=>{
            $("#serviceOverlayRoot").css("height", (parseInt($("#serviceOverlayContainer").css("height").replace("px", ""))+200) + "px");
        };
        const {
            dispatch,
            [inovateOSPageStrings.services] : services
        } = this.props;
        if(!services) inovateOSPageActions.getServices()(dispatch);
    }
    
    render() {
        const {
            classes,
            [inovateOSPageStrings.services] : services,
            [inovateOSUtilStrings.backendBaseUrl] : baseUrl,
            [inovateOSUtilStrings.subheadImage] : subheadImage,
        } = this.props;
        const count = this.props.count || 4
        return (
            <div id="serviceOverlayRoot" className={classes.root} style={{
                height : this.state.height,
                background : "url('"+subheadImage+"') center center /cover",
            }}>
                <div id="serviceOverlayContainer" ref={e=>this.overlayRef = e} className={classes.overlay}>
                    <div className={classes.container}>
                        <div className={classes.headerContainer}>
                            <Typography variant="h4" className={classes.header} paragraph>
                                Services
                            </Typography>
                        </div>
                        {services && services.map((item, index)=>{
                            return count - 1 >= index ? <ServiceBox 
                                key={index}
                                itemProps={{
                                    image : item.src,
                                    baseUrl : baseUrl,
                                    text : item.body && item.body[0] ? item.body[0] : null,
                                    header: item.header
                                }}
                                left={index % 2 === 0}
                                /> : null
                        })}
                        <div style={{
                            display : "flex",
                            flexGrow : 1,
                        }}/>
                        <div>
                            <Link to={inovateOSRouteNames.services} className={classes.allServicesLink}>All Services</Link>
                        </div>
                    </div>
                </div>
            </div>
        );
    }
}


_ServiceArea.propTypes = {
    classes : PropTypes.object.isRequired,
    count : PropTypes.number,
};
const mapStateToProps = ({inovateOSPageReducer, inovateOSUtilReducer}) => ({
    [inovateOSPageStrings.services] : inovateOSPageReducer[inovateOSPageStrings.services],
    [inovateOSUtilStrings.backendBaseUrl] : inovateOSUtilReducer[inovateOSUtilStrings.backendBaseUrl],
    [inovateOSUtilStrings.subheadImage] : inovateOSUtilReducer[inovateOSUtilStrings.subheadImage],
})


export const ServiceArea = connect(mapStateToProps)(withStyles(style)(_ServiceArea));
export {ServiceArea as default}