import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import {connect} from 'react-redux';
import { Typography, TableCell } from '@material-ui/core';
import { MyListCard, MyTable } from '../../../includes';
import { patientNameMapper } from '../../HIRPatients/patientNameMapper';
import ReactToPrint from 'react-to-print';
import { hirUtil } from '../../utils';
import { hirSettingStrings, hirSettingActions } from '../../HIRSettings/config';
import { hirAccountActions } from '../actions';
const style = theme => ({
    root: {
        width : 300,
        padding :10
    },
    bodyContainer : {

    },
    header : {
        fontWeight : "bold",
        textAlign : "center",
    },
    subHeader : {
        display : "block",
        fontSize : 11,
    },
    row : {
        display : "flex",
        width : "100%",
    },
    nameContainer : {
        width : "40%"
    },
    name : {
        fontWeight : "bold",
        fontSize : 12,
    },
    valueContainer : {
        width : "60%"
    },
    value : {
        fontSize : 12
    },
    printContainer : {
        display : 'flex',
        justifyContent : "center",
        marginTop : 20,
    },
    print : {
        backgroundColor : hirUtil.getTheme().primary,
        padding : 20,
        borderRadius : 20,
        fontSize : 14,
        color : hirUtil.getTheme().white,
    },
    printable : {
        marginBottom : 20,
        borderBottom : "solid 1px",
    },
    cell : {
        padding : 5,
    }
})
class _HIRReceiptMultiple extends Component {
    state = {
        paymentList : []
    }
    componentDidMount() {
        const {payment} = this.props;
        hirAccountActions.getPaymentGroup(payment.groupId, (done, result, message)=>{
            console.log(done, result, message);
            this.setState({paymentList : result})
        });
    }
    
    listComponent(item){
        const {classes} = this.props;
        return <div className={classes.itemContainer}>
            <div className={classes.item}>
                <strong>{patientNameMapper(item.name)}</strong> : 
            </div>
            <div className={classes.item}>
                {patientNameMapper(item.value)}
            </div>
        </div>
    }
    nameMapper(name){
        switch(name){
            case "actionDate" : return "Date";
            case "patientId" : return "PID";
            case "_id" : return "Transaction ID";
            case "name" : return "Name"
            case "amount" : return "Amount";
            case "revenueType" : return "Purpose";
            case "groupId" : return "Group ID";
            default : return name;
        }
    }
    valueMapper(name, value){
        const {
            [hirSettingStrings.settings] : settings 
        } = this.props;
        switch(name){
            case "patientId" : return String(value).padStart(6, "0");
            case "actionDate" : return new Date(value).toDateString();
            case "amount" : return Number(value).toLocaleString();
            case "revenueType" : 
                let iValue = value;
                if(settings){
                    const revenue = settings.find(item=>item.name === "revenue");
                    if(revenue && revenue.values){
                        const rOptions = revenue.values.find(item=>item.name === value);
                        if(rOptions) iValue = rOptions.value;
                    }
                }
                return iValue;
            default : return value;
        }
    }
    cellMapFormat = ({row, cellMap}) => {
        const {classes, [hirSettingStrings.settings]: settings} = this.props;
        if(row.total){
            switch(cellMap){
                case "amount" : return <TableCell className={classes.cell}>
                    <strong>{Number(row.total).toLocaleString()}</strong>
                </TableCell>
                case "revenueType" :return <TableCell className={classes.cell}>
                    <strong>Total</strong>
                </TableCell>
            }
        }else{
            switch(cellMap){
                case "amount" : return <TableCell className={classes.cell}>
                    {Number(row[cellMap]).toLocaleString()}
                </TableCell>
                case "revenueType" : return <TableCell style={{width : "56%"}} className={classes.cell}>
                    {hirSettingActions.getSettingValue(settings, "revenue", row[cellMap])}
                </TableCell>
                default : return <TableCell className={classes.cell}>
                    {row[cellMap]}
                </TableCell>
            }
        }
    }
    render() {
        const {classes, payment} = this.props;
        let {paymentList} = this.state;
        let total = 0;
        if(paymentList){
            for (let i = 0; i < paymentList.length; i++) {
                const pay = paymentList[i];
                total += parseInt(pay.amount);
            }
            paymentList = [...paymentList, {total}];
        }
        return (
            <div  className={classes.root}>
                <div className={classes.printable} style={{width : 300}} ref={e=>this.printComponent = e}>
                    <Typography paragraph className={classes.header}>
                        ST. MARY'S CHILDREN AND COMMUNITY HOSPITAL, UMUOWA
                        <Typography component="i" className={classes.subHeader}>
                            07034656479
                            08052972747
                        </Typography>
                    </Typography>
                    <Typography paragraph className={classes.header}>
                        Receipt
                    </Typography>
                    <div className={classes.bodyContainer} style={{marginBottom : 10}}>
                    {payment && Object.entries(payment).map((item, i)=>{
                        const name = item[0];
                        const value = item[1];
                        if(["staff", "by", "year", "month", "day", "revenueType"].indexOf(name) !== -1) return null;
                        return <div className={classes.row} key={i}>
                            <div className={classes.nameContainer}>
                                <Typography className={classes.name}>
                                    {this.nameMapper(name)}
                                </Typography>
                            </div>
                            <div className={classes.valueContainer}>
                                <Typography className={classes.value}>
                                    {this.valueMapper(name, value)}
                                </Typography>
                            </div>
                        </div>
                    })}
                    </div>
                    {paymentList &&  <div style={{marginTop : 10}}>
                            <MyTable
                                elevation={0}
                                header={["Description", "Amount (N)"]}
                                dataMap={["revenueType", "amount"]}
                                data={paymentList}
                                CellMap={this.cellMapFormat.bind(this)}
                                />
                        </div>
                    }
                </div>
                <div className={classes.printContainer}>
                    <ReactToPrint 
                        trigger={()=><button className={classes.print}>Print Receipt</button>}
                        content={()=>this.printComponent}
                    />
                </div>
            </div>
        );
    }
}
_HIRReceiptMultiple.propTypes = {
    classes : PropTypes.object.isRequired,
    payment : PropTypes.object,
};
const mapStateToProps = ({hirSettingReducer}) => ({
    [hirSettingStrings.settings] : hirSettingReducer[hirSettingStrings.settings],
})
export const HIRReceiptMultiple = connect(mapStateToProps)(withStyles(style)(_HIRReceiptMultiple));