import { subjectStrings, subjectConstants } from "./config";
import { subjectServices } from "./services";
import { callbackThrowable } from "../../../utils";
import { sessionServices } from "../Sessions";
import { timeTableServices } from "../TimeTable/config";

export const subjectActions = { 
    getTimeTableDurationFormat : (levelId, termId, callback)=>dispatch=>{
        timeTableServices.getTimeTableDurationFormat(levelId, termId, (done, result, message)=>{
            if(done) dispatch({
                type : subjectConstants.SET_SUBJECT,
                payload : {
                    [subjectStrings.timeTableDurationFormat] : result,
                }
            });
            if(callback) callback(true, result, message);
        })
    },
    setTimeTableEditeMode : mode => dispatch => dispatch({
        type : subjectConstants.SET_SUBJECT,
        payload : {
            [subjectStrings.timeTableEditMode] : mode
        }
    }),
    setSubjedTeacherEditMode : mode => dispatch => dispatch({
        type : subjectConstants.SET_SUBJECT,
        payload : {
            [subjectStrings.subjedTeacherEditMode] : mode
        }
    }),
    getLevelClasses : (levelId, callback) => dispatch => {
        sessionServices.getClasses(levelId, (done, result, message)=>{
            if(done) dispatch({
                type : subjectConstants.SET_SUBJECT,
                payload : {
                    [subjectStrings.selectedLevelClasses] : result
                }
            })
            if(callback) callback(done, result, message);
        })
    },
    setViewUseClassFlter : viewUseClassFilter => dispatch=>dispatch({
        type : subjectConstants.SET_SUBJECT,
        payload : {
            [subjectStrings.viewUseClassFlter] :viewUseClassFilter
        }
    }),
    getSubjectAssessments : (levelId, callback) => dispatch=> {
        subjectServices.getSubjectAssessments(levelId, (done, result, message)=>{
            if(done) dispatch({
                type : subjectConstants.SET_SUBJECT,
                payload : {
                    [subjectStrings.subjectAssessments] : result
                }
            });
            if(callback) callback(done, result, message);
        });
    },
    getSubjectClassStudents_NO_DISPATCH : (levelId, termId, classId, callback)=>{
        callbackThrowable(callback, "getSubjectClassStudents_NO_DISPATCH");
        subjectServices.getSubjectClassStudents(levelId, termId, classId, callback);
    },
    getSubjectLevelClassStudents : (levelId, classId, callback)=>dispatch=>{
        subjectServices.getSubjectClassStudents(levelId, classId, (done, result, message)=>{
            if(done) subjectActions.setSubjectStudents(result)(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getSubjectLevelStudents : (levelId, callback)=> dispatch => {
        subjectServices.getSubjectLevelStudents(levelId, (done, result, message)=>{
            if(done) subjectActions.setSubjectStudents(result)(dispatch);
            if(callback) callback(done, result, message);
        });
    },
    setSubjectStudents : students => dispatch => dispatch({
        type : subjectConstants.SET_SUBJECT,
        payload : {
            [subjectStrings.subjectStudents] : students
        }
    }),
    getAllSubjects : (lastId, row, callback) => dispatch => {
        subjectServices.getAllSubjects(lastId, row, (done, result, message)=>{
            if(done) subjectActions.setSubjects(result)(dispatch);
            if(callback) callback(done, result, message);
        });
    },
    setSubjects : subjects => dispatch =>dispatch({
        type : subjectConstants.SET_SUBJECT,
        payload : {
            [subjectStrings.subjects] : subjects
        }
    }),
    setSubjectCount : count => dispatch => dispatch({
        type : subjectConstants.SET_SUBJECT,
        payload : {
            [subjectStrings.subjectCount] : count
        }
    }),
    setUsePreviousSubjects : usePreviousSubjects => dispatch=>dispatch({
        type : subjectConstants.SET_SUBJECT,
        payload : {
            [subjectStrings.usePreviousSubjects] : usePreviousSubjects
        }
    }),
    setSelectedTerm : isTerminatorless => dispatch => dispatch({
        type : subjectConstants.SET_SUBJECT,
        payload : {
            [subjectStrings.selectedTerm] : isTerminatorless
        } 
    }),
    setSelectedLevel : level => dispatch => dispatch({
        type : subjectConstants.SET_SUBJECT,
        payload : {
            [subjectStrings.selectedLevel] : level
        } 
    }),
    setSubjectFilter : filter =>dispatch=>dispatch({
        type : subjectConstants.SET_SUBJECT,
        payload : {
            [subjectStrings.subjectFilter] : filter
        } 
    })
}