import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, mainStageHeaderAction, MyTable, HighlightedInfo } from '../../includes';
import { routeName, colors } from '../../../utils';
import { payrollStrings } from '../config';
import { payrollActions } from '../actions';
import { history } from '../../../helpers';
import { Checkbox, FormControlLabel, TableCell, FormControl, Typography, Button } from '@material-ui/core';


const style = theme => ({
    root: {
        marginTop : 20
    },
    cell : {
        padding : 5, 
        paddingLeft : 10
    }
})
class _PayCenter extends Component {
    constructor(props) {
        super(props);
        this.state = {
            lastId : null,
            rows : null,
            payrollEmployeeBrief : null,
            tableData : null,
            checkedAll : false,
            numberOfEmployees : 0,
            totalAmount : 0,
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "PAYROLL (PAY CENTER)",
            [headerStrings.backButtonAction] : null
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeName.dashboard},
            {name : "Payroll (Pay Center)", path : routeName.payrollPayCenter},
        ])(dispatch);
        mainStageHeaderAction({})(dispatch);
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {
            dispatch,
            [payrollStrings.payrollBenefits] : payrollBenefits,
            [payrollStrings.payrollDeductions]: payrollDeductions,
        } = this.props;
        const {
            lastId, rows
        } = this.state;
        payrollActions.getPayrollEmployeeBrief(lastId, rows)(dispatch);
        payrollActions.getPayrollEmployeeCount()(dispatch);
        if(!payrollBenefits)
            payrollActions.getPayrollBenefits()(dispatch);
        if(!payrollDeductions)
            payrollActions.getPayrollDeductions()(dispatch);
    }
    static getDerivedStateFromProps(props, state) {
        const {
            [payrollStrings.payrollBenefits] : payrollBenefits,
            [payrollStrings.payrollDeductions] : payrollDeductions,
            [payrollStrings.payrollEmployeeBrief] : payrollEmployeeBrief,
        } = props;
        // if(payrollBenefits && payrollDeductions && payrollEmployeeBrief){
        if(!state.payrollEmployeeBrief){
            state.payrollEmployeeBrief = payrollEmployeeBrief;
            state.tableData = PayCenter.generateTableData(
                payrollEmployeeBrief, payrollBenefits, payrollDeductions
            );
        }else if(JSON.stringify(state.payrollEmployeeBrief) !==
        JSON.stringify(payrollEmployeeBrief)){
            state.payrollEmployeeBrief = payrollEmployeeBrief;
            state.tableData = PayCenter.generateTableData(
                payrollEmployeeBrief, payrollBenefits, payrollDeductions
            );
        }
        // }
        return state;
    }
    static generateTableData(payrollEmployeeBrief, payrollBenefits, payrollDeductions){
        let data = [];
        if(payrollEmployeeBrief) for (let i = 0; i < payrollEmployeeBrief.length; i++) {
            const emp = payrollEmployeeBrief[i];
            const {_id, bioInfo, salary} = emp;
            let dataInfo = {
                _id, fullName : bioInfo.fullName
            };
            //not all the deduction or benefits are active 
            //hence get the new deduction and benefit you are paying (active)
            if(salary){
                let deducedAmount = 0;
                let benefitAmount = 0;
                const {gross, deductionIds, benefitIds} = salary;
                dataInfo.gross = gross;
                dataInfo.deductionIds = [];
                dataInfo.benefitIds = [];
                if(payrollDeductions && deductionIds) for (let j = 0; j < deductionIds.length; j++) {
                    const deductId = deductionIds[j];
                    const deductIdInfo = payrollDeductions.getFirstObjectByPropValue("_id", deductId);
                    if(deductIdInfo && deductIdInfo.item){
                        const {_id, usePercentage, amount, percent, active} = deductIdInfo.item;
                        if(!active) continue;
                        dataInfo.deductionIds.push(_id);
                        if(usePercentage){
                            deducedAmount += (Number(percent) / 100) * Number(gross);
                        }else{
                            deducedAmount += Number(amount);
                        }
                    }
                }
                if(payrollBenefits && benefitIds) for (let j = 0; j < benefitIds.length; j++) {
                    const benefitId = benefitIds[j];
                    const benefitIdInfo = payrollBenefits.getFirstObjectByPropValue("_id", benefitId);
                    if(benefitIdInfo && benefitIdInfo.item){
                        const {_id, usePercentage, amount, percent, active} = benefitIdInfo.item;
                        if(!active) continue;
                        dataInfo.benefitIds.push(_id);
                        if(usePercentage){
                            benefitAmount += (Number(percent) / 100) * Number(gross);
                        }else{
                            benefitAmount += Number(amount);
                        }
                    }
                }
                dataInfo.net = Number(gross) - deducedAmount + benefitAmount;
            }
            data.push(dataInfo);
        }
        return data;
    }
    checkAllEmployees = e => {
        const checked = e.target.checked;
        let tableData = [...this.state.tableData];
        let numberOfEmployees = this.state.numberOfEmployees || 0;
        let totalAmount = this.state.totalAmount || 0;
        if(tableData) for (let i = 0; i < tableData.length; i++) {
            const emp = tableData[i];
            tableData[i] = {...emp, checked};
            if(checked){
                totalAmount += Number(emp.net);
                numberOfEmployees++;
            }else{
                totalAmount -= Number(emp.net);
                numberOfEmployees--;
            }
        }
        this.setState({tableData, checkedAll: checked, totalAmount, numberOfEmployees});
    }
    customeHeader = ({item})=>{
        const {classes} = this.props;
        const {checkedAll} = this.state;
        switch(item){
            case "checked" : return <TableCell className={classes.cell}>
                <FormControlLabel
                    control={<Checkbox checked={checkedAll} size="small" onClick={this.checkAllEmployees.bind(this)}/>}
                    label="All"/>
                </TableCell>
            default : return <TableCell  className={classes.cell}>
                {item}
            </TableCell>;
        }
    }
    rowActoinHandler = row => () => {
        history.push(routeName.payrollEmployeeInfo_ + row._id, {row});
    }
    checkEmployee = row => (e)=> {
        e.stopPropagation();
        const checked = e.target.checked;
        let tableData = [...this.state.tableData];
        let totalAmount = this.state.totalAmount || 0;
        let numberOfEmployees = this.state.numberOfEmployees || 0;
        if(tableData){
            let {item, index} = tableData.getFirstObjectByPropValue("_id", row._id);
            tableData[index] = {...tableData[index], checked }
            if(checked){
                totalAmount += item.net;
                numberOfEmployees++;
            }else{
                totalAmount -= item.net;
                numberOfEmployees--;
            }
            this.setState({tableData, totalAmount, numberOfEmployees})
        }
    }
    cellMapFormat = ({row, cellMap}) => {
        const {classes} = this.props;
        switch(cellMap){
            case "checked" : return <TableCell className={classes.cell}>
                <FormControl>
                    <Checkbox size="small" onClick={this.checkEmployee(row)} checked={row[cellMap]}/>
                </FormControl>
            </TableCell>;
            case "net" :
            case "gross" : return <TableCell className={classes.cell}>
                {Number(row[cellMap]).toLocaleString()}
            </TableCell>
            default : return <TableCell className={classes.cell}>
                {row[cellMap]}
            </TableCell>
        }
    }
    render() {
        const {
            classes,
            [payrollStrings.payrollEmployeeCount] : employeeCount
        } = this.props;
        const {tableData, totalAmount, numberOfEmployees} = this.state;
        return (
            <div className={classes.root}>
                <HighlightedInfo closable>
                    The employee table contains only ACTIVE employees
                </HighlightedInfo>
                <HighlightedInfo type="secondary">
                    <Typography><span style={{fontWeight : "bold"}}>Employees :</span> {numberOfEmployees} / {employeeCount}</Typography>
                    <Typography><span style={{fontWeight : "bold"}}>Total Amount :</span> N {Number(totalAmount).toLocaleString()}</Typography>
                </HighlightedInfo>
                <div style={{display : "flex", flexDirection : "row", marginBottom : 10}}>
                    <div style={{display : "flex", flexGrow : 1}}/>
                    <Button disabled={numberOfEmployees === 0} variant="contained" color="primary">Pay</Button>
                </div>
                <MyTable
                    title="Select Employees to pay"
                    titleProps={{style : {color : colors.secondary}}}
                    header={["checked", "ID", "Name", "Gross (N)", "Net (N)"]}
                    CustomHeader={this.customeHeader.bind(this)}
                    dataMap={["checked", "_id", "fullName", "gross", "net"]}
                    data={tableData || []}
                    CellMap={this.cellMapFormat.bind(this)}
                    rowAction={this.rowActoinHandler.bind(this)}
                    />
            </div>
        );
    }
}


_PayCenter.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({payrollReducer}) => ({
    [payrollStrings.payrollBenefits] : payrollReducer[payrollStrings.payrollBenefits],
    [payrollStrings.payrollDeductions] : payrollReducer[payrollStrings.payrollDeductions],
    [payrollStrings.payrollEmployeeBrief] : payrollReducer[payrollStrings.payrollEmployeeBrief],
    [payrollStrings.payrollEmployeeCount] : payrollReducer[payrollStrings.payrollEmployeeCount],
})


export const PayCenter = connect(mapStateToProps)(withStyles(style)(_PayCenter));
export {PayCenter as default}