export const payableStrings = {

}
export const payableConstants = {
    SET_PAYABLE : "SET_PAYABLE",
    CLEAN_UP_PAYABLE :"CLEAN_UP_PAYABLE",
}
const payableInitialState = {

}
export const payableReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case payableConstants.SET_PAYABLE : 
            return {...state, ...payload};
        case payableConstants.CLEAN_UP_PAYABLE : 
            return {...state, ...payableInitialState}
        default : return {...state};
    }
}
export * from './actions';
export * from './services';
