import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { TableCell, FormControl, InputLabel, Select, MenuItem } from '@material-ui/core';


const style = theme => ({
    root: {
    }
})
class _StudentRemarkCellFormat extends Component {
    constructor(props) {
        super(props);
        this.state = {
            name : props.cellMap,
            value : props.row[props.cellMap]
        }
    }
    handleSelectChange= row => e=>{
        const value = e.target.value;
        this.setState({value : value});
        this.props.remarkChangeHandler(row._id, value);
    }
    render() {
        const {classes, cellMap, row, selectOptions} = this.props;
        switch(cellMap){
            case "remarkId" : return <TableCell>
                    <FormControl>
                        {/* <InputLabel htmlFor="remark-option">Remark</InputLabel> */}
                        <Select
                            onChange={this.handleSelectChange(row)}
                            value={this.state.value}
                            inputProps={{
                                id : "remark-option"
                            }}>
                                {selectOptions && selectOptions.map((item, index)=>
                                <MenuItem key={index} value={item._id}>{item.short}</MenuItem>)}
                            </Select>
                    </FormControl>
                </TableCell>
            default : return <TableCell>
                <FormControl>
                    {row[cellMap]}
                </FormControl>
            </TableCell>
        }
    }
}


_StudentRemarkCellFormat.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapDispatchToProps = dispatch => {
    return {
        dispatch
    }
}
const mapStateToProps = state => ({
    state
})


export const StudentRemarkCellFormat = connect(mapStateToProps,mapDispatchToProps)(withStyles(style)(_StudentRemarkCellFormat));