export const PrivateRoutePlane = ({component, ...props}) => (
    <Route {...props} render={props => { 
        return (true //Manager.hasLoggedIn()
            ? <Fragment>
                <Screen {...props} component={component}/> 
                <ChatFooter/>
            </Fragment>
            : <Redirect to={{ pathname: '/'+strings.login, state: { from: props.location } }} />
        )}
    } />
)
export const LogoutRoute = rest =>(
    <Route {...rest} render={props=>{
        appActions.logout()(store.dispatch);
        return <Redirect to={{ pathname: '/login', state: { from: props.location } }}/> 
    }}/>
)