import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyCustomTabs, mainStageHeaderAction, mainStageHeaderStrings } from '../../includes';
import { EmployeeList } from './EmployeeList';
import { payrollActions } from '../actions';
import EmployeeHeaderComponent from './EmployeeHeaderComponent';
import EmployeeStatus from './EmployeeStatus/EmployeeStatus';


const style = theme => ({
    root: {
        marginTop : 20
    }
})
class _Employees extends Component {
    constructor(props) {
        super(props);
        this.state = {
            tabValue : null,
        }
        const {dispatch} = this.props;
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                EmployeeHeaderComponent
            ]
        })(dispatch);
        this.updateTabComponent = this.updateTabComponent.bind(this);
    }
    updataTabValue = tabValue => {
        this.setState({tabValue});
        const {dispatch} = this.props;
        payrollActions.updateEmployeeTabValue(tabValue)(dispatch);
    }
    updateTabComponent = tabComponent => {
        const {dispatch} = this.props;
        payrollActions.updatePayrollEmployeeTabComponent(tabComponent)(dispatch);
    }
    render() {
        const {classes} = this.props;
        const { tabValue } = this.state;
        return (
            <div className={classes.root}>
                <MyCustomTabs
                    position="sticky"
                    tabs={{
                        emp : "Employess",
                        empStatus : "Employee status",
                    }}
                    getInitialTabValue={this.updataTabValue.bind(this)}
                    />
                <div style={{marginTop : 20}}>
                    {tabValue === "emp" && <EmployeeList
                        getContext={this.updateTabComponent}/>}
                    {tabValue === "empStatus" && <EmployeeStatus
                        getContext={this.updateTabComponent}/>}
                </div>
            </div>
        );
    }
}


_Employees.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = state => ({
    state
})


export const Employees = connect(mapStateToProps)(withStyles(style)(_Employees));
export {Employees as default}