import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { TableCell } from '@material-ui/core';
import { hirRouteNames } from '../../routeNames';
import { MyTable, history } from '../../utils';


const style = theme => ({
    root: {
        width : "100%",
    },
    cell : {
        padding : 5,
        fontSize : 11,
    }
})
class _HIRPatientList extends Component {
    cellMapFormat = superProps => ({row, cellMap}) => {
        const {classes} = this.props;
        const {myProfile} = row;
        switch(cellMap) {
            case "gender" : return <TableCell className={classes.cell}>
                {myProfile[cellMap] && (myProfile[cellMap] === "m" ? "Male" : "Female")}
            </TableCell>
            case "age" : 
                const age = new Date().getFullYear() - new Date(myProfile.dob).getFullYear()
                return <TableCell className={classes.cell}>
                    {age === 0 ? "< 1" : String(age)}
            </TableCell>
            case "name" : 
                let lastName, firstName, middleName;
                if(myProfile){
                    lastName = myProfile.lastName;
                    firstName = myProfile.firstName;
                    middleName = myProfile.middleName;
                }
                return <TableCell className={classes.cell}>
                <strong>{lastName}</strong>, {
                (firstName ? firstName : "") + " " +(middleName ? middleName : "")}
            </TableCell>
            case "phone" : return <TableCell className={classes.cell}>
                {myProfile.phone}
            </TableCell>
            case "_id" : return <TableCell className={classes.cell}>
                {String(row[cellMap]).padStart(6, "0")}
            </TableCell>
            default : return <TableCell className={classes.cell}>
                {myProfile[cellMap]}
            </TableCell>
        }
    }
    rowAction = row => () => {
        history.push({pathname : hirRouteNames.patientView_+row._id, state : row});
    }
    render() {
        const {classes, patients} = this.props;
        return (
            <div className={classes.root}>
                <MyTable
                    elevation={0}
                    header={["ID", "Old ID", "Name", "Gender", "Age", "Phone"]}
                    dataMap={["_id", "oldId", "name", "gender", "age", "phone"]}
                    data={patients}
                    rowAction={this.rowAction.bind(this)}
                    CellMap={this.cellMapFormat({
                    })}
                    {...this.props.tableProps}/>
            </div>
        );
    }
}


_HIRPatientList.propTypes = {
    classes : PropTypes.object.isRequired,
    patients : PropTypes.array,
    tableProps : PropTypes.shape(MyTable.propTypes),
};


export const HIRPatientList = withStyles(style)(_HIRPatientList);
export {HIRPatientList as default}