import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { IconButton, Checkbox, FormControlLabel, Typography, CircularProgress, TableCell } from '@material-ui/core';
import { CalendarToday } from '@material-ui/icons';
import Calendar from 'react-calendar';
import { HIRButton } from '../../Includes';
import { hirAccountActions } from '../actions';
import { hirAccountStrings } from '../config';
import { hirSettingStrings, hirSettingActions } from '../../HIRSettings/config';
import { hirMonthSelections as monthSelections, MyTable, MyDialog, history } from "../../utils";
import { hirRouteNames } from '../../routeNames';
import ReactToPrint from 'react-to-print';


const style = theme => ({
    root: {
    },
    header : {
        color : theme.colors.primary,
        fontWeight : "bold",
    },
    progress : {
        width : "30px !important",
        height : "30px !important",
    },
    cell : {
        fontSize : 11, 
        padding : 5,
    }
})
class _HIRRevenueList extends Component {
    constructor(props) {
        super(props);
        this.state = {
            monthOnlyView : false,
            calenderDialog : false,
            dateSearchBtnLoading : false,
            searchDate : new Date(),
        }
    }
    componentDidMount() {
        this.searchByDate();
        const {dispatch, [hirSettingStrings.settings] : settings} = this.props;
        if(!settings)
            hirSettingActions.getSettings()(dispatch);

    }
    
    onChange(e){
        const value = e.target.checked;
        this.setState({monthOnlyView : value},()=>{
            this.searchByDate();
        });
    }
    searchByDate(fromCalenderDialog){
        const {searchDate, monthOnlyView} = this.state;
        const {dispatch}=this.props;
        if(fromCalenderDialog){
            this.setState({dateSearchBtnLoading : true});
        }
        if(searchDate){
            const date = new Date(searchDate);
            hirAccountActions.getRevenuePaymentsByDate(
                date.getFullYear(), 
                date.getMonth() + 1,
                fromCalenderDialog ? date.getDate() :
                (monthOnlyView ? null : date.getDate()),
                (done, result, message)=>{
                    this.setState({dateSearchBtnLoading : false});
                    if(done && fromCalenderDialog) 
                        this.setState({calenderDialog : false, monthOnlyView : false});
                }
            )(dispatch);
        }
    }
    cellMapFormat = ({row, cellMap})=>{
        const {
            classes,
            [hirSettingStrings.settings] : settings
        } = this.props;
        if(row.lastLine){
            switch(cellMap){
                case "_id" : return <TableCell className={classes.cell}>
                    <strong>Total</strong>
                </TableCell>;
                case "total" : return <TableCell className={classes.cell}>
                    <strong>{Number(row.total).toLocaleString()}</strong>
                </TableCell> 
                default : return <TableCell className={classes.cell}>
                    {row[cellMap]}
                </TableCell>
            }
        }else{
            switch(cellMap){
                case "_id" : 
                    let value = "";
                    if(settings){
                        const setting = settings.find(item=>item.name === "revenue");
                        if(setting && setting.values){
                            if(!this.revenueCat) this.revenueCat = setting.values;
                            const option = setting.values.find(item=>item.name === row[cellMap]);
                            if(option) value = option.value;
                        }
                    }
                    return <TableCell className={classes.cell}>
                        {value}
                </TableCell>
                case "total" : return <TableCell className={classes.cell}>
                    {Number(row[cellMap]).toLocaleString()}
                </TableCell>
                default : return <TableCell className={classes.cell}>
                    {row[cellMap]}
                </TableCell>
            }
        }
    }
    rowAction = row=>()=>{
        if(row.lastLine) return;
        const {monthOnlyView, searchDate} = this.state
        history.push(
            hirRouteNames.accountViewPaymentDetail, 
            {
                name : row._id, type : "revenue",
                monthOnlyView, date : searchDate,
                revenueCats : this.revenueCat
            }
        )
    }
    render() {
        let {
            classes,
            [hirAccountStrings.revenueBasedPayments] : revenuePayments,
        } = this.props;
        let {monthOnlyView, calenderDialog, dateSearchBtnLoading, searchDate : date} = this.state;
        let searchDate = new Date(date);
        let total = 0;
        if(revenuePayments){
            for (let i = 0; i < revenuePayments.length; i++) {
                const element = revenuePayments[i];
                if(!isNaN(parseInt(element.total))) {
                    total += element.total;
                }
            }
            revenuePayments = [...revenuePayments, {lastLine : true, total}]
        }
        return (
            <div className={classes.root}>
                <div>
                    <IconButton onClick={()=>this.setState({calenderDialog : true})}>
                        <CalendarToday color="secondary"/>
                    </IconButton>
                    <FormControlLabel
                            value={monthOnlyView}
                            onChange={this.onChange.bind(this)}
                        control={<Checkbox/>}
                        label={<Typography style={{fontSize : 14}}>Month only view</Typography>}
                        />
                </div>
                <div style={{width : "100%"}} ref={e=>this.printComponent=e}>
                    <MyTable
                        titleProps={{
                            style : {
                                fontSize : 14
                            }
                        }}
                        title={searchDate && 
                            (monthOnlyView ? 
                                searchDate.getFullYear()+", "+(monthSelections.find(item=>item.value ==searchDate.getMonth()+1).name) : 
                                searchDate.toDateString()
                            )
                        }
                        header={["Name", "Total Amount"]}
                        dataMap={["_id", "total"]}
                        rowAction={this.rowAction.bind(this)}
                        data={revenuePayments}
                        CellMap={this.cellMapFormat.bind(this)}
                        />
                </div>
                <ReactToPrint 
                    trigger={()=><button>Print</button>}
                    content={()=>this.printComponent}
                />
                
                <MyDialog open={calenderDialog}
                 close={()=>this.setState({calenderDialog : false})}>
                     <div style={{
                         display : "flex",
                         flexDirection : "column",
                         alignItems : "center",
                         justifyContent : "center"
                         }}>
                             <Typography paragraph className={classes.header}>Search Payment by dates</Typography>
                            <Calendar
                                onChange={date=>this.setState({searchDate : date})}/>
                        <div style={{marginTop : 20}}>
                            <HIRButton type="primary" 
                                disabled={dateSearchBtnLoading}
                                onClick={()=>this.searchByDate(true)}>
                                    {dateSearchBtnLoading && 
                                    <CircularProgress color="secondary" 
                                        className={classes.progress}/>} Get Payments
                                </HIRButton>
                        </div>
                    </div>
                    
                 </MyDialog>            
            </div>
        );
    }
}


_HIRRevenueList.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({hirAccountReducer, hirSettingReducer}) => ({
    [hirAccountStrings.revenueBasedPayments] : hirAccountReducer[hirAccountStrings.revenueBasedPayments],
    [hirSettingStrings.settings] : hirSettingReducer[hirSettingStrings.settings],
})


export const HIRRevenueList = connect(mapStateToProps)(withStyles(style)(_HIRRevenueList));
export {HIRRevenueList as default}