import React, { PureComponent } from 'react';
import PropTypes from 'prop-types';
import { withStyles, TextField, FormGroup, FormControl, CircularProgress, Button, IconButton } from '@material-ui/core';
import Send from '@material-ui/icons/SendRounded'
import { trackerUtil } from '../../../utils';

const styles = theme => ({
    root : {
        backgroundColor: "white",
        // position : "fixed",
        // bottom : 1,
    },
    inputContainer : {
        display : "flex",
        flexDirection : "row",
    },
    input : {
        flex : 1,
        padding : 10,
        flexGrow : 1,
    },
    sendBtn : {
        backgroundColor : "transparent",
        border : "none"
    },
    icon : {
        color : trackerUtil.getTheme().secondary
    }
})


class _InputArea extends PureComponent {
    constructor(props) {
        super(props);
        this.state = {
            message : "",
            sending : false,
        }
    }
    
    static propTypes = {
        sendMessage : PropTypes.func,
    }

    handleChange = name => event => this.setState({[name] : event.target.value});
    send(){
        const {message} = this.state;
        const {sendMessage} = this.props;
        if(sendMessage)
            sendMessage(message, this);
    }
    render() {
        const {classes, small} = this.props;
        const {message, sending} = this.state;
        return (
            <FormGroup className={classes.root}>
                <FormControl className={classes.inputContainer}>
                    <TextField
                        value={message}
                        multiline
                        rowsMax={5}
                        onChange={this.handleChange("message")}
                        className={classes.input}
                        inputProps={{
                            style : small ? {fontSize : 11} : null
                        }}/>
                    <IconButton 
                        className={classes.sendBtn} 
                        variant="text" onClick={()=>this.send()}>
                        {sending ? <CircularProgress size={30} className={classes.icon}/>  :
                        <Send fontSize={small ? "small" : "large"} className={classes.icon}/>}
                    </IconButton>
                </FormControl>
            </FormGroup>
        )
    }
}
_InputArea.propTypes = {
    classes : PropTypes.object.isRequired,
    sendMessage : PropTypes.func,
    small : PropTypes.bool,
}
export const InputArea = withStyles(styles)(_InputArea);