import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { inventoryUtilStrings, inventoryUtil } from '../../utils';
import { Typography } from '@material-ui/core';


const style = theme => ({
    root: {
        padding : 10,
        display : "flex",
        justifyContent : "center",
        alignItems : 'center'
    },
    text : {
        fontSize : 21, 
        fontWeight : "bold",
        color : inventoryUtil.getTheme().secondary
    }
})
class _DrawerHeader extends Component {
    render() {
        const {
            classes,
            [inventoryUtilStrings.myProfile] : profile
        } = this.props;
        return (
            <div className={classes.root}>
                {profile && <Typography paragraph className={classes.text}>
                    {profile.lastName + ", " + profile.firstName}
                </Typography>}
            </div>
        );
    }
}


_DrawerHeader.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({inventoryUtilReducer}) => ({
    [inventoryUtilStrings.myProfile] : inventoryUtilReducer[inventoryUtilStrings.myProfile],
})


export const DrawerHeader = connect(mapStateToProps)(withStyles(style)(_DrawerHeader));
export {DrawerHeader as default}