import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import classNames from 'classnames';
import { Paper, InputBase, Button, FormControl, withWidth, TextField } from '@material-ui/core';
import { Search } from '@material-ui/icons';
import { mainStageHeaderStrings } from './constants';


const style = theme => ({
    root : {
        display : 'flex',
        backgroundColor : theme.colors.mainStageHeader,
    },
    root1 : {
        flexDirection : "column"
    },
    container : {
        display : "flex",
        alignItems : "center",
        [theme.breakpoints.down("sm")] : {
            width : "100%"
        }
    },
    search : {
        // color : theme.colors.wheat,
        margin: 10,
        borderRadius : 5,
        border : "solid 1px " + theme.colors.secondary
    },
    newButton : {
        margin : 10,
        backgroundColor : theme.colors.header,
        color : "white",
        "&:hover" : {
            backgroundColor: theme.colors.secondary
        }
    },
    searchButton : {
        margin : "10px 0px",
        color : theme.colors.secondary,
        backgroundColor : theme.colors.white,
        "&:hover" : {
            // backgroundColor: colors.primary
        }
    }
})
class _StageHeader extends Component {
    state = {
        keyword : "",
    }
    searchTextChange(e){
        const {onChangeCallback} = this.props;
        const keyword =  e.target.value;
        this.setState({keyword})
        if(onChangeCallback) onChangeCallback(keyword);
    }
    searchAction(e){
        const {
            [mainStageHeaderStrings.searchActions] : searchAction
        } = this.props;
        const {keyword} = this.state;
        if(searchAction)
            searchAction(keyword, this);
    }
    render() {
        const {keyword} = this.state;
        const {
            classes, buttons, width, theme,
            [mainStageHeaderStrings.searchActions] : searchAction,
            [mainStageHeaderStrings.components] : components, userType,
            [mainStageHeaderStrings.visible] : visible,
        } = this.props;
        if(!visible) return null;
        let smallBox;
        if(["xs", "sm"].indexOf(width) !== -1) 
            smallBox = true;
        return (
            <Paper {...this.props.paperProps} className={classNames(classes.root, smallBox && classes.root1)} elevation={2}>
                {searchAction && 
                <div className={classes.container}><FormControl style={{flexDirection : "row"}}>
                    <InputBase
                        inputProps={{
                            style :{ 
                                marginLeft : 5,
                            },
                        }}
                        style={{
                            backgroundColor : theme.colors.white
                        }}
                        value={keyword}
                        className={classes.search}
                        placeholder="Search"
                        onChange={this.searchTextChange.bind(this)}
                        {...this.props.searchInputProps}/>
                    <Button onClick={this.searchAction.bind(this)} className={classes.searchButton} variant="contained">
                        <Search/>
                    </Button>
                </FormControl></div>}
                {components && <Fragment>
                    <div style={{display : "flex", flexGrow: 1}}/>
                    <div style={{margin : 10}} className={classes.container}>
                        {components.map((Comp, index)=> 
                            <Comp key={index}/>
                        )}
                    </div>
                    </Fragment>
                }
                {buttons && 
                    <Fragment>
                        <div style={{display : "flex", flexGrow: 1}}/>
                        <div className={classes.container}>
                            {buttons.map((btn, index)=>{
                                const {value, className, ...props} = btn;
                                return <Button key={index}
                                        {...props}
                                        className={classNames(classes.newButton, className)}>
                                            {value}
                                    </Button>})}
                        </div>  
                    </Fragment>
                }                              
            </Paper>
        );
    }
}


_StageHeader.propTypes = {
    classes : PropTypes.object.isRequired,
    searchActions : PropTypes.func,
    buttons : PropTypes.array,
    searchInputProps : PropTypes.shape(InputBase.propTypes),
    paperProps : PropTypes.shape(Paper.propTypes),
    onChangeCallback : PropTypes.func,
    components : PropTypes.array,
    //...PropTypes.shape(Object.values(mainStageHeaderStrings).map(item=>({item : PropTypes.any}))),
};
const mapStateToProps = ({mainStageHeaderReducer}) => ({
    ...mainStageHeaderReducer
})
export const StageHeader = connect(mapStateToProps)(withStyles(style)(withWidth({withTheme : true})(_StageHeader)));
export const StageHeaderPlane = withStyles(style)(withWidth({withTheme : true})(_StageHeader));