import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Card, CardMedia, CardHeader, CardContent, CardActions, Grid, Chip } from '@material-ui/core';
import { colors } from '../../../../../utils';


const style = theme => ({
    root: {
        width : "100%",
        margin : 10,
    },
    griditem : {
        alignItems : "center",
        display : "flex",
        margin : 0,
        padding : 0,
    }
})
class _ItemDisplayCard extends Component {
    render() {
        const {
            classes, stockCategories, brands, itemTags
        } = this.props;
        const { 
            _id, name, categoryId, brandId, tagIds, description, imageUrl,
            stockInfo
        } = this.props.item || {};
        const {item : brandItem } = brands.getFirstObjectByPropValue("_id", brandId) || {};
        let title = name;
        if(brandItem) title += " (" + brandItem.name + ")";
        let category;
        const {item : categoryItem} = stockCategories.getFirstObjectByPropValue("_id", categoryId);
        if(categoryItem) category = categoryItem.name;
        console.log(this.props)
        return (
            <Card className={classes.root}>
                <CardHeader
                    title={title}/>
                <CardMedia style={{minHeight : 200, width : "100%"}} image="/images/sch_children.jpeg" title={name}/>
                <CardContent style={{fontSize : 11}}>
                    <Grid container spacing={2}>
                        <Grid className={classes.griditem} item xs={12} sm={12} md={12} lg={12} xl={12}>
                            <strong style={{color:colors.appRed}}>
                                Stock Category : 
                            </strong> {category}
                        </Grid>                        
                        <Grid className={classes.griditem} item xs={12} sm={12} md={12} lg={12} xl={12}>
                            <strong style={{color:colors.appRed}}>
                                Tags : 
                            </strong> {tagIds && tagIds.map(
                                (tagId, index)=>{
                                    let tagName;
                                    const {item : tagItem} = itemTags.getFirstObjectByPropValue("_id", tagId) || {};
                                    if(tagItem) tagName = tagItem.name;
                                    return <Chip size="small" style={{margin : 3}} key={index} label={tagName}/>
                                }
                            )}
                        </Grid>
                        <Grid className={classes.griditem} item xs={12} sm={12} md={12} lg={12} xl={12}>
                            <strong style={{color:colors.appRed}}>
                                Stock : 
                            </strong> { stockInfo && 
                                stockInfo.totalStock && 
                                Number(stockInfo.totalStock).toLocaleString()
                            }
                        </Grid>                        
                    </Grid>
                </CardContent>
                <CardActions>

                </CardActions>
            </Card>
        );
    }
}


_ItemDisplayCard.propTypes = {
    classes : PropTypes.object.isRequired,
    item : PropTypes.object,
    stockCategories : PropTypes.array,
    itemPackages : PropTypes.array,
    brands : PropTypes.array,
    itemTags : PropTypes.array,
};
const mapStateToProps = state => ({
    state
})


export const ItemDisplayCard = connect(mapStateToProps)(withStyles(style)(_ItemDisplayCard));
export {ItemDisplayCard as default}