import { headerStrings } from "./strings";
import { headerConstants } from "./constant"

export const headerActions = payload => dispatch => {
    payload = {[headerStrings.visible] : true, ...payload};
    dispatch({
        type : headerConstants.SET_HEADER,
        payload
    });
}

export const setHeader = {
    setHeaderTitle : component => dispatch => dispatch({
        type : headerConstants.SET_HEADER,
        payload : {
            position : headerStrings.headerTitle,
            component
        }
    }),
    useDrawer : (value=true) => dispatch => dispatch({
        type : headerConstants.SET_HEADER,
        payload : {
            position : headerStrings.drawer,
            component : value
        }
    }),
    useMorePoper : ({use=true, list=null}, callback) => dispatch => {
        dispatch({
            type : headerConstants.SET_HEADER,
            payload : {
                position : headerStrings.useMorePoper,
                component : { use, list}
            }
        });
        if(callback) callback();
    },
    setHeaderLeft : component => dispatch => dispatch({
        type : headerConstants.SET_HEADER,
        payload : {
            position : headerStrings.headerLeft,
            component
        }
    }),
    setHeaderRight : component => dispatch => dispatch({
        type : headerConstants.SET_HEADER,
        payload : {
            position : headerStrings.headerRight,
            component
        }
    }),
    setHeaderRightSecondary : component => dispatch => dispatch({
        type : headerConstants.SET_HEADER,
        payload : {
            position : headerStrings.headerRightSecondary,
            component
        }
    }),

    setRootProps : props => dispatch => dispatch({
        type : headerConstants.SET_HEADER,
        payload : {
            position : headerStrings.rootProps,
            component : props
        }
    })
};