import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {Link} from 'react-router-dom';
import {withStyles} from '@material-ui/core/styles';
import { TextField, FormGroup, FormControl, FormLabel, Typography, Button, CircularProgress } from '@material-ui/core';
import { appActions, alertAction } from '../../../actions';
import { insureUtil, insureActions, onEnterPress } from '../utils';
import { insureRouteNames } from '../routeNames';


const style = theme => ({
    root: {
        background : insureUtil.getTheme().secondary,
        backgroundSize : "cover",
        height : "100vh",
        width : "100vw",
    },
    overLay : {
        height : "100%",
        width : "100%",
        backgroundColor : insureUtil.getTheme().primaryTrans,
        display : "flex",
        flexDirection : "column",
        alignItems : "center",
        justifyContent : "center"
    },
    pageTitle : {
        fontWeight : 800,
        color : insureUtil.getTheme().white,
        fontFamily : "fantasy",
        marginBottom : 50,
    },
    formContainer : {
        backgroundColor : insureUtil.getTheme().primary, 
        padding : 20,
        borderRadius : 10,
        width : "50%",
        [theme.breakpoints.down("xs")] : {
            width : "80%"
        },
        [theme.breakpoints.up("md")] : {
            width : "30%",
        }
    },
    textField : {
        background : insureUtil.getTheme().white,
        borderRadius : 5,
        border : "none"
    },
    noBorder : {
        border : "none"
    },
    headerContainer : {
        marginBottom : 50,
    },
    header : {
        color : insureUtil.getTheme().white,
        fontWeight : "bold"
    },
    signupButton : {
        marginTop : 20,
        backgroundColor : insureUtil.getTheme().primary,
        color : insureUtil.getTheme().white
    }
})
class _Signup extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data  : {
                name : "",
                email : "",
                password : "",
                phone : "",
            },
            loading : false
        }
        this.fromLocation = this.props.location.state.fromLocation;
        if(insureUtil.isLogedIn())
            this.history.push(insureRouteNames.home);
    }
    handleChange=name=>event=>{
        let value = event.target.value;
        let data = {...this.state.data};
        data[name] = value;
        this.setState({data});
    }
    signup(){
        this.setState({loading : true});
        const {data} = this.state;
        const {dispatch} = this.props;
        const validationData = Object.entries(data).map((item, index)=>({name : item[0], value : item[1]}));
        console.log(validationData);
        if(validationData) for (let i = 0; i < validationData.length; i++) {
            const value = validationData[i].value;
            if(!String(value).trim()){
                appActions.showSnackbar(
                    alertAction.error("Empty field error!")
                )(this.props.dispatch);
                this.setState({loading : false});
                return;
            }
        }
        insureActions.signup(data, done => {
            if(done)
                this.props.history.replace(this.fromLocation || insureRouteNames.home);
            else this.setState({loading : false});
        })(dispatch);
    }
    render() {
        const {classes} = this.props;
        const {loading, data} = this.state;
        const {name, phone, email, password} = data;
        return (
            <div id="home" className={classes.root}>
                <div className={classes.overLay}>
                    {/* <Typography className={classes.pageTitle} variant="h4">MOBOINSURE (COOPERATIVE)</Typography> */}
                    <div className={classes.formContainer}>
                        <FormGroup>
                            <FormLabel className={classes.headerContainer}>
                                <Typography className={classes.header} component="h4" variant="h4">Signup</Typography>
                            </FormLabel>
                            <FormControl>
                                <TextField
                                    label="Full name"
                                    placeholder="Full name"
                                    margin="normal"
                                    onChange={this.handleChange("name")}
                                    value={name}
                                    className={classes.textField}
                                    variant="outlined"
                                    onKeyDown={onEnterPress(this.signup.bind(this))}/>
                            </FormControl>
                            <FormControl>
                                <TextField
                                    label="Phone Number"
                                    placeholder="Phone Number"
                                    margin="normal"
                                    onChange={this.handleChange("phone")}
                                    value={phone}
                                    className={classes.textField}
                                    variant="outlined"
                                    onKeyDown={onEnterPress(this.signup.bind(this))}/>
                            </FormControl>
                            <FormControl>
                                <TextField
                                    label="Email"
                                    placeholder="email"
                                    margin="normal"
                                    onChange={this.handleChange("email")}
                                    value={email}
                                    className={classes.textField}
                                    variant="outlined"
                                    onKeyDown={onEnterPress(this.signup.bind(this))}/>
                            </FormControl>
                            <FormControl>
                                <TextField
                                    label="Password"
                                    placeholder="password"
                                    margin="normal"
                                    onChange={this.handleChange("password")}
                                    value={password}
                                    type="password"
                                    className={classes.textField}
                                    variant="outlined"
                                    onKeyDown={onEnterPress(this.signup.bind(this))}/>
                            </FormControl>
                            <FormControl>
                                <Button
                                    disabled={loading}
                                    className={classes.signupButton}
                                    onClick={()=>this.signup()}>
                                        {loading && <CircularProgress size={20} 
                                        style={{color : insureUtil.getTheme().secondary}}/>} Create Account
                                    </Button>
                            </FormControl>
                            <div style={{marginTop : 20, display : 'flex'}}>
                                <Link style={{
                                    color : insureUtil.getTheme().secondary
                                }} to={insureRouteNames.home}>Home</Link>
                                <div style={{
                                    display : "flex",
                                    flexGrow : 1,
                                }}/>
                                <Link style={{
                                    color : insureUtil.getTheme().secondary
                                }} to={{pathname : insureRouteNames.login, state : {}}}>Login</Link>
                            </div>
                        </FormGroup>
                    </div>
                </div>
            
            </div>
        );
    }
}


_Signup.propTypes = {
    classes : PropTypes.object.isRequired
};



export const Signup = connect()(withStyles(style)(_Signup));
export {Signup as default};