import { agroUtilConstants, agroUtilStrings } from "./config";
import { agroUtilServices } from "./services";
import { _storeData } from "../../../utils";
import { errorNotice } from "./agroUtil";

export const agroUtilActions = payload => dispatch => dispatch({
    type : agroUtilConstants.SET_UTIL,
    payload 
});

export const agroActions = {
    getUser : callback => dispatch => {
        agroUtilServices.getUser((done, result, message)=>{
            if(done){
                agroUtilActions({
                    [agroUtilStrings.myProfile] : result.myProfile,
                    [agroUtilStrings.trackingMe] : result.trackingMe,
                    [agroUtilStrings.disableAllTracking] : result.disableAllTracking,
                })(dispatch);
            }
            if(callback) callback(done, result, message);
        })
    },
    signup : (data, callback) => dispatch => {
        agroUtilServices.signup(data, (done, result, message)=>{
            if(done){
                _storeData([agroUtilStrings.tokenAlias], result.myProfile.token);
                _storeData([agroUtilStrings.userAlias], result._id);
                agroUtilActions({
                    [agroUtilStrings.myProfile] : result.myProfile,
                    [agroUtilStrings.trackingMe] : result.trackingMe,
                    [agroUtilStrings.disableAllTracking] : result.disableAllTracking,
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    loging : (email, password, callback) => dispatch => {
        agroUtilServices.login(email, password, (done, result, message)=>{
            if(done){
                _storeData([agroUtilStrings.tokenAlias], result.myProfile.token);
                _storeData([agroUtilStrings.userAlias], result._id);
                agroUtilActions({
                    [agroUtilStrings.myProfile] : result.myProfile,
                    [agroUtilStrings.trackingMe] : result.trackingMe,
                    [agroUtilStrings.disableAllTracking] : result.disableAllTracking,
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    logout : () => {
        localStorage.removeItem([agroUtilStrings.tokenAlias]);
        localStorage.removeItem([agroUtilStrings.userAlias]);
    },
}
