import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import Chart from 'chart.js';
import { Paper, Typography} from '@material-ui/core';

const style = theme => ({
    root: {
    },
    root1: {
        
    },
    title : {paddingTop: 20, fontWeight : "bold", fontSize : 14},
})
class _MyChart extends Component {
    componentDidUpdate(){
        var defaultOptions = {
            scales: {
                yAxes: [{
                    ticks: {
                        beginAtZero: true
                    }
                }]
            }
        };
        var ctx = document.getElementById(this.props.canvasId).getContext('2d');
        var myChart = new Chart(ctx, {
            type: this.props.type || 'line',
            data: {
                labels: this.props.labels,
                datasets: this.props.datasets,
            },
            options: this.props.options || defaultOptions
        });
    }
    render() {
        const {classes, canvasId, nested, title} = this.props;
        const height = this.props.height || 400
        const root = nested ? classes.root1 : classes.root;
        return (
            <Paper className={root}>
                <Typography className={classes.title} align="center" variant="h5">{title}</Typography>
                <canvas style={{width: "100%"}} id={canvasId} height={height}></canvas>
            </Paper>
        );
    }
}


_MyChart.propTypes = {
    title : PropTypes.string.isRequired,
    classes : PropTypes.object.isRequired,
    type : PropTypes.string,
    labels : PropTypes.array.isRequired,
    datasets : PropTypes.array.isRequired,
    options : PropTypes.object,
    canvasId : PropTypes.string.isRequired,
    height: PropTypes.number,
    nested : PropTypes.bool,
};
const mapDispatchToProps = dispatch => {
    return {
        dispatch
    }
}
const mapStateToProps = state => ({
    state
})


export const MyChart = connect(mapStateToProps,mapDispatchToProps)(withStyles(style)(_MyChart));