import React, { Component } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import {withStyles} from '@material-ui/core/styles';
import { TextField, Button, IconButton, CircularProgress, Card, CardHeader, CardContent, CardActionArea, CardActions, Typography } from '@material-ui/core';
import { Cancel } from '@material-ui/icons';
const style = theme => ({
    root: {
        display : "flex",
        flexDirection : "column",
        margin : 10,
    },
    title : {},
    inputItemContainer : {
        display : "flex",
    },
    textField : {
        margin : 5,
        display : "flex"
    },
    btnContainer : {

    },
    btn : {
        margin : 5,
    },
    addBtn : {

    },
    cancelBtn : {},
    updateBtn : {},
})
class _TextFieldEditableCard extends Component {
    constructor(props) {
        super(props);
        this.state = {
            value : props.value,
            loading : false,
            editing : false,
        }
    }
    onChange = e => {
        const value =e.target.value;
        this.setState({value});
    }
    onUpdateClick(){
        this.setState({loading :true})
        const {value} = this.state;
        const {onUpdateClick } = this.props;
        if(onUpdateClick) onUpdateClick(value, this);
    }
    render() {
        const {classes, header} = this.props;
        const {value, loading, editing} = this.state;
        return (
            <Card className={classes.root}>
                <CardHeader className={classes.title} title={header} titleTypographyProps={this.props.titleTypographyProps}/>
                <CardContent className={classes.cardContent}>
                    {!editing ? 
                    <Typography paragraph>{value}</Typography> :
                    <TextField
                        className={classes.textField}
                        margin="normal"
                        value={value}
                        onChange={e=>this.onChange(e)}
                        multiline
                        rows={4}
                        rowsMax={4}/>}
                    </CardContent>
                {!editing ?
                    <CardActions className={classes.btnContainer}>
                        <Button
                            variant="contained"
                            color="primary"
                            className={classNames(classes.btn, classes.updateBtn)}
                            onClick={()=>this.setState({editing : true})}
                            >
                                Edit
                            </Button>
                    </CardActions> : 
                    <CardActions className={classes.btnContainer}>
                        <Button
                            variant="contained"
                            color="secondary"
                            className={classNames(classes.btn, classes.cancelBtn)}
                            onClick={()=>this.setState({editing : false})}>
                                Cancel
                            </Button>
                        <Button
                            variant="contained"
                            color="primary"
                            disabled={loading}
                            className={classNames(classes.btn, classes.updateBtn)}
                            onClick={e=>this.onUpdateClick(e)}>
                                {loading && <CircularProgress size={20}/>} Update
                            </Button>
                    </CardActions>
                }
            </Card>
        );
    }
}
_TextFieldEditableCard.propTypes = {
    classes : PropTypes.object.isRequired,
    header : PropTypes.string,
    value : PropTypes.string,
    onUpdateClick : PropTypes.func,
    titleTypographyProps : PropTypes.object,
};
export const TextFieldEditableCard = withStyles(style)(_TextFieldEditableCard);