import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { IconButton, withWidth, Hidden } from '@material-ui/core';
import { MoreVert, Info, ArrowBack } from '@material-ui/icons';
import { contactActions } from './actions';
import { contactStrings } from './config';


const style = theme => ({
    root: {
    },
    icon : {
        color : "white"
    }
})
class _HeaderControl extends Component {
    handleInfoClick=display=>()=>{
        const {dispatch} = this.props;
        contactActions.setPageDisplay(display)(dispatch);
    }
    render() {
        const {
            classes,
            [contactStrings.pageDisplay] : display
        } = this.props;
        return (
            <Fragment>
                <Hidden xsDown mdUp>
                    {display !== 3 ?
                        <IconButton onClick={this.handleInfoClick(3)}>                    
                                <Info className={classes.icon}/> 
                        </IconButton> :
                        <IconButton onClick={this.handleInfoClick(2)}>
                            <ArrowBack className={classes.icon}/>
                        </IconButton>
                    }
                </Hidden>
                <Hidden smUp>
                    {display === 2 ?
                        <Fragment>
                            <IconButton onClick={this.handleInfoClick(1)}>                    
                                <ArrowBack className={classes.icon}/>
                            </IconButton>
                            <IconButton onClick={this.handleInfoClick(3)}>                    
                                <Info className={classes.icon}/> 
                            </IconButton>
                        </Fragment> :
                        (display === 3 && 
                        <IconButton onClick={this.handleInfoClick(2)}>
                            <ArrowBack className={classes.icon}/>
                        </IconButton>)
                    }
                </Hidden>
            </Fragment>
        );
    }
}


_HeaderControl.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({contactReducer}) => ({
    [contactStrings.pageDisplay] : contactReducer[contactStrings.pageDisplay],
})


export const HeaderControl = connect(mapStateToProps)(withStyles(style)(_HeaderControl));
export {HeaderControl as default}