import { appReducer } from './appReducer';
import { socketIOReducer } from '../socket.io/config';
import { runningApp } from "../../App";
import { 
    breadCrumbReducer, 
    headerReducer, 
    screenReducer, 
    mainStageReducer,
    mainStageHeaderReducer,
    chatFooterReducer,
    formReducer,
} from '../components/includes';

import { 
    payrollReducer, inventoryReducers, 
    schoolManagerReducer, trackerReducers, 
    agroReducers, agroAdminReducers, insureReducers, 
    insureAdminReducers, inovateOSReducers, inovateOSAdminReducers, 
    hirReducers, hmsReducers
} from '../components';
import appNames from '../appNames';
export * from './appReducer';
//combination of apps are running as different apps and never combine thier reducers
function getReducers(runningApp, commonReducer){
    switch(runningApp){
        case appNames.agroAfrik : return {...commonReducer, ...agroReducers};
        case appNames.agroAfrikAdmin : return {...commonReducer,...agroAdminReducers};
        case appNames.tracker : return {...commonReducer, ...trackerReducers};
        case appNames.school : return {...commonReducer, ...schoolManagerReducer};
        case appNames.inventory : return {...commonReducer, ...inventoryReducers};
        case appNames.account : return {...commonReducer, ...payrollReducer};
        case appNames.moboinsure : return {...commonReducer, ...insureReducers};
        case appNames.moboinsureAdmin : return {...commonReducer, ...insureAdminReducers};
        case appNames.inovateOSSite : return {...commonReducer, ...inovateOSReducers};
        case appNames.inovateOSAdmin : return {...commonReducer, ...inovateOSAdminReducers};
        case appNames.healthRecord : return {...commonReducer, ...hirReducers};
        case appNames.hms : return {...commonReducer, ...hmsReducers}
    }
}

export const rootReducer = (function(runningApp){
    const commonReducer = {
        socketIOReducer, appReducer, headerReducer, screenReducer, breadCrumbReducer, mainStageReducer, mainStageHeaderReducer,
        chatFooterReducer, formReducer,
    }
    if(typeof runningApp === "string"){
        return getReducers(runningApp, commonReducer);
    }else{
        let returnedReducer = {};
        for (let i = 0; i < runningApp.length; i++) {
            const rApp = runningApp[i];
            returnedReducer = {...returnedReducer, ...getReducers(rApp, commonReducer)};
        }
        return returnedReducer;
    }
})(runningApp);

export {rootReducer as default};