export const insureAdminMessageStrings = {
    messages : "messages",
}
export const insureAdminMessageConstants = {
    SET_INSURE_ADMIN_MESSAGES : "SET_INSURE_ADMIN_MESSAGES",
}
export const insureAdminMessageReducer = (state={}, action) => {
    const {type, payload} = action;
    switch(type){
        case insureAdminMessageConstants.SET_INSURE_ADMIN_MESSAGES : 
            return {...state, ...payload};
        default : return state;
    }
}
export * from './actions';
export * from './services';