import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { 
    List, Card, CardHeader, ListItem, 
    ListItemText, CardContent, FormControl, TextField, Button, CardActions, Divider 
} from '@material-ui/core';


const style = theme => ({
    root: {
    }
})
class _MyListCard extends Component {
    constructor(props) {
        super(props);
        this.state = {
            searchString : ""
        }
    }
    
    onChange = e => {
        const value = e.target.value;
        this.setState({searchString : value});
        if(this.props.searchOnChange)
            this.props.searchOnChange(value);
    }
    render() {
        const {classes, component : CustomComponent, title, list, footer : Footer} = this.props;
        const {searchString} = this.state;
        return (
            <Card elevation={this.props.elevation} className={classes.root}>
                {title && <Fragment>
                    <CardHeader title={title}
                        {...this.props.cardHeaderProps}/>
                    <Divider/>
                </Fragment>}
                {this.props.searchOnChange && <CardContent>
                    <TextField
                        placeholder="Search"
                        onChange={this.onChange.bind(this)}
                        margin="normal"
                        {...this.props.searchInputProps}
                        value={searchString}/>
                </CardContent>}
                <List {...this.props.listProps}>
                    {list && list.map((item, index)=>
                        (CustomComponent ? 
                            (typeof item === "string" ? <CustomComponent key={index} item={item}/> : 
                            <CustomComponent key={index} {...item}/>) :
                            <ListItem key={index}
                                onClick={()=>this.props.listItemClick && this.props.listItemClick(item, index)} 
                                {...this.props.listItemProps}>
                                    <ListItemText>{
                                        typeof item === "string" ? item : (this.props.itemNameProp ? 
                                        item[this.props.itemNameProp] : 
                                        item.name)}</ListItemText>
                            </ListItem> 
                        )
                    )}
                </List>
                {this.props.finishBtnName && <CardActions>
                    <FormControl
                        style={{width : "100%"}}
                        >
                        <Button 
                            color="primary"
                            onClick={this.props.finishBtnAction}
                            {...this.props.finishBtnProps} 
                            >{this.props.finishBtnName}</Button>
                    </FormControl>
                </CardActions>}
                {Footer && 
                (typeof Footer === "string" ? Footer : <Footer/>)}
            </Card>
        );
    }
}


_MyListCard.propTypes = {
    classes : PropTypes.object.isRequired,
    title : PropTypes.string,
    cardHeaderProps : PropTypes.shape(CardHeader.propTypes),

    elevation : PropTypes.number,

    itemNameProp : PropTypes.string,
    list : PropTypes.array,
    listProps : PropTypes.object,
    listItemProps : PropTypes.object,
    listItemClick : PropTypes.func,

    component : PropTypes.func,

    searchInputProps : PropTypes.object,

    finishBtnAction : PropTypes.func,
    finishBtnProps : PropTypes.object,
    finishBtnName : PropTypes.string,

    searchOnChange : PropTypes.func,

    footer : PropTypes.any,
};

export const MyListCard = withStyles(style)(_MyListCard);