import { sessionServices } from "./services"
import { sessionStrings, sessionConstants } from "./config"

export const sessionActions = {
    setUsePreviousClasses : use => dispatch => dispatch({
        type : sessionConstants.SET_SESION,
        payload : {
            [sessionStrings.usePreviousClasses] : use
        }
    }),
    // getPreviousClasses : (levelIds, callback)=> dispatch=>{
    //     sessionActions.getClassesByLevelIds(levelIds, (done, result, message)=>{
    //         if(done) dispatch({
    //             type : sessionConstants.SET_SESION,
    //             payload : {
    //                 [sessionStrings.sessionPreviousClasses] : result
    //             }
    //         })
    //         if(callback)callback(done, result, message);
    //     });
    // },
    getClassesByLevelIds_NO_DISPATCH : (levelIds, callback) => {
        sessionServices.getClassesByLevelIds(levelIds, callback);
    },
    setUsePreviousLevel : usePrevious => dispatch => dispatch({
        type : sessionConstants.SET_SESION,
        payload : {
            [sessionStrings.usePreviousLevel] : usePrevious
        }
    }),
    setSessionPreviousLevels : levels => dispatch=>{
        dispatch({
            type : sessionConstants.SET_SESION,
            payload : {
                [sessionStrings.sessionPreviousLevels] : levels
            }
        })
    },
    getCurrentsessionTerms : callback => dispatch => {
        sessionServices.getSessionTerms(null, (done, result, message)=>{
            if(done) dispatch({
                type : sessionConstants.SET_SESION,
                payload : {
                    [sessionStrings.currentSessionTerms] : result
                }
            })
            if(callback) callback(done, result, message);
        })
    },
    getCurrentSessionLevel : callback => dispatch => {
        sessionServices.getSessionLevels(null, (done, result, message)=>{
            if(done){
                dispatch({
                    type : sessionConstants.SET_SESION,
                    payload : {
                        [sessionStrings.levels] : result
                    }
                })
            }
            if(callback) callback(done, result, message);
        })
    },
    getSessionLevels : (sessionId, callback)=>dispatch=>{
        sessionServices.getSessionLevels(sessionId, (done, result, message)=>{
            if(done){
                sessionActions.setSessionPreviousLevels(result)(dispatch);
            }
            if(callback) callback(done, result, message);
        })
    },
    getSessions : (callback) => dispatch =>{
        sessionServices.getSessions((done, result, message)=>{
            if(done) dispatch({
                type : sessionConstants.SET_SESION,
                payload : {
                    [sessionStrings.sessions] : result
                }
            })
            if(callback) callback(done, result, message);
        })
    },
    getSessionTerms : (sessionId, callback) => dispatch => {
        sessionServices.getSessionTerms(sessionId, (done, result, message)=>{
            if(done) dispatch({
                type : sessionConstants.SET_SESION,
                payload : {
                    [sessionStrings.terms] : result
                }
            })
            if(callback) callback(done, result, message);
        })
    },
    getAllTerms : callback => dispatch => {
        sessionServices.getAllTerms((done, result, message)=>{
            if(done) dispatch({
                type : sessionConstants.SET_SESION,
                payload : {
                    [sessionStrings.allTerms] : result
                }
            })
            if(callback) callback(done, result, message);
        })
    },
    cleanup : () => dispatch => dispatch({
        type : sessionConstants.SET_SESION_CLEAN_UP
    })
}