import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { insureAdminMessageActions } from './actions';
import { MyTable, MyDialog, breadCrumbActions } from '../../includes';
import { insureAdminMessageStrings } from './config';
import { MessageView } from './MessageView/MessageView';
import { TableCell, Typography, Button } from '@material-ui/core';
import { Reply, Delete, Add } from '@material-ui/icons';
import { insureAdminUtil } from '../utils';
import { appActions } from '../../../actions';
import { MessageReply } from './MessageReply';
import { insureAdminRouteNames } from '../routeNames';


const style = theme => ({
    root: {
        padding : 20,
    },
    cell : {
        padding : 5,
    },
    cellText : {
        fontSize : 12
    }
})
class _Messages extends Component {
    constructor(props) {
        super(props);
        this.state = {
            lastId : null,
            rows : 20,
            messageDisplayDialog : false,
            row : null,
            messageView : false,
        }
        const{dispatch} = props;
        breadCrumbActions.setBreadCrumb([
            {name : "Site", path : insureAdminRouteNames.home},
            {name : "Messages", path : insureAdminRouteNames.messages},
        ])(dispatch);
    }
    
    componentDidMount() {
        this.getMessage();
    }
    getMessage(){
        const {lastId, rows} = this.state;
        const {dispatch} = this.props;
        insureAdminMessageActions.getMessages(lastId, rows)(dispatch);
    }
    replyMessage = row => e => {
        e.stopPropagation();
        e.preventDefault();
        this.setState({
            row, messageDisplayDialog : true
        })
    }
    deleteMessage = row => e => {
        const {dispatch } = this.props;
        e.stopPropagation();
        e.preventDefault();
        appActions.showSnackDialog(
            "Are you sure you want to delete message from " + row.email,
            <Button key="delete" onClick={this.continueDeleteMessage(row._id)}>Continue</Button>
        )(dispatch);
    }
    continueDeleteMessage= (id)=>e=>{
        const {dispatch} = this.props;
        appActions.closeSnackDialog()(dispatch);
        insureAdminMessageActions.deleteMessages([id], done => {
            if(done) this.getMessage();
        })(dispatch);
    }
    cellMapFormat = props => ({row, cellMap}) => {
        const {classes} = this.props;
        switch(cellMap){
            case "action" : return <TableCell className={classes.cell}>
                <div style={{
                    display : 'flex',
                }}>
                    <Reply
                        onClick={props.replyMessage(row)}
                        style={{
                            color : insureAdminUtil.getTheme().secondary
                        }}/>
                    <Delete 
                        onClick={props.deleteMessage(row)}
                        color="secondary"
                        />
                </div>
            </TableCell>
            case "message" : return <TableCell className={classes.cell}>
                <Typography className={classes.cellText} noWrap>{row[cellMap]}</Typography>
            </TableCell>;
            default : return <TableCell className={classes.cell}>
                <Typography className={classes.cellText}>{row[cellMap]}</Typography>
            </TableCell>
        }
    }
    sendEmail(data, context){
        const {dispatch} = this.props;
        insureAdminMessageActions.sendEmail(data, done=>{
            context.setState({loading : false});
        })(dispatch);
    }
    render() {
        const {
            classes,
            [insureAdminMessageStrings.messages] : messages,
        } = this.props;
        const {
            messageDisplayDialog, row, messageView
        } = this.state;
        return (
            <div className={classes.root}>
                <Button 
                    variant="contained"
                    color="primary"
                    onClick={this.replyMessage({})}>
                    <Add/>  Compose
                </Button>
                <MyTable
                    header={["Name", "Email", "Message", "Actions"]}
                    dataMap={["name", "email", "message", "action"]}
                    data={messages || []}
                    rowAction={row=>()=>this.setState({
                        row, messageDisplayDialog : true,
                        messageView : true,
                    })}
                    CellMap={this.cellMapFormat({
                        replyMessage : this.replyMessage.bind(this),
                        deleteMessage : this.deleteMessage.bind(this),
                    })}
                    />
                <MyDialog 
                    close={()=>this.setState({
                        messageDisplayDialog : false,
                        messageView : false,
                    })}
                    open={messageDisplayDialog}>
                    {messageView ? 
                        <MessageView {...row}/> : 
                        <MessageReply {...row} 
                            send={this.sendEmail.bind(this)}/>}
                </MyDialog>
            </div>
        );
    }
}


_Messages.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({insureAdminMessageReducer}) => ({
    [insureAdminMessageStrings.messages] : insureAdminMessageReducer[insureAdminMessageStrings.messages],
})


export const Messages = connect(mapStateToProps)(withStyles(style)(_Messages));
export {Messages as default}