import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Web, PlaceRounded, Place } from '@material-ui/icons';
import { List, Avatar, Badge, Popover, ListItem, ListItemText } from '@material-ui/core';
import { chatFooterStrings } from '../../config';


const style = theme => ({
    root : {
        position : "fixed",
        bottom : 0,
        right : 1,
        display : "flex",
        flexDirection : "column",
        transition : "height 2s",
        zIndex : 1000,
    },
    container : {
        display : "flex",
        color : "white",
        padding : 10,
        borderRadius : "10px 10px 0 0",
        backgroundColor : "#515169",
    },
})
class _OverflowChatBox extends Component {
    constructor(props) {
        super(props);
        this.state = {
            anchorEl : null
        }
    }
    
    handleHeaderClick = e => {
        const target = e.currentTarget;
        this.setState(({anchorEl})=>({anchorEl : anchorEl ? null : target}));
    }
    render() {
        const {
            classes, right, contacts, maxChatBox,
            [chatFooterStrings.allChatListItemComponent] : ChatListComponent,
        } = this.props;
        const {anchorEl} = this.state;
        return (
            <div className={classes.root} style={{right}}>
                <div className={classes.container} onClick={e=>this.handleHeaderClick(e)}>
                    <Badge badgeContent={contacts ? contacts.length : 0} color="secondary">
                        <Place/>
                    </Badge>
                </div>
                {contacts && contacts.length >= maxChatBox && <Popover 
                    style={{zIndex : 2100}}
                    open={Boolean(anchorEl)}
                    anchorEl={anchorEl}
                    onClose={()=>this.setState({anchorEl : null})}>
                    <List style={{backgroundColor : "#9e9eb5", minWidth : "5cm"}}>
                        {contacts && contacts.map((item,index)=>
                        ChatListComponent ? 
                            <ChatListComponent
                                handleClickCallback={()=>this.setState({anchorEl : null})}
                                {...item} key={index}/> : 
                            <ListItem key={index} style={{padding : 5}} button>
                                <ListItemText>{item.name}</ListItemText>
                            </ListItem>)}
                    </List>
                </Popover>}
            </div>
        );
    }
}


_OverflowChatBox.propTypes = {
    classes : PropTypes.object.isRequired,
    right : PropTypes.number,
    contacts : PropTypes.array,
    maxChatBox : PropTypes.number,
};
const mapStateToProps = ({chatFooterReducer}) => ({
    [chatFooterStrings.allChatListItemComponent] : chatFooterReducer[chatFooterStrings.allChatListItemComponent],
})

export const OverflowChatBox = connect(mapStateToProps)(withStyles(style)(_OverflowChatBox));
export {OverflowChatBox as default}