import { inventoryUtilStrings } from "./config";
import { store } from "../../../../helpers";
import { _retrieveData } from "../../../../utils";
import { appActions, alertAction } from "../../../../actions";
import { errorNotice, successNotice, monthLabels, onEnterPress, _storeData } from "../../../../utils";

export const invSuccessNotice = successNotice;
export const invErrorNotice = errorNotice;
export const inventoryAppActions = appActions;
export const inventoryAlertActions = alertAction;

export * from '../../../../helpers';
export * from '../../../includes';
export * from '../../../../actions';
export const inventoryOnEnterPress = onEnterPress;
export const inventoryMonthLabel = monthLabels;
export const _inventoryStoreData = _storeData;
export const inventoryUtil = {
    getTheme : ()=>(store.getState().inventoryUtilReducer[inventoryUtilStrings.theme]),
    getToken : ()=>localStorage.getItem(store.getState().inventoryUtilReducer[inventoryUtilStrings.tokenAlias]),
    getUserId : () => localStorage.getItem(store.getState().inventoryUtilReducer[inventoryUtilStrings.userAlias]),
    isLogedIn : () => {
        const userId = inventoryUtil.getUserId();
        const token = inventoryUtil.getToken();
        return userId && token;
    },
    isAdmin : () => true,
    fetchGet : async (owner, action, stringQuery, callback)=>{
        const state = store.getState().inventoryUtilReducer;
        const USERID = _retrieveData(state[inventoryUtilStrings.userAlias]);
        const TOKEN = _retrieveData(state[inventoryUtilStrings.tokenAlias]);
        const TYPE = _retrieveData(state[inventoryUtilStrings.userType]);
        stringQuery = {...stringQuery, userId : USERID, token : TOKEN, type : TYPE, companyId : 1};
        let count = 0;
        let build = "";
        for (const i in stringQuery) {
            if (stringQuery.hasOwnProperty(i)) {
                const elem = stringQuery[i];
                if(count === 0){
                    build += "?"+i+"="+elem;
                }else build += "&"+i+"="+elem;
                count++;
            }
        }
        fetch(state[inventoryUtilStrings.backendUrl]+owner+"/"+action+build).then(
            response=> response.json()
        ).then(response=>{
            if(callback) callback(response)
        });
    },
    fetchPost : async (owner, action, options, callback, query = {})=>{
        const state = store.getState().inventoryUtilReducer;
        const USERID = _retrieveData(state[inventoryUtilStrings.userAlias]);
        const TOKEN = _retrieveData(state[inventoryUtilStrings.tokenAlias]);
        const TYPE = _retrieveData(state[inventoryUtilStrings.userType]);
        const stringQuery = {companyId : 1, userId : USERID, token : TOKEN, type : TYPE, ...query};
        let count = 0;
        let build = "";
        for (const i in stringQuery) {
            if (stringQuery.hasOwnProperty(i)) {
                const elem = stringQuery[i];
                if(count === 0){
                    build += "?"+i+"="+elem;
                }else build += "&"+i+"="+elem;
                count++;
            }
        }
        fetch(state[inventoryUtilStrings.backendUrl]+owner+"/"+action+build, options).then(
            response=> response.json()
        ).then(response=>callback(response))
        .catch(e => {
            console.error(e);
        });
    },
    post : async (data, owner, action, callback, query)=>{
        inventoryUtil.fetchPost(owner, action, {
            method : "post",
            headers : {
                "Content-Type" : "Application/json"
            },
            body : JSON.stringify(data)
        }, callback, query);
    }
}


