import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, breadCrumbActions, mainStageHeaderAction, FormDisplay, mainStageHeaderStrings, MyDialog, headerStrings } from '../../../includes';
import { colors } from '../../../../utils';
import { Grid } from '@material-ui/core';
import { ParentListDialog } from './ParentListDialog';
import { SideCounterCard } from './SideCounterCard';
import { studentStrings } from '../config';
import { studentActions } from '../actions';
import { routeNamesSchool } from '../../routeNames';

const style = theme => ({
    root: {
        marginTop : 50
    },
    backBtnHidden : {
        display : "none",
    },
    backBtnShow : {
        display : "block"
    }
})
class _NewStudent extends Component {
    constructor(props) {
        super(props);
        const {dispatch} = props;
        this.state = {
            stage : 1,
            parentDialog : false
        }
        
        headerActions({
            [headerStrings.headerTitle] : "NEW STUDENT",
            [headerStrings.backButtonAction] : ()=>{}
        })(dispatch);
        breadCrumbActions.addToBreadCrumb([
            {name : "New Student", path : routeNamesSchool.tea_stu_stu_new}
        ])(dispatch);
        mainStageHeaderAction({})(dispatch);
        // this.manipulateStageHeader(this.state.stage);
        this.getForms();
    }
    getForms(){
        const {
            [studentStrings.studentForm] : studentForm,
            [studentStrings.parentForm] : parentForm,
            [studentStrings.studentGroupForm] : groupingForm,
            dispatch
        } = this.props;
        console.log("forms", this.props);
        if(!studentForm) studentActions.getStudentForm()(dispatch);
        if(!parentForm) studentActions.getParentForm()(dispatch);
        if(!groupingForm) studentActions.getStudentGroupForm()(dispatch);
    }
    manipulateStageHeader(stage){
        if(stage === this.stageMonitor) return;
        const {dispatch} = this.props;
        switch(stage){
            case 1 : 
                this.stageMonitor = 1;
                return mainStageHeaderAction({
                    [mainStageHeaderStrings.buttons] : [
                        {
                            value:"Continue", style:{backgroundColor:colors.secondary, color : colors.white}, 
                            onClick:()=>this.setState(state => ({...state, stage: state.stage+1})) 
                        },                    
                    ]
                })(dispatch);
            case 2 :
                    this.stageMonitor = 2;
                    return mainStageHeaderAction({
                        [mainStageHeaderStrings.buttons] : [
                            {
                                value : "Back",
                                onClick :()=>this.setState(state=>({...state, stage: state.stage - 1})),
                            },{
                                value:"Continue", style:{backgroundColor:colors.secondary, color : colors.white}, 
                                onClick:()=>this.setState(state => ({...state, stage: state.stage+1})) 
                            },                    
                        ]
                    })(dispatch);
            case 3 : 
                this.stageMonitor = 3;
                return mainStageHeaderAction({
                    [mainStageHeaderStrings.buttons] : [
                        {
                            value : "Back",
                            onClick :()=>this.setState(state=>({...state, stage: state.stage - 1})),
                        },{
                            value:"Select Parent", style:{backgroundColor:colors.white, color : colors.primary}, 
                            onClick:()=>this.showParentDialog(),
                        },{
                            value:"Finish", style:{backgroundColor:colors.secondary, color : colors.white}, 
                            onClick:()=>this.finish(),
                        },                    
                    ]
                })(dispatch);
        }
    }
    showParentDialog = () => this.setState({parentDialog: true});
    finish(parent){
        console.log(parent);
    }
    render() {
        const {
            classes,
            [studentStrings.studentForm] : studentForm,
            [studentStrings.parentForm] : parentForm,
            [studentStrings.studentGroupForm] : groupingForm
        } = this.props;
        const {stage, parentDialog} = this.state;
        return (
            <div className={classes.root}>
                {this.manipulateStageHeader(stage)}
                {stage === 1 && studentForm && <FormDisplay {...studentForm}/>}
                {stage === 2 && <Grid container spacing={2}>
                    <Grid item xs={12} sm={12} md={6} lg={8} xl={8}>
                        {groupingForm && <FormDisplay {...groupingForm}/>}
                    </Grid>
                    <Grid item xs={12} sm={12} md={6} lg={4} xl={4}>
                        <SideCounterCard/>
                    </Grid>
                </Grid>}
                {stage === 3 && <FormDisplay {...parentForm}/>}
                <MyDialog open={parentDialog}>
                    <ParentListDialog 
                        closeDialog={()=>this.setState({parentDialog : false})}
                        finish={this.finish.bind(this)}/>
                    </MyDialog>
            </div>
        );
    }
}


_NewStudent.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({studentReducer}) => ({
    ...studentReducer
})


export const NewStudent = connect(mapStateToProps)(withStyles(style)(_NewStudent));
export {NewStudent as default}