import React from 'react';
import {connect} from 'react-redux';
import { Router, Switch, Route} from 'react-router-dom';
import { 
    headerActions, headerStrings, 
    MySnackbar, SnackDialog, screenActions
} from '../../includes';
import { InovateOSSiteRoute } from './RouteTemplates';
import { history } from '../../../helpers';
import { inovateOSMenuItem } from './menuItems';
import { inovateOSUtilActions, theme1, inovateOSUtil, inovateOSUtilStrings, inovateOSActions } from './utils';
import { withStyles } from '@material-ui/core';
import { inovateOSRoutes, inovateOSPriviteRoutes } from './routes';
import { inovateOSRouteNames } from './routeNames';
import { Unsubscribe } from './Unsubscribe';
import { InovateOSSiteHeaderLeftCompnent } from './InovateOSSiteHeaderLeftCompnent';
import $ from 'jquery';
import { inovateOSPageActions } from './Pages';

const styles = theme => ({
    mainStage : {
        margin : 0,
        padding : 0,
    }
})
class _InovateOSApp extends React.PureComponent{
    constructor(props) {
        super(props);
        const {
            dispatch, runningApp,
        } = props;
        const {pathname} = history.location;
        if(!String(pathname).startsWith("/super")){
            inovateOSUtilActions({
                [inovateOSUtilStrings.theme] : theme1,
                [inovateOSUtilStrings.tokenAlias] : "inovateOSToken",
                [inovateOSUtilStrings.userAlias] : "inovateOSUserId",
                [inovateOSUtilStrings.backendUrl] : "http://157.245.71.43/api/v1/", //"http://localhost:8001/api/v1/",
                [inovateOSUtilStrings.backendBaseUrl] : "http://157.245.71.43", //"http://localhost:8001",
                [inovateOSUtilStrings.isLoggedIn] : inovateOSUtil.isLogedIn("inovateOSUserId", "inovateOSToken"),
            })(dispatch);
            screenActions.setTheme(theme1)(dispatch);
            headerActions({
                [headerStrings.headerTitle] : "INOVATE-OS",
                [headerStrings.headerTitleProps] : {
                    style : {
                        borderBottom : "none",
                        color : inovateOSUtil.getTheme().white,
                    }
                },
                [headerStrings.headerRightComponent] : InovateOSSiteHeaderLeftCompnent,
                [headerStrings.drawer] : true,
                [headerStrings.visible] : true,
                [headerStrings.fullScreen] : true,
                [headerStrings.site] : true,
                // [headerStrings.showItemMenu] : true,
                [headerStrings.leftMenuButton] : true,
                [headerStrings.menuItems] : inovateOSMenuItem,
                [headerStrings.position] : "fixed",
                [headerStrings.siteLinkContainerProps]:{
                    style : {backgroundColor : inovateOSUtil.getTheme().secondary},
                },
                [headerStrings.siteLinkProps]:{
                    style : {color : inovateOSUtil.getTheme().white},
                },
            })(dispatch);
            /** check for token and userid in local storage
             * then get user information
             */
            inovateOSActions.getSettings()(dispatch);
            inovateOSPageActions.setServiceMenus(inovateOSMenuItem)(dispatch);
        }
    }
    componentDidMount(){
        // $("body").css("backgroundColor", inovateOSUtil.getTheme().background);
        $("title").text("InovateOS");
    }
    render(){
        return(
            <Router history={history}>
                <div>
                    <React.Suspense
                        fallback={<div>Loading...</div>}>
                        <Switch>
                            {inovateOSRoutes && inovateOSRoutes.map((route, index)=>{ 
                                return <InovateOSSiteRoute key={index} {...route}/>
                            })}
                            {/* {inovateOSPriviteRoutes && inovateOSPriviteRoutes.map((route, index)=>{
                                return <InovateOSPrivateRoute key={index} {...route}/>
                            })}
                            <InovateOSLogoutRoute path={inovateOSRouteNames.logout}/> */}
                            <Route path={inovateOSRouteNames.newsletterUnsub} component={Unsubscribe}/>
                            {/* <Route component={PageNotFound}/> */}
                        </Switch>
                    </React.Suspense>
                    <MySnackbar/>
                    <SnackDialog/>
                </div>
            </Router>
        )
    }
}
export const InovateOSApp =  connect()(withStyles(styles)(_InovateOSApp));