import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { TextParagraphEditableCard } from '../../TextParagraphEditableCard';
import { TextFieldEditableCard } from '../../TextFieldEditableCard';
import { ProfilePicture } from '../../ProfilePicture';
const style = theme => ({
    root: {
        marginTop : 20,
    }
})
class _ArticleEditableCard extends Component {
    render() {
        const {classes, body, header, title, src, baseUrl } = this.props;
        return (
            <div className={classes.root}>
                
                <ProfilePicture
                    title={header || title}
                    src={src}
                    editable
                    baseUrl={baseUrl}
                    uploadImage={this.props.uploadImage}/>
                <TextFieldEditableCard
                    header="Header"
                    value={header || title}
                    onUpdateClick={this.props.updateHeader}
                    />
                <TextParagraphEditableCard
                    header="Content"
                    value={body}
                    onUpdateClick={this.props.updateContent}/>
            </div>
        );
    }
}
_ArticleEditableCard.propTypes = {
    classes : PropTypes.object.isRequired,
    uploadImage : PropTypes.func,
    body : PropTypes.array,
    header : PropTypes.string,
    src : PropTypes.string,
    updateContent : PropTypes.func,
    updateHeader : PropTypes.func,
    baseUrl : PropTypes.string,
};
export const ArticleEditableCard = withStyles(style)(_ArticleEditableCard);