export const supplierStrings = {
    suppliersBrief : "suppliersBrief",
    supplierBrandEditMode : "supplierBrandEditMode",
    supplierBrands : "supplierBrands",
    stockCategories : "stockCategories",
    itemPackages : "itemPackages",
    allSupplierBrief : "allSupplierBrief",
    itemTags : "itemTags",
}
export const supplierConstants = {
    SET_SUPPLIER : "SET_SUPPLIER",
    CLEAN_UP_SUPPLIER :"CLEAN_UP_SUPPLIER",
}
const supplierInitialState = {

}
export const supplierReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case supplierConstants.SET_SUPPLIER : 
            return {...state, ...payload};
        case supplierConstants.CLEAN_UP_SUPPLIER : 
            return {...state, ...supplierInitialState}
        default : return {...state};
    }
}
export * from './actions';
export * from './services';
