import { assessmentConstants, assessmentStrings } from "./config";

export const assessmentActions = {
    setEditMode : mode => dispatch => dispatch({
        type : assessmentConstants.SET_ASSESSMENT,
        payload : {
            [assessmentStrings.editMode] : mode
        }
    }),
    setUsePreviousAssessments : use => dispatch => dispatch({
        type : assessmentConstants.SET_ASSESSMENT,
        payload : {
            [assessmentStrings.usePreviousAssessments] : use
        }
    }),
}