import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { invProductActions } from '../../actions';
import { invProductStrings } from '../../config';
import classNames from 'classnames';
import { MyTable, EditableCellMapFormat, inventoryUtil, appActions, alertAction } from "../../../utils";
import { Button } from '@material-ui/core';


const style = theme => ({
    root: {
    }
})
class _INVItemPackages extends Component {
    constructor(props) {
        super(props);
        this.state = {
            editMode : false,
            itemPackages : null,
        }
    }
    componentDidMount() {
        this.getProductPackages();
    }
    getProductPackages(){
        const {dispatch} = this.props;
        invProductActions.getProductPackages((done, result)=>{
            if(done) this.setState({itemPackages : result})
        })(dispatch);
    }
    cellMapFormat=superProps=>props=><EditableCellMapFormat {...props} {...superProps}/>
    deleteBtnHandler = row => () => {
        const {dispatch} = this.props;
        appActions.showSnackDialog("Are you sure you want to delete this package?",
        [<Button key="deleteProductPackage" onClick={()=>{
            appActions.closeSnackDialog()(dispatch);
            invProductActions.deleteProductPackage(row._id, (done, result)=>{
                if(done) this.setState({itemPackages : result})
            })(dispatch);
        }}>Delete</Button>])(dispatch)
    }
    editBtnHandler = row => () => {
        const {itemPackages} = this.state;
        const index = itemPackages.findIndex(item=>item._id===row._id);
        if(index || index === 0){
            itemPackages[index].editing = true;
            this.setState({itemPackages});
        }
    }
    addButtonHandler = length => () => {
        const {dispatch} = this.props;
        const data = {};
        const allContext = [];
        for (const cellMap in this.getNewPackageContext) {
            if (this.getNewPackageContext.hasOwnProperty(cellMap)) {
                const context = this.getNewPackageContext[cellMap];
                allContext.push(context);
                const {name, value } = context.state.data;
                if(name !== "_id"){
                    if(name === "name" && (!value || !String(value).trim())){
                        appActions.showSnackbar(
                            alertAction.error("Name field can not be empty!")
                        )(dispatch);
                        return ;
                    }else {
                        data[name] = value;
                    }
                }
            }
        }
        invProductActions.addProductPackage(data, (done, result)=>{
            if(done) {
                this.getProductPackages();
                allContext.forEach(context => {
                    context.setState(state=>({data : {...state.data, value : ""}}));
                });
            }
        })(dispatch);
    }
    editFinishBtnHandler = row => () => {
        const {dispatch} = this.props;
        const {context, _id} = row;
        const name = context.name.state.data.value;
        const description = context.description.state.data.value;
        if(!String(name).trim()){
            appActions.showSnackbar(
                alertAction.error("Name can not be empty field! insert a value")
            )(dispatch);
            return;
        }
        const data = {name, description};
        invProductActions.editProductPackage(_id, data, (done, result)=>{
            if(done) {
                this.setState({itemPackages : result});
            }
        })(dispatch);

    }
    cancelEditBtnHandler = row => () => {
        const {itemPackages} = this.state;
        const index = itemPackages.findIndex(item=>item._id===row._id);
        if(index || index === 0){
            delete itemPackages[index].editing;
            this.setState({itemPackages});
        }
    }
    getNewPackageContext = {};
    render() {
        let { classes} = this.props;
        let {itemPackages} = this.state;
        let header = ['ID', "Name", "Description"];
        let dataMap = ["_id", "name", "description"];
        if(inventoryUtil.isAdmin()){
            header = [...header, "Actions"];
            dataMap = [...dataMap, "action"];
            itemPackages = itemPackages ? 
                [...itemPackages.map(
                    item => ({...item, delible : true, editable : true})
                ), {new : true}] : 
                [{new : true}]
        }
        return (
            <div className={classNames("animated", "zoomIn",classes.root)}>
                <MyTable
                    header={header}
                    dataMap={dataMap}
                    data={itemPackages}
                    CellMap={this.cellMapFormat({
                        getContext:(context, cellMap)=>this.getNewPackageContext[cellMap]=context,
                        skipEdit:["_id"],
                        deleteBtnHandler : this.deleteBtnHandler.bind(this),
                        editBtnHandler : this.editBtnHandler.bind(this),
                        addButtonHandler : this.addButtonHandler.bind(this),
                        editFinishBtnHandler : this.editFinishBtnHandler.bind(this),
                        cancelEditBtnHandler : this.cancelEditBtnHandler.bind(this),
                    })}
                    />
            </div>
        );
    }
}


_INVItemPackages.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({invProductReducer}) => ({
    [invProductStrings.productPackages] : invProductReducer[invProductStrings.productPackages],
})


export const INVItemPackages = connect(mapStateToProps)(withStyles(style)(_INVItemPackages));
export {INVItemPackages as default}