export const inovateOSAdminMessageStrings = {
    messages : "messages",
}
export const inovateOSAdminMessageConstants = {
    SET_INSURE_ADMIN_MESSAGES : "SET_INSURE_ADMIN_MESSAGES",
}
export const inovateOSAdminMessageReducer = (state={}, action) => {
    const {type, payload} = action;
    switch(type){
        case inovateOSAdminMessageConstants.SET_INSURE_ADMIN_MESSAGES : 
            return {...state, ...payload};
        default : return state;
    }
}
export * from './actions';
export * from './services';