export const insureBlogStrings = {
    blogs : "blogs",
}
export const insureBlogConstants = {
    SET_BLOG : "SET_BLOG",
}
export const insureBlogReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case insureBlogConstants.SET_BLOG : 
            return {...state, ...payload};
        default : return {...state};
    }
}

export * from './actions';
export * from './services';