import { insureServiceServices } from "./services"
import { insureServiceStrings, insureServiceConstants } from "./config"
import { successNotice, errorNotice } from "../utils"

export const insureServiceActions = {
    verifyPhoneNumber : (phone, callback) => dispatch =>{
        insureServiceServices.verifyPhoneNumber(phone, (done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    submitPaymentInfo : (data, callback) => dispatch => {
        insureServiceServices.submitPaymentInfo(data, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    newCoopReg : (data, callback) => dispatch =>{
        insureServiceServices.newCoopReg(data, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getServices : callback => dispatch =>{
        insureServiceServices.getServiceInfo((done, result, message)=>{
            if(done) insureServiceActions.payload({
                [insureServiceStrings.services] : result.values
            })(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch => dispatch({
        type : insureServiceConstants.SET_INSURE_SERVICES,
        payload
    })
}