import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Subheader, Article } from '../../../../../includes';
import { inovateOSPageActions } from '../../actions';
import { inovateOSPageStrings } from '../../config';
import { inovateOSUtilStrings } from "../../../utils";


const style = theme => ({
    root: {
    },
    knowledge : {
        marginTop : 100
    },
    subheader :{},
    subContainer : {},
})
class _InovateOSServiceView extends Component {
    constructor(props) {
        super(props);
        
        this.serviceName = props.match.params.name;
    }
    componentDidMount() {
        const {
            dispatch, 
            [inovateOSPageStrings.services] : services,
        } = this.props;
        if(!services) inovateOSPageActions.getServices()(dispatch);
    }
    
    render() {
        const {
            classes,
            [inovateOSUtilStrings.subheadImage] : subheadImage,
            [inovateOSUtilStrings.backendBaseUrl] : baseUrl,
            [inovateOSPageStrings.services] : services
        } = this.props;
        let serviceItem = {};
        if(services){
            const {item} = services.getFirstObjectByPropValue("name", this.serviceName) || {};
            if(item) serviceItem = item;
        }
        return (
            <div className={classes.root}>
                <Subheader
                    classes={{
                        root : classes.subheader,
                        overlay : classes.subContainer,
                    }}
                    title={serviceItem.header}
                    image_url={subheadImage}
                    />
                <Article 
                    {...serviceItem}
                    baseUrl={baseUrl}
                    />
            </div>
        );
    }
}
_InovateOSServiceView.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({inovateOSUtilReducer, inovateOSPageReducer}) => ({
    [inovateOSUtilStrings.subheadImage] : inovateOSUtilReducer[inovateOSUtilStrings.subheadImage],
    [inovateOSUtilStrings.backendBaseUrl] : inovateOSUtilReducer[inovateOSUtilStrings.backendBaseUrl],
    [inovateOSPageStrings.services] : inovateOSPageReducer[inovateOSPageStrings.services],
})


export const InovateOSServiceView = connect(mapStateToProps)(withStyles(style)(_InovateOSServiceView));
export {InovateOSServiceView as default}