import { inovateOSUtil } from "../utils";
const {post, fetchGet} = inovateOSUtil;

export const inovateOSPageServices = {
    unsubscribe : (id, email, callback) => {
        fetchGet("app", "unsubscribe", {id, email}, ({unsubscribe, result, message})=>{
            callback(unsubscribe, result, message);
        })
    },
    subscribeNewsLetter : (name, email, callback) => {
        post({name, email}, "app", "subscribeNewsLetter", ({subscribeNewsLetter, result, message})=>{
            callback(subscribeNewsLetter, result, message);
        })
    },
    addMessage : (data, callback) => {
        post(data, "app", "addMessage", ({addMessage, result, message})=>{
            callback(addMessage, result, message);
        })
    },
}