import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { FormGroup, TextField, IconButton } from '@material-ui/core';
import { Done, Edit } from '@material-ui/icons';
import 'react-phone-number-input/style.css'
import PhoneInput from 'react-phone-number-input'
const style = theme => ({
    root: {
        display : "flex",
        flexDirection : "row",
        width : "100%",
        padding : "20px 10",
        justifyContent : "center",
        alignItems : "flex-end",
    },
})
class _TextFieldEditable extends Component {
    constructor(props) {
        super(props);
        this.state = {
            editing : false,
            value : null,
            loading : false,
        }
    }
    static getDerivedStateFromProps(props, state) {
        if(!state.value){
            state.value = props.value;
        }
        return state;
    }
    onChange(e){
        const value = e.target.value;
        this.setState({value});
    }
    doneBtnHandler(e){
        this.setState({editing : false, loading : true});
        const {value} = this.state;
        const {doneCallback} = this.props;
        if(doneCallback) 
            doneCallback(value, this);
    }
    editBtnHandler(){
        const { editCallback } = this.props;
        const { value } = this.state;
        this.setState({editing : true}, ()=>{
            if(editCallback) 
                editCallback(value);
        })
    }
    render() {
        const {classes,
            textFieldProps, 
            doneIconProp, 
            editIconProps, phone,
        } = this.props;
        const {value, editing, loading} = this.state;
        return (
            <FormGroup className={classes.root}>
                {phone ? 
                    <PhoneInput
                        className={classes.textField}                        
                        style={{
                            marginTop : 20,
                            marginBottom : 10,
                            padding : 10,
                            width : "70%"
                        }}
                        placeholder="Enter phone number"
                        value={value || ""}
                        disabled={!editing}
                        onChange={ value => this.setState({value})} 
                        />
                    : 
                    <TextField 
                        disabled={!editing}
                        style={{
                            width : "70%"
                        }}
                        value={value}
                        onChange={this.onChange.bind(this)}
                        {...textFieldProps}/>
                }
                {editing ? 
                    <IconButton  onClick={this.doneBtnHandler.bind(this)}>
                        <Done {...doneIconProp}/>
                    </IconButton> : 
                    <IconButton disabled={loading}  onClick={this.editBtnHandler.bind(this)}>
                        <Edit {...editIconProps}/>
                    </IconButton>
                }
            </FormGroup>
        );
    }
}
_TextFieldEditable.propTypes = {
    classes : PropTypes.object.isRequired,
    value : PropTypes.string,
    textFieldProps : PropTypes.object,
    doneIconProp : PropTypes.object,
    editIconProps : PropTypes.object,
    editCallback : PropTypes.func,
    doneCallback : PropTypes.func,
    phone : PropTypes.bool,
};
export const TextFieldEditable = withStyles(style)(_TextFieldEditable);