import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import {connect} from 'react-redux';
import { Header, screenStrings } from '../../../includes';
import Route from 'react-router-dom/Route';
import { Footer } from '../../../includes/SiteComponent';
import { inovateOSUtilStrings, inovateOSUtil } from '../utils';
import { InovateOSFooter } from '../InovateOSFooter';
const style = theme => ({
    root: {
        backgroundColor : inovateOSUtil.getTheme().background
    },
    subheader : {
        paddingTop : 100,
    },
    componentRoot : {
        [theme.breakpoints.up("sm")] : {
            padding : "0px 100px",
        }
    },
    headerStyle : {
        padding : "0px 100px",
        [theme.breakpoints.down("sm")] : {
            padding : 0,
        }
    },
    siteMenu : {
        paddingLeft : 100,
        paddingRight : 100
    },
    paper : {
        backgroundColor : inovateOSUtil.getTheme().primaryTrans,
        color : inovateOSUtil.getTheme().wheat,
        minHeight : "2cm"
    },
    linkItem : {
        textDecoration : "none",
        color : inovateOSUtil.getTheme().wheat,
        "&:hover" : {
            fontWeight : "bold",
            textShadow : "1px 1px 1px #a00e0e"
        },
    },
    logo : {
        height : 50,
        width : 50,
        boxShadow : "5px 5px 5px",
    }
})
class _InovateOSSiteRoute extends Component {
    render() {
        const {
            classes,
            [screenStrings.appTheme] : appTheme,
            [inovateOSUtilStrings.settings] : settings,
            component : Component, ...props
        } = this.props;
        let contactValue;
        if(settings) {
            const {item : contactItems} = settings.getFirstObjectByPropValue("name", "contactInfo") || {};
            if(contactItems) contactValue = contactItems.value;
        }
        return (
            <div style={{
                // padding : "0px 100px"
            }}>
            <Header
                classes={{
                    siteMenu : classes.siteMenu,
                    logo : classes.logo
                }}
                
                rootProps={{
                    className : classes.headerStyle,
                    style: {
                        backgroundColor : "#3939fff2", //appTheme ? appTheme.primaryTrans : null,
                    },
                    elevation : 0,
                }}
                titleProps={{
                    style : {
                        color : appTheme ? appTheme.backgroundTypo : null,
                        borderBottom : "none",
                    }
                }}
                drawerProps={{
                    color : appTheme ? appTheme.backgroundTypo : null,
                    bgColor : appTheme ? appTheme.drawerBg : null,
                }}
                iconProps={{
                    style : {color : appTheme ? appTheme.backgroundTypo : null}
                }} 
                subheaderMenuProps={{
                    classes : {
                        paper : classes.paper,
                        linkItem : classes.linkItem
                    }
                }}/>
            <Route {...props} component={prop=><Component 
                classes={{
                    subContainer : classes.componentRoot,
                    subheader : classes.subheader
                }} 
                {...prop}/>}/>
            <InovateOSFooter/>
        </div>
        );
    }
}
_InovateOSSiteRoute.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({screenReducer, inovateOSUtilReducer})=>({
    [screenStrings.appTheme] : screenReducer[screenStrings.appTheme],
    [inovateOSUtilStrings.settings] : inovateOSUtilReducer[inovateOSUtilStrings.settings]
})
export const InovateOSSiteRoute = connect(mapStateToProps)(withStyles(style)(_InovateOSSiteRoute));