import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import $ from 'jquery';
import {colors} from '../../../utils'
import { TextField, FormGroup, FormControl, FormLabel, Typography } from '@material-ui/core';
import {MyButton} from '../../includes';
import { appActions, alertAction } from '../../../actions';


const style = theme => ({
    root: {
        background : "url('./images/sch_children.jpeg') no-repeat center center",
        backgroundSize : "cover"
    },
    overLay : {
        height : "100%",
        width : "100%",
        backgroundColor : colors.grayTrans,
        display : "flex",
        alignItems : "center",
        justifyContent : "center"
    },
    formContainer : {
        backgroundColor : colors.primary, 
        padding : 20,
        borderRadius : 10,
        width : "50%",
        [theme.breakpoints.down("xs")] : {
            width : "80%"
        }
    },
    textField : {
        background : colors.white,
        borderRadius : 5,
        border : "none"
    },
    noBorder : {
        border : "none"
    },
    headerContainer : {
        marginBottom : 50
    },
    header : {
        color : colors.white,
        fontWeight : "bold"
    },
    loginButton : {
        marginTop : 20,
        color : colors.primary
    }
})
class _Login extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data  : {
                username : "",
                password : ""
            },
            loading : false
        }
    }
    handleChange=name=>event=>{
        let value = event.target.value;
        let data = {...this.state.data};
        data[name] = value;
        this.setState({data});
    }
    componentDidMount(){
        $("#home").css("height", window.innerHeight);
    }
    login(){
        const {username, password} = this.state.data;
        if(username.trim() === "" && password.trim() === ""){
            appActions.showSnackbar(
                alertAction.error("Empty field error!")
            )(this.props.dispatch);
            return;
        }
        appActions.login(username, password, (done, message, result) =>{
            if(done){
                if(result.myProfile.schoolAdmin || 
                    (result.mySchoolIds && result.mySchoolIds.length != 0))
                    this.props.history.replace("/");
                else this.props.history.replace("/outcast");
            }
        })(this.props.dispatch); 
    }
    render() {
        const {classes} = this.props;
        const {username, password, loading} = this.state;
        return (
            <div id="home" className={classes.root}>
                <div className={classes.overLay}>
                    <div className={classes.formContainer}>
                        <FormGroup>
                            <FormLabel className={classes.headerContainer}>
                                <Typography className={classes.header} component="h4" variant="h4">Login</Typography>
                            </FormLabel>
                            <FormControl>
                                <TextField
                                    label="Username"
                                    placeholder="username"
                                    margin="normal"
                                    onChange={this.handleChange("username")}
                                    value={username}
                                    className={classes.textField}
                                    variant="outlined"/>
                            </FormControl>
                            <FormControl>
                                <TextField
                                    label="Password"
                                    placeholder="password"
                                    margin="normal"
                                    onChange={this.handleChange("password")}
                                    value={password}
                                    type="password"
                                    className={classes.textField}
                                    variant="outlined"/>
                            </FormControl>
                            <FormControl>
                                <MyButton
                                    loading={loading}
                                    className={classes.loginButton}
                                    onClick={()=>this.login()}
                                    type="secondary" 
                                    value="Login"/>
                            </FormControl>
                        </FormGroup>
                    </div>
                </div>
            </div>
        );
    }
}


_Login.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapDispatchToProps = dispatch => {
    return {
        dispatch
    }
}
const mapStateToProps = state => ({
    state
})


export const Login = connect(mapStateToProps,mapDispatchToProps)(withStyles(style)(_Login));
export {Login as default};