import { trackerUtilConstants, trackerUtilStrings } from "./config";
import { trackerUtilServices } from "./services";
import { _storeData } from "../../../utils";
import { errorNotice } from "./trackerUtil";
import { store } from "../../../helpers";

export const trackerUtilActions = payload => dispatch => dispatch({
    type : trackerUtilConstants.SET_UTIL,
    payload 
});

export const trackerActions = {
    getUserInfo : (name, callback) => dispatch => {
        trackerUtilServices.getUserInfo(name, (done, result, message, data)=>{
            if(done){
                trackerUtilActions({
                    [trackerUtilStrings[name]] : result,
                })(dispatch);
            }else errorNotice(message, dispatch);
            
        });
    },
    getUser : callback => dispatch => {
        trackerUtilServices.getUser((done, result, message)=>{
            if(done){
                trackerUtilActions({
                    [trackerUtilStrings.myProfile] : result.myProfile,
                    [trackerUtilStrings.trackingMe] : result.trackingMe,
                    [trackerUtilStrings.disableAllTracking] : result.disableAllTracking,
                })(dispatch);
            }
            if(callback) callback(done, result, message);
        })
    },
    signup : (data, callback) => dispatch => {
        trackerUtilServices.signup(data, (done, result, message)=>{
            if(done){
                _storeData(store.getState().trackerUtilReducer[trackerUtilStrings.tokenAlias], result.myProfile.token);
                _storeData(store.getState().trackerUtilReducer[trackerUtilStrings.userAlias], result._id);
                trackerUtilActions({
                    [trackerUtilStrings.myProfile] : result.myProfile,
                    [trackerUtilStrings.trackingMe] : result.trackingMe,
                    [trackerUtilStrings.disableAllTracking] : result.disableAllTracking,
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    loging : (email, password, callback) => dispatch => {
        trackerUtilServices.login(email, password, (done, result, message)=>{
            if(done){
                _storeData(store.getState().trackerUtilReducer[trackerUtilStrings.tokenAlias], result.myProfile.token);
                _storeData(store.getState().trackerUtilReducer[trackerUtilStrings.userAlias], result._id);
                trackerUtilActions({
                    [trackerUtilStrings.myProfile] : result.myProfile,
                    [trackerUtilStrings.trackingMe] : result.trackingMe,
                    [trackerUtilStrings.disableAllTracking] : result.disableAllTracking,
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    logout : () => {
        localStorage.removeItem(store.getState().trackerUtilReducer[trackerUtilStrings.tokenAlias]);
        localStorage.removeItem(store.getState().trackerUtilReducer[trackerUtilStrings.userAlias]);
    },
}
