export const hirUtilStrings = {
    theme : "theme",
    tokenAlias : "tokenAlias",
    userAlias : "userAlias",
    userType : "userType",
    backendUrl : "backendUrl",
    backendBaseUrl : "backendBaseUrl",
    myProfile : "myProfile",
    defaultImage : "defaultImage",
}

export const hirUtilConstants = {
    SET_UTIL : "SET_UTIL",
}

export const hirUtilReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case hirUtilConstants.SET_UTIL : 
            return {...state, ...payload};
        default : return {...state};
    }
}

