import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { FormDisplay, formStrings, getFormDisplayData, inventoryAppActions, inventoryAlertActions } from '../../../../utils';
import {  } from "module";
import { INVCategorisedOptions } from './INVCategorisedOptions';
import { INVUnCategorisedOptions } from './INVUnCategorisedOptions';
import { INVButton } from '../../../../Includes';
const style = theme => ({
    root: {
    },
    createBtn : {
        marginTop : 20,
    }
})
class _INVNewDescription extends Component {
    constructor(props) {
        super(props);
        this.state = {
            loading : false,
        }
        this.formConfig = [
            {name : "name", label : "Description Name", placeholder : "Description name", type : "text"},
            {name : "categorised", label : "Categorised list", type : "check"}
        ]
    }
    formName = "NewItemDescription"
    createDescription(){
        this.setState({loading : true});
        const {dispatch, createDescription} = this.props;
        const data = getFormDisplayData(this.formContext, (name, value, data)=>{
            if(name === "name" && !String(value).trim()){
                inventoryAppActions.showSnackbar(
                    inventoryAlertActions.error("Description name is empty! Input a value")
                )(this.props.dispatch);
                return false;
            }else return true;
        })();
        if(data){
            data.values = this.valueContext.state.data;
            if(data.values.length === 0){
                inventoryAppActions.showSnackbar(
                    inventoryAlertActions.error("No value added to this description")
                )(dispatch)
                return this.setState({loading : false});
            }else{
                if(createDescription)
                    createDescription(data, this);
                else this.setState({loading : false});
            }
        }else {
            return this.setState({loading : false});
        }
        
    }
    render() {
        const {classes,
            [formStrings.forms] : forms    
        } = this.props;
        const {loading } = this.state;
        let categorised;
        if(forms){
            let form = forms[this.formName];
            if(form){
                categorised = form.categorised;
            }
        }
        return (
            <div className={classes.root}>
                <FormDisplay
                    getContext={context=>this.formContext = context}
                    header="New Item Description"
                    formName={this.formName}
                    formConfig={this.formConfig}
                    />
                {categorised ?
                    <INVCategorisedOptions
                        getContext={context=>this.valueContext=context}/> : 
                    <INVUnCategorisedOptions
                        getContext={context=>this.valueContext=context}/>}

                <INVButton
                    loading={loading}
                    classes={{
                        btn : classes.createBtn
                    }}
                    onClick={this.createDescription.bind(this)}>
                        Create Product Description
                    </INVButton>
            </div>
        );
    }
}

_INVNewDescription.propTypes = {
    classes : PropTypes.object.isRequired,
    createDescription : PropTypes.func,
};
const mapStateToProps = ({formReducer}) => ({
    [formStrings.forms] : formReducer[formStrings.forms],
})


export const INVNewDescription = connect(mapStateToProps)(withStyles(style)(_INVNewDescription));
export {INVNewDescription as default}