import { invSupplierServices } from "./services"
import { invSupplierConstants, invSupplierStrings } from "./config"
import { stockServices } from "../Stocks"
import { invProductServices } from "../INVProducts";
import { invErrorNotice, invSuccessNotice } from "../utils";

export const invSupplierActions = {
    searchSupplierMinMaxId : (keyword, callback) => dispatch => {
        invSupplierServices.searchSupplierMinMaxId(keyword, (done, result, message)=>{
            if(!done) invErrorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    searchSuppliers : (keyword, rows, skip, callback) => dispatch => {
        invSupplierServices.searchSuppliers(keyword, rows, skip, (done, result, message)=>{
            if(!done) invErrorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getSuppliers : (rows, skip, callback) => dispatch => {
        invSupplierServices.getSuppliers(rows, skip, (done, result, message)=>{
            if(!done) invErrorNotice(message, dispatch);
            else invSupplierActions.payload({
                [invSupplierStrings.suppliers] : result
            })(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    createSupplier : (data, callback) => dispatch => {
        invSupplierServices.createSupplier(data, (done, result, message)=>{
            //TODO : get all suppliers
            if(!done) invErrorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch => dispatch({
        type : invSupplierConstants.SET_SUPPLIER,
        payload
    }),





    getAllSuppliersBrief : callback => dispatch=>{
        invSupplierServices.getAllSuppliersBrief((done, result, message)=>{
            if(done) dispatch({
                type : invSupplierConstants.SET_SUPPLIER,
                payload : {
                    [invSupplierStrings.allSupplierBrief] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getItemTags : callback => dispatch => {
        invProductServices.getproductItemTags((done, result, message)=>{
            if(done) dispatch({
                type : invSupplierConstants.SET_SUPPLIER,
                payload : {
                    [invSupplierStrings.itemTags] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getItemPackages : callback => dispatch => {
        invProductServices.getItemPackages((done, result, message)=>{
            if(done) dispatch({
                type : invSupplierConstants.SET_SUPPLIER,
                payload : {
                    [invSupplierStrings.itemPackages] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getStockCategories : callback => dispatch => {
        stockServices.getStockCategories((done, result, message)=>{
            if(done) dispatch({
                type : invSupplierConstants.SET_SUPPLIER,
                payload : {
                    [invSupplierStrings.stockCategories] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getSupplierBrands : (lastId, rows, callback) => dispatch=>{
        invSupplierServices.getSupplierBrands(lastId, rows, (done, result, message)=>{
            if(done)dispatch({
                type : invSupplierConstants.SET_SUPPLIER,
                payload : {
                    [invSupplierStrings.supplierBrands] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    setBrandEditMode : mode => dispatch => dispatch({
        type : invSupplierConstants.SET_SUPPLIER,
        payload : {
            [invSupplierStrings.supplierBrandEditMode] : mode
        }
    }),
    getSupplier_NO_DISPATCH : (supplierId, callback)=>{
        invSupplierServices.getSupplier(supplierId, callback);
    },
    getSuppliersBrief : (lastId, rows, callback)=>dispatch=>{
        invSupplierServices.getSuppliersBrief(lastId, rows, (done, result, message)=>{
            if(done) dispatch({
                type : invSupplierConstants.SET_SUPPLIER,
                payload :{
                    [invSupplierStrings.suppliersBrief] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    }
}