
import io from 'socket.io-client';
import { trackerUtil } from './trackerUtil';
import { socketIOStrings, socketIOActions, socketIO, socketSubscription } from '../../../socket.io';
import { contactActions } from '../Contacts';
import { chatFooterStrings, chatFooterActions } from '../../includes';
import { socketFeedbackHandler } from './socketFeedback';
import { store } from '../../../helpers';

export const socketSetup = (callback) => {
    const dispatch = store.dispatch;
    const chatContacts = store.getState().chatFooterReducer[chatFooterStrings.allChatListData];
    const socket = io('http://localhost:8000/?'+
        'token=' + trackerUtil.getToken()+"&"+
        "userId="+trackerUtil.getUserId(), {
        path : '/mobile/trackerx/v1'
    });
    socket.on("connect", ()=>{
        console.log("socket connected");
        socketIOActions({
            [socketIOStrings.socket] : socket
        })(dispatch)
        socket.on("contactConnected", ({contactConnected, result, message})=>{
            if(contactConnected){
                if(!chatContacts || !chatContacts.getFirstObjectByPropValue("_id", result._id)){
                    result.active = true;
                    chatFooterActions({
                        [chatFooterStrings.allChatListData] : chatContacts ? [...chatContacts, result.myProfile] : [result.myProfile]
                    })(dispatch);
                }else{
                    let chatContactFilter =  chatContacts.getFirstObjectByPropValue("_id", result._id);
                    chatContacts[chatContactFilter.index] = {
                        ...chatContacts[chatContactFilter.index], 
                        active : true
                    };
                    chatFooterActions({
                        [chatFooterStrings.allChatListData] : [...chatContacts]
                    })(dispatch);
                }
            }
        })
        socketIO.on("feedback", res => {
            console.log('*************** START feedback ***************');
            console.log(res)
            console.log('*************** END feedback ***************');
            socketFeedbackHandler(res)
        });
        if(callback) callback();
    });
    socketSubscription();
}