import { hirUtil } from "../utils"

const {post, fetchGet} = hirUtil
const owner = "1";
export const hirUserServices = {
    searchUser : (keyword, callback) => {
        fetchGet(owner, "searchUser", {keyword}, ({searchUser, result, message})=>{
            callback({searchUser, result, message});
        })
    },
    updateProfile : (userId, profile, callback)=>{
        post({userId, profile}, owner, "updateUserProfile", ({updateUserProfile, result, message})=>{
            callback(updateUserProfile, result, message);
        })
    },
    activateUser : (id, callback) =>{
        fetchGet(owner, "activateUser", {id}, ({activateUser, result, message})=>{
            callback(activateUser, result, message);
        })
    },
    suspendUser : (id, callback) =>{
        fetchGet(owner, "suspendUser", {id}, ({suspendUser, result, message})=>{
            callback(suspendUser, result, message);
        });
    },
    archiveUser : (id, callback) =>{
        fetchGet(owner, "archiveUser", {id}, ({archiveUser, result, message})=>{
            callback(archiveUser, result, message);
        });
    },
    createUser : (data, callback) => {
        post(data, owner, "createUser", ({createUser, result, message})=>{
            callback(createUser, result, message);
        })
    },
    getUsers : (callback) => {
       fetchGet(owner, "getUsers", {}, ({getUsers, result, message})=>{
           callback(getUsers, result, message);
       })
    }
}