import { insureAdminCooperativeConstants, insureAdminCooperativeStrings } from "./config";
import { insureAdminCooperativeServices } from "./services";
import { errorNotice, successNotice } from "../utils";

export const insureAdminCooperativeActions = {
    unsuspendSubscriber : (id, callback) => dispatch=>{
        insureAdminCooperativeServices.unsuspendSubscriber(id, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, dispatch);
        })
    },
    suspendSubscriber : (id, callback) => dispatch=>{
        insureAdminCooperativeServices.suspendSubscriber(id, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, dispatch);
        })
    },
    activateSubscriber : (id, expDate, callback) => dispatch => {
        insureAdminCooperativeServices.activateSubscriber(id, expDate, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, dispatch);
        })
    },
    deactivateSubscriber : (id, callback) => dispatch => {
        insureAdminCooperativeServices.deactivateSubscriber(id, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, dispatch);
        })
    },
    deleteRequest : (id, callback) => dispatch => {
        insureAdminCooperativeServices.deleteRequest(id, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, dispatch);
        })
    },
    approveRequest : (id, userId, expDate, callback) => dispatch => {
        insureAdminCooperativeServices.approveRequest(id, userId, expDate, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, dispatch);
        })
    },
    getPayments : (lastId, rows, callback) => dispatch => {
        insureAdminCooperativeServices.getPayments(lastId, rows, (done, result, message)=>{
            if(done) insureAdminCooperativeActions.payload({
                [insureAdminCooperativeStrings.payments] :result
            })(dispatch); 
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);  
        })
    },
    getSubscribers : (lastId, rows, callback) => dispatch => {
        insureAdminCooperativeServices.getSubscribers(lastId, rows, (done, result, message)=>{
            if(done) insureAdminCooperativeActions.payload({
                [insureAdminCooperativeStrings.subscribers] : result
            })(dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);            
        })
    },
    payload : payload => dispatch =>dispatch({
        type : insureAdminCooperativeConstants.SET_INSURE_ADMIN_COOPERATIVE,
        payload
    })
}