export const insureLegalStrings = {
    legals :"legals",

};
export const insureLegalConstants = {
    SET_LEGAL : "SET_LEGAL",
}
export const insureLegalReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch (type){
        case insureLegalConstants.SET_LEGAL : 
            return {...state, ...payload};
        default : return {...state};
    }
}
export * from './actions';
export * from './services';
