import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyTable, SelectedInfo } from '../../../includes';
import { parentStrings, parentActions } from '../../Parents';
import { Paper, TextField, Button, FormControl, Grid , colors as mColors} from '@material-ui/core';
import { colors } from '../../../../utils';

const parentList = [

]
const style = theme => ({
    root: {
    },
    searchContainer : {
        margin: "50px 0px",
        display : "flex",
        alignItems : "center",
        justifyContent : "center",
        border : "solid 1px " + colors.primary
    },
    searchBtn : {
        backgroundColor : colors.primary,
        color : colors.white,
        "&:hover" : {
            backgroundColor : colors.primary
        }
    },
    finishBtn : {
        backgroundColor : colors.secondary,
        color : colors.white,
        "&:hover" : {
            backgroundColor : colors.secondary
        }
    },
    backBtn : {
        color : colors.primary,
        "&:hover" : {
            backgroundColor : colors.secondary
        }
    },
    
})
class _ParentListDialog extends Component {
    constructor(props) {
        super(props);
        this.state = {
            selectedParent : null,
            lastId : null,
            rows : 20,
        }
    }
    componentDidMount(){
        const {lastId, rows} = this.state;
        const {[parentStrings.parents] : parents, dispatch} = this.props;
        if(!parents) parentActions.getParents(lastId, rows)(dispatch);
    }
    nameMapping(name){
        switch(name){
            case "firstName" : return "First Name";
            case "lastName" : return "Last Name";
            case "middleName" : return "Middle Name";
            case "phone" : return "Phone";
            case "email" : return "Email";
        }
    }
    finish(){
        const {selectedParent} = this.state;
        this.props.finish(selectedParent);
        this.props.closeDialog();
    }
    render() {
        const {
            classes,
            [parentStrings.parents] : parents = []
        } = this.props;
        const {selectedParent} = this.state;
        return (
            <div className={classes.root}>
                {selectedParent && <SelectedInfo 
                    skip={["_id"]}
                    selectedInfo={selectedParent} 
                    nameMapping={this.nameMapping}
                    valueMapping={(name, value)=>value}
                    />}
                <Paper className={classes.searchContainer}>
                    <FormControl style={{padding : 10}}>
                        <TextField style={{backgroundColor : colors.grayTrans}} variant="outlined" margin="dense" label="Search" placeholder="type the name of parent"/>
                    </FormControl>
                    <FormControl style={{padding : 10}}>
                        <Button className={classes.searchBtn} >Search</Button>
                    </FormControl>
                    <div style={{display: "flex", flexGrow:1}}/>
                    <FormControl style={{padding : 10}}>
                        <Button className={classes.backBtn} 
                            onClick={this.props.closeDialog}>Back</Button>
                    </FormControl>
                    <FormControl style={{padding : 10}}>
                        <Button className={classes.finishBtn}
                            onClick={this.finish.bind(this)} >Finish</Button>
                    </FormControl>
                </Paper>
                <MyTable
                    header={["Last Name", "First Name", "Middle Name", "Phone", "Email"]}
                    dataMap={["lastName", "firstName", "middleName", "phone", "email"]}
                    data={parents}
                    rowAction={row=>()=>this.setState({selectedParent: row})}
                    />
            </div>
        );
    }
}


_ParentListDialog.propTypes = {
    classes : PropTypes.object.isRequired,
    closeDialog : PropTypes.func,
    finish : PropTypes.func,
};

const mapStateToProps = ({parentReducer}) => ({
    [parentStrings.parents] :parentReducer[parentStrings.parents]
})


export const ParentListDialog = connect(mapStateToProps)(withStyles(style)(_ParentListDialog));