import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import { TableCell, TextField, IconButton, withStyles, FormControl } from '@material-ui/core';
import { Add as AddIcon, Edit as EditIcon, Delete as DeleteIcon, Done as DoneIcon, Cancel as CancelIcon} from '@material-ui/icons';
import { colors } from '../../../../../utils';
const styles = theme => ({
    icon : {
        padding : 0
    }
})
class _TeacherRemarkCellMapFormat extends Component{
    constructor(props) {
        super(props);
        this.state = {
            data : {
                name : props.cellMap,
                value : props.row[props.cellMap]
            }
        }
        //get the context for editing / and adding new row
        //new row goes directory to the parent component, editing one using the row attachment
        if(props.row.new && props.getContext) props.getContext(this, props.cellMap);
        
    }
    handleChange = e => {   
        let data = {...this.state.data};
        data.value = e.target.value;
        this.setState({data});
    }
    render(){
        if(this.props.row.editing){
            if(this.props.row.context) this.props.row.context[this.props.cellMap] = this;
            else this.props.row.context = {[this.props.cellMap] : this};
        } 
        const {data} = this.state;
        const {
            classes, listLength,
            row, cellMap, addButtonHandler, 
            editBtnHandler, deleteBtnHandler, 
            editFinishBtnHandler, cancelEditBtnHandler
        } = this.props;
        if(row.new || row.editing){
            switch(cellMap){
                case "action" : return <TableCell>
                    {!row.editing ?
                        <IconButton 
                            className={classes.icon}
                            onClick={addButtonHandler && addButtonHandler(listLength)} 
                            style={{backgroundColor: colors.secondary, color :colors.white}}>
                            <AddIcon/>
                        </IconButton> :
                        <Fragment>
                            <IconButton
                                className={classes.icon} onClick={editFinishBtnHandler && editFinishBtnHandler(row)}>
                                <DoneIcon  style={{color : colors.secondary}}/>
                            </IconButton>
                            <IconButton
                                className={classes.icon} onClick={cancelEditBtnHandler && cancelEditBtnHandler(row)}>
                                <CancelIcon color="secondary"/>
                            </IconButton>
                        </Fragment>}                    
                </TableCell>
                case "_id" : return <TableCell></TableCell>;
                default : 
                    return <TableCell style={{padding: 10}}>
                        <TextField
                            style={{width : "100%"}}
                            value={data.value || ""}
                            margin="normal"
                            type={cellMap === "rate" ? "number" : "text"}
                            min={1}
                            max={5}
                            label={String(cellMap).toUpperCase()}
                            placeholder={String(cellMap)}
                            onChange={this.handleChange.bind(this)}/>
                    </TableCell>
            }
        }else{
            switch(cellMap){
                case "action" : return <TableCell><FormControl style={{flexDirection : "row"}}>
                        {row.editable && <IconButton
                            className={classes.icon} onClick={editBtnHandler && editBtnHandler(row)}>
                            <EditIcon/>
                        </IconButton>}
                        <IconButton
                            className={classes.icon} onClick={deleteBtnHandler && deleteBtnHandler(row)}>
                            <DeleteIcon color="secondary"/>
                        </IconButton>
                        </FormControl></TableCell>;
                default : 
                    return <TableCell style={{padding: 10}}>
                        {row[cellMap]}
                    </TableCell>
            }
        }
    }
}
_TeacherRemarkCellMapFormat.propTypes = {
    classes : PropTypes.object,
    listLength : PropTypes.number,
    deleteBtnHandler : PropTypes.func,
    editBtnHandler : PropTypes.func,
    addButtonHandler : PropTypes.func,
    editFinishBtnHandler : PropTypes.func,
    cancelEditBtnHandler : PropTypes.func,
}
export const TeacherRemarkCellMapFormat = withStyles(styles)(_TeacherRemarkCellMapFormat);