export const hookStateVisibility = (hooks, data) => {
    if(hooks && hooks.visibility){
        const vis = hooks.visibility;
        if(vis.variables && vis.variables.state){
            let {name : stateVarName, value : stateValue} = vis.variables.state;
            if(!data || !data[stateVarName] || data[stateVarName] !== stateValue){
                return false;
            }
        }
    }
    return true;
}
export const getFormDisplayData = (formDisplayContext, callback) => notify => {
    let newData = {};
    const {inputFieldContexes} = formDisplayContext;
    for (const name in inputFieldContexes) {
        if (inputFieldContexes.hasOwnProperty(name)) {
            const context = inputFieldContexes[name];
            const data = {...context.state.data};
            if(callback && !callback(name, data[name], context))
                return false;
            else{
                if(data[name])
                    newData[name] = data[name];
                else if(notify && !notify("Empty field", "error")){
                    return false;
                }
            }
        }
    }
    return newData;
}