import { supplierServices } from "./services"
import { supplierConstants, supplierStrings } from "./config"
import { stockServices } from "../Stocks"
import { productServices } from "../Products"

export const supplierActions = {
    getAllSuppliersBrief : callback => dispatch=>{
        supplierServices.getAllSuppliersBrief((done, result, message)=>{
            if(done) dispatch({
                type : supplierConstants.SET_SUPPLIER,
                payload : {
                    [supplierStrings.allSupplierBrief] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getItemTags : callback => dispatch => {
        productServices.getproductItemTags((done, result, message)=>{
            if(done) dispatch({
                type : supplierConstants.SET_SUPPLIER,
                payload : {
                    [supplierStrings.itemTags] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getItemPackages : callback => dispatch => {
        productServices.getItemPackages((done, result, message)=>{
            if(done) dispatch({
                type : supplierConstants.SET_SUPPLIER,
                payload : {
                    [supplierStrings.itemPackages] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getStockCategories : callback => dispatch => {
        stockServices.getStockCategories((done, result, message)=>{
            if(done) dispatch({
                type : supplierConstants.SET_SUPPLIER,
                payload : {
                    [supplierStrings.stockCategories] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getSupplierBrands : (lastId, rows, callback) => dispatch=>{
        supplierServices.getSupplierBrands(lastId, rows, (done, result, message)=>{
            if(done)dispatch({
                type : supplierConstants.SET_SUPPLIER,
                payload : {
                    [supplierStrings.supplierBrands] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    setBrandEditMode : mode => dispatch => dispatch({
        type : supplierConstants.SET_SUPPLIER,
        payload : {
            [supplierStrings.supplierBrandEditMode] : mode
        }
    }),
    getSupplier_NO_DISPATCH : (supplierId, callback)=>{
        supplierServices.getSupplier(supplierId, callback);
    },
    getSuppliersBrief : (lastId, rows, callback)=>dispatch=>{
        supplierServices.getSuppliersBrief(lastId, rows, (done, result, message)=>{
            if(done) dispatch({
                type : supplierConstants.SET_SUPPLIER,
                payload :{
                    [supplierStrings.suppliersBrief] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    }
}