export const insureAdminUtilStrings = {
    theme : "theme",
    tokenAlias : "tokenAlias",
    userAlias : "userAlias",
    backendUrl : "backendUrl",
    backendBaseUrl : "backendBaseUrl",
    myProfile : "myProfile",
    defaultImage : "defaultImage",
}

export const insureAdminUtilConstants = {
    SET_UTIL : "SET_UTIL",
}

export const insureAdminUtilReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case insureAdminUtilConstants.SET_UTIL : 
            return {...state, ...payload};
        default : return {...state};
    }
}

