import React from 'react';
import { routeNamesInventory } from "./routeNames";

const Dashboard = React.lazy(()=>import("./INVDashboard/INVDashboard"))
const NewStock= React.lazy(()=>import('./Stocks/Stocks/NewStock/NewStock'));
const Stocks= React.lazy(()=>import('./Stocks/Stocks/Stocks'));
const StockCategory = React.lazy(()=>import('./Stocks/Categories/Category'));
const StockStores = React.lazy(()=>import('./Stocks/Stores/Stores'));
const StockTransfers = React.lazy(()=>import('./Stocks/Transfers/Transfers'));
const StockTaking = React.lazy(()=>import('./Stocks/StockTaking/StockTaking'));
const ProductItems = React.lazy(()=>import('./INVProducts/INVProducts/Items'));
const ProductItem = React.lazy(()=>import('./INVProducts/INVProducts/Item/Item'));

const PriceList = React.lazy(()=>import('./PriceList/PriceList'));
const PriceListItems = React.lazy(()=>import('./PriceList/PriceListItems/PriceListItems'));
const NewPriceList = React.lazy(()=>import('./PriceList/NewPriceList/NewPriceList'));

const ProductNewItem = React.lazy(()=>import('./INVProducts/INVProducts/INVNewProduct/INVNewProduct'));
const ItemConfiguration = React.lazy(()=>import('./INVProducts/INVItemConfiguration/INVItemConfiguration'));
const PackagingItems = React.lazy(()=>import('./INVProducts/INVItemConfiguration/INVItemPackaging/INVItemsByPackaging/IVNItemsByPackaging'));
const Suppliers = React.lazy(()=>import('./INVSuppliers/INVSuppliers'));
const NewSupplier = React.lazy(()=>import('./INVSuppliers/INVNewSuppliers/INVNewSuppliers'));
const Supplier = React.lazy(()=>import('./INVSuppliers/Supplier/Supplier'));
const SupplierBrands = React.lazy(()=>import('./INVSuppliers/INVBrands/Brands'));
const NewSupplierBrand = React.lazy(()=>import("./INVSuppliers/INVBrands/INVNewBrand/INVNewBrand"));

export const inventoryRoutes = [
    { path : routeNamesInventory.dashboard, exact : true, component : Dashboard},
    { path : routeNamesInventory.newStock, exact : true,  component : NewStock },
    { path : routeNamesInventory.stocks, exact : true,  component : Stocks },
    { path : routeNamesInventory.stockCategory, exact : true,  component : StockCategory },
    { path : routeNamesInventory.stockStores, exact : true,  component : StockStores },
    { path : routeNamesInventory.stockTransfers, exact : true,  component : StockTransfers },
    { path : routeNamesInventory.stockTaking, exact : true,  component : StockTaking },
    { path : routeNamesInventory.items, exact : true, component : ProductItems},
    { path : routeNamesInventory.item, exact : true, component : ProductItem},

    { path : routeNamesInventory.newItem, exact : true, component : ProductNewItem},
    { path : routeNamesInventory.productConfig, exact : true, component : ItemConfiguration},

    { path : routeNamesInventory.priceListHx, exact : true, component : PriceList},
    { path : routeNamesInventory.priceListItem, exact : true, component : PriceListItems},
    { path : routeNamesInventory.priceListNew, exact : true, component : NewPriceList},
    
    { path : routeNamesInventory.suppliers, exact : true, component : Suppliers},
    { path : routeNamesInventory.newSupplier, exact : true, component : NewSupplier},
    { path : routeNamesInventory.supplier, exact : true, component : Supplier},
    { path : routeNamesInventory.supplierBrands, exact : true, component : SupplierBrands},
    { path : routeNamesInventory.newSupplierBrand, exact : true, component : NewSupplierBrand},

    { path : routeNamesInventory.packagingItems, exact : true, component : PackagingItems},
]