export const sessionStrings = {
    sessions : "sessions",
    terms : "terms",
    usePreviousLevel : "usePreviousLevel",                      //boolean
    sessionPreviousLevels : "sessionPreviousLevels",              //array
    // sessionPreviousClasses : "sessionPreviousClasses",
    usePreviousClasses : "usePreviousClasses",
    levels : "levels",
    allTerms : "allTerms",
    currentSessionTerms : "currentSessionTerms"
}

export const sessionConstants = {
    SET_SESION :"SET_SESSION",
    SET_SESION_CLEAN_UP : "SET_SESION_CLEAN_UP"
}


export const sessionReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case sessionConstants.SET_SESION : 
            return {...state, ...payload};
        case sessionConstants.SET_SESION_CLEAN_UP : 
            return {
                [sessionStrings.sessions] : state[sessionStrings.sessions]
            };
        default : return {...state};
    }
}
