import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { Card, CardMedia, CardContent, Typography } from '@material-ui/core';
const style = theme => ({
    root: {
        display : "flex",
        flexDirection : "column",
        alignItems : "center",
        width : 200,
        background : "#ffffff70",
    },
    header : {
        fontWeight : "bold",
        fontSize : 14,
        textAlign : "center",
    },
    body : {
        fontSize : 11,
        width : "100%",
        textAlign : "center",
    },
    img : {
        height : 100,
        width : 100,
    }
})
class _FeatureBox extends Component {
    constructor(props) {
        super(props);
        this.contentRef = React.createRef();
    }
    
    componentDidMount() {
        const{getContentHeight} = this.props;
        if(getContentHeight) 
        getContentHeight(this.contentRef.current.clientHeight);
    }
    
    render() {
        const {classes, body, title, image, header, baseUrl} = this.props;
        return (
            <Card className={classes.root}>
                <img src={baseUrl ? baseUrl+image : image} className={classes.img}/>
                <CardContent ref={this.contentRef}>
                    <Typography className={classes.header}>{header}</Typography>
                    <Typography className={classes.body}>{body}</Typography>
                </CardContent>
            </Card>
        );
    }
}
_FeatureBox.propTypes = {
    classes : PropTypes.object.isRequired,
    image : PropTypes.string,
    baseUrl : PropTypes.string,
    header : PropTypes.string,
    body : PropTypes.string,
    getContentHeight : PropTypes.func,
};
export const FeatureBox = withStyles(style)(_FeatureBox);