import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { hirSettingStrings, hirSettingActions } from '../../../HIRSettings/config';
import { TableCell, FormControl, InputLabel, Select, MenuItem, TextField, IconButton, Typography } from '@material-ui/core';
import { Add, Delete } from '@material-ui/icons';
import { HIRButton } from '../../../Includes';
import { hirAccountActions } from '../../actions';
import { hirAppActions as appActions, hirAlertActions as alertAction, MyTable } from '../../../utils';


class PaymentAmount extends Component{
    constructor(props) {
        super(props);
        this.state ={
            amount : ""
        }
        props.getContext(this);
    }
    onChange = name => e => {
        const value = e.target.value;
        this.setState({[name] : value});
    }
    render(){
        const {amount} = this.state;
        return <TextField
                style={{
                    width : "100%"
                }}
                type="number"
                margin="normal"
                placeholder="Amount"
                label="Amount"
                variant="outlined"
                value={amount}
                onChange={this.onChange("amount")}
            />
    }
}
const style = theme => ({
    root: {
    },
    btn : {
        marginTop : 20,
    },
    cell : {
        padding : 5,
    }
})
class _HIRMultiplePayment extends Component {
    constructor(props) {
        super(props);
        this.state = {
            revenueType : "",
            amount : "",
            paymentList : [
                
            ]
        }
    }
    onChange = name => e => {
        const value = e.target.value;
        this.setState({[name] : value});
    }
    addPayment(){
        const {dispatch} = this.props;
        const {revenueType, paymentList} = this.state;
        const amount = this.amountContext.state.amount
        if(!String(revenueType).trim() || !String(amount).trim()){
            appActions.showSnackbar(
                alertAction.error("Empty field!")
            )(dispatch);
            return;
        }
        paymentList.push({revenueType, amount : parseInt(amount)});
        this.setState({paymentList});
    }
    deleteRow = row => ()  => {
        const {paymentList} = this.state;
        const index = paymentList.findIndex(item=>JSON.stringify(item)===JSON.stringify(row));
        paymentList.splice(index, 1);
        this.setState({paymentList});
    }
    cellMapFormat = total=> ({row, cellMap}) => {
        const {
            [hirSettingStrings.settings] : settings,
            classes
        } = this.props;
        const {revenueType} = this.state;
        if(row.total){
            switch(cellMap){
                case "description" : return <TableCell className={classes.cell}>
                    <strong>Total</strong>
                </TableCell>
                case "amount" : return <TableCell className={classes.cell}>
                    <strong>N {Number(total).toLocaleString()}</strong>
                </TableCell>
                default : return <TableCell className={classes.cell}>

                </TableCell>
            }
        }
        else if(row.new){
            switch(cellMap){
                case "action" : return <TableCell className={classes.cell}>
                    <IconButton onClick={this.addPayment.bind(this)}>
                        <Add style={{color : "green"}}/>
                    </IconButton>
                </TableCell>
                case "amount" : 
                    return <TableCell className={classes.cell}>
                        <PaymentAmount
                            getContext={context=>this.amountContext = context }/>
                    </TableCell>
                case "description" : 
                    let revenueOptions = [];
                    if(settings){
                        const revenue = settings.find(item=>item.name==="revenue");
                        revenueOptions = revenue ? revenue.values : [];                        
                    }
                    return <TableCell className={classes.cell}>
                        <FormControl style={{
                                width : "100%"
                            }}>
                                <InputLabel htmlFor="revenueTypeSelection">Description</InputLabel>
                                <Select
                                    
                                    inputProps={{
                                        id : "revenueTypeSelection",
                                        style : {
                                            width : "100%"
                                        }
                                    }}
                                    variant="outlined"
                                    label="Description"
                                    placeholder="Description"
                                    value={revenueType}
                                    onChange={this.onChange("revenueType")}>                                    
                                        {revenueOptions && revenueOptions.map((item, index)=>
                                            <MenuItem key={index} value={item.name}>
                                                {item.value}
                                        </MenuItem>)}
                                    </Select>
                            </FormControl>                    
                        </TableCell>
                default : return <TableCell className={classes.cell}>
                    {row[cellMap]}
                </TableCell>
            }
        }else{
            switch(cellMap){
                case "action" : 
                    return <TableCell className={classes.cell}>
                        <Delete color="secondary" fontSize="small" onClick={this.deleteRow(row)}/>
                    </TableCell>
                case "description" : 
                    let iValue = row[cellMap];
                    if(settings){
                        iValue = hirSettingActions.getSettingValue(settings, "revenue", row.revenueType)
                    }
                    return <TableCell className={classes.cell}>
                        {iValue}
                    </TableCell>
                case "amount" : return <TableCell className={classes.cell}>
                    {Number(row[cellMap]).toLocaleString()}
                </TableCell>
                default : return <TableCell className={classes.cell}>
                    {row[cellMap]}
                </TableCell>
            }
        }
    }
    postPayment = amount => () => {
        const {paymentList} = this.state;
        const {dispatch, postPayment, editMode, editPayment} = this.props;
        if(paymentList.length === 0){
            appActions.showSnackbar(
                alertAction.error("No payment added")
            )(dispatch);
        }
        this.setState({loading : true});
        const data = {paymentList, amount};
        if(data){
            if(editMode && editPayment)
                editPayment(data, this);
            else if(postPayment)
                postPayment(data, this);
        }else this.setState({loading : false});
    }
    render() {
        const {classes, patient} = this.props;
        const {paymentList} = this.state;
        let lastName, firstName; 
        if(patient){
            const {myProfile} = patient;
            lastName = myProfile.lastName;
            firstName = myProfile.firstName;
        }
        let total = 0;
        if(paymentList){
            for (let i = 0; i < paymentList.length; i++) {
                const list = paymentList[i];
                total += Number(list.amount);
            }
        }
        let newPaymentList = paymentList ? [...paymentList, {new : true}, {total : true}] : [{new : true}, {total : true}];
        return (
            <div className={classes.root}>
                <Typography paragraph>{lastName && "New Payment for "+lastName+", "+firstName}</Typography>
                <MyTable
                    elevation={0}
                    header={["Description", "Amount", "Action"]}
                    dataMap={["description", "amount", "action"]}
                    data={newPaymentList}
                    CellMap={this.cellMapFormat(total)}
                    />
                <HIRButton 
                    classes={{
                        btn : classes.btn
                    }}
                    onClick={this.postPayment(total)}>
                    Post Payment
                </HIRButton>
            </div>
        );
    }
}


_HIRMultiplePayment.propTypes = {
    classes : PropTypes.object.isRequired,
    patient : PropTypes.object,
    postPayment : PropTypes.func,
    editMode : PropTypes.bool,
    paymentData : PropTypes.object,
    editPayment : PropTypes.func,
};
const mapStateToProps = ({hirSettingReducer}) => ({
    [hirSettingStrings.settings] : hirSettingReducer[hirSettingStrings.settings]
})


export const HIRMultiplePayment = connect(mapStateToProps)(withStyles(style)(_HIRMultiplePayment));
export {HIRMultiplePayment as default}