import React from 'react';
import { routeNamesInventory } from "./routeNames";
import {connect} from 'react-redux';
import { Router, Switch, Route} from 'react-router-dom';
import { 
    headerActions, headerStrings, screenActions,  mainStageAction, 
    MySnackbar, SnackDialog, mainStageHeaderAction,  mainStageStrings, breadCrumbActions
} from '../includes';
import { PrivateRoutePlane, LogoutRoute } from './InventoryRouteTemplates';
import { history } from '../../helpers';
import { inventoryMenuItem } from './menuItems';
import { inventoryUtilActions, theme1, inventoryUtil, inventoryUtilStrings, inventoryActions } from './utils';
import { withStyles } from '@material-ui/core';
import { inventoryRoutes } from './routes';
import $ from 'jquery';
import { DrawerHeader } from './Includes';
import { INVLogin } from './INVLogin';


const styles = theme => ({
    mainStage : {
        margin : 0,
        padding : 0,
    }
})
class _Inventory_App extends React.PureComponent{
    constructor(props) {
        super(props);

        const {pathname} = history.location;
        console.log(pathname);
        if(String(pathname).startsWith("/inv")){
            const {
                dispatch,
                [inventoryUtilStrings.myProfile] : myProfile,
            } = props;
            inventoryUtilActions({
                [inventoryUtilStrings.theme] : theme1,
                [inventoryUtilStrings.tokenAlias] : "inventoryToken",
                [inventoryUtilStrings.userAlias] : "inventoryUserId",
                [inventoryUtilStrings.userType] : "inventoryType",
                [inventoryUtilStrings.backendUrl] : "http://localhost:8003/api/v1/inventory/", 
                [inventoryUtilStrings.backendBaseUrl] : "http://localhost:8003",
                // [inventoryUtilStrings.backendUrl] : "http://192.168.0.10:8003/api/v1/inventory/", 
                // [inventoryUtilStrings.backendBaseUrl] : "http://192.168.0.10:8003",
                [inventoryUtilStrings.defaultImage] : "/image/default.png",
            })(dispatch);
            headerActions({
                [headerStrings.headerTitle] : "HEALTH RECORDS",
                [headerStrings.headerTitleProps] : {
                    style : {
                        borderBottom : "none",
                        color : inventoryUtil.getTheme().white,
                    }
                },
                [headerStrings.drawer] : true,
                [headerStrings.visible] : true,
                [headerStrings.menuItems] : inventoryMenuItem,
                [headerStrings.drawerHeader] : DrawerHeader
            })(dispatch);
            screenActions.setTheme(theme1)(dispatch);
            mainStageAction({
                [mainStageStrings.containerProps] : {
                    style : {
                        margin : 0,
                        padding : 0,
                        height : "calc(100vh - 115px)", 
                    }
                }
            })(dispatch);
            breadCrumbActions.setProps({
                style : {
                    borderBottom : "solid 1px " + theme1.primary,
                    marginBottom : 10
                }
            })(dispatch);
            mainStageHeaderAction({
                [mainStageHeaderAction.visible] : false,
            })(dispatch);            
            if(inventoryUtil.isLogedIn()){
                if(!myProfile)
                    inventoryActions.getUser()(dispatch);
            }        
        }
    }
    componentDidMount(){
        $("title").text("Medical Inventory");
        // window.addEventListener("beforeunload", e => {
        //     inventoryActions.logout();
        //     return null;
        // })
    }
    render(){
        return(
            <Router history={history}>
                <div>
                    <React.Suspense
                        fallback={<div>Loading...</div>}>
                        <Switch>
                            {inventoryRoutes && inventoryRoutes.map((route, index)=>{
                                
                                return <PrivateRoutePlane {...route} key={index}/>
                            })}
                            <Route path={routeNamesInventory.login} exact component={props=><INVLogin {...props}/>}/>
                            <LogoutRoute path={routeNamesInventory.logout}/>
                        </Switch>
                    </React.Suspense>
                    <MySnackbar/>
                    <SnackDialog/>
                </div>
            </Router>
        )
    }
}
const mapStateToProps = ({inventoryUtilReducer}) => ({
    [inventoryUtilStrings.myProfile] : inventoryUtilReducer[inventoryUtilStrings.myProfile],
})
export const Inventory_App =  connect(mapStateToProps)(withStyles(styles)(_Inventory_App));