import { hirUtil } from "../utils"

const {post, fetchGet, fetchPost} = hirUtil;
const owner = "1";
export const hirFamilyServices = {
    getAFamily : (familyId, callback) => {
        fetchGet(owner, "getAFamily", {familyId}, ({getAFamily, result, message})=>{
            callback(getAFamily, result, message);
        })
    },
    deleteFamilyMember : (familyId, patientId, callback) => {
        fetchGet(owner, "deleteFamilyMember", {familyId, patientId}, ({deleteFamilyMember, result, message})=>{
            callback(deleteFamilyMember, result, message);
        })
    },
    addFamilyMembers : (familyId, members, newMembers, callback)=>{
        post({familyId, members, newMembers}, owner, "addFamilyMembers", ({addFamilyMembers, result, message, newMemberId})=>{
            callback(addFamilyMembers, result, message, newMemberId);
        })
    },
    deleteFamily : (familyId, callback) => {
        fetchGet(owner, "deleteFamily", {familyId}, ({deleteFamily, result, message})=>{
            callback(deleteFamily, result, message);
        })
    },
    editFamilyRecord : (familyId, data, callback) => {
        post({familyId, data}, owner, "editFamilyRecord", ({editFamilyRecord, result, message})=>{
            callback(editFamilyRecord, result, message);
        })
    },
    createFamilyRecord : (data, callback) => {
        post(data, owner, "createFamilyRecord", ({createFamilyRecord, result, message})=>{
            callback(createFamilyRecord, result, message);
        })
    },
    getFamilies : (rows, skip, callback) => {
        fetchGet(owner, "getFamilies", {rows, skip}, ({getFamilies, result, message})=>{
            callback(getFamilies, result, message);
        })
    },
    getFamilyMinMaxIds : callback => {
        fetchGet(owner, "getFamilyMinMaxIds", {}, ({getFamilyMinMaxIds, result, message})=>{
            console.log(result);
            callback(getFamilyMinMaxIds, result, message);
        })
    }
}