import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Typography } from '@material-ui/core';
import { inovateOSUtil, inovateOSUtilStrings } from '../../utils';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faFacebook, faInstagram, faLinkedin, faTwitter, faGooglePlus } from '@fortawesome/free-brands-svg-icons';


const style = theme => ({
    root: {
        padding : 20,
    },
    header : {
        fontWeight : "bold",
        fontSize : 16,
        color : inovateOSUtil.getTheme().secondary,
    },
    icon : {
        color : inovateOSUtil.getTheme().secondary,
    },
    container : {
        display : "flex",
        flexDirection : "column",
        alignItems : "center",
        justifyContent : "center",
    },
    link : {
        margin : 5,
    }
})
class _FollowUs extends Component {
    render() {
        const {classes, [inovateOSUtilStrings.settings] : settings} = this.props;
        let contactInfo, facebook, instagram, linkedIn, twitter, googlePlus;
        if(settings) contactInfo = settings.find(item => item.name === "contactInfo");
        if(contactInfo && contactInfo.value) {
            const {value} = contactInfo
             facebook = value.facebook;
             instagram = value.instagram;
             linkedIn = value.linkedIn;
             twitter = value.twitter;
             googlePlus = value.googlePlus;
        }
        return (
            <div className={classes.root}>
                <div className={classes.container}>
                    <Typography paragraph className={classes.header}>Follow Us</Typography>
                    <div className={classes.content}>
                        {facebook && <a target="_blank" className={classes.link} href={/* "https://facebook.com/"+ */facebook}>
                            <FontAwesomeIcon className={classes.icon} size="2x" icon={faFacebook}/></a>}
                        {instagram && <a target="_blank" className={classes.link} href={/* "https://instagram.com/"+ */instagram}>
                            <FontAwesomeIcon className={classes.icon} size="2x" icon={faInstagram}/></a>}
                        {linkedIn && <a target="_blank" className={classes.link} href={/* "https://linkedin.com/mwlite/company/"+ */linkedIn}>
                            <FontAwesomeIcon className={classes.icon} size="2x" icon={faLinkedin}/></a>}
                        {googlePlus && <a target="_blank" className={classes.link} href={/* "https://googleplus.com/"+ */googlePlus}>
                            <FontAwesomeIcon className={classes.icon} size="2x" icon={faGooglePlus}/></a>}
                        {twitter && <a target="_blank" className={classes.link} href={/* "https://twitter.com/"+ */twitter}>
                            <FontAwesomeIcon className={classes.icon} size="2x" icon={faTwitter}/></a>}
                    </div>
                </div>
            </div>
        );
    }
}


_FollowUs.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({inovateOSUtilReducer}) => ({
    [inovateOSUtilStrings.settings] : inovateOSUtilReducer[inovateOSUtilStrings.settings],
})


export const FollowUs = connect(mapStateToProps)(withStyles(style)(_FollowUs));
export {FollowUs as default}