import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, MyTable, EditableCellMapFormat, HighlightedInfo} from "../../includes";
import { routeName } from '../../../utils';
import { Select, MenuItem} from '@material-ui/core';
import { history } from '../../../helpers';
import { payrollStrings, payrollActions } from '../config';

const style = theme => ({
    root: {
        marginTop : 20,
    }
})
class _PaymentSummary extends Component {
    constructor(props) {
        super(props);
        this.state = {
            lastId : null,
            rows : null
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "PAYMENT SUMMARY",
            [headerStrings.backButtonAction] : null,
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeName.dashboard},
            {name : "Payment Summary", path : routeName.payrollPaymentSummary},
        ])(dispatch);
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {
            dispatch,
            [payrollStrings.payrollBenefits] : payrollBenefits,
            [payrollStrings.payrollDeductions]: payrollDeductions,
            [payrollStrings.payrollEmployeeStatus]: payrollEmployeeStatus,
        } = this.props;
        const {
            lastId, rows
        } = this.state;
        payrollActions.getPayrollEmployeeBrief(lastId, rows)(dispatch);
        if(!payrollBenefits)
            payrollActions.getPayrollBenefits()(dispatch);
        if(!payrollDeductions)
            payrollActions.getPayrollDeductions()(dispatch);
        if(!payrollEmployeeStatus)
            payrollActions.getPayrollEmployeeStatus()(dispatch);
    }
    //show active 
    nameLinks = {
        id : "ID",
        name : "Name",
        gross : "Gross (N)",
        net : "Net (N)",
        status : "Status",
    }
    generateTableHeader(){
        let header = [
            {name : this.nameLinks.id}, 
            {name : this.nameLinks.name},
            {name : this.nameLinks.gross}]; 
        const {
            [payrollStrings.payrollBenefits] : payrollBenefits,
            [payrollStrings.payrollDeductions] : payrollDeductions,
        } = this.props;
        if(payrollBenefits) {    
            let subheaders = [];        
            for (let i = 0; i < payrollBenefits.length; i++) {
                const {_id, active} = payrollBenefits[i];
                if(active) subheaders.push(_id);
            }
            header.push({_id : "b", name : "Benefits", subheaders})
        }
        if(payrollDeductions) {
            let subheaders = [];
            for (let i = 0; i < payrollDeductions.length; i++) {
                const {_id, active} = payrollDeductions[i];
                if(active) subheaders.push(_id)
            }
            header.push({_id : "d", name : "Deductions", subheaders})
        }
        header.push({name : this.nameLinks.net}, {name : this.nameLinks.status});
        return header
    }
    tableHeaderMapper = subheader => {
        if(!subheader) return null;
        let newSubheader = subheader;
        const {
            [payrollStrings.payrollBenefits] : payrollBenefits,
            [payrollStrings.payrollDeductions] : payrollDeductions,
        } = this.props;
        try{
            const headSplit = subheader.split("_");
            if(headSplit[0] === "b"){
                const {item} = payrollBenefits.getFirstObjectByPropValue("_id", parseInt(headSplit[1])) || {};
                if(item){
                    if(item.usePercentage)
                        newSubheader = item.name + " ("+item.percent+"%)";
                    else
                        newSubheader = item.name
                }
            }else {
                const {item} = payrollDeductions.getFirstObjectByPropValue("_id", parseInt(headSplit[1])) || {};
                if(item){
                    if(item.usePercentage)
                        newSubheader = item.name + " ("+item.percent+"%)";
                    else
                        newSubheader = item.name
                }
            }
        }catch(e){
            console.error(e);
            console.log("This occured PAYMENTSUMMARY@tableHeaderMapper");
        }
        return newSubheader;
    }
    generateTableData(){
        let data = [];
        const {
            [payrollStrings.payrollBenefits] : payrollBenefits,
            [payrollStrings.payrollDeductions] : payrollDeductions,
            [payrollStrings.payrollEmployeeBrief] : payrollEmployeeBrief,
        } = this.props;
        if(payrollEmployeeBrief) for (let i = 0; i < payrollEmployeeBrief.length; i++) {
            const emp = payrollEmployeeBrief[i];
            const {_id, bioInfo, salary, statusId} = emp;
            let dataInfo = {
                [this.nameLinks.id] : _id, 
                [this.nameLinks.name] : bioInfo.fullName, 
                [this.nameLinks.status] : statusId
            };
            if(salary){
                let deducedAmount = 0;
                let benefitAmount = 0;
                const {gross, deductionIds, benefitIds} = salary;
                dataInfo[this.nameLinks.gross] = gross;
                if(payrollDeductions && deductionIds) for (let j = 0; j < deductionIds.length; j++) {
                    const deductId = deductionIds[j];
                    const deductIdInfo = payrollDeductions.getFirstObjectByPropValue("_id", deductId);
                    if(deductIdInfo && deductIdInfo.item){
                        const {_id, usePercentage, amount, percent, active} = deductIdInfo.item;
                        if(!active) continue;
                        if(usePercentage){
                            const calcAmount = (Number(percent) / 100) * Number(gross);
                            dataInfo["d_"+_id] = calcAmount;
                            benefitAmount -= calcAmount
                        }else{
                            dataInfo["d_"+_id] = amount;
                            benefitAmount -= Number(amount);
                        }
                    }
                }
                if(payrollBenefits && benefitIds) for (let j = 0; j < benefitIds.length; j++) {
                    const benefitId = benefitIds[j];
                    const benefitIdInfo = payrollBenefits.getFirstObjectByPropValue("_id", benefitId);
                    if(benefitIdInfo && benefitIdInfo.item){
                        const {_id, usePercentage, amount, percent, active} = benefitIdInfo.item;
                        if(!active) continue;
                        if(usePercentage){
                            const calcAmount = (Number(percent) / 100) * Number(gross);
                            dataInfo["b_"+_id] = calcAmount;
                            benefitAmount += calcAmount
                        }else{
                            dataInfo["b_"+_id] = amount;
                            benefitAmount += Number(amount);
                        }
                    }
                }
                dataInfo[this.nameLinks.net] = Number(gross) - deducedAmount + benefitAmount;
            }
            data.push(dataInfo);
        }
        console.log("generated data", data);
        return data;
    }
    cellMapFormat = superProps => props=><EditableCellMapFormat {...props} {...superProps}/>
    tableCellContentView = allStatus => (editing, {row, cellMap}) =>{ 
        switch(cellMap){
            case this.nameLinks.status :
                if(allStatus){
                    const {item} = allStatus.getFirstObjectByPropValue("_id",row[cellMap]) || {};
                    if(item){
                        return item.name;
                    }
                }
                return "Unknown";
            case this.nameLinks.id : return row[cellMap];
            default : 
                let result = Number(row[cellMap]);
                if(!isNaN(result))
                    return result.toLocaleString();
                else
                    return row[cellMap];                
        }
    }
    editBtnHandler = row => () => {
        let tableData = [...this.state.tableData];
        const {index} = tableData.getFirstObjectByPropValue("_id", row._id);
        tableData[index] = {...row, editing : true};
        this.setState({tableData});
    }
    render() {
        const {
            classes,
            [payrollStrings.payrollEmployeeStatus] : payrollEmployeeStatus,
        } = this.props;
        const header = this.generateTableHeader();
        return (
            <div className={classes.root}>
                <HighlightedInfo>
                    Showing only ACTIVE benefits and deductions.
                </HighlightedInfo>
                <MyTable
                    multiRowHeader={header}
                    headerName="name"
                    subHeaderMap={this.tableHeaderMapper.bind(this)}
                    subheaderIndicator="subheaders"
                    groupSubheaders
                    data={this.generateTableData()}
                    CellMap={this.cellMapFormat({
                        tableCellContentView : this.tableCellContentView(payrollEmployeeStatus),
                        editBtnHandler : this.editBtnHandler.bind(this),
                    })}
                    />
            </div>
        );
    }
}


_PaymentSummary.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({payrollReducer}) => ({
    [payrollStrings.payrollBenefits] : payrollReducer[payrollStrings.payrollBenefits],
    [payrollStrings.payrollDeductions] : payrollReducer[payrollStrings.payrollDeductions],
    [payrollStrings.payrollEmployeeBrief] : payrollReducer[payrollStrings.payrollEmployeeBrief],
    [payrollStrings.payrollEmployeeStatus] : payrollReducer[payrollStrings.payrollEmployeeStatus],
})


export const PaymentSummary = connect(mapStateToProps)(withStyles(style)(_PaymentSummary));
export {PaymentSummary as default}