import { formConstants, formStrings } from "./config";
import { store } from "../../../helpers";

export const formActions = {
    setFormData : (formName, fieldName, fieldValue) => dispatch => {
        let forms = store.getState().formReducer.forms || {};
        forms = forms ? {
            ...forms, 
            [formName] : forms[formName] ? 
                {...forms[formName], [fieldName] : fieldValue} :
                {[fieldName] : fieldValue}
        } : {[formName] : {[fieldName] : fieldValue}};
        formActions.payload({
            [formStrings.forms] : forms
        })(dispatch);
    },
    resetFormData : formName => dispatch => {
        let forms = store.getState().formReducer.forms || {};
        forms = forms && {
            ...forms, 
            [formName] : {}
        };
        formActions.payload({
            [formStrings.forms] : forms
        })(dispatch);
    },
    payload : payload => dispatch => dispatch({
        type : formConstants.SET_FORM,
        payload
    })
}