export const insureAboutUsStrings = {
    aboutUs : "aboutUs",
    settings : "settings",
}
export const insureAboutUsConstants = {
    SET_ABOUT_US : "SET_ABOUT_US",
}
export const insureAboutUsReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case insureAboutUsConstants.SET_ABOUT_US : 
            return {...state, ...payload};
        default : return {...state};
    }
}
export * from './actions';
export * from './services';