import { inovateOSAdminUtilConstants, inovateOSAdminUtilStrings } from "./config";
import { inovateOSAdminUtilServices } from "./services";
import { _storeData } from "../../../../utils";
import { errorNotice } from "./inovateOSAdminUtil";
import { store } from "../../../../helpers";

export const inovateOSAdminUtilActions = payload => dispatch => dispatch({
    type : inovateOSAdminUtilConstants.SET_UTIL,
    payload 
});

export const inovateOSAdminActions = {
    getUser : callback => dispatch => {
        inovateOSAdminUtilServices.getUser((done, result, message)=>{
            if(done){
                if(result && result.myProfile && result.myProfile.admin){
                    inovateOSAdminUtilActions({
                        [inovateOSAdminUtilStrings.myProfile] : result.myProfile,
                        [inovateOSAdminUtilStrings.trackingMe] : result.trackingMe,
                        [inovateOSAdminUtilStrings.disableAllTracking] : result.disableAllTracking,
                    })(dispatch);
                }
            }
            if(callback) callback(done, result, message);
        })
    },
    signup : (data, callback) => dispatch => {
        inovateOSAdminUtilServices.signup(data, (done, result, message)=>{
            if(done){
                if(result && result.myProfile && result.myProfile.admin){
                    _storeData([inovateOSAdminUtilStrings.tokenAlias], result.myProfile.token);
                    _storeData([inovateOSAdminUtilStrings.userAlias], result._id);
                    inovateOSAdminUtilActions({
                        [inovateOSAdminUtilStrings.myProfile] : result.myProfile,
                        [inovateOSAdminUtilStrings.trackingMe] : result.trackingMe,
                        [inovateOSAdminUtilStrings.disableAllTracking] : result.disableAllTracking,
                    })(dispatch);
                }else errorNotice("Invalid administrative profile", dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    loging : (email, password, callback) => dispatch => {
        inovateOSAdminUtilServices.login(email, password, (done, result, message)=>{
            const reducer = store.getState().inovateOSAdminUtilReducer;
            if(done){
                if(result && result.myProfile && result.myProfile.admin){
                    _storeData(reducer[inovateOSAdminUtilStrings.tokenAlias], result.myProfile.token);
                    _storeData(reducer[inovateOSAdminUtilStrings.userAlias], result._id);
                    inovateOSAdminUtilActions({
                        [inovateOSAdminUtilStrings.myProfile] : result.myProfile,
                    })(dispatch);
                }else errorNotice("Invalid administrative profile", dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    logout : () => {
        const reducer = store.getState().inovateOSAdminUtilReducer;
        localStorage.removeItem(reducer[inovateOSAdminUtilStrings.tokenAlias]);
        localStorage.removeItem(reducer[inovateOSAdminUtilStrings.userAlias]);
    },
}
