export const hirAccountStrings = {
    payments : "payments",
    revenueBasedPayments : "revenueBasedPayments",
    userBasedPayments : "userBasedPayments",
    viewDetailPayments :"viewDetailPayments",
}
export const hirAccountConstant = {
    SET_ACCOUNT : "SET_ACCOUNT",
}
export const hirAccountReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case hirAccountConstant.SET_ACCOUNT : 
            return {...state, ...payload};
        default : return state;
    }
}
