export const insureHomeStrings = {
    home : "home",
    carousel : "carousel",
}
export const insureHomeConstants = {
    SET_INSURE_HOME : "SET_INSURE_HOME",
}
export const insureHomeReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case insureHomeConstants.SET_INSURE_HOME : 
            return {...state, ...payload};
        default : return {...state};
    }
}