import { contactServices } from "./services"
import { contactStrings, contactConstants } from "./config"
import { successNotice, errorNotice, trackerUtilStrings, trackerUtilActions, trackerActions, trackerUtil } from "../utils";
import { store } from "../../../helpers";
import { chatFooterStrings, chatFooterActions } from "../../includes";

export const contactActions = {
    getMyOnlineContacts : callback => {
        contactServices.getMyOnlineContacts((done, result, message)=>{
            if(done){
                const {users, userIds} = result;
                if(users) users.forEach(contactActions.contactConnected);
            }
            if(callback) callback(done, result, message);
        })
    },
    contactConnected : user => {
        const dispatch = store.dispatch;
        const chatContacts = store.getState().chatFooterReducer[chatFooterStrings.allChatListData];
        if(!chatContacts || !chatContacts.find(item => item._id === user._id)){
            user.myProfile.active = true;
            user.myProfile._id = user._id;
            chatFooterActions({
                [chatFooterStrings.allChatListData] : chatContacts ? [...chatContacts, user.myProfile] : [user.myProfile]
            })(dispatch);
        }else{
            chatFooterActions({
                [chatFooterStrings.allChatListData] : [
                    ...chatContacts.map(
                        item=>item._id === user._id ? ({...item, active : true}) : item
                    )
                ]
            })(dispatch);
        }
    },
    iReceivedAMessage : ({newMessage, result, message}) => {
        if(newMessage)
            contactActions.setReceivedMessage(result)(store.dispatch);
    },
    amNotTrackingContact : contactId => {
        const contacts = store.getState().contactReducer[contactStrings.contacts];
        if(contacts){
            const userId = parseInt(trackerUtil.getUserId());
            const dispatch = store.dispatch;
            contactActions.payload({
                [contactStrings.contacts] : contacts.map(item=>{
                    if(item._id === contactId){ 
                        errorNotice(
                            item.myProfile.name + " has blocked you from tracking him", 
                            dispatch
                        );
                        if(item.trackingMe && 
                        item.trackingMe.indexOf(userId) !== -1){
                            item.trackingMe.splice(item.trackingMe.indexOf(userId), 1);
                        }
                    }
                    return item;
                })
            })(dispatch);
        }
    },
    amTrackingContact : contactId => {
        const contacts = store.getState().contactReducer[contactStrings.contacts];
        if(contacts){
            const userId = parseInt(trackerUtil.getUserId());
            const dispatch = store.dispatch;
            contactActions.payload({
                [contactStrings.contacts] : contacts.map(item=>{
                    if(item._id === contactId){ 
                        successNotice(
                            item.myProfile.name + " is allowing you to track him", 
                            dispatch
                        );
                        if(item.trackingMe && 
                        item.trackingMe.indexOf(userId) === -1){
                            item.trackingMe.push(userId);
                        }else if(!item.trackingMe){
                            item.trackingMe = [userId]
                        }
                    }
                    return item;
                })
            })(dispatch);
        }
    },
    setReceivedMessage : result => dispatch=>{
        const {fromId} = result;
        let messages = store.getState().contactReducer[contactStrings.messages] || {};
        messages[fromId] = messages[fromId] ? 
            [...messages[fromId], result] : 
            [result];
        contactActions.payload({
            [contactStrings.messages] : {...messages}
        })(dispatch);
        chatFooterActions({
            [chatFooterStrings.chatBoxMessages]: {...messages}
        })(dispatch);
    },
    sendMessage : (contactId, message, callback) => dispatch=> {
        contactServices.sendMessage(contactId, message, (done, result, message)=>{
            if(done){
                let messages = store.getState().contactReducer[contactStrings.messages] || {};
                messages[contactId] = messages[contactId] ? 
                    [...messages[contactId], result] : 
                    [result];
                contactActions.payload({
                    [contactStrings.messages] : {...messages}
                })(dispatch);
                chatFooterActions({
                    [chatFooterStrings.chatBoxMessages] : {...messages},
                })(dispatch);
            }
            if(callback) callback(done, result, message);
        })
    },
    getMessages : (contactId, lastId, rows, callback) => dispatch => {
        contactServices.getMessages(contactId, lastId, rows, (done, result, message, data)=>{
            let messages = store.getState().contactReducer[contactStrings.messages] || {};
            messages[data.contactId] = result;
            if(done) {
                contactActions.payload({
                    [contactStrings.messages] : {...messages}
                })(dispatch); 
                chatFooterActions({
                    [chatFooterStrings.chatBoxMessages] : {...messages}
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    disableAllTracking : (option, callback) => dispatch => {
        contactServices.disableAllTracking(option, (done, result, message, data)=>{
            if(done){
                successNotice(message, dispatch);
                trackerUtilActions({
                    [trackerUtilStrings.disableAllTracking] : data.option
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    disableTracking : (contactId, callback)=>dispatch=>{
        contactServices.disableTracking(contactId, (done, result, message)=>{
            if(done) {
                successNotice(message, dispatch);
                trackerUtilActions({
                    [trackerUtilStrings.trackingMe] : result
                })(dispatch);
            }
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    allowTracking : (contactId, callback) => dispatch=>{
        contactServices.allowTracking(contactId, (done, result, message)=>{
            console.log(done, result, message);
            if(done) {
                successNotice(message, dispatch);
                trackerUtilActions({
                    [trackerUtilStrings.trackingMe] : result
                })(dispatch);
            }
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    addNewContact : (phone, callback)=> dispatch=>{
        contactServices.addNewContact(phone, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        });
    },
    getContacts : callback => dispatch => {
        contactServices.getContacts((done, result, message)=>{
            if(done) dispatch({
                type : contactConstants.SET_CONTACT,
                payload : {
                    [contactStrings.contacts] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getUserLocationHx : (userId, callback) => dispatch => {
        contactServices.getUserLocationHx(userId, (done, result, message)=>{
            if(done) dispatch({
                type : contactConstants.SET_CONTACT,
                payload : {
                    [contactStrings.userLocationHx] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    setPageDisplay : pageDisplay => dispatch => dispatch({
        type : contactConstants.SET_CONTACT,
        payload : {
            [contactStrings.pageDisplay] : pageDisplay
        }
    }),
    payload : payload => dispatch=>dispatch({
        type : contactConstants.SET_CONTACT,
        payload
    })
}