import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { 
    Card, CardHeader, CardContent, CardActionArea, 
    CardActions, List, ListItem, ListItemText, ListItemIcon,
    Button, TextField
} from '@material-ui/core';
import { Delete } from '@material-ui/icons';
import { InfoText } from '../../includes';
import { appActions, alertAction } from '../../../actions';



const style = theme => ({
    root: {
    },
    catInput : {
        display : "flex",
        flexGrow : 1
    }
})
class _SessionCard extends Component {
    constructor(props) {
        super(props);
        this.state={
            data : {
                session : ""
            }
        }
    }
    handleOnChange=name=>e=>{
        let data = {...this.state.data};
        data[name] = e.target.value;
        this.setState({data});
    }
    addNewSession = () => {
        const {dispatch, getSession} = this.props;
        const {session} = this.state.data;
        if(session === "" || !session) {
            appActions.showSnackbar(
                alertAction.error("Empty field of session")
            )(dispatch);
            return;
        }
        getSession(session);
    }
    render() {
        const {classes, sessions, setSession} = this.props;
        const category = this.state.data.category
        return (
            <Card>
                <CardHeader 
                    title="Sessions"/>
                    <CardContent>
                        <List>
                        {sessions && sessions.map((sess, index) => 
                            <ListItem  onClick={setSession && setSession(sess)} style={{padding : 0}} divider key={index} button>
                                <ListItemText>
                                    {sess.name + " (start : "+sess.startDate + " "} 
                                    {sess.endDate && "end-date : " + sess.endDate} )
                                </ListItemText>
                                <ListItemIcon style={{minWidth:0}}>
                                    <Delete color="secondary"/>
                                </ListItemIcon>
                            </ListItem>)}
                        </List>
                </CardContent>
                <CardActions>
                    <div className={classes.catInput}>
                        <TextField
                            style={{width : "100%"}}
                            value={category}
                            variant="standard"
                            placeholder="New Session"
                            onChange={this.handleOnChange("session")}
                            margin="normal"/>
                    </div>
                        <Button onClick={this.addNewSession.bind(this)} variant="outlined" color="primary">Add</Button>
                </CardActions>
                <CardActionArea>
                    <InfoText>
                        A session should have a gap of at least 9 months
                    </InfoText>
                </CardActionArea>
            </Card>  
        );
    }
}


_SessionCard.propTypes = {
    classes : PropTypes.object.isRequired,
    sessions : PropTypes.array,
    setSession : PropTypes.func,  
    getSession : PropTypes.func,
};


export const SessionCard = connect()(withStyles(style)(_SessionCard));