import React from 'react';
import {connect} from 'react-redux';
import { Router, Switch, Route} from 'react-router-dom';
import { 
    headerActions, headerStrings, 
    MySnackbar, SnackDialog, screenActions
} from '../includes';
import { InsureSiteRoute, InsurePrivateRoute, InsureLogoutRoute } from './RouteTemplates';
import { history } from '../../helpers';
import { insureMenuItem } from './menuItems';
import { insureUtilActions, theme1, insureUtil, insureUtilStrings, insureActions } from './utils';
import { withStyles } from '@material-ui/core';
import $ from 'jquery';
import { insureRoutes, insurePriviteRoutes } from './routes';
import { PageNotFound } from '../PageNotFound';
import { RightHeaderComponent } from './includes';
import { insureRouteNames } from './routeNames';
import { Unsubscribe } from './Unsubscribe';

const styles = theme => ({
    mainStage : {
        margin : 0,
        padding : 0,
    }
})
class _MoboinsureApp extends React.PureComponent{
    constructor(props) {
        super(props);
        const {
            dispatch, runningApp,
        } = props;
        const {pathname} = history.location;
        if(!String(pathname).startsWith("/super")){
            insureUtilActions({
                [insureUtilStrings.theme] : theme1,
                [insureUtilStrings.tokenAlias] : "insureToken",
                [insureUtilStrings.userAlias] : "insureUserId",
                [insureUtilStrings.backendUrl] : /* "http://localhost:8000/api/v1/", // */"http://moboinsure.com/api/v1/",
                [insureUtilStrings.backendBaseUrl] : /* "http://localhost:8000", // */"http://moboinsure.com",
                [insureUtilStrings.isLoggedIn] : insureUtil.isLogedIn("insureUserId", "insureToken"),
            })(dispatch);
            screenActions.setTheme(theme1)(dispatch);
            headerActions({
                [headerStrings.headerTitle] : "MOBOINSURE 24/7",
                [headerStrings.headerTitleProps] : {
                    style : {
                        borderBottom : "none",
                        color : insureUtil.getTheme().white,
                    }
                },
                [headerStrings.headerRightComponent] : RightHeaderComponent,
                [headerStrings.drawer] : true,
                [headerStrings.visible] : true,
                [headerStrings.fullScreen] : true,
                [headerStrings.site] : true,
                [headerStrings.showItemMenu] : true,
                [headerStrings.leftMenuButton] : true,
                [headerStrings.menuItems] : insureMenuItem,
                [headerStrings.position] : "fixed",
                [headerStrings.siteLinkContainerProps]:{
                    style : {backgroundColor : insureUtil.getTheme().secondary},
                },
                [headerStrings.siteLinkProps]:{
                    style : {color : insureUtil.getTheme().white},
                },
            })(dispatch);
            insureActions.getSettings()(dispatch);
        }
    }
    componentDidMount(){
        // $("body").css("backgroundColor", insureUtil.getTheme().background);
        $("title").text("Moboinsure 24/7");
    }
    render(){
        console.log(process.env);
        return(
            <Router history={history}>
                <div>
                    <React.Suspense
                        fallback={<div>Loading...</div>}>
                        <Switch>
                            {insureRoutes && insureRoutes.map((route, index)=>{ 
                                return <InsureSiteRoute key={index} {...route}/>
                            })}
                            {insurePriviteRoutes && insurePriviteRoutes.map((route, index)=>{
                                return <InsurePrivateRoute key={index} {...route}/>
                            })}
                            <InsureLogoutRoute path={insureRouteNames.logout}/>
                            <Route path={insureRouteNames.newsletterUnsub} component={Unsubscribe}/>
                            {/* <Route component={PageNotFound}/> */}
                        </Switch>
                    </React.Suspense>
                    <MySnackbar/>
                    <SnackDialog/>
                </div>
            </Router>
        )
    }
}
export const MoboinsureApp =  connect()(withStyles(styles)(_MoboinsureApp));