import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { siteStrings } from '../config';
import { siteActions } from '../actions';
import { ContentControl } from '../ContentControl';



const style = theme => ({
    root: {
    }
})
class _AboutUs extends Component {
    componentDidMount() {
        const {
            [siteStrings.site] : site,
            dispatch,
        } = this.props;
        if(!site) siteActions.getSiteInfo()(dispatch);
    }
    
    render() {
        const {
            classes,
            [siteStrings.site] : site,
        } = this.props;
        console.log(this.props);
        const {item : home} = site && site.getFirstObjectByPropValue("name", "aboutUs") || {};
        return (
            <div className={classes.root}>
                {home && home.values && home.values.map((item, index)=>{

                    return <ContentControl {...item} key={index}/>
                })}
            </div>
        );
    }
}


_AboutUs.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({siteReducer}) => ({
    [siteStrings.site] : siteReducer[siteStrings.site],
})


export const AboutUs = connect(mapStateToProps)(withStyles(style)(_AboutUs));
export {AboutUs as default}