import { priceListServices } from "./services"
import { priceListStrings, priceListConstants } from "./config";
import { stockServices } from "../Stocks";
import { invProductServices } from "../INVProducts";

export const priceListActions = {
    getItemPackages : callback => dispatch => {
        invProductServices.getItemPackages((done, result, message)=>{
            if(done) dispatch({
                type : priceListConstants.SET_PRICE_LIST,
                payload : {
                    [priceListStrings.itemPackages] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getStockCategories : callback => dispatch => {
        stockServices.getStockCategories((done, result, message)=>{
            if(done) dispatch({
                type : priceListConstants.SET_PRICE_LIST,
                payload : {
                    [priceListStrings.stockCategories] : result,
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getPriceListItems : (priceListId, callback)=>dispatch => {
        priceListServices.getPriceListItems(priceListId, (done, result, message)=>{
            if(done) dispatch({
                type : priceListConstants.SET_PRICE_LIST,
                payload : {
                    [priceListStrings.pricelistItems] : result,
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getPriceLists : (lastId, rows, callback) => dispatch => {
        priceListServices.getPriceLists(lastId, rows, (done, result, message)=>{
            if(done) dispatch({
                type : priceListConstants.SET_PRICE_LIST,
                payload : {
                    [priceListStrings.pricelists] : result
                }
            });
            if(callback) callback(done, result, message);
        });
    }
}