import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import {Link} from 'react-router-dom';
import { inovateOSUtil } from '../../utils';
import {connect} from 'react-redux';
import { headerActions, headerStrings } from '../../../../includes';
import { Popper } from '@material-ui/core';
const style = theme => ({
    root: {
        display : "block",
        [theme.breakpoints.down("xs")] : {
            display : "none",
        }
    },
    linkItem : {
        textDecoration : "none",
        padding : 20,
        color : inovateOSUtil.getTheme().wheat,
        "&:hover" : {
            fontWeight : "bold",
            textShadow : "1px 1px 1px #a00e0e"
        },
        [theme.breakpoints.down("sm")] : {
            padding : 10,
        }
    }
})
class _InovateOSHeaderCompenentMenu extends Component {
    state = {
        anchorEl : null,
    }
    onMouseOver=name=>e=>{
        const target = e.target;
        const data = {
            top : target.offsetTop,
            left : target.offsetLeft + target.offsetParent.offsetLeft,
        }
        headerActions({
            [headerStrings.subheaderRibbon] : true,
            [headerStrings.subheaderRibbonName] : name,
            [headerStrings.subheaderRibbonOffsetLeft] : data.left,
            target,
        })(this.props.dispatch);
    }
    render() {
        const {classes, list} = this.props;
        return (
            <div className={classes.root} style={{
                right : 4,
            }}>
                {list && list.map((item, index)=>{
                    return <Link
                        onMouseOver={this.onMouseOver(item.name)}
                        className={classes.linkItem} 
                        to={item.pathname} 
                        key={index}>{item.name}</Link>
                })}
            </div>
        );
    }
}
_InovateOSHeaderCompenentMenu.propTypes = {
    classes : PropTypes.object.isRequired,
    list : PropTypes.array,
};

export const InovateOSHeaderCompenentMenu = connect()(withStyles(style)(_InovateOSHeaderCompenentMenu));