import { hirAppointmentConstants, hirAppointmentStrings } from "./config";
import { hirAppointmentServices } from "./services";
import { hirSuccessNotice as successNotice, hirErrorNotice as errorNotice, store } from "../utils";
export const hirAppointmentActions = {
    unApproveAppointment : (appointId, callback )=>dispatch => {
        hirAppointmentServices.unApproveAppointment(appointId, (done, result, message)=>{
            if(done){
                successNotice(message, dispatch);
                let appointments = store.getState().hirAppointmentReducer[hirAppointmentStrings.appointments];
                if(appointments){
                    appointments = appointments.map(item=>{
                        if(item._id === result._id)
                            return result
                        return item;
                    });
                    hirAppointmentActions.payload({
                        [hirAppointmentStrings.appointments] : appointments
                    })(dispatch);
                }
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        });
    },
    approveAppointment : (appointId, callback )=>dispatch => {
        hirAppointmentServices.approveAppointment(appointId, (done, result, message)=>{
            if(done){
                successNotice(message, dispatch);
                let appointments = store.getState().hirAppointmentReducer[hirAppointmentStrings.appointments];
                if(appointments){
                    appointments = appointments.map(item=>{
                        if(item._id === result._id)
                            return result
                        return item;
                    });
                    hirAppointmentActions.payload({
                        [hirAppointmentStrings.appointments] : appointments
                    })(dispatch);
                }
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        });
    },
    getAnAppointment : (appointId, callback) => dispatch =>{
        hirAppointmentServices.getAnAppointment(appointId, (done, result, message)=>{
            if(done){
                hirAppointmentActions.payload({
                    [hirAppointmentStrings.anAppointment] : result
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    searchAppointmentsByDate : (date, callback) =>dispatch => {
        hirAppointmentServices.searchAppointmentsByDate(date, (done, result, message)=>{
            if(done){
                hirAppointmentActions.payload({
                    [hirAppointmentStrings.appointments] : result
                })(dispatch)
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
            
        })
    },
    searchAppointments : (keyword, callback) =>dispatch => {
        hirAppointmentServices.searchAppointments(keyword, (done, result, message)=>{
            if(done){
                hirAppointmentActions.payload({
                    [hirAppointmentStrings.appointments] : result
                })(dispatch)
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    bookAppointment : (lastId, rows, data, callback) => dispatch => {
        hirAppointmentServices.bookAppointment(data, (done, result, message)=>{
            if(done){
                hirAppointmentActions.getAppointments(lastId, rows, 0)(dispatch);
                successNotice(message, dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getTodayAppointments : callback => dispatch => {
        hirAppointmentServices.getTodayAppointments((done, result, message)=>{
            if(done){
                hirAppointmentActions.payload({
                    [hirAppointmentStrings.appointments] : result
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getMaxMinAppointmentIds : callback => {
        hirAppointmentServices.getMaxMinAppointmentIds(callback);
    },
    getAppointments : (lastId, rows, skip, callback) => dispatch => {
        hirAppointmentServices.getAppointments(lastId, rows, skip, (done, result, message, minId, maxId)=>{
            if(done){
                hirAppointmentActions.payload({
                    [hirAppointmentStrings.appointments] : result
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message, minId, maxId);
        })
    },
    payload : payload => dispatch => dispatch({
        type : hirAppointmentConstants.SET_APPOINTMENT,
        payload
    })
}