import React, {Fragment} from 'react';
import { Screen, ChatFooter } from '../includes';
import {Redirect, Route} from 'react-router-dom';
import {trackerUtil, trackerActions} from  './utils';
import { routeNamesTracker } from './routeNames';

export const PrivateRoutePlane = ({component : Component, ...props}) => (
    <Route {...props} render={props => { 
        return (
            trackerUtil.isLogedIn()
            ? <Fragment>
                <Screen {...props} component={Component}/> 
                <ChatFooter/>
            </Fragment>
            : (props.match.path === routeNamesTracker.login ||
                props.match.path === routeNamesTracker.signup ?
                <Component {...props}/> : 
            <Redirect to={{ pathname: routeNamesTracker.login, state: { from: props.location } }} />)
        )}
    } />
);
export const LogoutRoute = rest =>(
    <Route {...rest} render={props=>{
        trackerActions.logout();
        return <Redirect to={{ pathname: '/login', state: { from: props.location } }}/> 
    }}/>
)