import { inovateOSAdminConstants, inovateOSAdminSiteStrings } from "./config";
import { inovateOSAdminSiteServices } from "./services";
import { successNotice, errorNotice } from "../utils";

export const inovateOSAdminSiteActions = {
    postNewArticle : (form, callback) => dispatch => {
        inovateOSAdminSiteServices.postNewArticle(form, (done, result, message)=>{
            if(done) {
                successNotice(message, dispatch);
                inovateOSAdminSiteActions.getSiteInfo()(dispatch);
            }
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    deleteArticle : (name, subname, callback) => dispatch => {
        inovateOSAdminSiteServices.deleteArticle(name, subname, (done, result, message)=>{
            if(done) {
                successNotice(message, dispatch);
                inovateOSAdminSiteActions.getSiteInfo()(dispatch);
            }
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    updateArticle : (property, name, subname, value, callback) => dispatch => {
        inovateOSAdminSiteServices.updateArticle(property, name, subname, value, (done, result, message)=>{
            if(done) {
                successNotice(message, dispatch);
                inovateOSAdminSiteActions.getSiteInfo()(dispatch);
            }
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    postFile : (form, callback) => dispatch =>{
        inovateOSAdminSiteServices.postFile(form, (done, result, message)=>{
            if(done) {
                successNotice(message, dispatch);
                // inovateOSAdminSiteActions.payload({
                //     [inovateOSAdminSiteStrings.siteInfo] : result
                // })(dispatch);
            }
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    postSiteInfo : (name, subname, propName, value, callback) => dispatch => {
        inovateOSAdminSiteServices.postSiteInfo(name, subname, propName, value, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getSiteInfo : callback => dispatch => {
        inovateOSAdminSiteServices.getSiteInfo((done, result, message)=>{
            if(done) inovateOSAdminSiteActions.payload({
                [inovateOSAdminSiteStrings.siteInfo] : result,
            })(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch => dispatch({
        type : inovateOSAdminConstants.SET_SITE_INFO,
        payload
    })
}