import { insureUserAccountConstants, insureUserAccountStrings } from "./config";
import { insureUserAccountServices } from "./services";
import { successNotice, errorNotice } from "../utils";

export const insureUserAccountActions = {
    createNextOfKin : (data, callback) => dispatch =>{
        insureUserAccountServices.createNextOfKin(data, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getCooperativeInfo : callback => dispatch =>{
        insureUserAccountServices.getCooperativeInfo((done, result, message)=>{
            if(done){
                insureUserAccountActions.payload({
                    [insureUserAccountStrings.cooperativeInfo]:result
                })(dispatch)
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getMyPayments : (lastId, rows, callback) => dispatch => {
        insureUserAccountServices.getMyPayments(lastId, rows, (done, result, message)=>{
            if(done) insureUserAccountActions.payload({
                [insureUserAccountStrings.payments] : result
            })(dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch => dispatch({
        type : insureUserAccountConstants.SET_INSURE_USER_ACCOUNT,
        payload
    })
}