import React, { Component } from 'react';
import { colors} from '../../../../utils';
import { sessionStrings } from '../config';
import { NewLevelMainStageHeader } from './NewLevelMainStageHeader';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyTable, mainStageHeaderAction, mainStageHeaderStrings, 
    HighlightedInfo, EditableCellMapFormat } from '../../../includes';
import { appActions, alertAction } from '../../../../actions';
import { Button } from '@material-ui/core';
;






const style = theme => ({
    root: {
        marginTop : 20
    }
})
class _NewLevels extends Component {
    constructor(props) {
        super(props);
        this.state = {
            previousLevels : [],
            previousLevelsUsable : [],
            levels : []
        }
        const {dispatch} = this.props;
        mainStageHeaderAction({
            [mainStageHeaderStrings.buttons] : [
                {name : "back", value : "Back", onClick : ()=>this.props.closeLevel()},
                {name : "continue", value : "Continue", 
                    style : {backgroundColor : colors.secondary}, 
                    onClick:this.continueToClasses.bind(this)
                }
            ],
            [mainStageHeaderStrings.components] : [
                NewLevelMainStageHeader
            ]
        })(dispatch)
    }
    continueToClasses = () => {
        const {levels, previousLevelsUsable} = this.state;
        const createdLevels = [...previousLevelsUsable, ...levels];
        this.props.moveToClasses(createdLevels);
    }
    static getDerivedStateFromProps(nextProps, prevState) {
        /**
         * TO DO
         * when for the levels that comes from the database 
         * ensure while inserting previous, that is not duplication (use _id to check)
         */
        if(nextProps[sessionStrings.sessionPreviousLevels] &&
        JSON.stringify(prevState.previousLevels) !== 
        JSON.stringify(nextProps[sessionStrings.sessionPreviousLevels])){
            prevState.previousLevels = nextProps[sessionStrings.sessionPreviousLevels];
            prevState.previousLevelsUsable = nextProps[sessionStrings.sessionPreviousLevels];
        }else if(!nextProps[sessionStrings.sessionPreviousLevels]){
            prevState.previousLevels = [];
            prevState.previousLevelsUsable = [];
        }
        return {...prevState};
    }
    
    cellMapContext = {};
    getCellMapContext = (context, name) => this.cellMapContext[name] = context;
    isEmptyNewLevel = newLevel => {
        const {name, short, index} = newLevel;
        if(!name || name.trim() === "" || !short || short.trim() === "", !index)
            return true;
        return false;
    }
    isUniqueNewLevel = newLevel => {
        const { levels, previousLevelsUsable } = this.state;
        for (let i = 0; i < levels.length; i++) {
            const level = levels[i];
            if(!level.new && (level.short === newLevel.short || level.index === newLevel.index)){
                return false;
            }
        }
        for (let i = 0; i < previousLevelsUsable.length; i++) {
            const level = previousLevelsUsable[i];
            if(level.short === newLevel.short || level.index === newLevel.index){
                return false;
            }
        }
        return true;
    }
    addButtonHandler = listLength => e => {
        let data = {};
        for (const mapItem in this.cellMapContext) {
            if (this.cellMapContext.hasOwnProperty(mapItem)) {
                const context = this.cellMapContext[mapItem];
                if(mapItem !== "action"){
                    const {name, value} = context.state.data;
                    data[name] = value;
                }
            }
        }
        data.editable = true;
        //new row is already number zero
        data.id = listLength;
        let levels = [...this.state.levels];
        if(!this.isUniqueNewLevel(data)){
            appActions.showSnackbar(
                alertAction.error("Duplicate index or short name")
            )(this.props.dispatch);
        }else if(this.isEmptyNewLevel(data)){
            appActions.showSnackbar(
                alertAction.error("Some empty field")
            )(this.props.dispatch);
        } else {            
            levels.unshift(data);
            this.setState({levels});
        }
    }
    editBtnHandler = row => () => {
        const {previousLevelsUsable, levels} = this.state;
        if(row._id) {
            for (let i = 0; i < previousLevelsUsable.length; i++) {
                let l = previousLevelsUsable[i];
                if(l._id === row._id){
                    previousLevelsUsable[i].editing = true;
                    break;
                }
            } 
            this.setState({previousLevelsUsable});
        }else {
            for (let i = 0; i < levels.length; i++) {
                const le = levels[i];
                if(le.id === row.id){
                    levels[i].editing = true;
                    break;
                }             
            };
            this.setState({levels});
        }
    }
    cancelEditBtnHandler = row => () => {
        const {previousLevelsUsable, levels} = this.state;
        //only ones with id (not _id ) are editable
        //the if(row._id) is a fancy one
        if(row._id) {
            for (let i = 0; i < previousLevelsUsable.length; i++) {
                let l = previousLevelsUsable[i];
                if(l._id === row._id){
                    delete previousLevelsUsable[i].editing;
                    break;
                }
            } 
            this.setState({previousLevelsUsable});
        }else {
            for (let i = 0; i < levels.length; i++) {
                const le = levels[i];
                if(le.id === row.id){
                    delete levels[i].editing;
                    break;
                }             
            };
            this.setState({levels});
        }
    }
    deleteBtnHandler = row => ()=>{
        const {previousLevelsUsable, levels} = this.state;
        const {dispatch} = this.props
        appActions.showSnackDialog(
            "Are you you want to delete this levle("+row.name+")", 
            [<Button key="cancel" onClick={()=>{
                if(row._id) {
                    for (let i = 0; i < previousLevelsUsable.length; i++) {
                        let l = previousLevelsUsable[i];
                        if(l._id === row._id){
                            previousLevelsUsable.splice(i, 1);
                            break;
                        }
                    } 
                    this.setState({previousLevelsUsable});
                }else {
                    for (let i = 0; i < levels.length; i++) {
                        const le = levels[i];
                        if(le.id === row.id){
                            levels.splice(i, 1);
                            break;
                        }             
                    };
                    this.setState({levels});
                }
                appActions.closeSnackDialog()(dispatch);
            }}>Continue</Button>]
        )(dispatch);        
    }
    editFinishBtnHandler = row => () => {
        const {previousLevelsUsable, levels} = this.state;
        let data = {};
        for (const i in row.context) {
            if (row.context.hasOwnProperty(i)) {
                const context = row.context[i];
                if(i !== "action"){
                    const {name, value} = context.state.data;
                    data[name] = value;
                }
            }
        }
        if(row._id) {
            for (let i = 0; i < previousLevelsUsable.length; i++) {
                let l = previousLevelsUsable[i];
                if(l._id === row._id){
                    delete previousLevelsUsable[i].editing;
                    previousLevelsUsable[i] = {
                        ...previousLevelsUsable[i],
                        ...data
                    }
                    break;
                }
            } 
            this.setState({previousLevelsUsable});
        }else {
            for (let i = 0; i < levels.length; i++) {
                const le = levels[i];
                if(le.id === row.id){
                    delete levels[i].editing;
                    levels[i] = {
                        ...levels[i],
                        ...data
                    };
                    break;
                }             
            };
            this.setState({levels});
        }
    }
    render() {
        const {classes,

        } = this.props;
        let levels = [...this.state.previousLevelsUsable, ...this.state.levels];
        levels.sort((a, b) => b.index - a.index);
        levels = [...levels, {new : true}]
        return (
            <div className={classes.root}>
                <HighlightedInfo>Check the checkbox to select from previous sessions</HighlightedInfo>
                <MyTable
                    title="School Levels"
                    header={["Name", "Short Name", "Index", ""]}
                    dataMap={["name", "short", "index", "action"]}
                    CellMap={EditableCellMapFormat}
                    titleProps={{style:{color : colors.gray, marginBottom : 20}}}
                    getCellMapContext={this.getCellMapContext.bind(this)}
                    addButtonHandler={this.addButtonHandler.bind(this)}
                    deleteBtnHandler={this.deleteBtnHandler.bind(this)}
                    editBtnHandler={this.editBtnHandler.bind(this)}
                    editFinishBtnHandler={this.editFinishBtnHandler.bind(this)}
                    cancelEditBtnHandler={this.cancelEditBtnHandler.bind(this)}
                    data={levels}/>
            </div>
        );
    }
}


_NewLevels.propTypes = {
    classes : PropTypes.object.isRequired,
    closeLevel : PropTypes.func,
    moveToClasses : PropTypes.func,
};

const mapStateToProps = ({sessionReducer}) => ({
    ...sessionReducer,
    [sessionStrings.sessionPreviousLevels] : sessionReducer[sessionStrings.sessionPreviousLevels],
})


export const NewLevels = connect(mapStateToProps)(withStyles(style)(_NewLevels));


