import React, { PureComponent } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Grid } from '@material-ui/core';
import { Blog } from './Blog';
import { NewsLetter } from './NewsLetter';
import { insureUtil } from '../../utils';
import { insureHomeActions } from '../actions';
import { appActions, alertAction } from '../../../../actions';

const style = theme => ({
    root: {
        backgroundColor : insureUtil.getTheme().secondary,
    },
    img : {
        height : 200,
        width : 200,
    }
})
class _KnowledgeArea extends PureComponent {
    subscribeNewsLetter(name, email, callback){
        const {dispatch} = this.props;
        insureHomeActions.subscribeNewsLetter({name, email}, done=>{
            if(callback) callback(done);
        })(dispatch);
    }
    notify(message, type){
        const {dispatch} = this.props;
        appActions.showSnackbar(
            type ? alertAction[type](message) :
            alertAction.error(message)
        )(dispatch);
    }
    render() {
        const {classes} = this.props;
        return (
            <div className={classes.root}>
                <Grid container spacing={4}>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <div style={{
                            display :"flex",
                            justifyContent : "center",
                            alignItems :"center",
                            height : "100%",
                            }}>
                                <img src="/images/newsletter.jpg" className={classes.img} title="moboinuser"/>
                        </div>
                    </Grid>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <NewsLetter
                            subscribeBtnClick={this.subscribeNewsLetter.bind(this)}
                            notify={this.notify.bind(this)}
                        />
                    </Grid>
                </Grid>
            </div>
        );
    }
}
_KnowledgeArea.propTypes = {
    classes : PropTypes.object.isRequired
};
export const KnowledgeArea = connect()(withStyles(style)(_KnowledgeArea));