import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import {FormControl, Menu, Button, MenuItem} from '@material-ui/core';
import { teacherStrings } from '../config';
import { colors } from '../../../../utils';
import { sessionStrings } from '../../Sessions';
import { teacherActions } from '../actions';

const style = theme => ({
    root: {
    },
    stageBtnComp : {
        backgroundColor : colors.white,
        color : colors.primary,
        margin : 10,
        "&:hover" : {
            backgroundColor : colors.white,
        }
    }
})
class _StageComponent extends Component {
    constructor(props) {
        super(props);
        this.state = {
            anchorEl : null, 
            anchorElClass : null,
            anchorElTerm : null
        }
        this.initializeComponent();
        this.handleLevelClose = this.handleLevelClose.bind(this);
        this.handleClassClose = this.handleClassClose.bind(this);
        this.handleTermClose = this.handleTermClose.bind(this);
    }
    initializeComponent = () => {
        const {
            dispatch,
            [teacherStrings.levels] : levels,
            [teacherStrings.terms] : terms,
        } = this.props;
        if(!levels) teacherActions.getLevels()(dispatch);
        if(!terms) teacherActions.getTerms()(dispatch);
    }
    handleLevelClose = level => (e) => {
        const {dispatch} = this.props;
        this.setState({anchorEl: null});
        teacherActions.setSelectedClass(null)(dispatch);
        teacherActions.setSelectedLevel(level)(dispatch);
        teacherActions.getClasses(level._id)(dispatch);
    }
    handleClassClose = selectedClass => () => {
        const {dispatch} = this.props;
        this.setState({anchorElClass: null});
        teacherActions.setSelectedClass(selectedClass)(dispatch);
    }
    handleTermClose = term => (e) => {
        const {dispatch} = this.props;
        teacherActions.setSelectedTerm(term)(dispatch);
        this.setState({anchorElTerm: null});
    }
    render() {
        const {
            classes,
            [teacherStrings.levels] : levels,
            [teacherStrings.selectedLevel] : selectedLevel,
            [teacherStrings.classes] : levelClasses,
            [teacherStrings.selectedClass] : selectedClass,
            [teacherStrings.terms]: terms,
            [teacherStrings.selectedTerm] : selectedTerm,
        } = this.props;
        const {anchorEl, anchorElClass, anchorElTerm} = this.state;
        console.log(levelClasses);
        return (
            <FormControl style={{flexDirection : "row"}}>
                <div>
                    <Button 
                        onClick={e=>this.setState({anchorEl : e.target})}
                        className={classes.stageBtnComp}
                        aria-controls="level-menu" 
                        aria-haspopup="true">{selectedLevel && selectedLevel.name || "Levels"}</Button>
                    <Menu
                        id="level-menu"
                        anchorEl={anchorEl}
                        open={Boolean(anchorEl)}
                        onClose={e=>this.setState({anchorEl : null})}>
                            {levels && levels.map((level, index)=>
                                <MenuItem onClick={this.handleLevelClose(level)} value={level._id} key={index}>
                                    {level.name}
                                </MenuItem>)}
                    </Menu>
                </div>
                <div>
                    <Button 
                        onClick={e=>this.setState({anchorElClass : e.target})}
                        className={classes.stageBtnComp}
                        aria-controls="class-menu" 
                        aria-haspopup="true">{selectedClass && selectedClass.name || "Classes"}</Button>
                    <Menu
                        id="class-menu"
                        anchorEl={anchorElClass}
                        keepMounted
                        open={Boolean(anchorElClass)}
                        onClose={e=>this.setState({anchorElClass : null})}>
                            {levelClasses && 
                            levelClasses[selectedLevel._id] && 
                            levelClasses[selectedLevel._id].map((cl, index)=>
                                <MenuItem 
                                    key={index}
                                    value={cl._id}
                                    onClick={this.handleClassClose(cl)}
                                    >{cl.name}</MenuItem>)}
                    </Menu>
                </div>
                <div>
                    <Button 
                        onClick={e=>this.setState({anchorElTerm : e.target})}
                        className={classes.stageBtnComp}
                        aria-controls="term-menu" 
                        aria-haspopup="true">
                            {selectedTerm && selectedTerm.name || "Terms"}
                        </Button>
                    <Menu
                        id="term-menu"
                        anchorEl={anchorElTerm}
                        keepMounted
                        open={Boolean(anchorElTerm)}
                        onClose={e=>this.setState({anchorElTerm : null})}>
                            {terms && terms.map((term, index)=> 
                            <MenuItem
                                key={index}
                                onClick={this.handleTermClose(term)}
                                value={term._id}>{term.name}</MenuItem>)}
                    </Menu>
                </div>
            </FormControl>
        );
    }
}


_StageComponent.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({teacherReducer}) => ({
    ...teacherReducer
})


export const StageComponent = connect(mapStateToProps)(withStyles(style)(_StageComponent));