import { contactActions } from "./actions";

export const socketContactFeedbackHandler = res => {
    const {action} = res;
    switch(action){
        case "trackingEnabled" : 
            return contactActions.amTrackingContact(res.contactId);
        case "trackingDisabled" : 
            return contactActions.amNotTrackingContact(res.contactId);
        case "receiveMessage" : return contactActions.iReceivedAMessage(res.result);
        case "contactConnected" : return contactActions.contactConnected(res.user);
    }
}