import { fetchGet, post } from "../utils"
const owner = "admin";
export const insureAdminCooperativeServices={
    unsuspendSubscriber : (id, callback) => {
        fetchGet(owner, "unsuspendSubscriber", {id}, ({unsuspendSubscriber, result, message})=>{
            callback(unsuspendSubscriber, result, message);
        })
    },
    suspendSubscriber : (id, callback) => {
        fetchGet(owner, "suspendSubscriber", {id}, ({suspendSubscriber, result, message})=>{
            callback(suspendSubscriber, result, message);
        })
    },
    activateSubscriber : (id, expDate, callback) => {
        post({id, expDate}, owner, "activateSubscriber", ({activateSubscriber, result, message})=>{
            callback(activateSubscriber, result, message);
        });
    },
    deactivateSubscriber : (id, callback) => {
        fetchGet(owner, "deactivateSubscriber", {id}, ({deactivateSubscriber, result, message})=>{
            callback(deactivateSubscriber, result, message);
        })
    },
    deleteRequest : (id, callback) => {
        fetchGet(owner, "deleteRequest", {paymentId: id}, ({deleteRequest, result, message})=>{
            callback(deleteRequest, result, message);
        })
    },
    approveRequest : (id, userId, expDate, callback) => {
        post({id, userId, expDate}, owner, "approveRequest", ({approveRequest, result, message})=>{
            callback(approveRequest, result, message);
        })
    },
    getPayments : (lastId, rows, callback) => {
        fetchGet(owner, "getPayments", {lastId, rows}, ({getPayments, result, message})=>{
            callback(getPayments, result, message);
        })
    },
    getSubscribers : (lastId, rows, callback) => {
        fetchGet(owner, "getSubscribers", {lastId, rows}, ({getSubscribers, result, message})=>{
            callback(getSubscribers, result, message);
        })
    }
}