export const hirFamilyStrings = {
    families : "hirFamilies",
    newFamilyMembers : "newFamilyMembers",
}
export const hirFamilyConstants = {
    SET_HIR_FAMILY : "SET_HIR_FAMILY",
}
export const hirFamilyReducer = (state={}, action)=>{
    const {payload, type} = action;
    switch(type){
        case hirFamilyConstants.SET_HIR_FAMILY : 
            return {...state, ...payload};
        default : return state;
    }
}
export * from './actions'
export * from './services';