import { insureHomeServices } from "./services"
import { insureHomeStrings, insureHomeConstants } from "./config";
import { errorNotice, successNotice } from "../utils"

export const insureHomeActions = {
    subscribeNewsLetter : (data, callback) =>dispatch=>{
        insureHomeServices.subscribeNewsLetter(data, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getCarouel : callback => dispatch => {
        insureHomeServices.getCarousel((done, result, message)=>{
            if(done) insureHomeActions.payload({
                [insureHomeStrings.carousel] : result
            })(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getHomeInfo : callback => dispatch => {
        insureHomeServices.getHomeInfo((done, result, message)=>{
            if(done) insureHomeActions.payload({
                [insureHomeStrings.home] : result
            })(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch => dispatch({
        type : insureHomeConstants.SET_INSURE_HOME,
        payload
    })
}