import { siteServices } from "./services"
import { siteConstants, siteStrings } from "./config"

export const siteActions = {
    updateSiteInfo : (data, callback) => dispatch => {
        siteServices.updateSiteInfo(data, (done, result, message)=>{
            //do something
            if(callback) callback(done, result, message);
        })
    },
    getSiteInfo : callback => dispatch => {
        siteServices.getSiteInfo((done, result, message)=>{
            if(done) siteActions.payload({
                [siteStrings.site] : result
            })(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch => dispatch({
        type : siteConstants.SET_SITE,
        payload 
    })
}