import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerStrings, headerActions, 
    breadCrumbActions, MyDialog, mainStageHeaderAction } from '../../includes';
import { SessionCard } from './SessionCard';
import { sessionStrings } from './config';
import { sessionActions } from './actions';
import { TermBoard } from './TermBoard';
import { NewTermForm } from './NewTermForm';
import { Grid, ExpansionPanel, ExpansionPanelSummary, Typography, ExpansionPanelDetails } from '@material-ui/core';
import { NewSessionOptions } from './NewSessionOptions';
import { NewLevels } from './NewLevels/NewLevels';
import { ExpandMore as ExpandMoreIcon } from '@material-ui/icons';
import { LevelClasses } from './LevelClasses';
import { appActions } from '../../../actions';
import { routeNamesSchool } from '../routeNames';


const style = theme => ({
    root: {
        marginTop : 50
    }
})
class _Sessions extends Component {
    constructor(props) {
        super(props);
        this.state = {
            selectedSession : {}, 
            newTermDialog :false,
            sessionLevelDialog : false,
            newSession : "",
            stage : 1,
            expanded : false
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "SESSIONS"
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "Sessions", path : routeNamesSchool.sessions},
        ])(dispatch);
        mainStageHeaderAction({})(dispatch);
        if(!props[sessionStrings.sessions]) 
            sessionActions.getSessions()(dispatch);
        
        /** DO FOR DIFF SESSION ON SELECT */
        sessionActions.getSessionTerms(1)(dispatch);
    }
    componentWillUnmount(){
        sessionActions.cleanup()(this.props.dispatch);
    }
    setSession = session => () => {
        this.setState({selectedSession: session});
    }
    newTermDialogOpen = ()=> this.setState({newTermDialog: true});
    newTermDialogClose = () => this.setState({newTermDialog:false});
    newSessionOptionDialogClose = () => this.setState({sessionLevelDialog: false});
    recieveSession = session => {
        const {[sessionStrings.sessions] : sessions = []} = this.props;
        if(sessions.length === 0)
            this.setState({stage: 2});
        else this.setState({sessionLevelDialog: true, newSession: session, levelOption : null});
    }
    sessionOptionHandler = levelOption => {
        const{newSession} = this.state;
        switch(parseInt(levelOption)){
            case 1 : 
            //use existing levels only
                break;
            case 2 : //use existing levels and classes
                break;
            default : //move to create levels and classes.
                this.setState({stage: 2}); break;
        }
    }
    backToSession = ()=>{
        mainStageHeaderAction({})(this.props.dispatch);
        this.setState({stage : 1})
    }
    moveToClasses = levels => {
        this.setState({stage: 3});
    }
    handleExpansionChange = panel => (event, isExpanded) => {
        this.setState({expanded : isExpanded ? panel : false});
    };
    finish = levelsWithClasses => {
        /**
         * TO DO 
         * DATABASE
         *  - create the levels, classes in it collections, for other session/ subsequent session to assess
         *  - use the ids in the created session
         */
        const {dispatch} = this.props;
        setTimeout(()=>{
            this.setState({stage : 1});
            appActions.toogleScreenProgress(false)(dispatch);
        }, 10000);
    }
    render() {
        const {classes, 
            [sessionStrings.sessions] : sessions = [],
            [sessionStrings.terms] : terms = []
        } = this.props;
        const { 
            newTermDialog, 
            sessionLevelDialog, selectedSession,
            expanded, stage} = this.state;
        return (
            stage === 1 ? 
                <div className={classes.root}>
                    <Grid container spacing={2}>
                        <Grid item xs={12} sm={8} md={8} lg={3} xl={3}>
                            <SessionCard 
                                sessions={sessions}
                                setSession={this.setSession.bind(this)}
                                getSession={this.recieveSession.bind(this)}/>
                        </Grid>
                        <Grid item xs={12} sm={12} md={12} lg={9} xl={9}>
                            <ExpansionPanel expanded={expanded === "levelBoard"} onChange={this.handleExpansionChange("levelBoard")}>
                                <ExpansionPanelSummary
                                    expandIcon={<ExpandMoreIcon/>}
                                    aria-controls="levelBoard-content"
                                    id="levelBoard-header">
                                        <Typography>Levels for session {selectedSession.name}</Typography>
                                </ExpansionPanelSummary>
                                <ExpansionPanelDetails>
                                    <TermBoard terms={terms} newTermDialogOpen={this.newTermDialogOpen.bind(this)}/>   
                                </ExpansionPanelDetails>
                            </ExpansionPanel>
                            <ExpansionPanel expanded={expanded === "termBoard"} onChange={this.handleExpansionChange("termBoard")}>
                                <ExpansionPanelSummary
                                    expandIcon={<ExpandMoreIcon/>}
                                    aria-controls="termBoard-content"
                                    id="termBoard-header">
                                        <Typography>Terms for session {selectedSession.name}</Typography>
                                </ExpansionPanelSummary>
                                <ExpansionPanelDetails>
                                    <TermBoard terms={terms} newTermDialogOpen={this.newTermDialogOpen.bind(this)}/>   
                                </ExpansionPanelDetails>
                            </ExpansionPanel>
                        </Grid>
                    </Grid>
                    <MyDialog open={newTermDialog}>
                        <NewTermForm closeDialog={this.newTermDialogClose.bind(this)}/>
                    </MyDialog>
                    <MyDialog open={sessionLevelDialog}>
                        <NewSessionOptions
                            closeDialog={this.newSessionOptionDialogClose.bind(this)}
                            continueHandler={this.sessionOptionHandler.bind(this)}/>
                    </MyDialog>
                </div> : 
                (stage === 2 ? 
                    <NewLevels
                        closeLevel={this.backToSession.bind(this)}
                        moveToClasses={()=>this.setState({stage : 3})}/> : 
                    <LevelClasses finish={this.finish.bind(this)}/>)
        );
    }
}


_Sessions.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({sessionReducer}) => ({
    ...sessionReducer
})


export const Sessions = connect(mapStateToProps)(withStyles(style)(_Sessions));
export {Sessions as default};