import { insureAboutUsServices } from "./services";
import { insureAboutUsConstants, insureAboutUsStrings } from "./config";
import { successNotice, errorNotice } from "../utils";
export const insureAboutUsActions = {
    unsubscribe : (id, email, callback) => dispatch => {
        insureAboutUsServices.unsubscribe(id, email, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    addMessage : (data, callback) => dispatch => {
        insureAboutUsServices.addMessage(data, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getSiteInfo : callback => dispatch => {
        insureAboutUsServices.getSiteInfo((done, result, message)=>{
            if(done) insureAboutUsActions.payload({
                [insureAboutUsStrings.aboutUs] : result
            })(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch => dispatch({
        type : insureAboutUsConstants.SET_ABOUT_US,
        payload
    })
}