export const trackerUtilStrings = {
    theme : "theme",
    tokenAlias : "tokenAlias",
    userAlias : "userAlias",
    backendUrl : "backendUrl",
    myProfile : "myProfile",
    trackingMe : "trackingMe",
    disableAllTracking : "disableAllTracking",
}

export const trackerUtilConstants = {
    SET_UTIL : "SET_UTIL",
}

export const trackerUtilReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case trackerUtilConstants.SET_UTIL : 
            return {...state, ...payload};
        default : return {...state};
    }
}

