export const socketIOStrings = {
    socket : "socket",
    tokenAlias : "tokenAlias",
    userIdAlias : "userIdAlias",
    socketEmitQueeue : "socketEmitQueeue",
    socketOnQueeue : "socketOnQueeue",
}
export const socketIOConstants = {
    SET_SOCKETIO : "SET_SOCKETIO",
}
export const socketIOReducer = (state = {}, action)=>{
    const {type, payload } = action; 
    switch(type){
        case socketIOConstants.SET_SOCKETIO : 
            return {...state, ...payload};
        default : return state;
    }
}
