import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, mainStageHeaderAction, mainStageHeaderStrings, breadCrumbActions, MyTable, SelectedInfo, headerStrings } from '../../includes';
import {TableCell } from '@material-ui/core';
import { colors } from '../../../utils';
import { StudentStageHeader } from './StudentStageHeader';
import { history } from '../../../helpers';
import { studentStrings } from './config';
import { studentActions } from './actions';
import { RemoveRedEye } from '@material-ui/icons';
import { routeNamesSchool } from '../routeNames';

const style = theme => ({
    root: {
        marginTop : 50
    }
})
class _Students extends Component {
    constructor(props) {
        super(props);
        this.state = {
            lastId : null,
            rows : 20,
            selectedStudent : null
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "STUDENTS",
            [headerStrings.backButtonAction] : null
        })(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                StudentStageHeader
            ],
            [mainStageHeaderStrings.buttons] : [
                {
                    value : "New Student", 
                    style:{backgroundColor:colors.white,color:colors.secondary},
                    onClick:()=>history.push(routeNamesSchool.tea_stu_stu_new)
                }
            ]
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "New Student", path : routeNamesSchool.students}
        ])(dispatch);
        
    }
    componentDidMount() {
        const {[studentStrings.students] : students, dispatch} = this.props;
        const {lastId, rows} = this.state;
        if(!students) studentActions.getStudents(lastId, rows)(dispatch);
    }
    selectStudent=row=>()=>{
        this.setState({selectedStudent: row})
    }
    cellMap = ({row, cellMap})=>{
        switch(cellMap){
            case "action" : return <TableCell style={{padding :5}}>
                <RemoveRedEye style={{color : colors.gray}} onClick={e=>{
                    e.stopPropagation();
                    this.props.history.push(routeNamesSchool.studentProfile_+row._id)
                }}/>
            </TableCell>;
            default : return <TableCell style={{padding : 5}}>{row[cellMap]}</TableCell>
        }
    }
    render() {
        const {classes, [studentStrings.students] : students} = this.props;
        const {selectedStudent} = this.state;
        return (
            <div className={classes.root}>
                {selectedStudent && <SelectedInfo 
                    selectedInfo={selectedStudent} 
                    nameMapping={name=>name}
                    valueMapping={(name, value)=>value}
                    skip={["sessionClassId", "sessionLevelId"]}/>}
                <MyTable
                    header={["Last Name", "First Name", "Middle Name", "Level", "Class"]}
                    dataMap={["lastName", "firstName", "middleName", "sessionLevel", "sessionClass", "action"]}
                    data={students}
                    rowAction={this.selectStudent.bind(this)}
                    CellMap={this.cellMap}
                    />
            </div>
        );
    }
}
/**
 * Details (bio, contact, parents info)
 * performance, marked scripts
 * remarks
 * leadership
 */

_Students.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({studentReducer}) => ({
    ...studentReducer
})


export const Students = connect(mapStateToProps)(withStyles(style)(_Students));
export {Students as default};