import { inventoryUtil } from "./inventoryUtil";
const {
    post, fetchGet, fetchPost
} = inventoryUtil;
const owner = "1";
export const inventoryUtilServices = {
    getUser : callback => {
        fetchGet(owner, "getUser", {}, ({getUser, result, message})=>{
            callback(getUser, result, message);
        })
    },
    login : (email, password, callback) => {
        post({email, password}, owner, "login", ({login, result, message})=>{
            callback(login, result, message);
        })
    },
    signup : (data, callback) => {
        post(data, owner, "signup", ({signup, result, message})=>{
            callback(signup, result, message);
        })
    }
}