import { insureAdminUtilConstants, insureAdminUtilStrings } from "./config";
import { insureAdminUtilServices } from "./services";
import { _storeData } from "../../../utils";
import { errorNotice } from "./insureAdminUtil";
import { store } from "../../../helpers";

export const insureAdminUtilActions = payload => dispatch => dispatch({
    type : insureAdminUtilConstants.SET_UTIL,
    payload 
});

export const insureAdminActions = {
    getUser : callback => dispatch => {
        insureAdminUtilServices.getUser((done, result, message)=>{
            if(done){
                if(result && result.myProfile && result.myProfile.admin){
                    insureAdminUtilActions({
                        [insureAdminUtilStrings.myProfile] : result.myProfile,
                        [insureAdminUtilStrings.trackingMe] : result.trackingMe,
                        [insureAdminUtilStrings.disableAllTracking] : result.disableAllTracking,
                    })(dispatch);
                }
            }
            if(callback) callback(done, result, message);
        })
    },
    signup : (data, callback) => dispatch => {
        insureAdminUtilServices.signup(data, (done, result, message)=>{
            if(done){
                if(result && result.myProfile && result.myProfile.admin){
                    _storeData([insureAdminUtilStrings.tokenAlias], result.myProfile.token);
                    _storeData([insureAdminUtilStrings.userAlias], result._id);
                    insureAdminUtilActions({
                        [insureAdminUtilStrings.myProfile] : result.myProfile,
                        [insureAdminUtilStrings.trackingMe] : result.trackingMe,
                        [insureAdminUtilStrings.disableAllTracking] : result.disableAllTracking,
                    })(dispatch);
                }else errorNotice("Invalid administrative profile", dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    loging : (email, password, callback) => dispatch => {
        insureAdminUtilServices.login(email, password, (done, result, message)=>{
            const reducer = store.getState().insureAdminUtilReducer;
            if(done){
                if(result && result.myProfile && result.myProfile.admin){
                    _storeData(reducer[insureAdminUtilStrings.tokenAlias], result.myProfile.token);
                    _storeData(reducer[insureAdminUtilStrings.userAlias], result._id);
                    insureAdminUtilActions({
                        [insureAdminUtilStrings.myProfile] : result.myProfile,
                    })(dispatch);
                }else errorNotice("Invalid administrative profile", dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    logout : () => {
        const reducer = store.getState().insureAdminUtilReducer;
        localStorage.removeItem(reducer[insureAdminUtilStrings.tokenAlias]);
        localStorage.removeItem(reducer[insureAdminUtilStrings.userAlias]);
    },
}
