import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, MyTable, EditableCellMapFormat } from '../../../includes';
import { routeName } from '../../../../utils';
import { payrollStrings } from '../../config';
import { payrollActions } from '../../actions';
import { history } from '../../../../helpers';
import { Select, MenuItem } from '@material-ui/core';


const style = theme => ({
    root: {
        marginTop : 20,
    }
})
class _EmployeeList extends Component {
    constructor(props) {
        super(props);
        this.state = {
            lastId : null,
            rows : null,
            payrollEmployeeBrief : null,
            tableData : null,
            editMode : null,
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "PAYROLL (EMPLOYEE)",
            [headerStrings.backButtonAction] : null
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeName.dashboard},
            {name : "Payroll (Employees)", path : routeName.payrollEmployees},
        ])(dispatch);
        if(props.getContext) props.getContext(this);
        this.initialiseComponent();
    }
    componentWillUnmount(){
        const {dispatch} = this.props;
        payrollActions.setEmployeeEditMode(false)(dispatch);
    }
    initialiseComponent(){
        const {
            dispatch,
            [payrollStrings.payrollBenefits] : payrollBenefits,
            [payrollStrings.payrollDeductions]: payrollDeductions,
            [payrollStrings.payrollEmployeeStatus]: payrollEmployeeStatus,
        } = this.props;
        const {
            lastId, rows
        } = this.state;
        payrollActions.getPayrollEmployeeBrief(lastId, rows)(dispatch);
        if(!payrollBenefits)
            payrollActions.getPayrollBenefits()(dispatch);
        if(!payrollDeductions)
            payrollActions.getPayrollDeductions()(dispatch);
        if(!payrollEmployeeStatus)
            payrollActions.getPayrollEmployeeStatus()(dispatch);
    }
    static getDerivedStateFromProps(props, state) {
        const {
            [payrollStrings.payrollBenefits] : payrollBenefits,
            [payrollStrings.payrollDeductions] : payrollDeductions,
            [payrollStrings.payrollEmployeeBrief] : payrollEmployeeBrief,
            [payrollStrings.employeeEditMode] : employeeEditMode,
        } = props;
        if(!state.payrollEmployeeBrief){
            state.payrollEmployeeBrief = payrollEmployeeBrief;
            state.tableData = EmployeeList.generateTableData(
                payrollEmployeeBrief, payrollBenefits, payrollDeductions
            );
        }else if(JSON.stringify(state.payrollEmployeeBrief) !==
        JSON.stringify(payrollEmployeeBrief)){
            state.payrollEmployeeBrief = payrollEmployeeBrief;
            state.tableData = EmployeeList.generateTableData(
                payrollEmployeeBrief, payrollBenefits, payrollDeductions
            );
        }else if (state.editMode !== employeeEditMode){
            state.editMode = employeeEditMode;
            if(!employeeEditMode && state.tableData)
                state.tableData = state.tableData.map(item=>{
                    delete item.editing;
                    return item;
                })
                
        }
        return state;
    }
    static generateTableData(payrollEmployeeBrief, payrollBenefits, payrollDeductions){
        let data = [];
        if(payrollEmployeeBrief) for (let i = 0; i < payrollEmployeeBrief.length; i++) {
            const emp = payrollEmployeeBrief[i];
            const {_id, bioInfo, salary, statusId} = emp;
            let dataInfo = {
                _id, fullName : bioInfo.fullName, statusId
            };
            if(salary){
                let deducedAmount = 0;
                let benefitAmount = 0;
                const {gross, deductionIds, benefitIds} = salary;
                dataInfo.gross = gross;
                if(payrollDeductions && deductionIds) for (let j = 0; j < deductionIds.length; j++) {
                    const deductId = deductionIds[j];
                    const deductIdInfo = payrollDeductions.getFirstObjectByPropValue("_id", deductId);
                    if(deductIdInfo && deductIdInfo.item){
                        const {usePercentage, amount, percent, active} = deductIdInfo.item;
                        if(!active) continue;
                        if(usePercentage){
                            deducedAmount += (Number(percent) / 100) * Number(gross);
                        }else{
                            deducedAmount += Number(amount);
                        }
                    }
                }
                if(payrollBenefits && benefitIds) for (let j = 0; j < benefitIds.length; j++) {
                    const benefitId = benefitIds[j];
                    const benefitIdInfo = payrollBenefits.getFirstObjectByPropValue("_id", benefitId);
                    if(benefitIdInfo && benefitIdInfo.item){
                        const {usePercentage, amount, percent, active} = benefitIdInfo.item;
                        if(!active) continue;
                        if(usePercentage){
                            benefitAmount += (Number(percent) / 100) * Number(gross);
                        }else{
                            benefitAmount += Number(amount);
                        }
                    }
                }
                dataInfo.net = Number(gross) - deducedAmount + benefitAmount;
            }
            data.push(dataInfo);
        }
        return data;
    }
    rowActoinHandler = row => () => {
        history.push(routeName.payrollEmployeeInfo_ + row._id, {row});
    }
    cellMapFormat = superProps => props=><EditableCellMapFormat {...props} {...superProps}/>
    tableCellContentView = allStatus => (editing, {row, cellMap}) =>{ 
        if(editing){
            switch(cellMap){
                case "statusId" : 
                    return <Select
                        value={row[cellMap]}>
                        {allStatus && allStatus.map((item, index)=>
                            <MenuItem key={index} value={item._id}>{item.name}</MenuItem>)}
                    </Select>
                default : return row[cellMap];
            }
        }else{
            switch(cellMap){
                case "statusId" : 
                    if(allStatus){
                        const {item} = allStatus.getFirstObjectByPropValue("_id",row[cellMap]) || {};
                        if(item){
                            return item.name;
                        }
                    }
                    return "Unknown";
                case "gross" :
                case "net" : return Number(row[cellMap]).toLocaleString();
                default : return row[cellMap];
            }
        }
    }
    editBtnHandler = row => () => {
        let tableData = [...this.state.tableData];
        const {index} = tableData.getFirstObjectByPropValue("_id", row._id);
        tableData[index] = {...row, editing : true};
        this.setState({tableData});
    }
    render() {
        const {
            classes,
            [payrollStrings.payrollEmployeeStatus] : payrollEmployeeStatus,
            [payrollStrings.employeeEditMode] : employeeEditMode
        } = this.props;
        let {tableData} = this.state;
        let header = ["ID", "Name", "Gross (N)", "Net (N)", "Status"];
        let dataMap = ["_id", "fullName", "gross", "net", "statusId"];
        if(employeeEditMode){
            header = [...header, "Actions"];
            dataMap = [...dataMap, "action"];
            tableData = tableData ? 
                [...tableData.map(item=>({...item, editable: true}))] :
                null;
        }
        return (
            <div className={classes.root}>
                <MyTable
                    header={header}
                    dataMap={dataMap}
                    data={tableData}
                    rowAction={!employeeEditMode ? this.rowActoinHandler.bind(this) : null}
                    CellMap={this.cellMapFormat({
                        tableCellContentView : this.tableCellContentView(payrollEmployeeStatus),
                        editBtnHandler : this.editBtnHandler.bind(this),
                    })}
                    />
            </div>
        );
    }
}


_EmployeeList.propTypes = {
    classes : PropTypes.object.isRequired,
    getcontext : PropTypes.func,
};
const mapStateToProps = ({payrollReducer}) => ({
    [payrollStrings.payrollBenefits] : payrollReducer[payrollStrings.payrollBenefits],
    [payrollStrings.payrollDeductions] : payrollReducer[payrollStrings.payrollDeductions],
    [payrollStrings.payrollEmployeeBrief] : payrollReducer[payrollStrings.payrollEmployeeBrief],
    [payrollStrings.payrollEmployeeStatus] : payrollReducer[payrollStrings.payrollEmployeeStatus],
    [payrollStrings.employeeEditMode] : payrollReducer[payrollStrings.employeeEditMode],
})


export const EmployeeList = connect(mapStateToProps)(withStyles(style)(_EmployeeList));
export {EmployeeList as default}