import { fetchGet, post } from "../utils"
const owner = "admin";
export const inovateOSAdminNewsletterServices = {
    getNewsletters : (lastId, rows, callback) => {
        fetchGet(
            owner, "getNewsletters", 
            {lastId, rows},
            ({getNewsletters, result, message})=>{
                callback(getNewsletters, result, message);
            }
        )
    },
    addNewsletter : (data, callback) => {
        post(data, owner, "addNewsletter", ({addNewsletter, result, message})=>{
            callback(addNewsletter, result, message);
        })
    },
    getNewsletterSubscribers : (lastId, rows, callback) => {
        fetchGet(
            owner, "getNewsletterSubscribers", 
            {lastId, rows}, 
            ({getNewsletterSubscribers, result, message})=>{
                callback(getNewsletterSubscribers, result, message);
        })
    }
}