import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { trackerUtil  } from '../../utils';
import { MessageBox } from '../../../includes';
import { InputArea } from "./InputArea";
import { contactStrings } from '../config';
import { contactActions } from '../actions';

const chatList = [
    {_id : 1, fromId : 1, toId : 2, message : "Come home", date : new Date()},
    {_id : 2, fromId : 2, toId :1, message : "Come home", date : new Date()},
]
const style = theme => ({
    root: {
        position : "relative",
        height : "100%",
        borderRight : "solid .1px " + trackerUtil.getTheme().secondary,
        background : trackerUtil.getTheme().backgroundLight,
    },
    chatContainer : {
        display : "flex",
        flexDirection : "column",
        flexGrow : 1,
        height : "calc(100% - 50px)",
        overflow : "scroll"
    },
    chatInputContainer : {
        // position : "fixed"
        position : 'relative'
    }
})
class _Chats extends Component {
    constructor(props) {
        super(props);
        this.state = {
            contactId : null,
            lastId : null,
            rows : 20,
        };
        this.userId = parseInt(trackerUtil.getUserId());
    }
    containerScrollToBottom(messages){
        if(this.chatContainer){
            const scrollHeight = this.chatContainer.scrollHeight;
            const height = this.chatContainer.clientHeight;
            const maxScrollTop = scrollHeight - height;
            this.chatContainer.scrollTop = maxScrollTop > 0 ? maxScrollTop : 0;
        }
    }
    static getDerivedStateFromProps(props, state) {
        const { 
            [contactStrings.contactId] : contactId,
            dispatch
        } = props;
        if(contactId){
           if(state.contactId !== contactId){
               Chats.getMessages(contactId, state.lastId, state.rows)(dispatch);
               state.contactId = contactId;
            }
        }
        return state;
    }
    componentDidUpdate(prevProps, prevState) {
        this.containerScrollToBottom();
    }
    
    static getMessages = (contactId, lastId, rows) => dispatch =>{
        contactActions.getMessages(contactId, lastId, rows)(dispatch)
    }
    sendMessage(message, context){
        if(!String(message.trim()))
            return;
        const {
            [contactStrings.contactId] : contactId,
            dispatch,
        } = this.props;
        contactActions.sendMessage(contactId, message, done => {
            context.setState({sending : false});
            if(done) {
                context.setState({message : ""});
            }
        })(dispatch);
    }
    contactHasMe(id, contacts){
        if(contacts){
            const {item : contact} = contacts.getFirstObjectByPropValue("_id", id);
            if(contact){
                this.contact = contact;
                if(contact.contactIds){
                    return contact.contactIds.indexOf(this.userId) !== -1;
                }
            }
        }
        return false;
    }
    contactName(id, contacts){
        if(contacts){
            const {item : contact} = contacts.getFirstObjectByPropValue("_id", id);
            if(contact)
                return contact.name;
        }
        return null;
    }
    render() {
        const {
            classes,
            [contactStrings.contactId] : contactId,
            [contactStrings.messages] : messages,
            [contactStrings.contacts] : contacts
        } = this.props;
        return (
            <div className={classes.root}>
                {!contactId ? null : 
                (this.contactHasMe(contactId, contacts) ? <Fragment>
                    <div ref={e=>this.chatContainer = e} className={classes.chatContainer} >
                        {messages && messages[contactId] && messages[contactId].map((item, index)=>{
                            return item.fromId === this.userId ? 
                                <MessageBox {...item} key={index}/> : 
                                <MessageBox {...item} key={index} left/>
                        })}
                        {this.containerScrollToBottom(messages)}
                    </div>
                    <div className={classes.chatInputContainer}>
                        <InputArea
                            sendMessage={this.sendMessage.bind(this)}/>
                    </div>
                </Fragment> : 
                <div style={{
                    display : "flex",
                    height : "100%",
                    justifyContent : "center",
                    alignItems : 'center'
                }}>
                    {this.contactName(contactId, contacts)} has not added you to his contact list.
                </div>)}
            </div>
        );
    }
}


_Chats.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({contactReducer}) => ({
    [contactStrings.contactId] : contactReducer[contactStrings.contactId],
    [contactStrings.messages] : contactReducer[contactStrings.messages],
    [contactStrings.contacts] : contactReducer[contactStrings.contacts],
})


export const Chats = connect(mapStateToProps)(withStyles(style)(_Chats));
export {Chats as default}