import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { inputTypes } from './inputTypes';
import { TextField, Button, FormControl, Typography } from '@material-ui/core';
import { MyTable } from '../../MyTable';
const style = theme => ({
    root: {
        
    },
    newInput : {
        width : "50%",
        [theme.breakpoints.down("xs")] : {
            width : "100%",
        }
    },
    addContainer : {
        justifyContent : "center",
    },
    addBtn : {
        padding: 14,
        margin: 5,
        marginTop: 10,
    },
    cancelBtn : {

    },
    finishBtn : {
        marginLeft : 10,
    }
})
class _OptionCreator extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data : null,
            name : "",
            value : "",
        }
    }
    componentDidMount() {
        this.refs.name.focus();
    }
    
    onChange=name=>e=>{
        const newName = e.target.value;
        let value = String(newName).split(" ").join("").toLowerCase();
        this.setState({[name] : newName, value});
    }
    addValue = () => {
        const {name, value, data : oldData} = this.state;
        //validate entries
        const {errorHandler} = this.props;
        if(!String(name).trim()){
            if(errorHandler) errorHandler("Empty field not accepted", "error", this);
            this.refs.name.focus();
            return;
        }
        if(oldData && oldData.getFirstObjectByPropValue("_id", value)){
            if(errorHandler) errorHandler("Option already exists", "error", this);
            this.refs.name.focus();
            return;
        }
        const data = oldData ? [...oldData, {name, _id : value}] : [{name, _id : value}];
        this.setState({data, name : "", value : ""});

    }
    finish(){
        const { data } = this.state;
        const { onFinishCallback } = this.props;
        if(onFinishCallback) 
            onFinishCallback(data);      
    }
    render() {
        const {classes} = this.props;
        const {data, name, value} = this.state;
        return (
            <div className={classes.root}>
                <div>
                    {data ? <MyTable
                        header={["Names", "Values"]}
                        dataMap={["name", "value"]}
                        data={data}/> : 
                        <Typography component="i" paragraph>Add options</Typography>}
                </div>
                <div style={{
                    display : "flex"
                }}>
                    <div style={{
                        display : "flex",
                        flex : 1
                    }}>
                        <TextField 
                            ref="name"
                            margin="normal"
                            variant="outlined"
                            placeholder="Name"
                            label="Name"
                            value={name}
                            onChange={this.onChange("name")}
                            className={classes.newInput}/>
                        <TextField 
                            margin="normal"
                            variant="outlined"
                            placeholder="Value"
                            label="Value"
                            value={value}
                            onChange={this.onChange("value")}
                            disabled
                            className={classes.newInput}/>
                    </div>
                    <FormControl className={classes.addContainer}>
                        <Button
                            className={classes.addBtn} 
                            onClick={this.addValue.bind(this)} 
                            color="primary" 
                            variant="contained">Add</Button>
                    </FormControl>
                </div>
                <div>
                    <Button 
                        className={classes.cancelBtn}
                        onClick={this.props.onCancelClick} 
                        color="secondary" 
                        variant="contained">Cancel</Button>
                    <Button 
                        className={classes.finishBtn}
                        onClick={this.finish.bind(this)} 
                        variant="contained">Finish</Button>
                </div>
            </div>
        );
    }
}
_OptionCreator.propTypes = {
    classes : PropTypes.object.isRequired,
    value : PropTypes.string,
    name : PropTypes.string,
    onCancelClick : PropTypes.func,
    onFinishCallback : PropTypes.func,
    errorHandler : PropTypes.func,
};
export const OptionCreator = withStyles(style)(_OptionCreator);