import React from 'react';
import { insureAdminRouteNames } from "./routeNames";
import {connect} from 'react-redux';
import { Router, Switch, Route} from 'react-router-dom';
import { 
    headerActions, headerStrings, screenActions,  mainStageAction, 
    MySnackbar, SnackDialog, mainStageHeaderAction, 
} from '../includes';
import { PrivateRoutePlane, LogoutRoute } from './RouteTemplates';
import { history } from '../../helpers';
import { insureAdminMenuItem } from './menuItems';
import { insureAdminUtilActions, theme1, insureAdminUtil, insureAdminUtilStrings, insureAdminActions } from './utils';
import { mainStageStrings } from '../includes/MainStage/constants';
import { withStyles } from '@material-ui/core';
import $ from 'jquery';
import { insureAdminRoutes } from './routes';
import Login from './Login/Login';


const styles = theme => ({
    mainStage : {
        margin : 0,
        padding : 0,
    }
})
class _MoboinsureAdminApp extends React.PureComponent{
    constructor(props) {
        super(props);

        const {pathname} = history.location;
        if(String(pathname).startsWith("/super")){
            const {
                dispatch,
                [insureAdminUtilStrings.myProfile] : myProfile,
            } = props;
            insureAdminUtilActions({
                [insureAdminUtilStrings.theme] : theme1,
                [insureAdminUtilStrings.tokenAlias] : "moboinsureAdminToken",
                [insureAdminUtilStrings.userAlias] : "moboinsureAdminUserId",
                [insureAdminUtilStrings.backendUrl] : /* "http://localhost:8000/api/v1/", // */"http://moboinsure.com/api/v1/",
                [insureAdminUtilStrings.backendBaseUrl] : /* "http://localhost:8000", // */"http://moboinsure.com",
                [insureAdminUtilStrings.defaultImage] : "/image/default.png",
            })(dispatch);
            headerActions({
                [headerStrings.headerTitle] : "MOBOINSURE 24/7",
                [headerStrings.headerTitleProps] : {
                    style : {
                        borderBottom : "none",
                        color : insureAdminUtil.getTheme().white,
                    }
                },
                [headerStrings.drawer] : true,
                [headerStrings.visible] : true,
                [headerStrings.menuItems] : insureAdminMenuItem,
            })(dispatch);
            screenActions.setTheme(theme1)(dispatch);
            mainStageAction({
                [mainStageStrings.containerProps] : {
                    style : {
                        margin : 0,
                        padding : 0,
                        height : "calc(100vh - 115px)",
                        marginTop : 66,
                    }
                }
            })(dispatch);
            mainStageHeaderAction({
                [mainStageHeaderAction.visible] : false,
            })(dispatch);            
            if(insureAdminUtil.isLogedIn()){
                if(!myProfile)
                    insureAdminActions.getUser()(dispatch);
                // chatConfiguration();
            }

        }
        
    }
    componentDidMount(){
        // $("body").css("backgroundColor", insureAdminUtil.getTheme().background);
        if(history.location.pathname.includes("/super"))
            $("title").text("Moboinsure 24/7 Admin");
    }
    render(){
        console.log(process.env);
        return(
            <Router history={history}>
                <div>
                    <React.Suspense
                        fallback={<div>Loading...</div>}>
                        <Switch>
                            {insureAdminRoutes && insureAdminRoutes.map((route, index)=>{
                                
                                return <PrivateRoutePlane {...route} key={index}/>
                            })}
                            <Route path={insureAdminRouteNames.login} exact component={props=><Login {...props}/>}/>
                            <LogoutRoute path="/super/logout"/>
                        </Switch>
                    </React.Suspense>
                    <MySnackbar/>
                    <SnackDialog/>
                </div>
            </Router>
        )
    }
}
const mapStateToProps = ({insureAdminUtilReducer}) => ({
    [insureAdminUtilStrings.myProfile] : insureAdminUtilReducer[insureAdminUtilStrings.myProfile],
})
export const MoboinsureAdminApp =  connect(mapStateToProps)(withStyles(styles)(_MoboinsureAdminApp));