import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { IconButton, Popover } from '@material-ui/core';
import { Chat } from '@material-ui/icons';
import { trackerUtil } from '../../../../Tracker/utils';
import AllChats from '../AllChats/AllChats';
import { history } from '../../../../../helpers';
import { chatFooterStrings } from '../../config';

const style = theme => ({
    root: {
        position : "fixed",
        bottom : 0,
        right : 1,
        display : "flex",
        flexDirection : "column",
        zIndex : 1000,
        overflow : "scroll"
    }
})
class _FabIconControl extends Component {
    constructor(props) {
        super(props);
        this.state = {
            anchorEl : null
        }

        this.appTheme = trackerUtil.getTheme();
    }
    onClick(){
        // this.openPopover();
        const {
            [chatFooterStrings.smallScreenFabClick] : smallScreenFabClick
        } = this.props;
        if(smallScreenFabClick)
            smallScreenFabClick();
    }
    openPopover = e => {
        const target = e.currentTarget;
        this.setState(({anchorEl})=>({anchorEl : anchorEl ? null : target}))
    }
    render() {
        const {classes} = this.props;
        const { anchorEl } = this.state;
        return (
            <div className={classes.root}>
                <IconButton onClick={this.onClick.bind(this)}>
                    <Chat style={{color : this.appTheme.white}} fontSize="large"/>
                </IconButton>
                <Popover 
                PaperProps={{
                    style : {overflow : "scroll"}
                }}
                open={Boolean(anchorEl)}
                anchorEl={anchorEl}
                onClose={()=>this.setState({anchorEl : null})}>
                    <AllChats nested
                        contentProps={{
                            style : {
                                backgroundColor : this.appTheme.backgroungLight
                            }
                        }}/>
                </Popover>
            </div>
        );
    }
}


_FabIconControl.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({chatFooterReducer}) => ({
    [chatFooterStrings.smallScreenFabClick] : chatFooterReducer[chatFooterStrings.smallScreenFabClick],
})


export const FabIconControl = connect(mapStateToProps)(withStyles(style)(_FabIconControl));
export {FabIconControl as default}