import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { TextField, FormLabel, FormControl, Button, CircularProgress } from '@material-ui/core';
import { Send } from '@material-ui/icons';
const style = theme => ({
    root: {
        marginTop : 20,
        display : "flex",
        flexDirection : "column",
    }
})
class _MessageReply extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data:{
                emails : props.email ? [props.email] : "",
                subject :"",
                body : ""
            }
        }
    }
    onChange=name=>e=>{
        const data = {...this.state.data};
        const value = e.target.value;
        data[name] = value;
        this.setState({data});
    }
    send(){
        this.setState({loading : true});
        const {data} = this.state;
        if(typeof data.emails === "string") 
            data.emails = data.emails.split(" ").join("").split(",");
        const { send } = this.props;
        if(send) send(data, this);
    }
    render() {
        const {loading } = this.state;
        const {emails, subject, body} = this.state.data;
        const {classes, email, message, name, send, footer : Footer} = this.props;
        return (
            <div className={classes.root}>
                <FormLabel>Messenger</FormLabel>
                <FormControl>
                    <TextField
                        margin="normal"
                        variant="outlined"
                        onChange={this.onChange("emails")}
                        value={emails}
                        label="Email"
                        placeholder="Emails"/>
                    <TextField
                        margin="normal"
                        variant="outlined"
                        onChange={this.onChange("subject")}
                        value={subject}
                        label="Subject"
                        placeholder="Subject"/>
                    <TextField
                        margin="normal"
                        variant="outlined"
                        onChange={this.onChange("body")}
                        value={body}
                        multiline
                        rows={10}
                        rowsMax={10}
                        label="Message"
                        placeholder="Message"/>
                    {send && <div>
                        <Button 
                            variant="contained" 
                            color="primary" 
                            onClick={this.send.bind(this)}
                            disabled={loading}>
                            {loading && <CircularProgress style={{color : "white"}} size={20}/>} 
                            <Send/>
                            Send    
                        </Button>
                    </div>}
                    {Footer && <Footer/>}
                </FormControl>
            </div>
        );
    }
}
_MessageReply.propTypes = {
    classes : PropTypes.object.isRequired,
    send : PropTypes.func,
    footer : PropTypes.oneOfType([PropTypes.func,PropTypes.object,]),
    email : PropTypes.string,
    name : PropTypes.string,
    message : PropTypes.string,
};
export const MessageReply = withStyles(style)(_MessageReply);