import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Switch, FormControl,FormControlLabel } from '@material-ui/core';
import { colors } from '../../../utils';
import { studentStrings } from './config';
import { studentActions } from './actions';
import { MyPopupMenu } from '../../includes';


const style = theme => ({
    root: {
    },
    menuButton: {
        color : colors.white, 
        backgroundColor : colors.secondary
    }
})
class _StudentStageHeader extends Component {
    constructor(props) {
        super(props);
        this.state = {
            selectedLevel : null,
            selectedClass : null,
        }
    }
    
    handleLevelMenuClick = selectedLevel => {
        const {dispatch} = this.props;
        this.setState({selectedLevel, menuAnchorEl : null});
        studentActions.setSelectedLevel(selectedLevel)(dispatch);
    }
    handleClassMenuClick = selectedClass => {
        const {dispatch} = this.props;
        this.setState({selectedClass, classMenuAnchorEl : null});
        studentActions.setSelectedClass(selectedClass)(dispatch);
    }
    render() {
        let {
            classes,
            [studentStrings.showAllStudents] : showAll
        } = this.props;
        const {selectedLevel, menuAnchorEl, selectedClass, classMenuAnchorEl} = this.state;
        const levels = [
            {name : "Primary 1", short : "P1"},
            {name : "Primary 2", short : "P2"},
            {name : "Primary 3", short : "P3"},
        ]
        const sessionClasses = [
            {name : "Primary 1 A", short : "P1A"},
            {name : "Primary 1 B", short : "P1B"},
            {name : "Primary 1 C", short : "P1C"},
            {name : "Primary 1 D", short : "P1D"},
        ]
        return (
            <div className={classes.root}>
                <FormControlLabel style={{
                    padding : 10,
                    justifyContent : "center",
                    color : colors.white
                }}
                    control={<Switch style={{color : colors.white}} checked={this.props.showAllStudents||false} onChange={e=>{
                        studentActions.setShowAllStudents(e.target.checked)(this.props.dispatch);
                    }}/>}
                    label="Show all students"/>
                {!showAll && <Fragment>
                    <FormControl style={{padding : 10}}>
                        <MyPopupMenu
                            buttonName="level"
                            buttonValue={(selectedLevel && selectedLevel.name) || "Select Level"}
                            optionNameProp="short"
                            optionValueProp="_id"
                            options={levels}
                            classes={{button: classes.menuButton}}
                            optionClickCallback={this.handleLevelMenuClick.bind(this)}
                            />
                    </FormControl>
                    <FormControl style={{padding : 10}}>
                        <MyPopupMenu
                            buttonName="class"
                            buttonValue={(selectedClass && selectedClass.name) || "Select Class"}
                            options={sessionClasses}
                            optionNameProp="short"
                            optionValueProp="_id"
                            classes={{button: classes.menuButton}}
                            optionClickCallback={this.handleClassMenuClick.bind(this)}
                        />
                    </FormControl>
                </Fragment>}
            </div>
        );
    }
}


_StudentStageHeader.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({studentReducer}) => ({
    [studentStrings.showAllStudents] : studentReducer[studentStrings.showAllStudents],
})


export const StudentStageHeader = connect(mapStateToProps)(withStyles(style)(_StudentStageHeader));