export const insureUserAccountStrings = {
    payments : "insureUserAccountPayments",
    cooperativeInfo : "insureUserAccountCooperativeInfo",
}
export const insureUserAccountConstants = {
    SET_INSURE_USER_ACCOUNT : "SET_INSURE_USER_ACCOUNT"
}
export const insureUserAccountReducer = (state={}, action) => {
    const {type, payload} = action;
    switch(type){
        case insureUserAccountConstants.SET_INSURE_USER_ACCOUNT : 
            return {...state, ...payload};
        default : return state;
    }
}
export * from './actions';
export * from './services';