import React from 'react';
import { routeNamesTracker } from "./routeNames";
import {connect} from 'react-redux';
import { Router, Switch} from 'react-router-dom';
import { headerActions, headerStrings, screenActions, mainStageHeaderAction, mainStageHeaderStrings, mainStageAction, breadCrumbActions, MySnackbar, SnackDialog, chatFooterActions, chatFooterStrings } from '../includes';
import { PrivateRoutePlane, LogoutRoute } from './RouteTemplates';
import { history } from '../../helpers';
import { trackerMenuItems } from './menuItems';
import { trackerUtilActions, theme1, trackerUtil, trackerUtilStrings, trackerActions, socketSetup } from './utils';
import { mainStageStrings } from '../includes/MainStage/constants';
import { withStyles } from '@material-ui/core';
import $ from 'jquery';
import { chatConfiguration } from './Chats';





const Dashboard = React.lazy(()=>import('./Map/Map'));
const Contacts= React.lazy(()=>import('./Contacts/Contacts'));
const Chats = React.lazy(()=>import('./Chats/Chats'));
const MyAccount = React.lazy(()=>import('./MyAccount/MyAccount'));
const MyProfile = React.lazy(()=>import('./MyProfile/MyProfile'));
const Requests = React.lazy(()=>import("./Requests/Requests"));
const Login = React.lazy(()=>import("./Login/Login"));
const Signup = React.lazy(()=>import("./Signup/Signup"));

export const trackerRoutes = [
    {path : routeNamesTracker.dashboard, exact : true, component : Dashboard},
    {path : routeNamesTracker.contacts, exact : true, component : Contacts},
    {path : routeNamesTracker.chats, exact : true, component : Chats},
    {path : routeNamesTracker.myAccount, exact : true, component : MyAccount},
    {path : routeNamesTracker.myProfile, exact : true, component : MyProfile},
    {path : routeNamesTracker.requests, exact : true, component : Requests},
    {path : routeNamesTracker.login, exact : true, component : Login},
    {path : routeNamesTracker.signup, exact : true, component : Signup},
]
const styles = theme => ({
    mainStage : {
        margin : 0,
        padding : 0,
    }
})
class _TrackerApp extends React.PureComponent{
    constructor(props) {
        super(props);
        const {
            dispatch,
            [trackerUtilStrings.myProfile] : myProfile,
            [chatFooterStrings.allChatListData] : chatContacts
        } = props;
        trackerUtilActions({
            [trackerUtilStrings.theme] : theme1,
            [trackerUtilStrings.tokenAlias] : "trackerToken",
            [trackerUtilStrings.userAlias] : "trackerUserId",
            [trackerUtilStrings.backendUrl] : "http://localhost:8000/mobile/trackerx/v1/"
        })(dispatch);
        socketSetup();
        
        headerActions({
            [headerStrings.drawer] : true,
            [headerStrings.visible] : true,
            [headerStrings.fullScreen] : true,
            [headerStrings.leftMenuButton] : true,
            [headerStrings.menuItems] : trackerMenuItems,
            [headerStrings.position] : "fixed",
        })(dispatch);
        breadCrumbActions.hide()(dispatch);
        screenActions.setTheme(theme1)(dispatch);
        mainStageAction({
            [mainStageStrings.containerProps] : {
                style : {
                    margin : 0,
                    padding : 0,
                    height : "calc(100vh - 115px)",
                    marginTop : 66,
                }
            }
        })(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.visible] : false,
        })(dispatch);
        
        if(trackerUtil.isLogedIn()){
            if(!myProfile)
                trackerActions.getUser()(dispatch);
            chatConfiguration();
        }
        
    }
    componentDidMount(){
        $("body").css("backgroundColor", trackerUtil.getTheme().background);
    }
    render(){
        console.log(process.env);
        return(
            <Router history={history}>
                <div>
                    <React.Suspense
                        fallback={<div>Loading...</div>}>
                        <Switch>
                            {trackerRoutes && trackerRoutes.map((route, index)=>
                                <PrivateRoutePlane {...route} key={index}/>)}
                            <LogoutRoute path="/logout"/>
                        </Switch>
                    </React.Suspense>
                    <MySnackbar/>
                    <SnackDialog/>
                </div>
            </Router>
        )
    }
}
const mapStateToProps = ({trackerUtilReducer, chatFooterReducer}) => ({
    [trackerUtilStrings.myProfile] : trackerUtilReducer[trackerUtilStrings.myProfile],
    [chatFooterStrings.allChatListData] : chatFooterReducer[chatFooterStrings.allChatListData],
})
export const TrackerApp =  connect(mapStateToProps)(withStyles(styles)(_TrackerApp));