import { insureLegalServices } from "./services"
import { insureLegalConstants, insureLegalStrings } from "./config";

export const insureLegalActions = {
    getLegal : callback => dispatch => {
        insureLegalServices.getLegal((done, result, message)=>{
            if(done) insureLegalActions.payload({
                [insureLegalStrings.legals] : result
            })(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch =>dispatch({
        type : insureLegalConstants.SET_LEGAL,
        payload
    })
}