import React, { PureComponent, Fragment } from 'react';
import {connect} from 'react-redux';
import MainStage from '../MainStage/MainStage';
import PropTypes from 'prop-types';
import { Header, headerStrings } from '../Header';
import { withStyles, withTheme} from '@material-ui/core';
import { drawerWidth } from '../Header/Drawer';
import { ThemeProvider } from '@material-ui/styles';

const styles = theme => ({
    root : {
        [theme.breakpoints.up("sm")] : {
            marginLeft : drawerWidth
        }
    },
    componentRoot : {
        margin : 10,
    }
})
class _Screen extends PureComponent {
    constructor(props) {
        super(props);
        this.componentTheme = {
            ...props.theme, 
            colors : props.appTheme
        }
    }
    
    render() {
        const {
            classes, drawer, fullScreen, appTheme,
            component : Component, ...otherProps
        } = this.props;
        return (
            <div className={drawer && !fullScreen ? classes.root : ""} {...this.props.containerProps}>
                <Header 
                    rootProps={{                    
                        style: {
                            backgroundColor : appTheme ? appTheme.primary : null,
                        }
                    }}
                    headerTitleProps={{
                        style : {
                            color : appTheme ? appTheme.backgroundTypo : null,
                            borderBottom : "none",
                        },
                    }}
                    drawerProps={{
                        color : appTheme ? appTheme.backgroundTypo : null,
                        bgColor : appTheme ? appTheme.drawerBg : null,
                    }}
                    iconProps={{
                        style : {color : appTheme ? appTheme.backgroundTypo : null}
                    }} 
                    subheaderMenuProps={{
                        [headerStrings.offsetHeight] : 78,
                    }}/>
                <MainStage appTheme={appTheme}>
                    <ThemeProvider theme={this.componentTheme}>
                        <Component classes={{
                            root : classes.componentRoot
                        }} {...otherProps}/>
                    </ThemeProvider>
                </MainStage>
            </div>
        )
    }
}
_Screen.propTypes = {
    containerProps : PropTypes.object,
}
const mapStateToProps = ({screenReducer, headerReducer}) => ({
    ...screenReducer, 
    drawer : headerReducer[headerStrings.drawer], 
    fullScreen : headerReducer[headerStrings.fullScreen],
})
export const Screen = connect(mapStateToProps)(withStyles(styles)(withTheme(_Screen)));
export {Screen as default};