export const insureAdminSiteStrings = {
    siteInfo : "siteInfo",
}
export const insureAdminConstants = {
    SET_SITE_INFO : "SET_SITE_INFO"
}
export const insureAdminSiteReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case insureAdminConstants.SET_SITE_INFO :
            return {...state, ...payload};
        default : return {...state}
    }
}
export * from './actions';
export * from './services';