import { post } from "./agroAdminUtil"
import { socketIO } from "../../../socket.io";

export const agroAdminUtilServices = {
    getUser : callback => {
        socketIO.emit("getUser");
        socketIO.on("getUser", ({getUser, result, message})=>{
            callback(getUser, result, message);
        })
    },
    login : (email, password, callback) => {
        socketIO.emit("login", {email, password});
        socketIO.on("login", ({login, result, message})=>{
            callback(login, result, message);
        });
        
        // post({email, password}, "app", "login", ({login, result, message})=>{
        //     callback(login, result, message);
        // })
    },
    signup : (data, callback) => {
        // post(data, "app", "signup", ({signup, result, message})=>{
        //     callback(signup, result, message);
        // })
        socketIO.emit("signup", data);
        socketIO.on("signup", ({signup, result, message})=>{
            callback(signup, result, message);
        });
    }
}