import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {Link} from 'react-router-dom';
import {withStyles} from '@material-ui/core/styles';
import { Subheader, Article } from '../../../includes';
import { insureUtilStrings } from '../../utils';
import { CardActions } from '@material-ui/core';
import { insureRouteNames } from '../../routeNames';
import { KnowledgeArea } from '../../Home/KnowledeArea';
import { insureServiceActions } from '../actions';
import { insureServiceStrings } from '../config';


const style = theme => ({
    root: {
    },
    knowledge : {
        marginTop : 100
    }
})
class _ServiceView extends Component {
    constructor(props) {
        super(props);
        
        this.serviceName = props.match.params.name;
        console.log(props);
    }
    componentDidMount() {
        const {
            dispatch, 
            [insureServiceStrings.services] : services,
        } = this.props;
        if(!services) insureServiceActions.getServices()(dispatch);
    }
    
    render() {
        const {
            classes,
            [insureUtilStrings.subheadImage] : subheadImage,
            [insureUtilStrings.backendBaseUrl] : baseUrl,
            [insureServiceStrings.services] : services
        } = this.props;
        let serviceItem = {};
        if(services){
            const {item} = services.getFirstObjectByPropValue("name", this.serviceName) || {};
            if(item) serviceItem = item;
        }
        return (
            <div className={classes.root}>
                <Subheader
                    title={serviceItem.header}
                    image_url={subheadImage}
                    />
                <Article 
                    {...serviceItem}
                    baseUrl={baseUrl}
                    footer={serviceItem.name === "cooperative" ?
                        ()=><CardActions style={{margin : 10}}>
                            <Link to={insureRouteNames.coopReg}>Register</Link>
                            <Link to={insureRouteNames.coopReg}>Subscribe</Link>
                            <Link to={insureRouteNames.coopVerify}>Verify</Link>
                        </CardActions> : null}
                    />
                <KnowledgeArea classes={{
                    root : classes.knowledge                    
                }}/>
            </div>
        );
    }
}
_ServiceView.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({insureUtilReducer, insureServiceReducer}) => ({
    [insureUtilStrings.subheadImage] : insureUtilReducer[insureUtilStrings.subheadImage],
    [insureUtilStrings.backendBaseUrl] : insureUtilReducer[insureUtilStrings.backendBaseUrl],
    [insureServiceStrings.services] : insureServiceReducer[insureServiceStrings.services],
})


export const ServiceView = connect(mapStateToProps)(withStyles(style)(_ServiceView));
export {ServiceView as default}