export const insureAdminNewsletterStrings = {
    subscribers : "insureAdminNewsletterSubscribers",
    newsletters : "insureAdminNewsletters",
}
export const insureAdminNewsletterConstants = {
    SET_INSURE_ADMIN_NEWSLETTER : "SET_INSURE_ADMIN_NEWSLETTER",
}
export const insureAdminNewsletterReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case insureAdminNewsletterConstants.SET_INSURE_ADMIN_NEWSLETTER : 
            return {...state, ...payload};
        default : return state;
    }
}
export * from './actions';
export * from './services';