import { stockServices } from "./services"
import { stockConstants, stockStrings } from "./config"
import { invProductServices } from "../INVProducts"

export const stockActions = {
    getStoreStock : (storeId, lastId, rows, callback)=>dispatch=>{
        stockServices.getStoreStock(storeId, lastId, rows, (done, result, message)=>{
            if(done) dispatch({
                type : stockConstants.SET_STOCK,
                payload : {
                    [stockStrings.storeStocks] : result,
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    setSelectedStore : store => dispatch => dispatch({
        type : stockConstants.SET_STOCK,
        payload : {
            [stockStrings.selectedStore] : store
        }
    }),
    setStockEditMode : mode => dispatch =>dispatch({
        type : stockConstants.SET_STOCK,
        payload : {
            [stockStrings.stockEditMode] : mode
        }
    }),
    getStocks : (lastId, rows, callback) => dispatch=>{
        stockServices.getStocks(lastId, rows, (done, result, message)=>{
            if(done) dispatch({
                type : stockConstants.SET_STOCK,
                payload : {
                    [stockStrings.stocks] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getItemFroms : callback => dispatch => {
        invProductServices.getItemForms((done, result, message)=>{
            if(done) dispatch({
                type : stockConstants.SET_STOCK,
                payload : {
                    [stockStrings.itemForms] : result,
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getItemPackaging : callback => dispatch => {
        invProductServices.getItemPackagings((done, result, message)=>{
            if(done) dispatch({
                type : stockConstants.SET_STOCK,
                payload : {
                    [stockStrings.itemPackaging] : result,
                }
            })
            if(callback) callback(done, result, message)
        })
    },  
    getItemPackages : callback => dispatch => {
        invProductServices.getItemPackages((done, result, message)=>{
            if(done) dispatch({
                type : stockConstants.SET_STOCK,
                payload : {
                    [stockStrings.itemPackages] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    setStockTransferEditMode : mode => dispatch => dispatch({
        type : stockConstants.SET_STOCK,
        payload : {
            [stockStrings.stockTransferEditMode] : mode
        }
    }),
    getAllTransfers : callback => dispatch=>{
        stockServices.getAllTransfers((done, result, message)=>{
            if(done) dispatch({
                type : stockConstants.SET_STOCK,
                payload : {
                    [stockStrings.stockTransfers] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getStores : callback => dispatch => {
        stockServices.getStores((done, result, message)=>{
            if(done) dispatch({
                type : stockConstants.SET_STOCK,
                payload : {
                    [stockStrings.stores] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    setStoreEditMode : mode => dispatch => dispatch({
        type : stockConstants.SET_STOCK,
        payload : {
            [stockStrings.storeEditMode] : mode
        }
    }),
    setStockCategoryComponent : component => dispatch=>dispatch({
        type : stockConstants.SET_STOCK,
        payload : {
            [stockStrings.stockCategoryComponent] : component
        }
    }),
    setStockCategoryEditMode : mode => dispatch=>dispatch({
        type : stockConstants.SET_STOCK,
        payload : {
            [stockStrings.stockCategoryEditMode] : mode
        }
    }),
    getStockCategories : callback=>dispatch=>{
        stockServices.getStockCategories((done, result, message)=>{
            if(done) dispatch({
                type : stockConstants.SET_STOCK,
                payload : {
                    [stockStrings.stockCategories] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    }
}