import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { insureServiceStrings } from '../config';
import { ServiceCard } from './ServiceCard';
import { Grid, Typography } from '@material-ui/core';
import { insureServiceActions } from '../actions';
import { insureUtilStrings, insureUtil } from '../../utils';
import { insureRouteNames } from '../../routeNames';


const style = theme => ({
    root: {
        // paddingBottom : 100
    },
    header : {
        width : "fit-content",
        color : insureUtil.getTheme().white,
        borderBottom : "solid 5px " + insureUtil.getTheme().primary,
        marginBottom : 50,
    },
    rootOverlay : {
        backgroundColor : "#ff572299",
    },
    gridContainer : {
        padding : 50,
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        [theme.breakpoints.up("md")] : {
            padding : "100px 100px",
        },
    },
    gridItem : {
        
    },
})
class _ServiceSummaryView extends Component {
    componentDidMount() {
        const {
            dispatch,
            [insureServiceStrings.services] : services,
        } = this.props;
        if(!services) insureServiceActions.getServices()(dispatch);
    }
    
    render() {
        const {
            classes, [insureServiceStrings.services] : serviceInfo,
            [insureUtilStrings.backendBaseUrl] : baseUrl,
            [insureUtilStrings.subheadImage] : subheadImage,
        } = this.props;
        return (
            <div className={classes.root} style={{
                background : "url('" +subheadImage+"') no-repeat center center /cover"
            }}>
               <div className={classes.rootOverlay}>
                    <div  className={classes.gridContainer}>
                    <Typography variant="h4" className={classes.header} paragraph>
                        Services
                    </Typography>
                        <Grid container spacing={4}>                        
                            {serviceInfo && serviceInfo.map(
                                (item, index)=><Grid 
                                    className={classes.gridItem} key={index} 
                                    item xs={12} sm={6} md={4} lg={4} xl={4}>
                                    <ServiceCard {...item} baseUrl={baseUrl} 
                                        toUrl={{pathname: insureRouteNames.serviceView_ + item.name}}/>
                                </Grid>)}
                        </Grid>
                    </div>
                </div>
            </div>
        );
    }
}


_ServiceSummaryView.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({insureServiceReducer, insureUtilReducer}) => ({
    [insureServiceStrings.services] : insureServiceReducer[insureServiceStrings.services],
    [insureUtilStrings.backendBaseUrl] : insureUtilReducer[insureUtilStrings.backendBaseUrl],
    [insureUtilStrings.subheadImage] : insureUtilReducer[insureUtilStrings.subheadImage],
})


export const ServiceSummaryView = connect(mapStateToProps)(withStyles(style)(_ServiceSummaryView));
export {ServiceSummaryView as default}