import { accountConstants, accountStrings } from "./config";
import { accountServices } from "./services";

export const accountActions = {
    getAccountExpenditures : (year, month, categoryId, callback)=>dispatch=>{
        accountServices.getAccountExpenditures(year, month, categoryId, (done, result, message)=>{
            if(done) dispatch({
                type : accountConstants.SET_ACCOUNT,
                payload: {
                    [accountStrings.accountExpenditures] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    setExpenditureEditMode : mode => dispatch=>dispatch({
        type : accountConstants.SET_ACCOUNT,
        payload : {
            [accountStrings.expendEditMode] : mode
        }
    }),
    setExpenditureTabValue: tabValue=>dispatch=>dispatch({
        type : accountConstants.SET_ACCOUNT,
        payload : {
            [accountStrings.expendTabValue] : tabValue
        }
    }),
    setExpenditureTabComponent : tabComponent=>dispatch=>dispatch({
        type : accountConstants.SET_ACCOUNT,
        payload : {
            [accountStrings.expendTabComponent] : tabComponent
        }
    }),
    getAccountExpenditureCategories : callback => dispatch => {
        accountServices.getAccountExpenditureCategories((done, result, message)=>{
            if(done)dispatch({
                type : accountConstants.SET_ACCOUNT,
                payload : {
                    [accountStrings.expendCategories] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getAccountIncomes : (year, month, categoryId, callback)=>dispatch=>{
        accountServices.getAccountIncomes(year, month, categoryId, (done, result, message)=>{
            if(done) dispatch({
                type : accountConstants.SET_ACCOUNT,
                payload: {
                    [accountStrings.accountIncomes] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    setIncomeEditMode : mode => dispatch=>dispatch({
        type : accountConstants.SET_ACCOUNT,
        payload : {
            [accountStrings.expendEditMode] : mode
        }
    }),
    setIncomeTabValue: tabValue=>dispatch=>dispatch({
        type : accountConstants.SET_ACCOUNT,
        payload : {
            [accountStrings.expendTabValue] : tabValue
        }
    }),
    setIncomeTabComponent : tabComponent=>dispatch=>dispatch({
        type : accountConstants.SET_ACCOUNT,
        payload : {
            [accountStrings.expendTabComponent] : tabComponent
        }
    }),
    getAccountIncomeCategories : callback => dispatch => {
        accountServices.getAccountIncomeCategories((done, result, message)=>{
            if(done)dispatch({
                type : accountConstants.SET_ACCOUNT,
                payload : {
                    [accountStrings.expendCategories] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getStudentFeeTx : (termId, callback) => dispatch=> {
        accountServices.getStudentFeeTx(termId, (done, result, message)=>{
            if(done) dispatch({
                type : accountConstants.SET_ACCOUNT,
                payload : {
                    [accountStrings.studentFeeList] : result
                }
            })
            if(callback) callback(done, result, message);
        });
    },
    setSelectedTerm : term => dispatch => dispatch({
        type : accountConstants.SET_ACCOUNT,
        payload : {
            [accountStrings.selectedTerm] : term
        }
    }),
    setSelectedSession : selectedSession => dispatch => dispatch({
        type : accountConstants.SET_ACCOUNT, 
        payload: {
            [accountStrings.selectedSession] : selectedSession
        }
    })
}