import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { MyTable } from "../../utils";
import { TableCell } from '@material-ui/core';
const style = theme => ({
    root: {
        
    },
    cell : {
        padding : 5,
        fontSize : 11,
    }
})
class _INVSupplierList extends Component {    
    cellMapFormat = ({row, cellMap}) => {
        const {classes} = this.props;
        switch(cellMap){
            
            default : return <TableCell className={classes.cell}>
                {row[cellMap]}
            </TableCell>
        }
    }
    render() {
        const {classes, suppliers} = this.props;
        return (
            <div className={classes.root}>
                <MyTable
                    header={["ID", "Name", "Address", "Email", "Phone Number"]}
                    dataMap={["_id", "name", "address", "email", "phone"]}
                    CellMap={this.cellMapFormat.bind(this)}
                    data={suppliers}
                    {...this.props.tableProps}
                />
            </div>
        );
    }
}
_INVSupplierList.propTypes = {
    classes : PropTypes.object.isRequired,
    suppliers : PropTypes.array,
    tableProps : PropTypes.shape(MyTable.propTypes),
};
export const INVSupplierList = withStyles(style)(_INVSupplierList);