import { hirSettingServices } from "./services"
import { errorNotice, successNotice } from "../../../utils"
import { hirSettingConstants, hirSettingStrings } from "./config";

export const hirSettingActions = {
    editSettingValue : (settingId, valueName, value, callback) => dispatch => {
        hirSettingServices.editSettingValue({settingId, valueName, value}, (done, result, message)=>{
            if(done){
                successNotice(message, dispatch);
                hirSettingActions.payload({
                    [hirSettingStrings.settings] : result
                })(dispatch)
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    deleteSettingValue : (settingId, valueName, callback) => dispatch => {
        hirSettingServices.deleteSettingValue(settingId, valueName, (done, result, message)=>{
            if(done){
                successNotice(message, dispatch);
                hirSettingActions.payload({
                    [hirSettingStrings.settings] : result
                })(dispatch)
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    addSettingValue : (data, callback) => dispatch => {
        hirSettingServices.addSettingValue(data, (done, result, message)=>{
            if(done){
                successNotice(message, dispatch);
                hirSettingActions.payload({
                    [hirSettingStrings.settings] : result
                })(dispatch)
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getSettings : callback => dispatch => {
        hirSettingServices.getSettings((done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            else {
                hirSettingActions.payload({
                    [hirSettingStrings.settings] : result
                })(dispatch);
            }
            if(callback)callback(done, result, message);
        })
    },
    getSettingValue(settings, name, subname){        
        let iValue = null;
        if(settings){
            const revenue = settings.find(item=>item.name === name);
            if(revenue && revenue.values){
                const rOptions = revenue.values.find(item=>item.name === subname);
                if(rOptions) iValue = rOptions.value;
            }
        }
        return iValue;
    },
    payload : payload => dispatch => dispatch({
        type : hirSettingConstants.SET_SETTING , 
        payload 
    })
}