import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { Typography, Grid, Hidden, withWidth } from '@material-ui/core';
import { BoxDivider } from './BoxDivider';
import { ItemContainer } from './ItemContainer';
const style = theme => ({
    root: {
        display : "flex",
    },
    gridContainer: {
        justifyContent : "center",
        paddingBottom : 20,
    },
})
class _ServiceBox extends Component {
    componentDidMount() {
        const {setHeight} = this.props;
        if(setHeight) setHeight();
    }    
    render() {
        const {classes, width, left} = this.props;
        return (
            <div className={classes.root}>
                <Grid className={classes.gridContainer} container spacing={2}>
                    {width === "xs" && !left ? null : 
                    <Grid item xs={12} sm={5} md={5} lg={5} xl={5}>
                        {left && <ItemContainer {...this.props.itemProps}/>}
                    </Grid>}
                    <Hidden xsDown>
                        <Grid style={{
                            padding : 0
                        }} item xs={2} sm={2} md={2} lg={2} xl={2}>
                            <BoxDivider left={left}/>
                        </Grid>
                    </Hidden>
                    {width === "xs" && left ? null : 
                    <Grid item xs={12} sm={5} md={5} lg={5} xl={5}>
                        {!left && <ItemContainer {...this.props.itemProps}/>}
                    </Grid>}
                </Grid>
            </div>
        );
    }
}
_ServiceBox.propTypes = {
    classes : PropTypes.object.isRequired,
    itemProps : PropTypes.shape(ItemContainer.propTypes),
    left : PropTypes.bool,
    setHeight : PropTypes.func,
};
export const ServiceBox = withStyles(style)(withWidth()(_ServiceBox));