import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { TextField, FormGroup, FormControl, FormLabel, Typography, Button } from '@material-ui/core';
import { appActions, alertAction } from '../../../actions';
import { inventoryUtil, inventoryActions, inventoryUtilStrings } from '../utils';
import { routeNamesInventory } from '../routeNames';
import { onEnterPress } from '../../../utils';
import { Carousel } from '../../includes';


const style = theme => ({
    root: {
        background : inventoryUtil.getTheme().primary,
        backgroundSize : "cover",
        height : "100vh",
        width : "100vw",
        position : "relative"
    },
    overLay : {
        position : "absolute",
        height : "100%",
        width : "100%",
        backgroundColor : inventoryUtil.getTheme().primaryTrans,
        display : "flex",
        flexDirection : "column",
        alignItems : "center",
        justifyContent : "center",
        top : 0,
        zIndex : 100,
    },
    pageTitle : {
        fontWeight : 800,
        color : inventoryUtil.getTheme().white,
        fontFamily : "fantasy",
        marginBottom : 50,
    },
    formContainer : {
        backgroundColor : inventoryUtil.getTheme().secodary, 
        padding : 20,
        borderRadius : 10,
        width : "50%",
        [theme.breakpoints.down("xs")] : {
            width : "80%"
        },
        [theme.breakpoints.up("md")] : {
            width : "30%",
        }
    },
    textField : {
        background : inventoryUtil.getTheme().white,
        borderRadius : 5,
        border : "none"
    },
    noBorder : {
        border : "none"
    },
    headerContainer : {
        marginBottom : 50,
        display : "flex",
        justifyContent :"center",
    },
    header : {
        color : inventoryUtil.getTheme().white,
        fontWeight : "bold",
        textAlign : "center"
    },
    loginButton : {
        marginTop : 20,
        backgroundColor : inventoryUtil.getTheme().secondary,
        color : inventoryUtil.getTheme().white
    },
    carousel: {
        height : "100vh"
    }
})
class _INVLogin extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data  : {
                email : "",
                password : "",
                loading : false
            },
            loading : false
        }
    }
    componentWillMount(){
        if(inventoryUtil.isLogedIn())
            this.props.history.replace(routeNamesInventory.dashboard);
    }
    handleChange=name=>event=>{
        let value = event.target.value;
        let data = {...this.state.data};
        data[name] = value;
        this.setState({data});
    }
    login(){
        // this.setState({loading : true});
        const {email, password} = this.state.data;
        const {dispatch} = this.props;
        if(email.trim() === "" && password.trim() === ""){
            appActions.showSnackbar(
                alertAction.error("Empty field error!")
            )(this.props.dispatch);
            this.setState({loading : false});
            return;
        }
        inventoryActions.loging(email, password, done => {
            if(done)
                this.props.history.replace(routeNamesInventory.dashboard);
            else this.setState({loading : false});
        })(dispatch);
    }
    render() {
        const {classes,
            [inventoryUtilStrings.backendBaseUrl] : baseUrl} = this.props;
        const {
            username, password, loading,
        } = this.state;
        return (
            <div id="home" className={classes.root}>
                <Carousel
                    interval={5000}
                    hideOverlay
                    classes={{
                        root : classes.carousel
                    }}
                    items={[
                        {name : 1, src : "/loginImages/1.jpg"},
                        {name : 1, src : "/loginImages/2.jpg"},
                        {name : 1, src : "/loginImages/3.jpg"},
                        {name : 1, src : "/loginImages/4.jpg"},
                        {name : 1, src : "/loginImages/5.jpg"},
                        {name : 1, src : "/loginImages/6.jpg"},
                        {name : 1, src : "/loginImages/7.jpg"},
                        {name : 1, src : "/loginImages/9.jpg"},
                        {name : 1, src : "/loginImages/10.jpg"},
                        {name : 1, src : "/loginImages/11.jpg"},
                        {name : 1, src : "/loginImages/12.jpg"},
                        {name : 1, src : "/loginImages/13.jpg"},
                        {name : 1, src : "/loginImages/14.jpg"},
                        {name : 1, src : "/loginImages/15.jpg"},
                    ]}
                    baseUrl={baseUrl}
                    />
                <div className={classes.overLay}>
                    <Typography className={classes.pageTitle} component="center" variant="h4">HEALTH RECORDS</Typography>
                    <div className={classes.formContainer}>
                        <FormGroup>
                            <FormLabel className={classes.headerContainer}>
                                <Typography className={classes.header} component="h4" variant="h4">Login</Typography>
                            </FormLabel>
                            <FormControl>
                                <TextField
                                    label="Email"
                                    placeholder="email"
                                    margin="normal"
                                    onChange={this.handleChange("email")}
                                    value={username}
                                    className={classes.textField}
                                    variant="outlined"
                                    onKeyDown={onEnterPress(this.login.bind(this))}/>
                            </FormControl>
                            <FormControl>
                                <TextField
                                    label="Password"
                                    placeholder="password"
                                    margin="normal"
                                    onChange={this.handleChange("password")}
                                    value={password}
                                    type="password"
                                    className={classes.textField}
                                    variant="outlined"
                                    onKeyDown={onEnterPress(this.login.bind(this))}/>
                            </FormControl>
                            <FormControl>
                                <Button
                                    disabled={loading}
                                    className={classes.loginButton}
                                    onClick={()=>this.login()}>
                                        Login
                                    </Button>
                            </FormControl>
                        </FormGroup>
                    </div>
                </div>
            
            </div>
        );
    }
}


_INVLogin.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({inventoryUtilReducer}) => ({
    [inventoryUtilStrings.backendBaseUrl] : inventoryUtilReducer[inventoryUtilStrings.backendBaseUrl]
})


export const INVLogin = connect(mapStateToProps)(withStyles(style)(_INVLogin));
export {INVLogin as default};