import { post, fetchGet } from "../utils"
const owner = "admin";
export const insureAdminMessageServices = {
    sendEmail : (emailData, callback) => {
        post(emailData, owner, "sendEmail", ({sendEmail, result, message})=>{
            callback(sendEmail, result, message);
        })
    },
    deleteMessages : (messageIds, callback) => {
        post(messageIds, owner, "deleteMessages", ({deleteMessages, result, message})=>{
            callback(deleteMessages, result, message);
        })
    },
    getMessages : (lastId, rows, callback)=>{
        fetchGet(owner, "getMessages", {lastId, rows}, ({getMessages, result, message})=>{
            callback(getMessages, result, message);
        })
    }
}