import React, { PureComponent } from 'react'
import {Link} from 'react-router-dom';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import { withStyles, Typography } from '@material-ui/core';
import { colors } from '../../../utils';
const styles = theme => ({
    root : {
        padding : 10, 
        display : "flex",
    },
    crumb : {
        color : colors.primary,
        textDecoration : "none"
    }
})
class _BreadCrumb extends PureComponent {
    render() {
        const {classes, breadCrumb, visible} = this.props;
        if(!visible) return null
        return (
            <div className={classes.root} {...this.props.rootProps}>
                {breadCrumb && breadCrumb.map(
                    (p, i) => 
                    i === breadCrumb.length - 1 ?
                    <Typography key={i} style={{color : colors.gray, fontWeight : 'bold'}}>{p.name}</Typography>:
                    <Link className={classes.crumb} key={i} to={{pathname : p.path, state : {from : p.from}}}>
                        <Typography style={{color : colors.primary, fontWeight : 'bold'}}>{p.name + " /"}</Typography>
                    </Link>
                )}
            </div>
        )
    }
}
_BreadCrumb.propTypes = {
    breadCrumb : PropTypes.arrayOf(PropTypes.shape({
        path : PropTypes.string,
        from : PropTypes.string,
        name : PropTypes.string,
    })),
    rootProps : PropTypes.object,
}
const mapStateToProps = ({breadCrumbReducer}) => ({
    breadCrumb : breadCrumbReducer.breadCrumb,
    visible : breadCrumbReducer.visible,
    rootProps : breadCrumbReducer.rootProps
})
export default connect(mapStateToProps)(withStyles(styles)(_BreadCrumb));