import React from 'react';
import { insureAdminRouteNames } from "./routeNames";
import { Messages } from './Messages';
import { InsureAdminNewsletter } from './Newsletter';

const Site = React.lazy(()=>import("./Site/Site"));
const Cooperative = React.lazy(()=>import("./Cooperative/Cooperative"));

export const insureAdminRoutes = [
    {path : insureAdminRouteNames.home, exact : true, component : Site},
    {path : insureAdminRouteNames.cooperative, exact : true, component : Cooperative},
    {path : insureAdminRouteNames.messages, exact : true, component : Messages},
    {path : insureAdminRouteNames.newsletter, exact : true, component : InsureAdminNewsletter},
]