import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, mainStageHeaderAction, mainStageHeaderStrings, MyTable, EditableCellMapFormat, MyListCard, MyListCardMenuPopup } from '../../includes';
import { routeName } from '../../../utils';
import BenefitHeaderComponent from './BenefitHeaderComponent';
import { payrollActions } from '../actions';
import { payrollStrings } from '../config';
import { TextField, Switch, FormControlLabel, Checkbox, ListItem } from '@material-ui/core';


const style = theme => ({
    root: {
        marginTop : 20,
    }
})
class _Benefits extends Component {
    constructor(props) {
        super(props);
        const {dispatch} = props;
        this.state = {
            selections : null
        }
        headerActions({
            [headerStrings.headerTitle] : "PAYROLL - BENEFITS"
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeName.dashboard},
            {name : "Payroll (Benefits)", path : routeName.payrollBenefits},
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                BenefitHeaderComponent
            ]
        })(dispatch);
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {
            dispatch
        } = this.props;
        payrollActions.getPayrollBenefits()(dispatch);
    }
    handleListCompCheckbox = (row, value) => e => {
        console.log(e.target.checked);
        // const checked = e.target.checked;
        // let selections; 
        // if(this.state.selections)
        //     selections = [...this.state.selections];  
        // else selections = [];      
        // if(checked)
        //     selections.push(value);
        // else 
        //     selections.splice(
        //         selections.indexOf(value), 
        //         1
        //     );
        // this.setState({selections});
    }
    employeeListComponent = row => selections => props => {
        return <ListItem key={props.index}>
            <FormControlLabel
                control={
                    <Checkbox
                        checked={selections && selections.indexOf(props._id) !== -1}
                        onChange={this.handleListCompCheckbox(row, props._id)}
                        />
                }
                label={props.fullName}/>
        </ListItem>
    }
    employeeListSearchOnChange = keyword => {
        console.log("keyword", keyword);
    }
    cellMapFormat=superProps=>props=><EditableCellMapFormat {...props} {...superProps}/>
    tableCellContentView = (editing, {row, cellMap})=>{
        if(editing){
            switch(cellMap){
                case "action" : return null;
                case "percent" : return <TextField type="number"/>;
                case "amount" : return <TextField type="number"/>;
                case "general" : 
                case "usePercentage" : 
                    return <Switch size="small"/>
                case "employeeIds" : 
                    return <MyListCardMenuPopup
                                myListCardProps={{
                                    elevation:0,
                                    list:[
                                        {_id: 1, fullName : "Agu Chijioke C"},
                                        {_id: 1, fullName : "John Onyinye C"},
                                    ],
                                    itemNameProp:"fullName",
                                    searchInputProps:{
                                        style : {width : "100%"},
                                        placeholder : "Search subjects"
                                    },
                                    finishBtnName:"Finish",
                                    searchOnChange:word=>console.log("search ", word),
                                    finishBtnAction:()=>{},
                                    listItemComponent:this.employeeListComponent(row)
                                }}
                                />
                default : return <TextField/>
            }
        }else{
            switch(cellMap){
                case "action" : return null;
                case "general" : 
                case "usePercentage" : 
                    return <Switch size="small" disabled/>
                case "amount" : return row[cellMap] && Number(row[cellMap]).toLocaleString();
                case "employeeIds" : 
                    return row[cellMap] && row[cellMap].length;
                default : return row[cellMap];
            } 
        }
    }
    render() {
        let tableHeader = ["ID", "Name", "Description", "%", "Percent", "Amount", "General", "Employees","Activation"];
        let dataMap = ["_id", "name", "description", "usePercentage", "percent", "amount", "general", "employeeIds", "activation"];
        let {
            classes,
            [payrollStrings.payrollBenefits] : payrollBenefits,
            [payrollStrings.benefitEditMode] : benefitEditMode,
            
        } = this.props;
        if(true){ //benefitEditMode){
            tableHeader = [...tableHeader, "Actions"];
            dataMap = [...dataMap, "action"];
            payrollBenefits = payrollBenefits ?
                [...payrollBenefits.map(
                    roll=>({...roll, delible: true, editable : true})
                ), {new: true}] :
                [{new : true}];
        }
        return (
            <div className={classes.root}>
                <MyTable
                    header={tableHeader}
                    dataMap={dataMap}
                    data={payrollBenefits}
                    CellMap={this.cellMapFormat({
                        skipEdit : ["_id"],
                        tableCellContentView : this.tableCellContentView.bind(this),
                    })}
                    />
            </div>
        );
    }
}


_Benefits.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({payrollReducer}) => ({
    [payrollStrings.payrollBenefits] : payrollReducer[payrollStrings.payrollBenefits],
    [payrollStrings.benefitEditMode] : payrollReducer[payrollStrings.benefitEditMode],
})


export const Benefits = connect(mapStateToProps)(withStyles(style)(_Benefits));
export {Benefits as default}