import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Typography, IconButton, ListItem, ListItemText, List, Popper, ListItemIcon, Badge } from '@material-ui/core';
import { Settings } from '@material-ui/icons';
import classNames from 'classnames';
import ChatFooter from '../../ChatFooter';
import { chatFooterStrings } from '../../config';


const style = theme => ({
    root : {
        position : "fixed",
        bottom : 0,
        right : 1,
        width : ChatFooter.width,
        display : "flex",
        flexDirection : "column",
        transition : "height 2s",
        zIndex : 1000
    },
    nestedRoot : {
        width : ChatFooter.width,
        display : "flex",
        flexDirection : "column",
        transition : "height 2s",
    },
    container : {
        display : "flex",
        color : "white",
        padding : 10,
        borderRadius : "10px 10px 0 0",
        backgroundColor : "#515169",
    },
    nestedContainer : {
        display : "flex",
        color : "white",
        padding : 10,
        borderRadius : "10px 10px 0 0",
        backgroundColor : "#515169",
    },
    grow : {
        display : "flex",
        flexGrow : 1,
    },
    chatContent : {
        maxHeight: "5cm",
        minHeight : "10cm",
        overflow: "scroll",
        border: "solid .1px",
    }
})
class _AllChats extends Component {
    constructor(props) {
        super(props);
        this.state = {
            expanded : false,
            anchorEl : null,
        }
        this.closePopper = this.closePopper.bind(this);
    }    
    expand(){
        this.setState(({expanded})=>({expanded : !expanded}));
        this.closePopper();
    }
    settingPopup(e){
        e.stopPropagation();
        const target = e.currentTarget;
        this.setState(({anchorEl})=>({anchorEl : anchorEl ? null : target}));
    }
    closePopper = ()=>this.setState({anchorEl : null});
    render() {
        let {
            classes, 
            contentContainerStyler,
            [chatFooterStrings.allChatContainerProps] : containerProps,
            [chatFooterStrings.allChatListData] : list,
            [chatFooterStrings.allChatListItemOnClickHandler] : listItemOnClick,
            [chatFooterStrings.allChatListItemValueProp] : itemValueProp,
            [chatFooterStrings.allChatListItemComponent] : ListItemComponent,
            [chatFooterStrings.allChatSettingPopupContent] : SettingPopupContent,
        } = this.props;
        const {style : containerStyle, ...otherContainerProps} = containerProps || {};
        containerProps = otherContainerProps;
        const { expanded, anchorEl } = this.state;
        let style;
        if(expanded) style = {
            height : "auto",
        }; else style = {
            height : 0,
            minHeight : 0
        }
        if(containerStyle) style = {...style, ...containerStyle};

        if(contentContainerStyler) 
            style = {...style, ...contentContainerStyler};
        
        return (
            <div className={classes.root}>
                <div className={classes.container} onClick={()=>this.expand()}>
                    <Typography style={{fontWeight : "bold"}} component="strong">CHAT</Typography>
                    <div className={classes.grow}/>
                    {!expanded && <IconButton style={{padding : 0}} onClick={e=>this.settingPopup(e)}>
                        <Settings style={{color: "white"}} fontSize="small"/>
                    </IconButton>}
                    {SettingPopupContent && <Popper 
                        style={{backgroundColor : "white", borderRadius : 5}}
                        open={Boolean(anchorEl)}
                        anchorEl={anchorEl}
                        onClose={this.closePopper}
                        >
                        <SettingPopupContent close={this.closePopper} context={this}/>
                    </Popper>}
                </div>
                <div className={classNames(classes.chatContent)} {...containerProps} style={style}>
                    <List>
                        {list && list.map((item, index)=>{                        
                            return ListItemComponent ? 
                                <ListItemComponent {...item} key={index}/> :
                                <ListItem key={index}>
                                    <ListItemText onClick={listItemOnClick}>{itemValueProp ? item[itemValueProp] : item.name}</ListItemText>
                                </ListItem>
                        })}
                    </List>
                </div>
            </div>
        );
    }
}


_AllChats.propTypes = {
    classes : PropTypes.object.isRequired,
    contentContainerStyler : PropTypes.object,
};

const mapStateToProps = ({chatFooterReducer}) => ({
    ...chatFooterReducer
})


export const AllChats = connect(mapStateToProps)(withStyles(style)(_AllChats));
export {AllChats as default}