import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import classNames from 'classnames';
import { connect } from "react-redux";
import {Link} from 'react-router-dom';
import { Subheader } from '../../../../../includes';
import { ServiceItemBox } from './ServiceItemBox';
import { inovateOSPageStrings, inovateOSPageActions } from '../../config';
import { inovateOSUtil, inovateOSUtilStrings} from '../../../utils';
import { inovateOSRouteNames } from '../../../routeNames';

const style = theme => ({
    root: {
        // padding : 10
    },
    subheader : {},
    subContainer : {},
    serviceItemsContainer : {
        paddingBottom : 100,
    },
    itemBox : {
        margin : "150px 5px"
    },
    primaryBtn : {
        backgroundColor : inovateOSUtil.getTheme().secondary,
        borderRadius : 8,
        padding : 10,
        color : inovateOSUtil.getTheme().white,
        marginLeft : 20,
        textDecoration : "none",
    }
})

class _InovateOSServices extends Component {
    componentDidMount() {
        const {
            dispatch,
            [inovateOSPageStrings.services] : services,
        } = this.props;
        if(!services)
            inovateOSPageActions.getServices()(dispatch);
    }
    
    render() {
        const {
            classes, userAlt, 
            [inovateOSPageStrings.services] : services,
            [inovateOSUtilStrings.backendBaseUrl] : baseUrl,
            [inovateOSUtilStrings.subheadImage] : subheadImage,
        } = this.props;
        return (
            <div className={classes.root}>
                <Subheader
                    classes={{
                        root : classes.subheader,
                        overlay : classes.subContainer,
                    }}
                    title="Services"
                    image_url={subheadImage}/>
                <div className={classNames(classes.serviceItemsContainer, classes.subContainer)}>
                    {services && services.map((item, index)=>{
                        item.paperProps = {style: {background : "transparent"}};
                        item.baseUrl=baseUrl;
                        item.headerLink = {
                            pathname : inovateOSRouteNames.serviceItem_+item.name,
                            state : {name : item.name, body : item.body, header : item.header, src : item.src}
                        };
                        return userAlt ? <ServiceItemBox 
                            classes={{root : classes.itemBox}}  
                            alt={index % 2 === 0} 
                            {...item} 
                            key={index}/>: 
                        <ServiceItemBox 
                            classes={{root : classes.itemBox}} 
                            {...item} 
                            key={index}/>
                    })}
                </div>
            </div>
        );
    }
}
_InovateOSServices.propTypes = {
    classes : PropTypes.object.isRequired,
    userAlt : PropTypes.bool,
};
const mapStateToProps = ({inovateOSPageReducer, inovateOSUtilReducer}) => ({
    [inovateOSPageStrings.services] : inovateOSPageReducer[inovateOSPageStrings.services],
    [inovateOSUtilStrings.backendBaseUrl] : inovateOSUtilReducer[inovateOSUtilStrings.backendBaseUrl],
    [inovateOSUtilStrings.subheadImage] : inovateOSUtilReducer[inovateOSUtilStrings.subheadImage],
})
export const InovateOSServices = connect(mapStateToProps)(withStyles(style)(_InovateOSServices));
export {InovateOSServices as default};