export const inovateOSAdminNewsletterStrings = {
    subscribers : "inovateOSAdminNewsletterSubscribers",
    newsletters : "inovateOSAdminNewsletters",
}
export const inovateOSAdminNewsletterConstants = {
    SET_INSURE_ADMIN_NEWSLETTER : "SET_INSURE_ADMIN_NEWSLETTER",
}
export const inovateOSAdminNewsletterReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case inovateOSAdminNewsletterConstants.SET_INSURE_ADMIN_NEWSLETTER : 
            return {...state, ...payload};
        default : return state;
    }
}
export * from './actions';
export * from './services';