export const inovateOSAdminSiteStrings = {
    siteInfo : "siteInfo",
}
export const inovateOSAdminConstants = {
    SET_SITE_INFO : "SET_SITE_INFO"
}
export const inovateOSAdminSiteReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case inovateOSAdminConstants.SET_SITE_INFO :
            return {...state, ...payload};
        default : return {...state}
    }
}
export * from './actions';
export * from './services';