import React, {Fragment} from 'react';
import { Screen, Header } from '../includes';
import {Redirect, Route} from 'react-router-dom';
import {insureAdminUtil, insureAdminActions} from  './utils';
import { insureAdminRouteNames } from './routeNames';


export const PrivateRoutePlane = ({component : Component, ...props}) => (
    <Route {...props} render={props => { 
        return (
            insureAdminUtil.isLogedIn()
            ? <Fragment>
                <Screen {...props} component={Component}/>
            </Fragment>
            : (props.match.path === insureAdminRouteNames.login ||
                props.match.path === insureAdminRouteNames.signup ?
                <Component {...props}/> : 
            <Redirect to={{ pathname: insureAdminRouteNames.login, state: { from: props.location } }} />)
        )}
    } />
);
export const LogoutRoute = rest =>(
    <Route {...rest} render={props=>{
        insureAdminActions.logout();
        return <Redirect to={{ pathname: insureAdminRouteNames.login, state: { from: props.location } }}/> 
    }}/>
)