import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import classNames from 'classnames';
import {IconButton, Snackbar} from '@material-ui/core';
import SnackbarContent from '@material-ui/core/SnackbarContent';
import CheckCircleIcon from '@material-ui/icons/CheckCircle';
import ErrorIcon from '@material-ui/icons/Error';
import InfoIcon from '@material-ui/icons/Info';
import CloseIcon from '@material-ui/icons/Close';
import WarningIcon from '@material-ui/icons/Warning';
import green from '@material-ui/core/colors/green';
import amber from '@material-ui/core/colors/amber';
import {withStyles} from '@material-ui/core/styles';
import { appActions } from '../../../actions';


const variantIcon = {
    success : CheckCircleIcon,
    warning : WarningIcon,
    error: ErrorIcon,
    info : InfoIcon
};

const styles1 = theme => ({
    success: {
        backgroundColor: green[600],
    },
    error: {
        backgroundColor: theme.palette.error.dark
    },
    info : {
        backgroundColor: theme.palette.primary.dark
    },
    warning : {
        backgroundColor : amber[700]
    },
    icon : {
        fontSize: 20
    },
    iconVariant : {
        opacity: 0.9,
        marginRight: theme.spacing.unit
    }, 
    message : {
        display: 'flex',
        alignItems : 'center'
    }
});

function MySnackbarContent(props){
    const {classes, className, message, onClose, variant, ...other} = props;
    const Icon = variantIcon[variant];

    return(
        <SnackbarContent
            className={classNames(classes[variant], className)}
            aria-describedby="client-snackbar"
            message={
                <span id="client-snackbar" className={classes.message}>
                    <Icon className={classNames(classes.icon, classes.iconVariant)}/>
                    {message}
                </span>
            }
            action={[
                <IconButton
                    key="close"
                    aria-label="Close"
                    color="inherit"
                    className={classes.close}
                    onClick={onClose}>
                    <CloseIcon className={classes.icon}/>    
                </IconButton>,
            ]}
            {...other}
        />
    );
}
MySnackbarContent.propTypes = {
    classes : PropTypes.object.isRequired,
    className: PropTypes.string,
    message : PropTypes.node,
    onClose : PropTypes.func,
    variant : PropTypes.oneOf(['success', 'warning', 'error', 'info']).isRequired
}
const MySnackbarContentWrapper = withStyles(styles1)(MySnackbarContent);

const styles2 = theme => ({
    margin: {
        margin : theme.spacing.unit
    }
})
class MySnackbarComponent extends Component {
    //not using this again
    state = {
        open: false
    }
    handleClick= ()=>{
        appActions.showSnackbar({
            variant : 'success',
            message : 'this is me'
        })(this.props.dispatch);
    };
    handleClose = (event, reason) => {
        if(reason === 'clickaway'){
            return;
        }
        appActions.closeSnackbar()(this.props.dispatch);
        // this.props.closeSnackbar();
    };
    render() { 
        return (
            <div>
                <Snackbar
                    anchorOrigin={{
                        vertical: 'bottom',
                        horizontal: 'right'
                    }}
                    open={this.props.snackbar.open}
                    autoHideDuration={6000}
                    onClose={this.handleClose}
                >
                    <MySnackbarContentWrapper
                        onClose={this.handleClose}
                        variant={this.props.snackbar.variant}
                        message={this.props.snackbar.message}
                    />
                </Snackbar>
            </div>
        );
    }
}
MySnackbarComponent.propTypes = {
    classes : PropTypes.object.isRequired
}
const mapStateToProps = ({appReducer}) => ({
    snackbar : appReducer.snackbar,
})
export const MySnackbar = connect(mapStateToProps)(withStyles(styles2)(MySnackbarComponent));
export {MySnackbar as default};

