import React, {Fragment} from 'react';
import { Screen } from '../../includes';
import {Redirect, Route} from 'react-router-dom';
import {inovateOSAdminUtil, inovateOSAdminActions} from  './utils';
import { inovateOSAdminRouteNames } from './routeNames';


export const PrivateRoutePlane = ({component : Component, ...props}) => (
    <Route {...props} render={props => { 
        return (
            inovateOSAdminUtil.isLogedIn()
            ? <Fragment>
                <Screen {...props} component={Component}/>
            </Fragment>
            : (props.match.path === inovateOSAdminRouteNames.login ||
                props.match.path === inovateOSAdminRouteNames.signup ?
                <Component {...props}/> : 
            <Redirect to={{ pathname: inovateOSAdminRouteNames.login, state: { from: props.location } }} />)
        )}
    } />
);
export const LogoutRoute = rest =>(
    <Route {...rest} render={props=>{
        inovateOSAdminActions.logout();
        return <Redirect to={{ pathname: inovateOSAdminRouteNames.login, state: { from: props.location } }}/> 
    }}/>
)