import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { TextField, Button, CircularProgress, FormLabel } from '@material-ui/core';
import { Send } from '@material-ui/icons';
const style = theme => ({
    root: {
        display : "flex",
        flexDirection : "column",
    }
})
class _MessageBox extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data : {
                subject : "",
                message : ""
            }, 
            laoding : false
        }
    }
    onClick(){
        const {onSendClick, notify} = this.props;
        const {data} = this.state;
        const {message, subject} = data;
        this.setState({loading : true})
        if(!String(message).trim() || !String(subject).trim()){
            if(notify) notify("Empty field!", "error");
            this.setState({loading : false})
            return;
        }
        if(onSendClick) onSendClick(data, this);
    }
    onChange = name => e => {
        const value = e.target.value;
        const data = {...this.state.data};
        data[name] = value;
        this.setState({data});
    }
    render() {
        const {classes} = this.props;
        const {loading} = this.state;
        const {message, subject} = this.state.data;
        return (
            <div className={classes.root}>
                <FormLabel>New Message</FormLabel>
                <TextField
                    variant="outlined"
                    label="Subject"
                    placeholder="Subject"
                    margin="normal"
                    value={subject}
                    onChange={this.onChange("subject")}/>
                <TextField
                    variant="outlined"
                    label="Message"
                    placeholder="Message"
                    multiline
                    rows={10}
                    rowsMax={10}
                    margin="normal"
                    value={message}
                    onChange={this.onChange("message")}
                    />
                <div>
                    <Button
                        variant="contained"
                        color="primary"
                        disabled={loading}
                        onClick={this.onClick.bind(this)}>
                            {loading ? <CircularProgress size={18}/> : <Send/>} Send
                        </Button>
                </div>
            </div>
        );
    }
}
_MessageBox.propTypes = {
    classes : PropTypes.object.isRequired, 
    onSendClick : PropTypes.func,
    notify : PropTypes.func,
};
export const MessageBox = withStyles(style)(_MessageBox);