export const subjectStrings = {
    subjectFilter : "subjectFilter",
    selectedLevel : "selectedLevel",
    selectedTerm : "selectedTerm",
    usePreviousSubjects : "usePreviousSubjects",
    subjectCount : "subjectCount",
    viewUseClassFlter : "viewUseClassFlter",
    selectedLevelClasses : "selectedLevelClasses",
    subjectStudents : "subjectStudents",
    subjectAssessments : "subjectAssessments",
    subjedTeacherEditMode : "subjedTeacherEditMode",
    subjects : "subjects",
    timeTableEditMode : "timeTableEditMode",
    timeTableDurationFormat : "timeTableDurationFormat",
}
export const subjectConstants = {
    SET_SUBJECT : "SET_SUBJECT",
    CLEAN_UP_SUBJECT : "CLEAN_UP_SUBJECT",
}
export const subjectReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case subjectConstants.SET_SUBJECT :
            return {...state, ...payload};
        case subjectConstants.CLEAN_UP_SUBJECT :
            return {};
        default : return {...state};
    }
}
export * from './actions';
export * from './services';
