import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { Inventory_App } from './Inventory';
import { HIRApp } from './HealthRecord';
import { history } from '../../helpers';
const style = theme => ({
    root: {
        
    }
})
class _hmsApp extends Component {
    render() {
        const {pathname} = history.location;
        if(String(pathname).startsWith("/inv")){
            return <Inventory_App/>
        }else if(String(pathname).startsWith('/hir')){
            return <HIRApp/>
        }else{
            return <div>This is the welcome page</div>
        }
    }
}
_hmsApp.propTypes = {
    classes : PropTypes.object.isRequired
};
export const hmsApp = withStyles(style)(_hmsApp);