export const formStrings = {
    forms : "forms",
}
export const formConstants = {
    SET_FORM : "SET_FORM",
}
export const formReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case formConstants.SET_FORM : 
            return {...state, ...payload};
        default : return {...state, ...payload};
    }
}
export * from './actions';