import {fetchGet, post} from '../utils';
const owner = "user";
export const insureUserAccountServices = {
    createNextOfKin : (data, callback) => {
        post(data, owner, "createNextOfKin", ({createNextOfKin, result, message})=>{
            callback(createNextOfKin, result, message);
        })
    },
    getCooperativeInfo : callback => {
        fetchGet(owner, "getCooperativeInfo", {}, ({getCooperativeInfo, result, message})=>{
            callback(getCooperativeInfo, result, message);
        })
    },
    getMyPayments : (lastId, rows, callback) => {
        fetchGet(owner, "getMyPayments", {lastId, rows}, ({getMyPayments, result, message})=>{
            callback(getMyPayments, result, message);
        })
    }
}