import { productServices } from "./services"
import { productConstants, productStrings } from "./config"
import { stockServices } from "../Stocks"

export const productActions = {
    getProductDescriptions : callback => dispatch => {
        productServices.getProductDescriptions((done, result, message)=>{
            if(done) productActions.setProductDescriptions(result)(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    setProductDescriptions : descriptions => dispatch => dispatch({
        type : productConstants.SET_PRODUCT, 
        payload : {
            [productStrings.productDescriptions] : descriptions
        }
    }),
    getStockCategoryItems : (stockCategoryId, callback) => dispatch => {
        productServices.getStockCategoryItems(stockCategoryId, (done, result, message)=>{
            if(done) dispatch({
                type : productConstants.SET_PRODUCT,
                payload : {
                    [productStrings.stockCategoryItems] : result
                }
            });
            if(callback) callback(done, result, message);
        });
    },
    getStockCategories : callback => dispatch=> {
        stockServices.getStockCategories((done, result, message)=>{
            if(done) dispatch({
                type : productConstants.SET_PRODUCT,
                payload : {
                    [productStrings.stockCategories] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getItem : (itemId, callback) => dispatch=>{
        productServices.getAnItem(itemId, (done, result, message)=>{
            if(done) productActions.setItem(result)(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    setItem : item => dispatch => dispatch({
        type : productConstants.SET_PRODUCT,
        payload : {
            [productStrings.item] : item
        }
    }),
    getItemPackagings : callback => dispatch => {
        productServices.getItemPackagings((done, result, message)=>{
            if(done) dispatch({
                type : productConstants.SET_PRODUCT,
                payload : {
                    [productStrings.itemPackagings] : result,
                }
            });
            if(callback)callback(done, result, message);
        })
    },
    getItemPackages : callback => dispatch => {
        productServices.getItemPackages((done, result, message)=>{
            if(done) dispatch({
                type : productConstants.SET_PRODUCT,
                payload : {
                    [productStrings.itemPackages] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    getItemForms : callback => dispatch => {
        productServices.getItemForms((done, result, message)=>{
            if(done) dispatch({
                type : productConstants.SET_PRODUCT,
                payload : {
                    [productStrings.itemForms] : result,
                }
            }); 
            if(callback) callback(done, result, message);
        })
    },
    setItemConfigTabValue : tabValue => dispatch=>dispatch({
        type : productConstants.SET_PRODUCT,
        payload : {
            [productStrings.itemConfigTabValue] : tabValue
        }
    }),
    getproductItemsBrief_NO_DISPATCH : (lastId, rows, callback)=>{
        productServices.getproductItemsBrief(lastId, rows, callback);
    },
    setConfigComponent : component => dispatch=>dispatch({
        type : productConstants.SET_PRODUCT,
        payload : {
            [productStrings.itemConfigComponent] : component
        }
    }),
    setProductConfigEditMode : mode => dispatch=>dispatch({
        type : productConstants.SET_PRODUCT,
        payload : {
            [productStrings.itemConfigEditMode] : mode
        }
    }),
    getproductItemTags : callback => dispatch =>{
        productServices.getproductItemTags((done, result, message)=>{
            if(done) dispatch({
                type : productConstants.SET_PRODUCT,
                payload : {
                    [productStrings.productItemTags] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    }
}