import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import {connect} from 'react-redux';
import { ListItem, ListItemText} from '@material-ui/core';
import { chatFooterActions, chatFooterStrings } from '../../includes';
const style = theme => ({
    root: {
        display : "flex",
        flexDirection : "column",
        padding : 0,
        paddingLeft : 5,
        width : "100%"
    },
    name : {
        name : 0,
        width : "100%",
    },
    itemHead : {
        display : "flex",
        flexDirection : "row",
        marginLeft : 5,
        alignItems : "center",
        width : "100%",
    },
    active : {
        width : 10,
        height : 10,
        borderRadius : "100%",
        backgroundColor : "green",
        margin : 10,
    }
})
class _AllChatListItemComponent extends Component {
    handleClick = () => {
        let {
            name, _id,
            [chatFooterStrings.chattingContacts] : contacts,
            dispatch,
            handleClickCallback,
         } = this.props;
        const newContact = {_id, name};
        if(!contacts || !contacts.getFirstObjectByPropValue("_id", _id)){
            contacts = contacts ? [...contacts, newContact] : [newContact];
            this.makeContactActive(contacts, _id);
            chatFooterActions({
                [chatFooterStrings.chattingContacts] : contacts,
            })(dispatch)
        }else {
            this.makeContactActive(contacts, _id);
            chatFooterActions({
                [chatFooterStrings.chattingContacts] : [...contacts],
            })(dispatch)
        }
        if(handleClickCallback) handleClickCallback();
    }
    makeContactActive(contacts, _id){
        const {item, index} = contacts.getFirstObjectByPropValue("_id", _id);
        if(contacts && item){
            const replaced = contacts[0];
            contacts[0] = item;
            contacts[index] = replaced;
        }
    }
    render() {
        const {classes, _id, name, active} = this.props;
        return (
            <ListItem divider button className={classes.root} onClick={this.handleClick.bind()}>
                <div className={classes.itemHead}>
                    {active && <div className={classes.active}/>}
                    <ListItemText className={classes.name}>{name}</ListItemText>
                </div> 
            </ListItem>
        );
    }
}
_AllChatListItemComponent.propTypes = {
    classes : PropTypes.object.isRequired,
    handleClickCallback : PropTypes.func,
};
const mapStateToProps = ({chatFooterReducer}) => ({
    [chatFooterStrings.chattingContacts] : chatFooterReducer[chatFooterStrings.chattingContacts],
})
export const AllChatListItemComponent = connect(mapStateToProps)(withStyles(style)(_AllChatListItemComponent));