export const teacherStrings = {
    levels : "levels",
    classes : "levelClasses",
    terms : "terms",
    selectedLevel : "selectedLevel",
    selectedClass : "selectedClass",
    selectedTerm : "selectedTerm",
    teacherRemarks : "teacherRemarks",
    classStudentRemarks : "classStudentRemarks",
    levelTeachers : "levelTeachers",

}
export const teacherConstants = {
    SET_TEACHER : "SET_TEACHER",
    CLEAN_UP_TEACHER : "CLEAN_UP_TEACHER",
}
export const teacherReducer = (state={}, action) => {
    const {type, payload} = action;
    switch(type){
        case teacherConstants.SET_TEACHER : 
            return {...state, ...payload};
        case teacherConstants.CLEAN_UP_TEACHER :
            return {};
        default : return {...state};
    }
}
