import { socketIO } from "../../../socket.io"

export const profileServices = {
    sendImage : (data, callback) => {
        socketIO.emit("profileImage", data);
        socketIO.on("profileImage", ({profileImage, result, message, data})=>{
            console.log(profileImage, result, message, data);
        })
    },
    updateProfile : (data, callback)=>{
        socketIO.emit("updateProfile", data);
        socketIO.on("updateProfile", ({updateProfile, result, message, data})=>{
            callback(updateProfile, result, message, data);
        });
    }
}