import { post, fetchGet } from "./insureUtil"
import { socketIO } from "../../../socket.io";

export const insureUtilServices = {
    getForms : callback => {
        fetchGet("app", "getForms", {name : "forms"}, ({getForms, result, message})=>{            
            callback(getForms, result ? result.values : [], message);
        })
    },
    getSettings : callback =>{
        fetchGet("app", "getSettings", {name : "settings"}, ({getSettings, result, message})=>{
            callback(getSettings, result.values, message);
        });
    },
    getUser : callback => {
        fetchGet("admin", "getUser", {}, ({getUser, result, message})=>{
            callback(getUser, result, message);
        })
    },
    login : (email, password, callback) => {
        post({email, password}, "app", "login", ({login, result, message})=>{
            callback(login, result, message);
        })
    },
    signup : (data, callback) => {
        post(data, "app", "signup", ({signup, result, message})=>{
            callback(signup, result, message);
        })
    }
}