import { appConstants } from "../constants";
import { appServices } from "../services";
import {_storeData, errorNotice, successNotice } from "../utils";
import { alertAction } from "./alertActions";
import Manager from "../manager";

export const appActions = {
    unsetPushedNotificationIds : () => dispatch => dispatch({
        type : appConstants.UNSET_PUSHED_NOTIFICATION_IDS
    }),
    setPushedNotificationIds : (schoolId, lastId) =>dispatch=>dispatch({
        type : appConstants.SET_PUSHED_NOTIFICATION_IDS,
        payload : {
            schoolId, data : lastId
        }
    }),
    updateLastNotificationIds : (schoolId, lastId, callback)=>dispatch=>{
        appServices.updateLastNotificationIds(schoolId, lastId, (done, result, message)=>{
            if(callback) callback(done, message, result);
        })
    },
    getNewMessages : (schoolId, lastId, callback, noUpdate) => dispatch => {
        appServices.getNewMessages(schoolId, lastId, (done, result, message)=>{
            if(done && result && result.length !== 0){
                if(!noUpdate) dispatch({
                    type : appConstants.UPDATE_NEW_SCHOOL_NOTIFICATION,
                    payload : {
                        schoolId, data : result
                    }
                })
            }
            if(callback) callback(done, message, result);
        })
    },
    getNotificationCountByDate : (schoolId, lastDate, callback)=>dispatch=>{
        appServices.getNotificationCountByDate(schoolId, lastDate, (done,result, message)=>{
            if(done && result && result.length !== 0) dispatch({
                type : appConstants.SET_NOTIFICATION_COUNTS,
                payload : {
                    schoolId, count : result
                }
            })
            if(callback) callback(done, message, result);
        })
    },
    getNotificationCount : (schoolId, lastId, callback) => dispatch => {
        appServices.getNotificationCount(schoolId, lastId, (done, result, message)=>{
            if(done && result && result.length !== 0) dispatch({
                type : appConstants.SET_NOTIFICATION_COUNTS,
                payload : {
                    schoolId, count : result
                }
            })
            if(callback) callback(done, message, result);
        })
    },
    setNotificationCount : (schoolId, count, callback) => dispatch => dispatch({
        type : appConstants.SET_NOTIFICATION_COUNTS,
        payload : {
            schoolId, count
        }
    }),
    setLastNotificationId : (schoolId, id, callback) => dispatch => {
        dispatch({
            type : appConstants.SET_LAST_NOTIFICATION_ID,
            payload : {
                schoolId , id
            }
        })
    },
    archiveSchool : (schoolId, callback) => dispatch=>{
        appServices.archiveSchool(schoolId, (done, result, message)=>{
            if(done) updateUser(result, dispatch);
            if(callback) callback(done, message, result);
        })
    },
    unsubscribeUser : (subscriberId, schoolId, callback) => dispatch => {
        appServices.unsubscribeUser(subscriberId, schoolId, (done, result, message)=>{
            if(done) {
                dispatch({
                    type : appConstants.SET_SUBSCRIBERS,
                    payload : result
                });
            }
            if(callback) callback(done, message, result);
        })
    },
    getSubscribers : (schoolId, callback)=> dispatch=>{
        appServices.getSubscribers(schoolId, (done, result, message)=>{
            if(done) dispatch({
                type : appConstants.SET_SUBSCRIBERS,
                payload : {schoolId, users : result}
            })
            if(callback)callback(done, message, result);
        })
    },
    deleteSchoolEnrollment : (schoolId, callback) => dispatch => {
        appServices.deleteSchoolEnrollment(schoolId, (done, result, message)=>{
            if(done) updateUser(result, dispatch);
            if(callback) callback(done, message);
        })
    },
    addSchoolEnrollment : (data, callback)=>dispatch=>{
        appServices.addSchoolEnrollment(data, (done, result, message)=>{
            if(done) updateUser(result, dispatch);
            if(callback) callback(done, message, result);
        })
    },
    newSchoolSecret : (schoolId, callback) => dispatch => {
        appServices.newSchoolSecret(schoolId, (done, result, message)=>{
            if(done) dispatch({
                type : appConstants.SET_SCHOOL_SECRET,
                payload : result
            });
            if(callback) callback(done, message, result);
        })
    }, 
    addNewMessage : (data, callback) => dispatch=>{
        const {schoolId} = data;
        appServices.addNewMessage(data, (done, result, message)=>{
            if(done) {
                successNotice(message, dispatch);
                dispatch({
                    type : appConstants.ADD_SCHOOL_MESSAGE, // appConstants.SET_SCHOOL_MESSAGES,
                    payload : {schoolId, data : result}
                })
            }else errorNotice(message, dispatch);
            if(callback) callback(done, message, result);
        })
    }, 
    updateSchool : (school, callback) => dispatch => {
        appServices.updateSchool(school, (done, result, message)=>{
            if(done){
                successNotice(message, dispatch);
                dispatch({
                    type : appConstants.SET_SCHOOL_INFO,
                    payload : school
                });
            }else errorNotice(message, dispatch);
            if(callback) callback(done, message);
        })
    },
    getSchool : (schoolId, callback) => dispatch => {
        appServices.getSchool(schoolId, (done, result, message)=>{
            if(done) dispatch({
                type : appConstants.SET_SCHOOL_INFO,
                payload : result
            }); else errorNotice(message, dispatch);
            if(callback) callback(done, message, result);
        })
    },
    addNewSchool : (data, callback) => dispatch => {
        appServices.addNewSchool(data, (done, result, message)=>{
            if(done) {
                successNotice(message, dispatch);
                updateUser(result, dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, message);
        })
    }, 
    signupWithSchool : (data, callback) => dispatch=>{
        appServices.signupWithSchool(data, (done, result, message)=>{
            if(done) updateUser(result, dispatch);
            if(callback) callback(done, message);
        })
    },
    fetchMoreMessages : (schoolId, lastId, rows, callback) => dispatch => {
        //should come under the else statement
        appServices.getMessages(schoolId, lastId, rows, (done, result, message)=>{
            if(done && result.length !== 0) dispatch({
                type : appConstants.UPDATE_SCHOOL_MESSAGES,
                payload : {
                    schoolId,
                    data : result
                }
            })
            if(callback) callback(done, message, result);
        })
    },
    getMessages : (schoolId, lastId, rows, callback) => dispatch => {
        //should come under the else statement
        appServices.getMessages(schoolId, lastId, rows, (done, result, message)=>{
            if(done) dispatch({
                type : appConstants.SET_SCHOOL_MESSAGES,
                payload : {
                    schoolId,
                    data : result
                }
            })
            if(callback) callback(done, message, result);
        })
    },
    updateProfile : (profile, callback)=> dispatch => {
        appServices.updateProfile(profile, (done, result, message)=>{
            if(done) dispatch({
                type : appConstants.SET_MY_PROFILE,
                payload : profile
            });
            if(callback) callback(done, message);
        })
    },
    getUser : callback => dispatch => {
        appServices.getUser((done, result, message)=>{
            if(done) updateUser(result, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, message, result); 
        })
    },
    login : (username, password, callback) => dispatch => {
        appServices.lobin(username, password, (done, result, message) => {
            if(done) {
                if(result.myProfile.schoolAdmin || 
                    (result.mySchoolIds && result.mySchoolIds.length != 0))
                    updateUser(result, dispatch)
            } else errorNotice(message, message);
            if(callback) callback(done, message, result);            
        })
    },
    signup : (data, callback) => dispatch => {
        appServices.signup(data, (done, result, message) => {
            if(done){
                updateUser(result, dispatch);
                // _storeData(strings.token, result.myProfile.token);
                // _storeData(strings.userId, result._id);
            }
            if(callback) callback(done, message, result);
        })
    },
    fetchMoreNotifications : (schoolId, lastId, rows, callback) => dispatch => {
        appServices.getMessages(schoolId, lastId, rows, (done, result, message)=>{
            if(done) dispatch({
                type : appConstants.UPDATE_SCHOOL_NOTIFICATIONS,
                payload : {
                    schoolId,
                    data : result
                }
            })
            if(callback) callback(done, message, result);
        })
    },    
    getNotifications : (schoolId, lastId, rows, callback) => dispatch => {
        appServices.getMessages(schoolId, lastId, rows, (done, result, message)=>{
            if(done) dispatch({
                type : appConstants.SET_SCHOOL_NOTIFICATIONS,
                payload : {
                    schoolId,
                    data : result
                }
            })
            if(callback) callback(done, message, result);
        })
    },  
    logout : () => dispatch => {
        localStorage.removeItem(Manager.tokenAlias);
        localStorage.removeItem(Manager.userIdAlias);
        dispatch({
            type : appConstants.USER_LOGOUT
        });
    },
    toogleScreenProgress : toggle => dispatch => dispatch({
        type : appConstants.TOOGLE_SCREEN_PROGRESS,
        payload : toggle
    }),
    showSnackbar : (options)=>{
        return (dispatch) => {
            const newOption = {...options, open: true};
            dispatch({
                type : appConstants.SNACKBAR_OPEN,
                payload: newOption
            });
        }
    },
    closeSnackbar : () => {
        return (dispatch) => {
            dispatch({
                type: appConstants.SNACKBAR_CLOSE,
            })
        }
    },
    showSnackDialog : (message, ...actions) => (dispatch, callback) => {
        alertAction.toggleSnackDialog(true, message, actions, callback)(dispatch);
    },
    closeSnackDialog : () => dispatch => {
        alertAction.toggleSnackDialog(false, "", [])(dispatch);
    }
}
async function updateUser(result, dispatch){
    if(!result) return;
    try{
        if(result.myProfile) {
            dispatch({
                type : appConstants.SET_MY_PROFILE,
                payload : result.myProfile
            })
            await _storeData(Manager.tokenAlias, result.myProfile.token);
        }
        await _storeData(Manager.userIdAlias, String(result._id));
        if(result.mySchoolIds) dispatch({
            type : appConstants.SET_MY_SCHOOL_IDS,
            payload : result.mySchoolIds
        })
        if(result.mySchools) dispatch({
            type : appConstants.SET_MY_SCHOOLS,
            payload : result.mySchools
        })
        if(result.enrolledSchools) dispatch({
            type : appConstants.SET_ENROLLED_SCHOOLS,
            payload : result.enrolledSchools
        })
        if(result.enrolledSchoolIds) dispatch({
            type : appConstants.SET_ENROLLED_SCHOOLIDS,
            payload : result.enrolledSchoolIds
        })
        if(result.schoolSecret) dispatch({
            type : appConstants.SET_SCHOOL_SECRET,
            payload : result.schoolSecret
        });
        if(result.lastNotificationId) dispatch({
            type : appConstants.SET_INITIAL_LAST_NOTIFICATION_IDS,
            payload : result.lastNotificationId
        })
    }catch(e){
        console.log("UPDATE_USER_CATCH_PROMISE", e);
    }
}