import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { invProductActions } from '../../actions';
import { invProductStrings } from '../../config';
import INVPackagingDisplay from './INVPackagingDisplay/INVPackagingDisplay';
import { Grid } from '@material-ui/core';
import { INVButton } from '../../../Includes';
import { StageHeaderPlane, MyDialog, HighlightedInfo } from '../../../utils';
import {INVNewProductPackaging} from './INVNewProductPackaging';
import classNames from 'classnames';


const style = theme => ({
    root: {
    }
})
class _INVItemPackaging extends Component {
    constructor(props) {
        super(props);
        this.state = {
            newPackaginDialog : false,
        }
    }
    
    componentDidMount() {
        const {
            dispatch,
            [invProductStrings.productPackages] : productPackages
        } = this.props;
        this.getProductPackagings();
        if(!productPackages) invProductActions.getProductPackages()(dispatch);
    }
    getProductPackagings(){
        const {dispatch} = this.props;
        invProductActions.getProductPackagings()(dispatch);
    }
    componentWillUnmount(){
        invProductActions.setProductConfigEditMode(false)(this.props.dispatch);
    }
    newPackaging(){
        const {classes} = this.props;
        return <INVButton
            onClick={()=>this.setState({newPackaginDialog : true})}>
                New Packaging
            </INVButton>
    }
    createPackaging(data, context){
        const {dispatch} = this.props;
        invProductActions.createProductPackaging({packageIds : data}, (done, result)=>{
            if(done){
                this.setState({newPackaginDialog : false});
                this.getProductPackagings();
            }else context.setState({loading : false});
        })(dispatch);
    }
    editPackaging(packagingId, packageIds, context){
        const {dispatch} = this.props;
        invProductActions.editPackaging(packagingId, packageIds, (done, result)=>{
            if(done){
                this.setState({newPackaginDialog : false});
                this.getProductPackagings();
            }else context.setState({loading : false});
        })(dispatch);
    }
    onPackagingEdit(editingPackaging){
        this.setState({editingPackaging, editMode : true, newPackaginDialog : true});
    }

    render() {
        const {
            classes,
            [invProductStrings.productPackages] : productPackages,
            [invProductStrings.productPackagings] : productPackagings,
        } = this.props;
        const {newPackaginDialog, editingPackaging, editMode } = this.state;
        return (
            <div className={classNames(classes.root, "animated", "zoomIn")}>
                <div style={{marginBottom : 20}}>
                    <StageHeaderPlane
                        classes={{root : classes.headerStage}}
                        visible={true}
                        components={[
                            this.newPackaging.bind(this)
                        ]}
                        />
                </div>
                <HighlightedInfo>
                    Please note that modification of the packaging will affect products already assign to it,
                    this is detrimental during sales.
                </HighlightedInfo>
                <Grid container spacing={2}>                    
                    {productPackagings && productPackagings.map(
                        (packaging, index)=>
                            <Grid key={index} item xs={6} sm={4} md={4} lg={2} xl={2}>
                                <INVPackagingDisplay
                                    packages={productPackages}
                                    packaging={packaging}
                                    editable
                                    canSeeList
                                    onEdit={this.onPackagingEdit.bind(this)}
                                />
                            </Grid>
                    )}
                </Grid>
                <MyDialog
                    open={newPackaginDialog}
                    close={()=>this.setState({newPackaginDialog : false})}>
                        <INVNewProductPackaging
                            createPackaging={this.createPackaging.bind(this)}
                            editMode={editMode}
                            packaging={editingPackaging}
                            editPackaging={this.editPackaging.bind(this)}/>
                    </MyDialog>
            </div>
        );
    }
}


_INVItemPackaging.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({invProductReducer}) => ({
    [invProductStrings.itemConfigEditMode] : invProductReducer[invProductStrings.itemConfigEditMode],
    [invProductStrings.productPackages] : invProductReducer[invProductStrings.productPackages],
    [invProductStrings.productPackagings] : invProductReducer[invProductStrings.productPackagings],
});
export const INVItemPackaging = connect(mapStateToProps)(withStyles(style)(_INVItemPackaging));
export {INVItemPackaging as default}