import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { FeatureBox } from './FeatureBox';
import { inovateOSUtil, inovateOSUtilStrings } from '../../../utils';
import { inovateOSPageStrings } from '../../config';
import { inovateOSPageActions } from '../../actions';


const style = theme => ({
    root:{
        position : "relative",
        background : "linear-gradient(180deg, black, "+ inovateOSUtil.getTheme().background+")",
    }, 
    floater : {
        borderRadius : 5,
        display : "flex",
        justifyContent : "center",
        position : "absolute",
        width: "100%",
        top: -100,
        background: "transparent",
        zIndex: 100,
    }
})
class _InovateOSWhatWeDo extends Component {
    constructor(props) {
        super(props);
        this.state = {
            height : [],
        }
        this.setHeight = this.setHeight.bind(this);
    }
    componentDidMount() {
        const {
            dispatch, 
            [inovateOSPageStrings.attributes] : attributes
        } = this.props;
        if(!attributes) inovateOSPageActions.getAttributs()(dispatch);
    }
    
    setHeight(h){
        this.setState(({height})=>({height : [...height, h]}));
    }
    render() {
        const {
            classes,
            [inovateOSPageStrings.attributes] : attributes,
            [inovateOSUtilStrings.backendBaseUrl]: baseUrl
        } = this.props;
        let {height} = this.state;
        height = height.sort((a, b)=>b-a);
        return (
            <div className={classes.root}
            style={{
                minHeight : height[0] && height[0]
            }}>
                <div className={classes.floater}>
                    {attributes && attributes.slice(0, 3).map((item, index)=>{

                        return <FeatureBox
                            key={index}
                            header={item.header}
                            body={item.body && item.body[0] ? item.body[0] : null}
                            image={item.src}
                            baseUrl={baseUrl}
                            getContentHeight={this.setHeight}/>
                    })}
                </div>
            </div>
        );
    }
}


_InovateOSWhatWeDo.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({inovateOSPageReducer, inovateOSUtilReducer}) => ({
    [inovateOSPageStrings.attributes] : inovateOSPageReducer[inovateOSPageStrings.attributes],
    [inovateOSUtilStrings.backendBaseUrl] : inovateOSUtilReducer[inovateOSUtilStrings.backendBaseUrl],
})


export const InovateOSWhatWeDo = connect(mapStateToProps)(withStyles(style)(_InovateOSWhatWeDo));
export {InovateOSWhatWeDo as default}