import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import {connect} from "react-redux";
import { KnowledgeArea } from '../Home/KnowledeArea';
import { Typography } from '@material-ui/core';
import { insureUtilStrings, insureUtil } from '../utils';
import { Subheader } from '../../includes';
import { insureAboutUsStrings } from './config';
import { insureAboutUsActions } from './actions';
const style = theme => ({
    root: {
    },
    aboutus : {
        minHeight : "15cmå",
        margin : "100px 20px",
        display : "flex",
        flexDirection : "column",
        justifyContent : "center",
        alignItems : "center",
        [theme.breakpoints.up("md")] : {
            paddingRight : "25%",
            paddingLeft : "25%",
            textAlign : "center"
        }
    },
    title : {
        fontWeight : "bold",
        marginBottom : 50,
        borderBottom : "solid 5px " + insureUtil.getTheme().appRed,
        color : insureUtil.getTheme().primary,
    }
})
class _AboutUs extends Component {
    componentDidMount() {
        const {dispatch} = this.props;
        insureAboutUsActions.getSiteInfo()(dispatch);
    }
    
    render() {
        const {
            classes,
            [insureUtilStrings.subheadImage] : subheadImage,
            [insureAboutUsStrings.aboutUs] : aboutUs
        } = this.props;
        return (
            <div className={classes.root}>
                <Subheader
                    image_url={subheadImage}
                    title="About Us"/>
                <div className={classes.aboutus}>
                    <Typography variant="h5"
                        className={classes.title}
                        paragraph>
                            ABOUT US
                        </Typography>
                    {aboutUs && aboutUs.value && aboutUs.value.map((item, index)=>{
                        return <Typography paragraph key={index}>{item}</Typography>
                    })}
                </div>
                <KnowledgeArea/>
            </div>
        );
    }
}
_AboutUs.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({insureUtilReducer, insureAboutUsReducer}) => ({
    [insureUtilStrings.subheadImage] : insureUtilReducer[insureUtilStrings.subheadImage],
    [insureAboutUsStrings.aboutUs] : insureAboutUsReducer[insureAboutUsStrings.aboutUs],
})
export const AboutUs = connect(mapStateToProps)(withStyles(style)(_AboutUs));
export {AboutUs as default};