
export default class Manager{
    static blogImagePath = process.env.REACT_APP_IMAGE_PATH; //"https://agroblog.herokuapp.com/web/agroblog/image/";
    static base_uri = process.env.REACT_APP_BASE_URI; //"https://agroblog.herokuapp.com/web/agroblog/v1/";
    static facebookAppId = process.env.REACT_APP_FACEBOOK_APPID; //"674756889610644";
    static facebookUri = process.env.REACT_APP_FACEBOOK_URI; //"http://www.facebook.com";
    static myDomain = process.env.REACT_APP_DOMAIN;
    static tokenAlias = process.env.REACT_APP_TOKEN_ALIAS;
    static userIdAlias = process.env.REACT_APP_USERID_ALIAS;
    static isLoggedIn = false;

    static getShareUri(id){
        return encodeURI(this.myDomain +"/blog/" + id);
    }
    static hasLoggedIn(){
        if(!this.isLoggedIn){
            const loginString = localStorage.getItem(this.tokenAlias);
            if(loginString) this.isLoggedIn = true;
        } 
        return this.isLoggedIn;
    }
    static fetchGet(owner, action, stringQuery, callback){
        let count = 0;
        let build = "";
        for (const i in stringQuery) {
            if (stringQuery.hasOwnProperty(i)) {
                const elem = stringQuery[i];
                if(count === 0){
                    build += "?"+i+"="+elem;
                }else build += "&"+i+"="+elem;
                count++;
            }
        }
        fetch(this.base_uri+owner+"/"+action+build).then(
            response=> response.json()
        ).then(response=>{
            if(callback) callback(response)
        });
    }
    static fetchPost(owner, action, options, callback){
        return fetch(this.base_uri+owner+"/"+action, options).then(
            response=> response.json()
        ).then(response=>callback(response));
    }
    
}