export  const hirDashboardConstants = {
    SET_HIR_DASHBOARD : "SET_HIR_DASHBOARD"
}
export const hirDashboardReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case hirDashboardConstants.SET_HIR_DASHBOARD : 
            return {...state, ...payload};
        default : return state;
    }
}
