import React, { Component } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import {withStyles} from '@material-ui/core/styles';
import Calendar from 'react-calendar';
import { Popover, Button, Typography, FormGroup, FormControl, TextField, FormLabel } from '@material-ui/core';
const style = theme => ({
    root: {
        
    },
    textfield :{
        
    },
    formcontrol : {
        marginTop : 20
    },
    actionBtn : {
        margin : 5
    }
})
class _NewTermForm extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data : {
                startDate : new Date(),
                endDate : new Date()
            },
            anchorEl : null,
            dateType : null
        }
    }
    handleChange = name => e => {
        let data = {...this.state.data};
        data[name] = e.target.value;
        this.setState({data});
    }
    handleDateSelection = date => {
        this.setState(state => ({...state, anchorEl : null,  data : {...state.data, [this.state.dateType]: date}}));
    }
    handleDateBtn = dateType => e =>  this.setState({dateType, anchorEl : e.target});
    handleClosePopover = () => this.setState({anchorEl : null});
    render() {
        const {classes, closeDialog} = this.props;
        const {anchorEl, dateType, data} = this.state;
        const {startDate, endDate} = data;
        return (
            <FormGroup className={classes.root}>
                <FormLabel>New Term</FormLabel>
                <FormControl className={classes.formcontrol}>
                    <TextField
                        className={classes.textfield}
                        margin="normal"
                        onChange={this.handleChange("name")}
                        placeholder="Term Name"
                        label="Term Name"/>
                </FormControl>
                <FormControl className={classes.formcontrol}>
                    <TextField
                        className={classes.textfield}
                        margin="normal"
                        multiline
                        rowsMax={3}
                        onChange={this.handleChange("description")}
                        placeholder="Description"
                        label="Description"/>
                </FormControl>
                <FormControl className={classes.formcontrol} style={{
                    justifyContent : "space-around",
                    flexDirection : 'row'
                }}>
                    <Button 
                        variant="contained" 
                        color="primary" 
                        onClick={this.handleDateBtn("startDate")}>
                            Start Date: {startDate.toLocaleDateString()}
                    </Button>
                    <Button 
                        variant="contained" 
                        color="secondary" 
                        onClick={this.handleDateBtn("endDate")}>
                            End Date : {endDate.toLocaleDateString()}
                    </Button>
                </FormControl>
                <FormControl className={classes.formcontrol} style={{flexDirection : "row"}}>
                    <Button variant="outlined" 
                        color="secondary" 
                        onClick={closeDialog}
                        className={classNames(classes.actionBtn)}>Cancel</Button>
                    <Button variant="outlined" color="primary" className={classNames(classes.actionBtn)}>Create Term</Button>
                </FormControl>

                <Popover
                    // id={id}
                    open={Boolean(anchorEl)}
                    anchorEl={anchorEl}
                    onClose={this.handleClosePopover.bind(this)}
                    anchorOrigin={{
                        vertical: 'bottom',
                        horizontal: 'left',
                    }}
                    transformOrigin={{
                        vertical: 'top',
                        horizontal: 'left',
                    }}
                >
                    <Typography style={{textAlign:"center"}}>{dateType === "startDate" ? "Start Date" : "End Date"}</Typography>
                    <Calendar
                        onChange={this.handleDateSelection.bind(this)}
                        value={data[dateType]}/>
                </Popover>
            </FormGroup>
        );
    }
}
_NewTermForm.propTypes = {
    classes : PropTypes.object.isRequired,
    closeDialog : PropTypes.func,
};
export const NewTermForm = withStyles(style)(_NewTermForm);