export const inovateOSAdminUtilStrings = {
    theme : "theme",
    tokenAlias : "tokenAlias",
    userAlias : "userAlias",
    backendUrl : "backendUrl",
    backendBaseUrl : "backendBaseUrl",
    myProfile : "myProfile",
    defaultImage : "defaultImage",
}

export const inovateOSAdminUtilConstants = {
    SET_UTIL : "SET_UTIL",
}

export const inovateOSAdminUtilReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case inovateOSAdminUtilConstants.SET_UTIL : 
            return {...state, ...payload};
        default : return {...state};
    }
}

