export const reportStrings = {

}
export const reportConstants = {
    SET_REPORT : "SET_REPORT",
    CLEAN_UP_REPORT :"CLEAN_UP_REPORT",
}
const reportInitialState = {

}
export const reportReducer_inventory = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case reportConstants.SET_REPORT : 
            return {...state, ...payload};
        case reportConstants.CLEAN_UP_REPORT : 
            return {...state, ...reportInitialState}
        default : return {...state};
    }
}
