export const payrollConstants = {
    SET_PAYROLL : "SET_PAYROLL",
    CLEAN_UP_PAYROLL : "CLEAN_UP_PAYROLL",
}
export const payrollReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case payrollConstants.SET_PAYROLL : 
            return {...state, ...payload};
        case payrollConstants.CLEAN_UP_PAYROLL : 
            return {};
        default : return {...state};
    }
}
