import { fetchGet, post } from "../utils";
export const insureHomeServices = {
    subscribeNewsLetter : (data, callback) => {
        post(data, "app", "subscribeNewsLetter", ({subscribeNewsLetter, result, message})=>{
            callback(subscribeNewsLetter, result, message);
        })
    },
    getCarousel : callback=>{
        fetchGet("app", "getSiteInfo", {name : "carousel"}, ({getSiteInfo, result, message})=>{
            console.log(getSiteInfo, result, message);
            callback(getSiteInfo, result, message);
        });
    },
    getHomeInfo : callback=>{
        fetchGet("app", "getSiteInfo", {name : "home"}, ({getSiteInfo, result, message})=>{
            console.log(getSiteInfo, result, message);
            callback(getSiteInfo, result, message);
        }); return;
        callback(true, {
            _id : 1,
            name : "home",
            values : [
                {
                    name : "intro",
                    header : "Introduction",
                    value : [
                        "Emergency health insurance can be cheap, easy to access, prompt and better.",
                        "The Golden hour for a health emergency is within the first 24 hours, "+
                        "hence the need to have it insured. You need not be a civil servant, "+
                        "corporate worker nor an internet expert, your phone number is your identity.",
                        "Start a journey with us, enrol with as low as N100 monthly."
                    ]
                }
            ]
        })
    }
}