import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, breadCrumbActions, headerStrings, 
    mainStageHeaderAction, mainStageHeaderStrings, MyTable } from '../../../../includes';
import { TeacherRemarkCellMapFormat } from './TeacherRemarkCellMapFormat';
import { Button } from '@material-ui/core';
import { appActions } from '../../../../../actions';
import { colors } from '../../../../../utils';
import { teacherStrings, teacherActions } from '../../config';
const style = theme => ({
    root: {
        marginTop : 20
    }
})
class _RemarkSetting extends Component {
    constructor(props) {
        super(props);
        this.state = {
            teacherRemarksUnusable : null,
            teacherRemarks : null
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "REMARK SETTING",
        })(dispatch);
        breadCrumbActions.addToBreadCrumb([
            {name : "Setting" , path : ""}
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.buttons] : [
                {value : "Back", onClick : this.props.back}
            ]
        })(dispatch);
        this.initializeComponent();
    }
    initializeComponent(){
        const {
            [teacherStrings.teacherRemarks] : teacherRemarks,
            dispatch
        } = this.props;
        if(!teacherRemarks) 
            teacherActions.getTeacherRemarks()(dispatch);
    }
    cellMapContext = {};
    getCellMapContext = (context, name) => this.cellMapContext[name] = context;
    static getDerivedStateFromProps(nextProps, prevState) {
        if(JSON.stringify(nextProps[teacherStrings.teacherRemarks])
        !== JSON.stringify(prevState.teacherRemarksUnusable)){
            prevState.teacherRemarks = nextProps[teacherStrings.teacherRemarks];
            prevState.teacherRemarksUnusable = prevState.teacherRemarks
        }
        return {...prevState};
    }
    
    addButtonHandler = listLength => e => {
        let data = {};
        for (const mapItem in this.cellMapContext) {
            if (this.cellMapContext.hasOwnProperty(mapItem)) {
                const context = this.cellMapContext[mapItem];
                if(mapItem !== "action"){
                    const {name, value} = context.state.data;
                    data[name] = value;
                }
            }
        }
        data.id = listLength;
        let studentRemarks = [...this.state.studentRemarks];
        teacherActions.addRemark(data, (done, result)=>{
            
        })
    }
    editBtnHandler = row => () => {
        
    }
    cancelEditBtnHandler = row => () => {
        
    }
    deleteBtnHandler = row => ()=>{
        const {dispatch} = this.props
        
        appActions.showSnackDialog(
            "Are you you want to delete this levle("+row.name+")", 
            [<Button key="cancel" onClick={()=>{
                
                appActions.closeSnackDialog()(dispatch);
            }}>Continue</Button>]
        )(dispatch);        
    }
    editFinishBtnHandler = row => () => {
        
    }
    render() {
        const {classes} = this.props;
        let {
            [teacherStrings.teacherRemarks] : teacherRemarks,
        } = this.props;
        if(teacherRemarks) teacherRemarks = [
            ...teacherRemarks.map(item=>({...item, editable:true})), 
            {new : true}
        ];
        else teacherRemarks = [{new :true}];
        return (
            <div className={classes.root}>
                <MyTable
                    header={["ID", "Short name", "Description", "Rate", "Actions"]}
                    dataMap={["_id", "short", "description", "rate", "action"]}
                    data={teacherRemarks}
                    CellMap={TeacherRemarkCellMapFormat}
                    getCellMapContext={this.getCellMapContext}
                    titleProps={{style:{color : colors.gray, marginBottom : 20}}}
                    getCellMapContext={this.getCellMapContext.bind(this)}
                    addButtonHandler={this.addButtonHandler.bind(this)}
                    deleteBtnHandler={this.deleteBtnHandler.bind(this)}
                    editBtnHandler={this.editBtnHandler.bind(this)}
                    editFinishBtnHandler={this.editFinishBtnHandler.bind(this)}
                    cancelEditBtnHandler={this.cancelEditBtnHandler.bind(this)}
                    />
            </div>
        );
    }
}


_RemarkSetting.propTypes = {
    classes : PropTypes.object.isRequired,
    back : PropTypes.func,
};
const mapStateToProps = ({teacherReducer}) => ({
    [teacherStrings.teacherRemarks] : teacherReducer[teacherStrings.teacherRemarks],
})


export const RemarkSetting = connect(mapStateToProps)(withStyles(style)(_RemarkSetting));