import { staffConstants, staffStrings } from "./config";
import { staffServices } from "./staffServices";


export const staffActions = {
    
    getStaff : {
        admins : callback => dispatch => {
            staffServices.getStaff("admin", (done, result, message)=>{
                if(done) dispatch({
                    type : staffConstants.SET_STAFF,
                    payload : {
                        [staffStrings.staffListAdmin] : result
                    }
                })
                if(callback) callback(done, result, message);
            })
        },
        teachers : callback => dispatch => {
            staffServices.getStaff("teacher", (done, result, message)=>{
                if(done) dispatch({
                    type : staffConstants.SET_STAFF,
                    payload : {
                        [staffStrings.staffListTeacher] : result
                    }
                })
                if(callback) callback(done, result, message);
            })
        },
        others : callback => dispatch => {
            staffServices.getStaff("other", (done, result, message)=>{
                if(done) dispatch({
                    type : staffConstants.SET_STAFF,
                    payload : {
                        [staffStrings.staffListOthers] : result
                    }
                })
                if(callback) callback(done, result, message);
            })
        },
    },
    setStaffForm: payload  => dispatch => dispatch({
        type : staffConstants.SET_STAFF,
        payload
    }),
    getStaffForms : {
        admin : callback => dispatch => {
            //use get and query to contain the form type (teacher, admin, others)
            staffServices.getForm("admin", (done, result, message)=>{
                if(done) dispatch({
                    type : staffConstants.SET_STAFF,
                    payload : {
                        [staffStrings.formAdmin] : result
                    }
                })
                if(callback) callback(done, result, message);
            })
        },
        teacher : callback => dispatch => {
            //use get and query to contain the form type (teacher, admin, others)
            staffServices.getForm("teacher", (done, result, message)=>{
                if(done) dispatch({
                    type : staffConstants.SET_STAFF,
                    payload : {
                        [staffStrings.formTeacher] : result
                    }
                })
                if(callback) callback(done, result, message);
            })
        },
        others : callback => dispatch => {
            //use get and query to contain the form type (teacher, admin, others)
            staffServices.getForm("others", (done, result, message)=>{
                if(done) dispatch({
                    type : staffConstants.SET_STAFF,
                    payload : {
                        [staffStrings.formOthers] : result
                    }
                })
                if(callback) callback(done, result, message);
            })
        },
    },
    getStaffCategories : callback => dispatch => {
        staffServices.getStaffCategories((done, result, message)=>{
            if(done) dispatch({
                type : staffConstants.SET_STAFF,
                payload : {
                    [staffStrings.categories] : result
                }
            })
            if(callback) callback(done, result);
        })
    },
}