import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { connect } from "react-redux";
import {Link} from 'react-router-dom';
import { Header, Subheader } from '../../../includes';
import { ServiceItemBox } from './ServiceItemBox';
import { KnowledgeArea } from '../../Home/KnowledeArea';
import { insureServiceStrings } from '../config';
import { insureServiceActions } from '../actions';
import { insureUtilStrings, insureUtil } from '../../utils';
import { Button } from '@material-ui/core';
import { insureRouteNames } from '../../routeNames';

const style = theme => ({
    root: {
        // padding : 10
    },
    serviceItemsContainer : {
        marginBottom : 100,
    },
    itemBox : {
        margin : "150px 5px"
    },
    primaryBtn : {
        backgroundColor : insureUtil.getTheme().secondary,
        borderRadius : 8,
        padding : 10,
        color : insureUtil.getTheme().white,
        marginLeft : 20,
        textDecoration : "none",
    }
})

class _Services extends Component {
    componentDidMount() {
        const {
            dispatch,
            [insureServiceStrings.services] : services,
        } = this.props;
        if(!services)
            insureServiceActions.getServices()(dispatch);
    }
    
    render() {
        const {
            classes, userAlt, 
            [insureServiceStrings.services] : services,
            [insureUtilStrings.backendBaseUrl] : baseUrl,
            [insureUtilStrings.subheadImage] : subheadImage,
        } = this.props;
        return (
            <div className={classes.root}>
                <Subheader
                    title="Services"
                    image_url={subheadImage}/>
                <div className={classes.serviceItemsContainer}>
                    {services && services.map((item, index)=>{
                        item.baseUrl=baseUrl;
                        item.headerLink = {
                            pathname : insureRouteNames.serviceView_+item.name,
                            state : {name : item.name, body : item.body, header : item.header, src : item.src}
                        };
                        if(item.name === "cooperative"){
                            item.footer = ()=><div>
                                <Link className={classes.primaryBtn} 
                                    to={insureRouteNames.coopReg}>
                                        Register
                                    </Link>
                                <Link className={classes.primaryBtn} 
                                    to={insureRouteNames.coopSub}>
                                        Subscribe
                                    </Link>
                                <Link className={classes.primaryBtn} 
                                    to={insureRouteNames.coopVerify}>
                                        Verify
                                    </Link>
                            </div>;
                        }
                        return userAlt ? <ServiceItemBox 
                            classes={{root : classes.itemBox}}  
                            alt={index % 2 === 0} 
                            {...item} 
                            key={index}/>: 
                        <ServiceItemBox 
                            classes={{root : classes.itemBox}} 
                            {...item} 
                            key={index}/>
                    })}
                </div>
                <KnowledgeArea/>
            </div>
        );
    }
}
_Services.propTypes = {
    classes : PropTypes.object.isRequired,
    userAlt : PropTypes.bool,
};
const mapStateToProps = ({insureServiceReducer, insureUtilReducer}) => ({
    [insureServiceStrings.services] : insureServiceReducer[insureServiceStrings.services],
    [insureUtilStrings.backendBaseUrl] : insureUtilReducer[insureUtilStrings.backendBaseUrl],
    [insureUtilStrings.subheadImage] : insureUtilReducer[insureUtilStrings.subheadImage],
})
export const Services = connect(mapStateToProps)(withStyles(style)(_Services));
export {Services as default};