import { inovateOSUtilConstants, inovateOSUtilStrings } from "./config";
import { inovateOSUtilServices } from "./services";
import { inovateOSUtil } from "./inovateOSUtil";
import { store } from "../../../../helpers";
import { errorNotice, _storeData } from "../../../../utils";
import { headerActions, headerStrings } from "../../../includes";
export const inovateOSUtilActions = payload => dispatch => dispatch({
    type : inovateOSUtilConstants.SET_UTIL,
    payload 
});

export const inovateOSActions = {
    getForms : callback => dispatch => {
        inovateOSUtilServices.getForms((done, result, message)=>{
            if(done) inovateOSUtilActions({
                [inovateOSUtilStrings.forms] : result
            })(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getSettings : callback => dispatch => {
        inovateOSUtilServices.getSettings((done, result, message)=>{
            if(done) {
                const subheadItem = result ? result.find(item=>item.name==="subheadImage") : null;
                const logo = result ? result.find(item=>item.name==="logo") : null;
                // const {item : subheadItem} = result.getFirstObjectByPropValue("name", "subheadImage");
                if(subheadItem){
                    inovateOSUtilActions({
                        [inovateOSUtilStrings.subheadImage] : 
                        store.getState().inovateOSUtilReducer[inovateOSUtilStrings.backendBaseUrl]+subheadItem.value
                    })(dispatch)
                }
                if(logo) headerActions({
                    [headerStrings.logo] : 
                    store.getState().inovateOSUtilReducer[inovateOSUtilStrings.backendBaseUrl]+logo.value
                })(dispatch);
                inovateOSUtilActions({
                    [inovateOSUtilStrings.settings] : result
                })(dispatch);
            }
            if(callback) callback(done, result, message);
        })
    },
    getUser : callback => dispatch => {
        inovateOSUtilServices.getUser((done, result, message)=>{
            if(done){
                inovateOSUtilActions({
                    [inovateOSUtilStrings.myProfile] : result ? result.myProfile : null
                })(dispatch);
            }
            if(callback) callback(done, result, message);
        })
    },
    signup : (data, callback) => dispatch => {
        inovateOSUtilServices.signup(data, (done, result, message)=>{
            const reducer = store.getState().inovateOSUtilReducer;
            if(done){
                _storeData(reducer[inovateOSUtilStrings.tokenAlias], result.myProfile.token);
                _storeData(reducer[inovateOSUtilStrings.userAlias], result._id);
                inovateOSUtilActions({
                    [inovateOSUtilStrings.myProfile] : result.myProfile,
                    [inovateOSUtilStrings.isLoggedIn] : inovateOSUtil.isLogedIn(),
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    login : (email, password, callback) => dispatch => {
        inovateOSUtilServices.login(email, password, (done, result, message)=>{
            const reducer = store.getState().inovateOSUtilReducer;
            if(done){
                _storeData(reducer[inovateOSUtilStrings.tokenAlias], result.myProfile.token);
                _storeData(reducer[inovateOSUtilStrings.userAlias], result._id);
                inovateOSUtilActions({
                    [inovateOSUtilStrings.myProfile] : result.myProfile,
                    [inovateOSUtilStrings.isLoggedIn] : inovateOSUtil.isLogedIn(),
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    logout : () => {
        const reducer = store.getState().inovateOSUtilReducer;
        localStorage.removeItem(reducer[inovateOSUtilStrings.tokenAlias]);
        localStorage.removeItem(reducer[inovateOSUtilStrings.userAlias]);
        inovateOSUtilActions({
            [inovateOSUtilStrings.isLoggedIn] : false
        })(store.dispatch);
    },
}
