import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Close } from '@material-ui/icons';
import ChatFooter from '../../ChatFooter';
import { Typography, ListItem, ListItemText, IconButton, List } from '@material-ui/core';
import { MessageBox } from '../../../MessageBox';
import { chatFooterStrings } from '../../config';
import { InputArea } from '../../../../Tracker/Contacts/Chats/InputArea';


const style = theme => ({
    root : {
        position : "fixed",
        bottom : 0,
        right : 1,
        width : ChatFooter.width,
        display : "flex",
        flexDirection : "column",
        transition : "height 2s",
        zIndex : 1000,
        maxHeight : "10cm",
    },
    container : {
        display : "flex",
        color : "white",
        padding : 10,
        borderRadius : "10px 10px 0 0",
        backgroundColor : "#515169",
    },
    grow : {
        display : "flex",
        flexGrow : 1,
    },
    chatContent : {
        display : "flex",
        flexDirection : "column",
        maxHeight: "5cm",
        minHeight : "5cm",
        overflow: "scroll",
        border: "solid .1px",
    },
    chatContainer : {
        display : "flex",
        flexDirection : "column",
        flexGrow : 1,
        height : "calc(100% - 50px)",
        overflow : "scroll"
    },
    input : {
        fontSize : 11,
        padding : 5,
    },
    message : {
        fontSize : 12,
        color : "black",
    }
})
class _ChatBox extends Component {
    constructor(props) {
        super(props);
        this.state = {
            hasHappend : false,
            expanded : false,
            lastId : null,
            rows : 100,
        }
    }
    componentDidMount() {
        this.containerScrollToBottom();
        const {
            dispatch, 
            _id , 
            [chatFooterStrings.getMessagesAction] : getMessagesAction,
            messages
        } = this.props;
        const {lastId, rows} = this.state;
        if(!messages && getMessagesAction)
            getMessagesAction(_id, lastId, rows)(dispatch);
    }
    
    static getDerivedStateFromProps(props, state) {
        if(!state.hasHappend && props.open){
            state.hasHappend = true;
            state.expanded = true;
        }
        return state;
    }
    componentDidUpdate(prevProps, prevState) {
        this.containerScrollToBottom();
    }
    containerScrollToBottom(messages){
        if(this.chatContainer){
            const scrollHeight = this.chatContainer.scrollHeight;
            const height = this.chatContainer.clientHeight;
            const maxScrollTop = scrollHeight - height;
            this.chatContainer.scrollTop = maxScrollTop > 0 ? maxScrollTop : 0;
        }
    }
    close = () => {
        const {close, _id} = this.props;
        if(close) close(_id, this);
    }
    expand(){
        this.setState(({expanded})=>({expanded : !expanded}))
    }
    sendMessage(message, context){
        if(!String(message.trim()))
            return;
        const {
            dispatch,
            _id, 
            [chatFooterStrings.sendMessageAction] : sendMessageAction,
        } = this.props;
        if(sendMessageAction) sendMessageAction(_id, message, done => {
            context.setState({sending : false});
            if(done) {
                context.setState({message : ""});
            }
        })(dispatch);
    }
    render() {
        let {
            classes, name, _id, right, messages, 
            [chatFooterStrings.chatBoxContentContainerProps] : containerProps,
            [chatFooterStrings.userId] : userId,
        } = this.props;
        const { expanded } = this.state;
        console.log(this.props);
        let style;
        if(expanded) style = {
            height : "auto",
        }; else style = {
            height : 0,
            minHeight : 0
        }
        if(containerProps){
            const {style : cStyle, ...othersContainerProps} = containerProps;
            if(cStyle) style = {...style, ...cStyle};
            containerProps = othersContainerProps;
        }
        return (
            <div className={classes.root} style={{right}}>
                <div className={classes.container} onClick={()=>this.expand()}>
                    <Typography style={{fontWeight : "bold"}} component="strong">{name}</Typography>
                    <div className={classes.grow}/>
                    <IconButton onClick={this.close.bind(this)} style={{padding : 0}}>
                        <Close style={{color: "white"}} fontSize="small"/>
                    </IconButton>
                </div>
                <div 
                    className={classes.chatContent} 
                    style={style} 
                    {...containerProps}>
                    <div ref={e=>this.chatContainer = e} className={classes.chatContainer}>
                        {messages && messages.map((item, index)=>
                            item.fromId === userId ? 
                                <MessageBox key={index} classes={{message : classes.message}} {...item}/> : 
                                <MessageBox key={index} classes={{message : classes.message}} small {...item} left/>
                        )}
                        {/* {this.containerScrollToBottom()} */}
                    </div>
                    <div className={classes.chatInputContainer}>
                        <InputArea
                            classes={{input : classes.input}}
                            small
                            sendMessage={this.sendMessage.bind(this)}/>
                    </div>
                </div>
            </div>
        );
    }
}


_ChatBox.propTypes = {
    classes : PropTypes.object.isRequired,
    right : PropTypes.number.isRequired,
    name : PropTypes.string.isRequired,
    id : PropTypes.number,
    close : PropTypes.func,
    open : PropTypes.bool,
    messages : PropTypes.array,
};
const mapStateToProps = ({chatFooterReducer}) => ({
    [chatFooterStrings.chatBoxContentContainerProps] : chatFooterReducer[chatFooterStrings.chatBoxContentContainerProps],
    [chatFooterStrings.userId] : chatFooterReducer[chatFooterStrings.userId],
    [chatFooterStrings.getMessagesAction] : chatFooterReducer[chatFooterStrings.getMessagesAction],
    [chatFooterStrings.sendMessageAction] : chatFooterReducer[chatFooterStrings.sendMessageAction],
})


export const ChatBox = connect(mapStateToProps)(withStyles(style)(_ChatBox));
export {ChatBox as default}