import { appConstants } from "../constants";
var initialState = {
    screenProgress : false,
    snackbar: {
        open : false,
        variant: '',
        message: ""
    },
    snackDialog : {
        open : false, 
        message : "",
        actions : null
    },
    userId : null,
    userToken : null,
    userType : 1,


    mySchools : null,
    mySchoolIds : null,
    myProfile : null,
    enrolledSchools : null,
    enrolledSchoolIds : null,
    lastNotificationId : null,
    notifications : null,
    messages : null,
    schoolInfo : null,
    schoolSecret : null,
    subscribers : null,
    notificationCounts : null,
    pushedNotificationIds : null
    // booted : false
}

export const appReducer = (state = initialState, action)=> {
    const {type , payload} = action;
    switch (type) {
        case appConstants.UNSET_PUSHED_NOTIFICATION_IDS : 
            return {...state, pushedNotificationIds : null};
        case appConstants.SET_PUSHED_NOTIFICATION_IDS : 
            let pushedNotificationIds = {...state.pushedNotificationIds};
            if(!pushedNotificationIds || !pushedNotificationIds[payload.schoolId]) 
                pushedNotificationIds = {
                    [payload.schoolId] : payload.data
            }; else pushedNotificationIds[payload.schoolId] = payload.data;
            return {...state, pushedNotificationIds};
        case appConstants.SET_NOTIFICATION_COUNTS :
            let notificationCounts = {...state.notificationCounts};
            if(!notificationCounts) notificationCounts ={
                [payload.schoolId] : payload.count
            }; else notificationCounts[payload.schoolId] = payload.count;
            return {...state, notificationCounts};
        case appConstants.SET_LAST_NOTIFICATION_ID : 
            let lastNotificationId = {...state.lastNotificationId};
            if(!lastNotificationId) lastNotificationId = {
                [payload.schoolId] : payload.id
            };else lastNotificationId[payload.schoolId] = payload.id;
            return {...state, lastNotificationId};
        case appConstants.SET_SUBSCRIBERS : 
            let subscribers = {...state.subscribers};
            if(subscribers) subscribers[payload.schoolId] = payload.users
            else subscribers = {[payload.schoolId] : payload.users};
            return {...state, subscribers};
        case appConstants.SET_SCHOOL_SECRET : 
            return {...state, schoolSecret : payload}; 
        case appConstants.SET_SCHOOL_INFO :
            let schoolInfo;
            if(!state.schoolInfo) schoolInfo = {[payload._id] : payload};
            else schoolInfo= {...state.schoolInfo, [payload._id] : payload};
            return {...state, schoolInfo};
        case appConstants.UPDATE_SCHOOL_MESSAGES : 
            let upMsg = {...state.messages};
            if(!upMsg || !upMsg[payload.schoolId]) upMsg = {
                [payload.schoolId] : payload.data
            }
            else upMsg[payload.schoolId].unshift(...payload.data);
            return {...state, messages : upMsg};
        case appConstants.ADD_SCHOOL_MESSAGE : 
            let addMsg = {...state.messages};
            if(!addMsg || !addMsg[payload.schoolId]) addMsg = {
                [payload.schoolId] : payload.data
            }
            else addMsg[payload.schoolId].push(payload.data);
            return {...state, messages : addMsg};
        case appConstants.SET_SCHOOL_MESSAGES : 
            let messages = {...state.messages};
            if(!messages) messages = {
                    [payload.schoolId] : payload.data
                }
            else messages[payload.schoolId] = payload.data;
            return {...state, messages};
        case appConstants.UPDATE_NEW_SCHOOL_NOTIFICATION : 
            let newNotif = {...state.notifications};
            if(!newNotif || !newNotif[payload.schoolId]) newNotif = {
                [payload.schoolId] : payload.data
            }; else newNotif[payload.schoolId].push(...payload.data);
            return {...state, notifications: newNotif};
        case appConstants.UPDATE_SCHOOL_NOTIFICATIONS : 
            let notif = {...state.notifications};
            if(!notif) notif = {
                    [payload.schoolId] : payload.data
                }
            else notif[payload.schoolId].unshift(...payload.data);
            return {...state, notif};
        case appConstants.SET_SCHOOL_NOTIFICATIONS : 
            let notifications = {...state.notifications};
            notifications = {
                    [payload.schoolId] : payload.data
                }
            return {...state, notifications};
        case appConstants.SET_INITIAL_LAST_NOTIFICATION_IDS : 
            return {...state, lastNotificationId : payload};
        case appConstants.SET_ENROLLED_SCHOOLIDS: 
            return {...state, enrolledSchoolIds: payload};
        case appConstants.SET_ENROLLED_SCHOOLS : 
            return {...state, enrolledSchools : payload}
        case appConstants.SET_MY_PROFILE : 
            return {...state, myProfile : payload};
        case appConstants.SET_MY_SCHOOLS : 
            return {...state, mySchools : payload};
        case appConstants.SET_MY_SCHOOL_IDS : 
            return {...state, mySchoolIds : payload};
        case appConstants.SET_BOOT_STATUS : 
            return {...state, booted: true};

        case appConstants.TOOGLE_SCREEN_PROGRESS : 
            return {...state, screenProgress : payload};
        case appConstants.USER_LOGOUT : 
            return initialState;
        case appConstants.TOGGLE_SNACK_DIALOG : 
            return {...state, snackDialog: payload}
        case appConstants.SNACKBAR_OPEN : 
            return {...state, snackbar : payload};
        case appConstants.SNACKBAR_CLOSE : 
            return {...state, snackbar : {...state.snackbar, message: '', open: false}};
        default:
            return state;
    }
}