export const inovateOSPageStrings = {
    carousel : "carousel",
    homeInfo : "homeInfo",
    services : "services",
    aboutUs : "aboutUs",
    attributes : "attributes",
}
export const inovateOSPageConstants = {
    SET_INOVATE_OS_PAGE: "SET_INOVATE_OS_PAGE",
}
export const inovateOSPageReducer = (state = {}, action)=>{
    const {payload, type} = action;
    switch(type){
        case inovateOSPageConstants.SET_INOVATE_OS_PAGE : 
            return {...state, ...payload};
        default : return state;
    }
}
export * from './actions';
export * from './services';