import { inovateOSAdminNewsletterConstants, inovateOSAdminNewsletterStrings } from "./config";
import { inovateOSAdminNewsletterServices } from "./services";
import { errorNotice, successNotice } from "../utils";

export const inovateOSAdminNewsletterActions = {
    getNewsletters : (lastId, rows, callback) => dispatch => {
        inovateOSAdminNewsletterServices.getNewsletters(lastId, rows, (done, result, message)=>{
            if(done) {
                inovateOSAdminNewsletterActions.payload({
                    [inovateOSAdminNewsletterStrings.newsletters] : result
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    addNewsletter : (data, callback)=>dispatch => {
        inovateOSAdminNewsletterServices.addNewsletter(data, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getSubscribers : (lastId, rows, callback) => dispatch => {
        inovateOSAdminNewsletterServices.getNewsletterSubscribers(lastId, rows, (done, result, message)=>{
            if(done){
                inovateOSAdminNewsletterActions.payload({
                    [inovateOSAdminNewsletterStrings.subscribers] : result
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch => dispatch({
        type : inovateOSAdminNewsletterConstants.SET_INSURE_ADMIN_NEWSLETTER,
        payload
    })
}