import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { invProductStrings } from '../config';
import { invProductActions } from '../actions';
import { Grid, FormControlLabel, Checkbox, Button } from '@material-ui/core';
import { MyListCard } from '../../utils';


const style = theme => ({
    root: {

    }
})
class _ItemSelection extends Component {
    constructor(props) {
        super(props);
        this.state = {
            selectedCategory : null,
            data : {},
            selectedItems : [],
        }
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {
            dispatch,
            [invProductStrings.stockCategories] : stockCategories,
        } = this.props;
        if(!stockCategories) invProductActions.getStockCategories()(dispatch);
    }
    listItemClick = (item, index) => {
        const{dispatch} = this.props;
        invProductActions.getStockCategoryItems(item._id)(dispatch);
        this.setState({selectedCategory: item});
    }
    continueBtnHandler = () => {
        const {continueAction} = this.props;
        const {data, selectedItems} = this.state;
        if(continueAction) continueAction(data, selectedItems);
    }
    checkBtnHandler = (categoryId, itemId) => e => {
        const {
            [invProductStrings.stockCategoryItems] : stockCategoryItems,
        } = this.props;
        const checked = e.target.checked;
        let {data, selectedItems} = this.state;
        data = data ? {...data} : {};
        selectedItems = selectedItems ? [...selectedItems] : [];
        //put this in state 
        if(data[categoryId]){
            checked ? data[categoryId].push(itemId) : 
                data[categoryId].splice(data[categoryId].indexOf(itemId), 1);
            data[categoryId] = [...data[categoryId]];
        }
        else data[categoryId] = [itemId];

        if(checked){
            const {item : catItem} = stockCategoryItems.getFirstObjectByPropValue("_id", itemId);
            if(catItem) selectedItems.push(catItem);
        }else {
            const {item: includedItem, index  : includedIndex} = selectedItems.getFirstObjectByPropValue("_id", itemId);
            if(includedItem) selectedItems.splice(includedIndex, 1);
        }
        this.setState({data, selectedItems});
    }
    render() {
        const {
            classes,
            [invProductStrings.stockCategories] : stockCategories,
            [invProductStrings.stockCategoryItems] : stockCategoryItems,
            closeDialog
        } = this.props;
        const { selectedCategory, data } = this.state;
        return (
            <Grid container spacing={2} className={classes.root}>
                <Grid container spacing={2}>
                    <Grid item xs={12} sm={4} md={4} lg={4} xl={4}>
                        <MyListCard
                            title="Categories"
                            elevation={0}
                            list={stockCategories}
                            listItemProps={{button : true}}
                            listItemClick={this.listItemClick.bind(this)}
                            itemNameProp="name"/>
                    </Grid>
                    <Grid item xs={12} sm={8} md={8} lg={8} xl={8}>
                        <MyListCard
                            title="Items"
                            elevation={0}
                            list={stockCategoryItems}
                            itemNameProp="name"
                            listProps={{ style : {
                                minHeight : "10cm",
                                overflow : "scroll"
                            }}}
                            component={props=><FormControlLabel
                                label={props.name}
                                control={<Checkbox 
                                    checked={selectedCategory &&
                                        data[selectedCategory._id] && 
                                        data[selectedCategory._id].indexOf(props._id) !== -1}
                                    onChange={this.checkBtnHandler(
                                        selectedCategory && selectedCategory._id,
                                        props._id
                                    )}/>}
                                />}
                            />
                        {!selectedCategory &&
                        <div> Select a category!</div>}
                    </Grid>
                </Grid>
                <Grid item xs={12} sm={12} md={12} lg={12} xl={12}>
                    <Button onClick={closeDialog} variant="outlined" color="secondary">Cancel</Button>
                    <Button onClick={this.continueBtnHandler.bind(this)} style={{marginLeft : 20}} variant="outlined" color="primary">Continue</Button>
                </Grid>
            </Grid>
        );
    }
}



_ItemSelection.propTypes = {
    classes : PropTypes.object.isRequired,
    closeDialog : PropTypes.func,
    continueAction : PropTypes.func,
};
const mapStateToProps = ({invProductReducer}) => ({
    [invProductStrings.stockCategories] : invProductReducer[invProductStrings.stockCategories],
    [invProductStrings.stockCategoryItems] : invProductReducer[invProductStrings.stockCategoryItems],
})


export const ItemSelection = connect(mapStateToProps)(withStyles(style)(_ItemSelection));
export {ItemSelection as default}