export const contactStrings = {
    userLocationHx : "userLocationHx",
    pageDisplay : "pageDisplay",
    contacts : "contacts",
    messages : "messages",
    contactId : "contactId",
}
export const contactConstants = {
    SET_CONTACT : "SET_CONTACT",
}

export const contactReducer = (state={
    [contactStrings.pageDisplay] : 1
}, action)=>{
    const {type, payload} = action;
    switch(type){
        case contactConstants.SET_CONTACT :
            return {...state, ...payload};

        default : return {...state};
    }
}

export * from './actions';
export * from './services';