import { inventoryUtilConstants, inventoryUtilStrings } from "./config";
import { inventoryUtilServices } from "./services";
import { inventoryMenuItem2, inventoryMenuItem } from "../menuItems";
import {_inventoryStoreData as _storeData, invErrorNotice as errorNotice, headerStrings, headerActions, store } from "./inventoryUtil";


export const inventoryUtilActions = payload => dispatch => dispatch({
    type : inventoryUtilConstants.SET_UTIL,
    payload 
});

export const inventoryActions = {
    getUser : callback => dispatch => {
        inventoryUtilServices.getUser((done, result, message)=>{
            if(done){
                userInitialisation(result, dispatch);
            }
            if(callback) callback(done, result, message);
        })
    },
    // signup : (data, callback) => dispatch => {
    //     inventoryUtilServices.signup(data, (done, result, message)=>{
    //         if(done){
    //             _storeData([inventoryUtilStrings.tokenAlias], result.myProfile.token);
    //             _storeData([inventoryUtilStrings.userAlias], result._id);
    //             inventoryUtilActions({
    //                 [inventoryUtilStrings.myProfile] : result.myProfile,
    //             })(dispatch);
    //         }else errorNotice(message, dispatch);
    //         if(callback) callback(done, result, message);
    //     })
    // },
    loging : (email, password, callback) => dispatch => {
        inventoryUtilServices.login(email, password, (done, result, message)=>{
            if(done){
                userInitialisation(result, dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    logout : () => {
        const reducer = store.getState().inventoryUtilReducer;
        inventoryUtilActions({
            [inventoryUtilStrings.myProfile] : null
        })(store.dispatch);
        headerActions({
            [headerStrings.menuItems] : inventoryMenuItem
        })(store.dispatch);
        localStorage.removeItem(reducer[inventoryUtilStrings.tokenAlias]);
        localStorage.removeItem(reducer[inventoryUtilStrings.userAlias]);
    },
}
const userInitialisation = ({_id, myProfile}, dispatch) => {
    const reducer = store.getState().inventoryUtilReducer;
    _storeData(reducer[inventoryUtilStrings.tokenAlias], myProfile.token);
    _storeData(reducer[inventoryUtilStrings.userAlias], _id);
    inventoryUtilActions({
        [inventoryUtilStrings.myProfile] : myProfile,
    })(dispatch);
    if(myProfile && [0, 11].indexOf(myProfile.privilege) !== -1){
        headerActions({
            [headerStrings.menuItems] : inventoryMenuItem2
        })(dispatch);
    }
}