import React, { PureComponent } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { Typography } from '@material-ui/core';
const style = theme => ({
    root: {
        height : 100,
        position : "relative",
        width : "100vw",
    },
    overlay : {
        position : "absolute",
        zIndex : 1000,
        left : 0,
        top : 0,
        height : "100%",
        width : "100%",
        backgroundColor : "#808080c2",
        display : "flex",
        flexDirection : "column",
        justifyContent : "flex-end",
    },
    title :{
        color : "white",
        fontWeight : "bold",
        padding: 20,
    }
})
class _Subheader extends PureComponent {
    changeBG(){
        this.refs.subhead.style.background = "url("+this.props.image_url+") no-repeat center center /cover";
    }
    
    render() {
        const {classes, title} = this.props;
        return (
            <div ref="subhead" className={classes.root} {...this.props.containerProps}
                style={{
                    background : "url("+this.props.image_url+") no-repeat center center /cover"
                }}>
                <div className={classes.overlay}>
                    <Typography variant="h5" paragraph className={classes.title} {...this.props.titleProps}>
                        {title}
                    </Typography>
                </div>
            </div>
        );
    }
}
_Subheader.propTypes = {
    classes : PropTypes.object.isRequired,
    containerProps : PropTypes.object,
    image_url : PropTypes.string,
    title : PropTypes.string,
};
export const Subheader = withStyles(style)(_Subheader);