import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { inovateOSUtilStrings, inovateOSUtil } from '../../utils';
import { Phone, Home, Email, Schedule } from '@material-ui/icons';
import { Typography } from '@material-ui/core';


const style = theme => ({
    root: {
    },
    container : {
        display : "flex",
        flexDirection : "column",
        padding : 20,
    },
    item : {
        display : 'flex',
        alignItems : "center",
        padding : 10,
    },
    header : {
        fontWeight : "bold",
        fontSize : 16,
        color : inovateOSUtil.getTheme().secondary,
    },
    icon : {
        color : inovateOSUtil.getTheme().secondary,
    },
    text : {
        paddingLeft : 10,
        color : inovateOSUtil.getTheme().wheat
    }
})
class _ContactUs extends Component {
    render() {
        const {classes, [inovateOSUtilStrings.settings] : settings} = this.props;
        let contactInfo, phone, address, email;
        if(settings) contactInfo = settings.find(item => item.name === "contactInfo");
        if(contactInfo && contactInfo.value) {
            const {value} = contactInfo
             phone = value.phone;
             address = value.address;
             email = value.email;
        }
        return (
            <div className={classes.root}>
                <div className={classes.container}>
                    <Typography paragraph className={classes.header}>Contact Us</Typography>
                    <div className={classes.item}>
                        <Phone className={classes.icon}/>  
                        <Typography className={classes.text}>
                            {phone}
                        </Typography>
                    </div>
                    <div className={classes.item}>
                        <Home className={classes.icon}/>  
                        <Typography className={classes.text}>
                            {address}
                        </Typography>
                    </div>
                    <div className={classes.item}>
                        <Email className={classes.icon}/>  
                        <Typography className={classes.text}>
                            {email}
                        </Typography>
                    </div>
                    <div className={classes.item}>
                        <Schedule className={classes.icon}/>  
                        <Typography className={classes.text}>
                            Working Days/Hours: Mon - Fri / 9:00 AM - 5:30 PM
                        </Typography>
                    </div>
                </div>
            </div>
        );
    }
}


_ContactUs.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({inovateOSUtilReducer}) => ({
    [inovateOSUtilStrings.settings] : inovateOSUtilReducer[inovateOSUtilStrings.settings],
})


export const ContactUs = connect(mapStateToProps)(withStyles(style)(_ContactUs));
export {ContactUs as default}