export const agroAdminUtilStrings = {
    theme : "theme",
    tokenAlias : "tokenAlias",
    userAlias : "userAlias",
    backendUrl : "backendUrl",
    myProfile : "myProfile",
    trackingMe : "trackingMe",
    disableAllTracking : "disableAllTracking",
}

export const agroAdminUtilConstants = {
    SET_UTIL : "SET_UTIL",
}

export const agroAdminUtilReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case agroAdminUtilConstants.SET_UTIL : 
            return {...state, ...payload};
        default : return {...state};
    }
}

