
import React, { PureComponent } from 'react'
import { withStyles, Dialog, IconButton } from '@material-ui/core';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { Close } from '@material-ui/icons';
const styles = theme => ({
    dialogPaper : {
        minHeight : 100,
        width : "70%",
        padding : 20,
        [theme.breakpoints.down("xs")] : {
            width : "100%"
        }
    },
    close : {
        position : "absolute",
        top : 20,
        right : 20,
        zIndex : 1100
    }
})
class _MyDialog extends PureComponent {
    static propTypes = {
        open : PropTypes.bool.isRequired,
    }
    render() {
        const {classes, children, open, close} = this.props;
        return (
            <Dialog classes={{paper : classNames(classes.dialogPaper)}} open={open}>
                    {close && <IconButton className={classes.close} onClick={close}>
                        <Close color="secondary"/>
                    </IconButton>}
                    {children}
            </Dialog>
        )
    }
}
_MyDialog.propTypes = {
    classes : PropTypes.object.isRequired,
    close : PropTypes.func,
}
export const MyDialog = withStyles(styles)(_MyDialog);
export {MyDialog as default};