import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import {Link} from 'react-router-dom';
import { insureAdminNewsletterActions } from '../actions';
import { MyTable } from '../../../includes';
import { insureAdminNewsletterStrings } from '../config';
import { TableCell, Typography } from '@material-ui/core';
import { insureAdminRouteNames } from '../../routeNames';


const style = theme => ({
    root: {
    },
    cell : {
        padding : 5,
    },
    cellBtn : {
        padding : 0,
        textTransform : "lowercase",
    }
})
class _Subscribers extends Component {
    constructor(props) {
        super(props);
        this.state = {
            lastId : null,
            rows : 20
        }
    }
    componentDidMount() {
        const {dispatch} = this.props;
        const {lastId, rows} = this.state;
        insureAdminNewsletterActions.getSubscribers(lastId, rows)(dispatch);
    }
    cellMapFormat = props => ({row, cellMap})=> {
        const {classes} = this.props;
        switch(cellMap){
            case "action" : return <TableCell className={classes.cell}>
                <a href={insureAdminRouteNames.newsletterUnsub_+row._id+"?from="+insureAdminRouteNames.newsletter}>Unsubscribe</a>
            </TableCell>;
            default : return <TableCell className={classes.cell}>
                <Typography style={{fontSize : 12}}>{row[cellMap]}</Typography>
            </TableCell>
        }
    }
    render() {
        const {
            classes,
            [insureAdminNewsletterStrings.subscribers] : subscribers
        } = this.props;
        return (
            <div className={classes.root}>
                <MyTable
                    header={["ID", "Name", "Email", "Actions"]}
                    dataMap={["_id", "name", "email", "action"]}
                    data={subscribers}
                    CellMap={this.cellMapFormat({})}
                    />
            </div>
        );
    }
}


_Subscribers.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({insureAdminNewsletterReducer}) => ({
    [insureAdminNewsletterStrings.subscribers] : insureAdminNewsletterReducer[insureAdminNewsletterStrings.subscribers],
})


export const Subscribers = connect(mapStateToProps)(withStyles(style)(_Subscribers));
export {Subscribers as default}