import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Collapse, Paper, ListItem } from '@material-ui/core';
import {Link} from 'react-router-dom';
import { headerStrings } from '../strings';


const style = theme => ({
    root: {
        
    },
    paper : {
    },
    linkItem : {
    }
})
class _SubheaderMenu extends Component {
    render() {
        const {
            classes,
            [headerStrings.subheaderRibbon] : subheaderRibbon,
            [headerStrings.subheaderRibbonOffsetLeft] : subheaderRibbonOffsetLeft,
            [headerStrings.subheaderRibbonName] : subheaderRibbonName,
            [headerStrings.offsetHeight] : offsetHeight,
            [headerStrings.subheaderRibbonFullWidth] : fullWidth,
            [headerStrings.menuItems] : menuItems,
        } = this.props;
        let item; 
        if(menuItems){
            item = menuItems.find(item=>item.name===subheaderRibbonName && item.tree);
        }
        if(!item)
            return null;
        return (
            <div className={classes.root}
                style={{
                    minWidth : "3cm",
                    position : !fullWidth && "absolute",
                    left : subheaderRibbonOffsetLeft,
                    top : offsetHeight || 78,
                }}>
                <Collapse                     
                    className={classes.collapse} in={subheaderRibbon}>
                    <Paper style={{
                        borderRadius : 0,
                        padding : 10,
                    }} elevation={4} className={classes.paper}>
                        {item.tree.map((item, index)=>{

                            return <ListItem 
                                style={{
                                    padding : 5
                                }}
                                key={index}>
                                <Link
                                key={index}
                                className={classes.linkItem}
                                to={item.pathname}>
                                    {item.name}
                                </Link>
                            </ListItem>
                        })}
                    </Paper>
                </Collapse>
            </div>
        );
    }
}


_SubheaderMenu.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({headerReducer}) => ({
    [headerStrings.subheaderRibbon] : headerReducer[headerStrings.subheaderRibbon],
    [headerStrings.subheaderRibbonOffsetLeft] : headerReducer[headerStrings.subheaderRibbonOffsetLeft],
    [headerStrings.subheaderRibbonName] : headerReducer[headerStrings.subheaderRibbonName],
    [headerStrings.offsetHeight] : headerReducer[headerStrings.offsetHeight],
    [headerStrings.subheaderRibbonFullWidth] : headerReducer[headerStrings.subheaderRibbonFullWidth],
    [headerStrings.menuItems] : headerReducer[headerStrings.menuItems],
})


export const SubheaderMenu = connect(mapStateToProps)(withStyles(style)(_SubheaderMenu));
export {SubheaderMenu as default}