export const productStrings = {
    productItemTags : "productItemTags",
    itemConfigTabValue : "itemConfigTabValue",
    itemConfigComponent : "itemConfigComponent",
    itemConfigEditMode : "itemConfigEditMode",
    itemForms : "itemForms",
    itemPackages : "itemPackages",
    itemPackagings : "itemPackagings",
    item : "item",
    stockCategories : "stockCategories",
    stockCategoryItems : "stockCategoryItems", 
    productDescriptions : "productDescriptions",
}
export const productConstants = {
    SET_PRODUCT : "SET_PRODUCT",
    CLEAN_UP_PRODUCT :"CLEAN_UP_PRODUCT",
}
const productInitialState = {

}
export const productReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case productConstants.SET_PRODUCT : 
            return {...state, ...payload};
        case productConstants.CLEAN_UP_PRODUCT : 
            return {...state, ...productInitialState}
        default : return {...state};
    }
}
export * from './actions';
export * from './services';
