import { socketIO } from "../../../socket.io"

export const contactServices = {
    getMyOnlineContacts : callback => {
        socketIO.emit("getMyOnlineContacts", {});
        socketIO.on("getMyOnlineContacts", ({getMyOnlineContacts, result, message})=>{
            callback(getMyOnlineContacts, result, message);
        })
    },
    sendMessage : (contactId, message, callback)=>{
        socketIO.emit("newMessage", {contactId, message});
        socketIO.on("newMessage", ({newMessage, result, message})=>{
            callback(newMessage, result, message);
        })
    },
    getMessages : (contactId, lastId, rows, callback) => {
        socketIO.emit("getMessages", {contactId, lastId, rows});
        socketIO.on("getMessages", ({getMessages, result, message, data})=>{
            callback(getMessages, result, message, data);
        })
    },
    disableAllTracking : (option, callback) => {
        socketIO.emit("disableAllTracking", {option});
        socketIO.on("disableAllTracking", ({disableAllTracking, result, message, data})=>{
            callback(disableAllTracking, result, message, data);
        })
    },
    disableTracking : (contactId, callback) => {
        socketIO.emit("disableTracking", {contactId});
        socketIO.on("disableTracking", ({disableTracking, result, message, data})=>{
            callback(disableTracking, result, message, data);
        })
    },
    allowTracking : (contactId, callback) => {
        socketIO.emit("allowTracking", {contactId});
        socketIO.on("allowTracking", ({allowTracking, result, message})=>{
            callback(allowTracking, result, message);
        })
    },
    getContacts : callback => {
        socketIO.emit("getContacts");
        socketIO.on("getContacts", ({getContacts, result, message})=>{
            callback(getContacts, result, message);
        })
    },
    addNewContact : (phone, callback)=>{
        socketIO.emit("addNewContact", {phone});
        socketIO.on("addNewContact", ({addNewContact, result, message})=>{
            callback(addNewContact, result, message);
        });
    },
    getUserLocationHx : (userId, callback) => {
        callback(true, [
            {
                userId : 1,
                date : new Date(),
                lat : 9.076479, 
                lng : 7.398574
            },
            {
                userId : 2,
                date : new Date(),
                lat : 12.076479, 
                lng : 7.398574
            },
            {
                userId : 3,
                date : new Date(),
                lat : 11.076479, 
                lng : 7.398574
            },
        ])
    }
}