import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { TextField, Typography, Button } from '@material-ui/core';
import { inovateOSRouteNames } from '../routeNames';


const style = theme => ({
    root: {
    },
    container:{
        display : "flex",
        flexDirection : "column",
        alignItems : "center",
        marginTop : 20,
    }
})
class _Unsubscribe extends Component {
    constructor(props) {
        super(props);
        console.log(props);
        this.state = {
            email : "",
            loading : false,
        }
        this.subId = props.match.params.id;
        const search = props.location.search;
        this.from = search ? String(search).substr(search.indexOf("=")+1) : null;
        console.log(this.from);
    }
    unsubscribe() {
        const {dispatch} = this.props;
        const {email} = this.state;
        this.setState({loading :true})
        
    }
    onChange = name => e => {
        const value = e.target.value;
        this.setState({[name] : value});
    }
    render() {
        const {classes} = this.props;
        const {email, loading} = this.state;
        return (
            <div className={classes.root}>
                <div className={classes.container}>
                    <Typography variant="h4">UNSUBSCRIBE</Typography>
                    <Typography>Type in your email address to unsubscribe</Typography>
                    <TextField
                        value={email}
                        margin="normal"
                        label="Email"
                        placeholder="Email"
                        onChange={this.onChange("email")}
                        />
                    <Button color="secondary" 
                        onClick={this.unsubscribe.bind(this)}
                        disabled={loading}
                        variant="contained">
                            Unsubscribe
                        </Button>
                </div>
            </div>
        );
    }
}


_Unsubscribe.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = state => ({
    state
})


export const Unsubscribe = connect(mapStateToProps)(withStyles(style)(_Unsubscribe));
export {Unsubscribe as default}