export const studentStrings = {
    showAllStudents : "showAllStudents",
    selectedLevel : "selectedLevel",
    selectedClass : "selectedClass",
    studentProfile: "studentProfile",
    students : "students",
    studentForm : "studentForm",
    parentForm : "parentForm",
    studentGroupForm : "studentGroupForm",
}
export const studentConstant = {
    SET_STUDENT : "SET_STUDENT",
    CLEAN_UP_STUDENT : "CLEAN_UP_STUDENT"
}
export const studentReducer = (state = {}, action) => {
    const {type, payload} = action;
    switch(type) {
        case studentConstant.SET_STUDENT :
            return {...state, ...payload};
        case studentConstant.CLEAN_UP_STUDENT :
            return {};
        default : return {...state};
    }
}
export const nameMapper = (name)=>{
    switch(name){
        case "currentSessionLevel" : return "Current Level";
        case "currentSessionClass" : return "Current Class";
        case "lastLevelPosition" : return "Last Level Position";
        case "lastClassPosition" : return "Last Class Position";
        case "name" : return "Name";
        case "number" : return "Number";
        case "bank" : return "Bank";
        case "lastName" : return "Last Name";
        case "firstName" : return "First Name";
        case "middleName" : return "Middle Name";
        case "dob" : return "Date of Birth";
        case "address" : return "Address";
        case "city" : return "City";
        case "state" : return "State";
        case "country" : return "Country";
        case "gender" : return "Gender";
        case "email" : return "Email";
        case "phone" : return "Phone";
        default : return name;
    }
}
