import { sessionServices } from "../Sessions";
import { timeTableConstant, timeTableStrings } from "./config";
import { timeTableServices } from "./services";
import { subjectServices } from "../Subjects";

export const timeTableActions = {
    setTabComponent : component => dispatch => dispatch({
        type : timeTableConstant.SET_TIMETABLE,
        payload : {
            [timeTableStrings.tabComponent] : component
        }
    }),
    setTabValue : tabValue => dispatch => dispatch({
        type : timeTableConstant.SET_TIMETABLE,
        payload : {
            [timeTableStrings.tabValue] : tabValue
        }
    }),
    getSubjects : (levelId, termId, callback)=>dispatch=>{
        subjectServices.getLevelTermSubjects(levelId, termId, (done, result, message)=>{
            if(done)dispatch({
                type : timeTableConstant.SET_TIMETABLE,
                payload : {
                    [timeTableStrings.subjects] : result
                }
            });
            if(callback)callback(done,result, message);
        })
    },
    getTimeTableDurationFormat : (levelId, termId, callback) => dispatch=>{
        timeTableServices.getTimeTableDurationFormat(levelId, termId, (done, result, message)=>{
            if(done)dispatch({
                type : timeTableConstant.SET_TIMETABLE,
                payload : {
                    [timeTableStrings.timeTableDurationFormat] : result,
                }
            });
            if(callback) callback(done, result, message);
        });
    },
    setTimeTableEditeMode : mode => dispatch => dispatch({
        type : timeTableConstant.SET_TIMETABLE,
        payload : {
            [timeTableStrings.timeTableEditMode] : mode
        }
    }),
    getTerms : (levelId, callback)=>dispatch=>{
        sessionServices.getSessionTerms(null, (done, result, message)=>{
            if(done) dispatch({
                type : timeTableConstant.SET_TIMETABLE,
                payload : {
                    [timeTableStrings.terms] : result
                }
            });
            if(callback) callback(done, result, message);
        })
    },
    setSelectedTerm : (term) => dispatch => dispatch({
        type : timeTableConstant.SET_TIMETABLE,
        payload : {
            [timeTableStrings.selectedTerm] : term
        }
    }),
    getLevels : (callback) => dispatch => {
        sessionServices.getSessionLevels(null, (done, result, message)=>{
            if(done)dispatch({
                type : timeTableConstant.SET_TIMETABLE,
                payload : {
                    [timeTableStrings.levels] : result
                }
            })
            if(callback) callback(done, result, message);
        })
    },
    setSelectedLevel : selectedLevel => dispatch => dispatch({
        type : timeTableConstant.SET_TIMETABLE,
        payload : {
            [timeTableStrings.selectedLevel] : selectedLevel
        }
    }),
}