import { socketIOStrings, socketIOConstants } from './config';
import { store } from '../helpers';
let handledSockets = [];
export const socketSubscription = function(){
    store.subscribe(()=>{
        const reducer = store.getState().socketIOReducer;
        const socket =  reducer[socketIOStrings.socket];
        const socketEmitQueeue = reducer[socketIOStrings.socketEmitQueeue];
        const socketOnQueeue = reducer[socketIOStrings.socketOnQueeue];
        if(socket){
            if(socketEmitQueeue){
                 for (let i = 0; i < socketEmitQueeue.length; i++) {
                    const emitObj = socketEmitQueeue[i];
                    const onObj = socketOnQueeue[i];
                    socketIO.emit(emitObj.action, emitObj.data);
                    socketEmitQueeue.splice(i, 1);
                    if(onObj){
                        console.log("emitting", onObj.action);
                        socketIO.on(onObj.action, onObj.callback);
                        socketOnQueeue.splice(i, 1);
                    }
                }
                if(socketEmitQueeue.length !== 0){
                    store.dispatch({
                        type : socketIOConstants.SET_SOCKETIO,
                        payload : {
                            [socketIOStrings.socketEmitQueeue] : [...socketEmitQueeue],
                            [socketIOStrings.socketOnQueeue] : [...socketOnQueeue]
                        }
                    });
                }
            }
        }
    });
}
export const socketIO = {
    emit : (action, data, callback) => {
        const reducer = store.getState().socketIOReducer;
        const socket =  reducer[socketIOStrings.socket];
        if(socket){
            socket.emit("app", action, data, callback);
        }
        else{
            let emitQueeue = reducer[socketIOStrings.socketEmitQueeue] || [];
            store.dispatch({
                type : socketIOConstants.SET_SOCKETIO,
                payload : {
                    [socketIOStrings.socketEmitQueeue] : [...emitQueeue, {action, data}]
                }
            })
        }
    },
    on : (action, callback)=>{
        const reducer = store.getState().socketIOReducer;
        const socket =  reducer[socketIOStrings.socket];
        if(socket){
            if(handledSockets.indexOf(action) === -1){
                socket.on(action, callback);
                handledSockets.push(action);
            }
        }
        else {
            let onQueeue = reducer[socketIOStrings.socketOnQueeue] || [];
            store.dispatch({
                type : socketIOConstants.SET_SOCKETIO,
                payload : {
                    [socketIOStrings.socketOnQueeue] : [...onQueeue, {action, callback}]
                }
            });
        }
    }
};