import { hirAccountConstant, hirAccountStrings } from "./config";
import { hirAccountServices } from "./services";
import { errorNotice, successNotice } from "../../../utils";
import { hirPatientServices } from "../HIRPatients";
import { store } from "../../../helpers";

export const hirAccountActions = {
    updatePayment : (paymentId, data, callback) => dispatch => {
        hirAccountServices.updatePayment(paymentId, data, (done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            else successNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    deletePayment : (paymentId, groupId, callback) => dispatch => {
        hirAccountServices.deletePayment(paymentId, groupId, (done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            else successNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    searchPaymentsByPatient : (keyword, callback) => dispatch => {
        hirAccountServices.searchPaymentsByPatient(keyword, (done, result, message)=>{
            if(done){
                hirAccountActions.payload({
                    [hirAccountStrings.payments] : result
                })(dispatch)
            }else errorNotice(message, dispatch);
            if(callback)callback(done, result, message);
        })
    },
    searchPaymentsByDate : (year, month, day, callback) => dispatch => {
        hirAccountServices.searchPaymentsByDate(year, month, day, (done, result, message)=>{
            if(done){
                hirAccountActions.payload({
                    [hirAccountStrings.payments] : result
                })(dispatch)
            }else errorNotice(message, dispatch);
            if(callback)callback(done, result, message);
        })
    },
    getPaymentByUserIdAndDate : (userId, year, month, day, callback)=> dispatch =>{
        hirAccountServices.getPaymentByUserIdAndDate(
            userId, year, month, day,
            (done, result, message)=>{
                if(done){
                    hirAccountActions.payload({
                        [hirAccountStrings.viewDetailPayments] : result
                    })(dispatch);
                }else errorNotice(message, dispatch);
                if(callback) callback(done, result, message);
            }
        )
    },
    getPaymentByRevenueTypeAndDate : (revenueName, year, month, day, callback)=> dispatch =>{
        hirAccountServices.getPaymentByRevenueTypeAndDate(
            revenueName, year, month, day,
            (done, result, message)=>{
                if(done){
                    hirAccountActions.payload({
                        [hirAccountStrings.viewDetailPayments] : result
                    })(dispatch);
                }else errorNotice(message, dispatch);
                if(callback) callback(done, result, message);
            }
        )
    },
    getUserPaymentsByDate : (year, month, day, callback) => dispatch =>{
        hirAccountServices.getUserPaymentsByDate(year, month, day, (done, result, message)=>{
            if(done){
                hirAccountActions.payload({
                    [hirAccountStrings.userBasedPayments] : result
                })(dispatch);
            }else errorNotice(message, dispatch)
            if(callback) callback(done, result, message);
        })
    },
    getRevenuePaymentsByDate : (year, month, day, callback) => dispatch =>{
        hirAccountServices.getRevenuePaymentsByDate(year, month, day, (done, result, message)=>{
            if(done){
                hirAccountActions.payload({
                    [hirAccountStrings.revenueBasedPayments] : result
                })(dispatch);
            }else errorNotice(message, dispatch)
            if(callback) callback(done, result, message);
        })
    },
    getSearchMinMaxPatientId : (keyword, callback) => {
        hirPatientServices.getSearchMinMaxPatientId(keyword, callback);
    },
    getPaymentGroup : (groupId, callback) => {
        hirAccountServices.getPaymentGroup(groupId, callback);
    },
    postPayment : (lastId, rows, patientId, data, callback) => dispatch =>{
        hirAccountServices.postPayment({patientId, data}, (done, result, message)=>{
            if(done) {
                successNotice(message, dispatch);
                // hirAccountActions.getPayments(lastId, rows)(dispatch);
            }
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getPayments : (lastId, rows, callback) => dispatch =>{
        hirAccountServices.getPayments(lastId, rows, (done, result, message)=>{
            if(done){
                hirAccountActions.payload({
                    [hirAccountStrings.payments] : result
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    
    payload : payload => dispatch =>dispatch({
        type : hirAccountConstant.SET_ACCOUNT,
        payload
    })
}