import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import classNames from 'classnames';
import { Grid, TextField, Paper } from '@material-ui/core';
import { inventoryUtil } from '../../../../utils';
import { ArrowDownwardOutlined } from '@material-ui/icons';
import { invProductStrings } from '../../../config';
import { invProductActions } from '../../../actions';


const style = theme => ({
    root: {
        background : inventoryUtil.getTheme().background,
    },
    package : {
        margin : 5,
        border : "solid 2px " + inventoryUtil.getTheme().background,
        borderRadius : 10,
        padding : 10,
        fontSize : 12,
    },
    productStyle : {
        border : "solid 2px "+inventoryUtil.getTheme().secondary,
        color : inventoryUtil.getTheme().secondary,
    },
    packageContainer : {
        display : "flex",
        flexDirection : "column",
        alignItems : "center",
    }
})
class _INVProductPackagingCount extends Component {
    state = {
        packageCount : {},
    }
    componentDidMount() {
        const {dispatch, [invProductStrings.productPackages] : productPackages} = this.props;
        if(!productPackages)
            invProductActions.getProductPackages()(dispatch);
    }
    
    onChangeCount = packageId => e => {
        const value = e.target.value;
        const {packageCount} = this.state;
        packageCount[packageId] = parseInt(value);
        this.setState({packageCount});
    }
    render() {
        const {
            classes, packaging,
            [invProductStrings.productPackages] : productPackages
        } = this.props;
        const {packageCount} = this.state;
        return (
            <Paper className={classes.root}>
                <Grid container spacing={2}>
                    {packaging && packaging.packageIds && 
                    packaging.packageIds.map((packageId, index)=>{
                        let pack;
                        if(packageId !== 1){
                            pack = productPackages.find(_item=>_item._id == packageId);
                        }
                        return pack && <Fragment key={index}>
                            <Grid item xs={6} sm={6} md={6} lg={6} xl={6}>
                                <div className={classes.packageContainer} key={index}>
                                    <div className={classes.package}>{pack.name}</div>
                                    <ArrowDownwardOutlined color="secondary"/>
                                </div>
                            </Grid>
                            <Grid item>
                                <TextField
                                    variant="outlined"
                                    disabled={index === 0}
                                    value={index === 0 ? 1 : packageCount[packageId]}
                                    label={pack.name + " count"}
                                    placeholder="count"
                                    type="number"
                                    onChange={this.onChangeCount(packageId)}
                                    />
                            </Grid>
                        </Fragment>
                    })}
                    <Grid item xs={6} sm={6} md={6} lg={6} xl={6}>
                        <div className={classes.packageContainer}>
                            <span className={classNames(classes.package, classes.productStyle)}>PRODUCT</span>
                        </div>
                    </Grid>
                    <Grid item>
                        <TextField
                            variant="outlined"
                            value={packageCount["final"]}
                            label={"Product count"}
                            placeholder="count"
                            type="number"
                            onChange={this.onChangeCount("final")}
                            />
                    </Grid>
                </Grid>
            </Paper>
        );
    }
}


_INVProductPackagingCount.propTypes = {
    classes : PropTypes.object.isRequired,
    packaging : PropTypes.object,
};
const mapStateToProps = ({invProductReducer}) => ({
    [invProductStrings.productPackages] : invProductReducer[invProductStrings.productPackages],
})


export const INVProductPackagingCount = connect(mapStateToProps)(withStyles(style)(_INVProductPackagingCount));
export {INVProductPackagingCount as default}