export const insureServiceStrings = {
    services : "services",
}
export const insureServiceConstants = {
    SET_INSURE_SERVICES : "SET_INSURE_SERVICES",
}
export const insureServiceReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case insureServiceConstants.SET_INSURE_SERVICES : 
            return {...state, ...payload};
        default : return {...state};
    }
}