function getAppComponent(runningApp){
    switch(runningApp){
        case appNames.school : return SchoolManagement;
        case appNames.tracker : return TrackerApp;
        case appNames.agroAfrik : return AgroAfrikApp;
        case appNames.agroAfrikAdmin : return AgroAfrikAdminApp;
        case appNames.moboinsure : return MoboinsureApp;
        case appNames.moboinsureAdmin : return MoboinsureAdminApp;
        case appNames.inovateOSSite : return InovateOSApp;
        case appNames.inovateOSAdmin : return InovateOSAdminApp;
        case appNames.healthRecord : return HIRApp;
        case appNames.inventory : return Inventory_App;
        case appNames.hms : return hmsApp;
    }
}
export const runningApp = appNames.healthRecord; // [appNames.healthRecord, appNames.inventory]; // [appNames.inovateOSSite, appNames.inovateOSAdmin];
function getRunningAppComponent(runningApp){
    if(typeof runningApp === "string"){
        return getAppComponent(runningApp);
    }else{
        return props => <Fragment>
            {runningApp.map((rApp, index)=>{
                const Component = getAppComponent(rApp);
                return <Component runningApp={runningApp} key={index} {...props}/>
            })}
        </Fragment>
    }
}
export default connect()(getRunningAppComponent(runningApp))