import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyCustomTabs, breadCrumbActions } from '../../../includes';
import { inovateOSAdminRouteNames } from '../routeNames';
import { Subscribers } from './Subscribers';
import Messages from './Messages/Messages';


const style = theme => ({
    root: {
    },
    container : {
        padding : 20,
    }
})
class _inovateOSAdminNewsletter extends Component {
    constructor(props) {
        super(props);
        const {dispatch} = props;
        breadCrumbActions.setBreadCrumb([
            {name : "Site", path : inovateOSAdminRouteNames.home},
            {name : "Newsletter", path : inovateOSAdminRouteNames.newsletter}
        ])(dispatch);
        this.state= {
            tabValue : null
        }
    }
    
    render() {
        const {classes} = this.props;
        const {tabValue} = this.state;
        return (
            <div className={classes.root}>
                <MyCustomTabs
                    position="sticky"
                    tabs={{
                        subs : "Subscribers",
                        message : "Messages",
                    }}
                    getInitialTabValue={tabValue=>this.setState({tabValue})}
                    />
                <div className={classes.container}>
                    {tabValue === "subs" && <Subscribers/>}
                    {tabValue === "message" && <Messages/>}
                </div>
            </div>
        );
    }
}


_inovateOSAdminNewsletter.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = state => ({
    state
})


export const inovateOSAdminNewsletter = connect(mapStateToProps)(withStyles(style)(_inovateOSAdminNewsletter));
export {inovateOSAdminNewsletter as default}