import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyTable, EditableCellMapFormat,  HighlightedInfo, inventoryUtil, appActions, alertAction } from "../../../utils";
import { invProductStrings } from '../../config';
import { invProductActions } from '../../actions';
import { Button } from '@material-ui/core';
import classNames from 'classnames';


const style = theme => ({
    root: {
    }
})
class _INVProductCategories extends Component {
    state ={
        productCats : null
    }
    componentDidMount() {
        this.getProductCats();
    }    
    getProductCats(){
        const {dispatch} = this.props;
        invProductActions.getProductCats((done, result)=>{
            if(done) this.setState({productCats : result});
        })(dispatch);
    }
    newCatContext = {};
    cellMapFormat=superProps=>props=><EditableCellMapFormat {...props} {...superProps}/>
    deleteBtnHandler = row => () => {
        const {dispatch} = this.props;
        appActions.showSnackDialog("Are you sure you want to delete this tag?",
        [<Button key="deleteCat" onClick={()=>{
            appActions.closeSnackDialog()(dispatch);
            invProductActions.deleteProductCat(row._id, (done)=>{
                if(done) this.getProductCats();
            })(dispatch);
        }}>Delete</Button>])(dispatch);
    }
    editBtnHandler = row => () => {
        const {productCats} = this.state;
        const index = productCats.findIndex(item=>item._id === row._id);
        if(index || index === 0){
            productCats[index].editing = true;
        }
        this.setState({productCats});
    }
    addButtonHandler = row => () => {
        const {dispatch} = this.props;
        const nameComponent = this.newCatContext.name;
        const descriptionComponent = this.newCatContext.description;
        const name = nameComponent.state.data.value;
        const description = descriptionComponent.state.data.value;
        if(!name || !String(name).trim()){
            appActions.showSnackbar(
                alertAction.error("Cat name can not be an empty string")
            )(dispatch);
            return;
        }
        const data = {name, description};
        invProductActions.createProductCat(data, (done, result)=>{
            if(done) {
                nameComponent.setState({value : ""});
                descriptionComponent.setState({vallue : ""});
                this.getProductCats();
            }
        })(dispatch);
    }
    editFinishBtnHandler = row => () => {
        const {dispatch} = this.props;        
        const {context} = row;
        const {name : nComponent, description : dComponent} = context;
        const name = nComponent.state.data.value;
        const description = dComponent.state.data.value;
        if(!name || !String(name).trim()){
            appActions.showSnackbar(
                alertAction.error("Cat name can not be an empty string")
            )(dispatch);
            return;
        }
        const data = {name, description};
        invProductActions.updateProductCat(row._id, data, (done)=>{
            if(done) {
                this.getProductCats();
            }
        })(dispatch);
    }
    cancelEditBtnHandler = row => () => {
        const {productCats} = this.state;
        const index = productCats.findIndex(item=>item._id === row._id);
        if(index || index === 0){
            delete productCats[index].editing;
        }
        this.setState({productCats});
    }
    render() {
        const {classes} = this.props;
        let {productCats} = this.state;
        let header = ["ID", "Name", "Descriptions"];
        let dataMap = ["_id", "name", "description"];
        if(inventoryUtil.isAdmin()){
            header = [...header, "Actions"];
            dataMap = [...dataMap, "action"];
            productCats = productCats ? 
                [...productCats.map(
                    item=>({...item, delible : true, editable : true})
                ), {new : true}] : 
                [{new : true}];
        }
        return (
            <div className={classNames(classes.root, "animated", "zoomIn")}>
                <HighlightedInfo>
                    Deleting a category already in use will default the item tags to 'UNKNOWN'
                </HighlightedInfo>
                <MyTable
                    header={header}
                    dataMap={dataMap}
                    data={productCats||[]}
                    CellMap={this.cellMapFormat({
                        skipEdit : ["_id"],
                        getContext : (context, cellMap) => this.newCatContext[cellMap] = context,
                        deleteBtnHandler : this.deleteBtnHandler.bind(this),
                        editBtnHandler : this.editBtnHandler.bind(this),
                        addButtonHandler : this.addButtonHandler.bind(this),
                        editFinishBtnHandler : this.editFinishBtnHandler.bind(this),
                        cancelEditBtnHandler : this.cancelEditBtnHandler.bind(this),
                    })}
                />
            </div>
        );
    }
}


_INVProductCategories.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({invProductReducer}) => ({
    [invProductStrings.productCats] : invProductReducer[invProductStrings.productCats],
})


export const INVProductCategories = connect(mapStateToProps)(withStyles(style)(_INVProductCategories));
export {INVProductCategories as default}