import { breadCrumbConstants } from "./config";

export const breadCrumbActions = {
    hide : () => dispatch => dispatch({
        type : breadCrumbConstants.BREAD_CRUMB_HIDE,
    }),
    addToBreadCrumb : value => dispatch=>dispatch({
        type : breadCrumbConstants.BREAD_CRUMB_ADD,
        payload : value
    }),
    setBreadCrumb : value => dispatch => dispatch({
        type : breadCrumbConstants.BREAD_CRUMB,
        payload : value
    }),
    setProps : props => dispatch => dispatch({
        type : breadCrumbConstants.SET_PROPS,
        payload : props
    })
}