import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { FormGroup, FormLabel, FormControl, Radio, RadioGroup, FormControlLabel, Button } from '@material-ui/core';
const style = theme => ({
    root: {
        
    },
    actionBtn : {
        padding : 5
    }
})
class _NewSessionOptions extends Component {
    constructor(props) {
        super(props);
        this.state = {
            option : 1
        }
    }
    handleChange=e=>this.setState({option: e.target.value});
    continue = () => {
        this.props.closeDialog();
        this.props.continueHandler(this.state.option);
    }
    render() {
        const {classes, closeDialog} = this.props;
        return (
            <div className={classes.root}>
                <FormGroup>
                        <FormLabel style={{margin : "20px 0px", textAlign: "center"}}>Level Selection</FormLabel>
                        <FormControl>
                            <RadioGroup
                                style={{
                                    alignItems : "center"
                                }}
                                value={this.state.option}
                                onChange={this.handleChange.bind(this)}>
                                <FormControlLabel
                                    control={<Radio value="1"/>}
                                    label="Use existing levels only"/>
                                <FormControlLabel
                                    control={<Radio value="2"/>}
                                    label="Use existing levels and classes"/>
                                <FormControlLabel
                                    control={<Radio value="3"/>}
                                    label="Create new Levels"/>
                            </RadioGroup>
                        </FormControl>
                        <FormControl style={{flexDirection: "row", margin : "20px 0px", justifyContent : "center"}}>
                            <Button className={classes.actionBtn} onClick={closeDialog} variant="outlined" color="secondary">Cancel</Button>
                            <Button className={classes.actionBtn} style={{marginLeft : 10}} onClick={this.continue.bind(this)} variant="outlined" color="primary">Continue</Button>
                        </FormControl>
                    </FormGroup>
            </div>
        );
    }
}
_NewSessionOptions.propTypes = {
    classes : PropTypes.object.isRequired,
    closeDialog : PropTypes.func,
    continueHandler : PropTypes.func,
};
export const NewSessionOptions = withStyles(style)(_NewSessionOptions);