import { insureAdminNewsletterConstants, insureAdminNewsletterStrings } from "./config";
import { insureAdminNewsletterServices } from "./services";
import { errorNotice, successNotice } from "../utils";

export const insureAdminNewsletterActions = {
    getNewsletters : (lastId, rows, callback) => dispatch => {
        insureAdminNewsletterServices.getNewsletters(lastId, rows, (done, result, message)=>{
            if(done) {
                insureAdminNewsletterActions.payload({
                    [insureAdminNewsletterStrings.newsletters] : result
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    addNewsletter : (data, callback)=>dispatch => {
        insureAdminNewsletterServices.addNewsletter(data, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getSubscribers : (lastId, rows, callback) => dispatch => {
        insureAdminNewsletterServices.getNewsletterSubscribers(lastId, rows, (done, result, message)=>{
            if(done){
                insureAdminNewsletterActions.payload({
                    [insureAdminNewsletterStrings.subscribers] : result
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch => dispatch({
        type : insureAdminNewsletterConstants.SET_INSURE_ADMIN_NEWSLETTER,
        payload
    })
}