import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Button } from '@material-ui/core';
import { Add } from '@material-ui/icons';
import { MyTable, MyDialog } from '../../../../includes';
import { inovateOSAdminNewsletterStrings } from '../config';
import { MessageBox } from './MessageBox';
import { appActions, alertAction } from '../../../../../actions';
import { inovateOSAdminNewsletterActions } from '../actions';


const style = theme => ({
    root: {
        margin : 20,
    },
    msgBoxRoot : {
        marginTop : 20,
    }
})
class _Messages extends Component {
    constructor(props) {
        super(props);
        this.state = {
            newMessageDialog : false,
            lastId : null,
            rows : 20,
        }
    }
    componentDidMount() {
        this.getNewsletters();
    }
    
    getNewsletters(){
        const {dispatch} = this.props;
        const {lastId, rows} = this.state;
        inovateOSAdminNewsletterActions.getNewsletters(lastId, rows)(dispatch);
    }
    sendMessage(data, context){
        const {dispatch} = this.props;
        inovateOSAdminNewsletterActions.addNewsletter(data, done => {
            context.setState({loading : false});
            if(done){
                this.setState({newMessageDialog: false});
                this.getNewsletters();
            }
        })(dispatch);
    }
    notify(message, type){
        const {dispatch} = this.props;
        appActions.showSnackbar(
            alertAction[type](message)
        )(dispatch);
    }
    render() {
        const {
            classes,
            [inovateOSAdminNewsletterStrings.newsletters] : newsletters
        } = this.props;
        const {newMessageDialog} = this.state;
        console.log(this.props);
        return (
            <div className={classes.root}>
                <Button
                    variant="contained"
                    color="primary"
                    onClick={()=>this.setState({newMessageDialog : true})}>
                        <Add/> Compose
                    </Button>
                <MyTable
                    header={["ID", "Subject", "Message", "Actions"]}
                    dataMap={["_id", "subject", "message", "action"]}
                    data={newsletters || []}
                    />

                <MyDialog open={newMessageDialog} 
                    close={()=>this.setState({newMessageDialog: false})}>
                    <MessageBox
                        classes={{root : classes.msgBoxRoot}}
                        onSendClick={this.sendMessage.bind(this)}
                        notify={this.notify.bind(this)}/>
                </MyDialog>
            </div>
        );
    }
}


_Messages.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({inovateOSAdminNewsletterReducer}) => ({
    [inovateOSAdminNewsletterStrings.newsletters] : inovateOSAdminNewsletterReducer[inovateOSAdminNewsletterStrings.newsletters],
})


export const Messages = connect(mapStateToProps)(withStyles(style)(_Messages));
export {Messages as default}