import { agroAdminUtilConstants, agroAdminUtilStrings } from "./config";
import { agroAdminUtilServices } from "./services";
import { _storeData } from "../../../utils";
import { errorNotice } from "./agroAdminUtil";

export const agroAdminUtilActions = payload => dispatch => dispatch({
    type : agroAdminUtilConstants.SET_UTIL,
    payload 
});

export const agroAdminActions = {
    getUser : callback => dispatch => {
        agroAdminUtilServices.getUser((done, result, message)=>{
            if(done){
                agroAdminUtilActions({
                    [agroAdminUtilStrings.myProfile] : result.myProfile,
                    [agroAdminUtilStrings.trackingMe] : result.trackingMe,
                    [agroAdminUtilStrings.disableAllTracking] : result.disableAllTracking,
                })(dispatch);
            }
            if(callback) callback(done, result, message);
        })
    },
    signup : (data, callback) => dispatch => {
        agroAdminUtilServices.signup(data, (done, result, message)=>{
            if(done){
                _storeData([agroAdminUtilStrings.tokenAlias], result.myProfile.token);
                _storeData([agroAdminUtilStrings.userAlias], result._id);
                agroAdminUtilActions({
                    [agroAdminUtilStrings.myProfile] : result.myProfile,
                    [agroAdminUtilStrings.trackingMe] : result.trackingMe,
                    [agroAdminUtilStrings.disableAllTracking] : result.disableAllTracking,
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    loging : (email, password, callback) => dispatch => {
        agroAdminUtilServices.login(email, password, (done, result, message)=>{
            if(done){
                _storeData([agroAdminUtilStrings.tokenAlias], result.myProfile.token);
                _storeData([agroAdminUtilStrings.userAlias], result._id);
                agroAdminUtilActions({
                    [agroAdminUtilStrings.myProfile] : result.myProfile,
                    [agroAdminUtilStrings.trackingMe] : result.trackingMe,
                    [agroAdminUtilStrings.disableAllTracking] : result.disableAllTracking,
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    logout : () => {
        localStorage.removeItem([agroAdminUtilStrings.tokenAlias]);
        localStorage.removeItem([agroAdminUtilStrings.userAlias]);
    },
}
