import { inovateOSUtilServices, inovateOSUtil } from "../utils";
import { errorNotice, successNotice } from "../../../../utils";
import { inovateOSPageConstants, inovateOSPageStrings } from "./config";
import { inovateOSPageServices } from "./services";
import { inovateOSRouteNames } from "../routeNames";
import { headerActions, headerStrings } from "../../../includes";

export const inovateOSPageActions = {
    setServiceMenus : (menuItems, callback) => dispatch => {
        inovateOSPageActions.getServices((done, {values : services}, message)=>{
            if(menuItems){
                menuItems = menuItems.map(item => {
                    if(item.name === "Services" && services){
                        item.tree = services.map(
                            item=>({
                                name : item.header, 
                                pathname : inovateOSRouteNames.serviceItem_+item.name
                            })
                        )
                    }
                    return {...item}
                });
                headerActions({
                    [headerStrings.menuItems] : [...menuItems],
                })(dispatch);
            }
            if(callback) callback(done, services, message);
        })(dispatch);
    },
    unsubscribe : (id, email, callback) => dispatch => {
        inovateOSPageServices.unsubscribe(id, email, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    subscribeNewsLetter : (name, email, callback) => dispatch => {
        inovateOSPageServices.subscribeNewsLetter(name, email, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    addMessage : (data, callback) => dispatch => {
        inovateOSPageServices.addMessage(data, (done, result, message)=>{
            if(done) successNotice(message, dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getAttributs : callback => dispatch => {
        inovateOSUtilServices.getSiteInfo("attributes", null, (done, result, message)=>{
            if(done) inovateOSPageActions.payload({
                [inovateOSPageStrings.attributes] : result.values
            })(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getAboutUs : callback => dispatch => {
        inovateOSUtilServices.getSiteInfo("aboutUs", null, (done, result, message)=>{
            if(done) inovateOSPageActions.payload({
                [inovateOSPageStrings.aboutUs] : result
            })(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getServices : callback => dispatch =>{
        inovateOSUtilServices.getSiteInfo("services", null, (done, result, message)=>{
            if(done) inovateOSPageActions.payload({
                [inovateOSPageStrings.services] : result.values
            })(dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getHomeInfo : callback => dispatch => {
        inovateOSUtilServices.getSiteInfo("home", null, (done, result, message)=>{
            if(done) inovateOSPageActions.payload({
                [inovateOSPageStrings.homeInfo] : result,
            })(dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getCarousel : callback => dispatch => {
        inovateOSUtilServices.getSiteInfo("carousel", null, (done, result, message)=>{
            if(done) inovateOSPageActions.payload({
                [inovateOSPageStrings.carousel] : result
            })(dispatch);
            else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch => dispatch({
        type : inovateOSPageConstants.SET_INOVATE_OS_PAGE,
        payload
    })
}