import { profileServices } from "./services"
import { profileConstants } from "./config"
import { store } from "../../../helpers"
import { trackerUtilStrings, errorNotice, trackerUtilActions } from "../utils"

export const profileActions = {
    sendImage : (data, callback)=>dispatch=>{
        profileServices.sendImage(data, (done, result, message)=>{
            
        })
    },
    updateProfile : (data, callback) => dispatch => {
        profileServices.updateProfile(data, (done, result, message, data)=>{
            let profile = store.getState().trackerUtilReducer[trackerUtilStrings.myProfile] || {};
            if(done){
                trackerUtilActions({
                    [trackerUtilStrings.myProfile] : {...profile, ...data}
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch => dispatch({
        type : profileConstants.SET_PROFILE,
        payload
    })
}